# ── Harden NiceGUI's session cookie ────────────────────────────────────────
# NiceGUI uses Starlette's SessionMiddleware (driven by storage_secret in
# ui.run) to back app.storage.user. We monkey-patch the constructor so that
# whenever NiceGUI instantiates it, the cookie gets secure defaults:
#   - SameSite=Lax (default already, but explicit)
#   - HttpOnly (Starlette default, can't be read by JavaScript)
#   - Secure flag in server mode (we run behind HTTPS via Cloudflare)
def _harden_session_middleware():
    import starlette.middleware.sessions as _sm
    _orig_init = _sm.SessionMiddleware.__init__
    def _patched_init(self, app, secret_key, **kwargs):
        kwargs.setdefault("same_site", "lax")
        kwargs.setdefault("max_age", 14 * 24 * 60 * 60)
        if _SERVER_MODE:
            kwargs.setdefault("https_only", True)
        _orig_init(self, app, secret_key, **kwargs)
    _sm.SessionMiddleware.__init__ = _patched_init
_harden_session_middleware()

# ── Security headers middleware (CSP, XFO, etc.) ───────────────────────────
# Defense in depth: even if some XSS slips through our HTML sanitizer, the
# Content Security Policy header tells the browser to refuse to execute
# inline scripts from any origin we didn't explicitly allow.
#
# NiceGUI itself uses inline scripts and inline styles heavily for its
# component rendering, so we have to allow 'unsafe-inline' for both. That
# means CSP isn't a silver bullet against XSS  -  but it DOES still block:
#   - <script src=> loaded from any third-party domain we don't allow
#   - <iframe> embeds
#   - eval() (via the 'unsafe-eval' restriction)
#   - form actions to off-site domains
#   - the page being framed by an attacker (clickjacking)
# Plus the X-Frame-Options, X-Content-Type-Options, and Referrer-Policy
# headers cover the most common browser hardening best-practices.
@app.middleware("http")
async def _security_headers_middleware(request, call_next):
    response = await call_next(request)
    # Skip injecting headers on the websocket upgrade response
    if response.status_code == 101:
        return response
    csp_parts = [
        "default-src 'self'",
        # NiceGUI uses inline JS + Vue templates, so we have to allow it.
        # 'unsafe-eval' is required by Vue 3 in dev/runtime template mode.
        "script-src 'self' 'unsafe-inline' 'unsafe-eval'",
        "style-src 'self' 'unsafe-inline' https://fonts.googleapis.com",
        "font-src 'self' https://fonts.gstatic.com data:",
        "img-src 'self' data: blob: https:",
        "connect-src 'self' wss: https:",
        # Block all <iframe> embeds  -  we never use them and any injected
        # iframe would be an attack vector.
        "frame-src 'none'",
        "frame-ancestors 'none'",  # clickjacking protection
        "form-action 'self'",
        "base-uri 'self'",
        "object-src 'none'",
    ]
    response.headers["Content-Security-Policy"] = "; ".join(csp_parts)
    response.headers["X-Frame-Options"] = "DENY"
    response.headers["X-Content-Type-Options"] = "nosniff"
    response.headers["Referrer-Policy"] = "strict-origin-when-cross-origin"
    response.headers["Permissions-Policy"] = (
        "geolocation=(), microphone=(), camera=(), payment=()"
    )
    # Override NiceGUI's immutable JS cache for component files. NiceGUI
    # sets `max-age=31536000, immutable` on /_nicegui/.../components/*.js
    # which means patched files (like our editor.js toolbar fix) are NEVER
    # re-fetched by browsers. Force short cache so patches take effect.
    _path = request.url.path
    if '/_nicegui/' in _path and '/components/' in _path:
        # MutableHeaders may not replace on __setitem__  -  delete first
        if "cache-control" in response.headers:
            del response.headers["cache-control"]
        response.headers["cache-control"] = "no-cache, max-age=0, must-revalidate"
    return response

# ── Authenticated PDF route ────────────────────────────────────────────────
# Replaces the old `app.add_static_files('/pdfs', ...)` which served every
# generated PDF publicly by filename  -  a Broken Object Level Authorization
# hole because filenames were guessable (company-name based) and there was
# no auth check at all. The new route reads the authenticated user's email
# from the signed session cookie and only serves files from THAT user's
# per-user PDFs/ directory.
from starlette.responses import FileResponse, Response
from starlette.requests import Request


# ── Healthcheck endpoint ──────────────────────────────────────────────────
# Lightweight endpoint the reconnect overlay polls after a deploy. Returns
# a tiny plaintext "ok" without requiring auth or touching any per-user
# state  -  so it's safe to poll rapidly without eating resources.
@app.get("/healthz")
def _healthz():
    from starlette.responses import PlainTextResponse
    return PlainTextResponse("ok", headers={"Cache-Control": "no-store"})


@app.get("/pdfs/{filename:path}")
def _serve_pdf(filename: str, request: Request):
    """Attachment serving. On desktop (single-user mode) serves from the
    local PDFs/ directory without auth. On the cloud server, requires a
    valid signed session cookie and only serves files from THAT user's
    per-user PDFs/ directory.

    Despite the route name, serves ALL allowed attachment file types
    (PDF, Word, Excel, PowerPoint, images, text/CSV/RTF) — they all live
    in the same per-user PDFs directory regardless of extension. The
    /pdfs/ prefix is kept for backward compat with existing campaign
    JSONs that reference attachments by that URL."""
    # Block obvious path traversal before doing any work
    if "/" in filename or "\\" in filename or ".." in filename:
        return Response(status_code=404)
    # Reject anything outside the allowed attachment extension list
    _ext = filename.rsplit(".", 1)[-1].lower() if "." in filename else ""
    if _ext not in _ALLOWED_ATTACHMENT_EXTS:
        return Response(status_code=404)
    # Resolve the right media type. mimetypes covers the standard set;
    # we explicitly map a few that mimetypes misses or returns wrong on
    # some platforms (Windows registry-driven results vary).
    import mimetypes as _mt
    _media_type = _mt.guess_type(filename)[0] or "application/octet-stream"
    _ext_overrides = {
        "docx": "application/vnd.openxmlformats-officedocument.wordprocessingml.document",
        "xlsx": "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
        "pptx": "application/vnd.openxmlformats-officedocument.presentationml.presentation",
        "doc":  "application/msword",
        "xls":  "application/vnd.ms-excel",
        "ppt":  "application/vnd.ms-powerpoint",
        "pdf":  "application/pdf",
        "rtf":  "application/rtf",
        "csv":  "text/csv",
        "txt":  "text/plain",
        "odt":  "application/vnd.oasis.opendocument.text",
        "ods":  "application/vnd.oasis.opendocument.spreadsheet",
        "odp":  "application/vnd.oasis.opendocument.presentation",
    }
    if _ext in _ext_overrides:
        _media_type = _ext_overrides[_ext]

    # Desktop mode: single user, no auth, serve from the global _user_pdf_dir()
    if not _SERVER_MODE:
        try:
            local_path = _user_pdf_dir() / filename
            if local_path.is_file():
                return FileResponse(
                    str(local_path),
                    media_type=_media_type,
                    headers={"Cache-Control": "private, max-age=300"},
                )
        except Exception:
            pass
        return Response(status_code=404)

    # Server mode: resolve the signed-in user's email. NiceGUI stores user
    # data under `app.storage.user` (session-scoped), so that's the
    # authoritative source. We also fall back to Starlette's request.session
    # for belt-and-suspenders, in case the NiceGUI context isn't established
    # for this raw FastAPI route.
    email = ""
    try:
        email = (app.storage.user.get("email") or "").strip()
    except Exception:
        pass
    if not email:
        try:
            sess = request.session
            if isinstance(sess, dict):
                user_obj = sess.get("user", {})
                if isinstance(user_obj, dict):
                    email = (user_obj.get("email") or "").strip()
                if not email and isinstance(sess.get("email"), str):
                    email = sess["email"].strip()
        except Exception:
            pass
    if not email:
        # Distinctive log line so we can grep journalctl for unauth hits
        # while we verify this fix. Remove once confirmed stable.
        try:
            print(f"[PDF_AUTH] 401 for filename={filename!r} "
                  f"session_keys={list(request.session.keys()) if hasattr(request,'session') else 'no-session'}",
                  flush=True)
        except Exception:
            pass
        return Response(status_code=401)
    # Resolve to the requesting user's per-user PDFs directory
    safe_name = email.lower().replace("@", "_at_").replace(".", "_")
    if not re.match(r"^[a-z0-9_]+$", safe_name):
        return Response(status_code=400)
    user_pdf_dir = _BASE_DATA_DIR / "users" / safe_name / "PDFs"
    pdf_path = user_pdf_dir / filename
    # Defense in depth: resolve and confirm the file lives inside the user dir
    try:
        pdf_resolved = pdf_path.resolve()
        user_resolved = user_pdf_dir.resolve()
        if not str(pdf_resolved).startswith(str(user_resolved)):
            return Response(status_code=404)
    except Exception:
        return Response(status_code=404)
    if not pdf_path.is_file():
        return Response(status_code=404)
    return FileResponse(
        str(pdf_path),
        media_type=_media_type,
        headers={"Cache-Control": "private, max-age=300"},
    )

# Avatars stay public-but-unguessable. The email_key in the URL is the
# safe-encoded email; only routes that anyone with the URL is allowed to
# read should use this pattern. Path-traversal is blocked by the regex.
@app.get("/avatar/{email_key}")
def _serve_avatar(email_key: str):
    """Serve a user's profile photo. email_key is the safe-encoded email
    (e.g. 'mike_at_example_com')."""
    if not re.match(r"^[a-z0-9_]+$", email_key):
        return Response(status_code=404)
    photo_dir = _BASE_DATA_DIR / "users" / email_key / "profile"
    if not photo_dir.exists():
        return Response(status_code=404)
    for f in photo_dir.glob("avatar.*"):
        if f.is_file():
            return FileResponse(str(f), headers={"Cache-Control": "private, max-age=60"})
    return Response(status_code=404)


@app.get("/tenant_logo")
def _serve_tenant_logo():
    """Serve the requesting user's tenant logo (shared across email
    domain). Used by the Tenant Branding form to show a live preview
    of the current logo so admins can confirm what's deployed before
    replacing it. Reads the user's email from the session cookie and
    looks up the tenant directory by domain — no caller-provided path,
    so no traversal vector."""
    try:
        email = (app.storage.user.get("email") or "").strip().lower()
    except Exception:
        return Response(status_code=404)
    if not email or "@" not in email:
        return Response(status_code=404)
    p = _tenant_logo_path(email)
    if not p:
        return Response(status_code=404)
    return FileResponse(p, headers={"Cache-Control": "private, max-age=30"})


# City hero photo route — serves cached Unsplash thumbnails to the
# newsletter editor's hero gallery via plain URLs instead of inline
# base64 (which was held in NiceGUI's widget tree and accumulated
# memory across modal opens). Files live in the SHARED city_images
# cache dir; no per-user auth needed since these are generic city
# photos already published on Unsplash. Strictly bounded to
# {slug}.unsplash.{N}.hero.jpg files inside that single directory.
@app.get("/city_image/{slug}/{variant}.jpg")
def _serve_city_image(slug: str, variant: str):
    if "/" in slug or "\\" in slug or ".." in slug or not slug:
        return Response(status_code=404)
    if not variant.isdigit() or len(variant) > 2:
        return Response(status_code=404)
    cache_dir = _BASE_DATA_DIR / "city_images"
    target = cache_dir / f"{slug}.unsplash.{int(variant)}.hero.jpg"
    if not target.is_file():
        return Response(status_code=404)
    return FileResponse(
        str(target),
        media_type="image/jpeg",
        headers={"Cache-Control": "public, max-age=86400"},
    )


# Newsletter email image cache. We used to inline every image as base64
# directly in the email body — emails routinely hit 350+ KB and Gmail
# would clip / mangle them. Now in server mode we write the bytes once
# to disk and reference an https URL in the email; emails drop to
# ~30 KB and render cleanly across Gmail / Outlook / Apple Mail.
@app.get("/email_img/{subdir}/{filename}")
def _serve_email_img(subdir: str, filename: str):
    """Serve a cached newsletter image. Path traversal is rejected and
    only known subdirs are allowed. Long cache header (1 week) since
    filenames are content-addressed (sha1 of bytes) — same image always
    has the same URL, safe to cache forever."""
    for component in (subdir, filename):
        if not component or "/" in component or "\\" in component or ".." in component:
            return Response(status_code=404)
    # Allowlist of subdirs we ever write into. Keeps random URLs from
    # being routable into other server data.
    if subdir not in ("cat", "hero", "avatar", "activity", "corner",
                      "logo", "flag", "roundup"):
        return Response(status_code=404)
    target = _BASE_DATA_DIR / "email_imgs" / subdir / filename
    if not target.is_file():
        return Response(status_code=404)
    name_lower = filename.lower()
    if name_lower.endswith((".jpg", ".jpeg")):
        media = "image/jpeg"
    elif name_lower.endswith(".png"):
        media = "image/png"
    elif name_lower.endswith(".gif"):
        media = "image/gif"
    else:
        media = "application/octet-stream"
    return FileResponse(
        str(target),
        media_type=media,
        headers={"Cache-Control": "public, max-age=604800, immutable"},
    )


# Static asset route  -  strict allowlist of files in the project root that
# may be served. Replaces the old `add_static_files('/static', _APP_DIR)`
# which exposed the entire source tree (including flowdrip_app.py) to the
# public. Only files in _STATIC_ALLOWLIST can be downloaded.
@app.get("/static/{filename:path}")
def _serve_static_asset(filename: str):
    # Strip query string artifacts (e.g. cache-buster ?v=3 the framework
    # may pass through into the path) and reject anything with traversal.
    name = filename.split("?", 1)[0]
    if "/" in name or "\\" in name or ".." in name or not name:
        return Response(status_code=404)
    if name not in _STATIC_ALLOWLIST:
        return Response(status_code=404)
    target = _APP_DIR / name
    if not target.is_file():
        return Response(status_code=404)
    return FileResponse(
        str(target),
        headers={"Cache-Control": "public, max-age=86400"},
    )


# Desktop installer download  -  302 redirects to the real CDN URL set in
# the DRIPDROP_DESKTOP_URL env var. Going through this route instead of
# linking the CDN directly means: (1) we can swap CDNs without re-deploying
# the landing page, (2) we can later add download analytics, (3) we can
# show a friendly error if the URL isn't configured yet.
from starlette.responses import RedirectResponse, PlainTextResponse, HTMLResponse

@app.get("/download")
def _download_desktop():
    # Gate the desktop installer behind a signed-in account. Unauthenticated
    # visitors get bounced to /login?next=/download so they land right back
    # here after signing in. Registration still requires an invite code, so
    # this effectively ties every download to an approved beta user.
    try:
        if not app.storage.user.get("authenticated"):
            return RedirectResponse(url="/login?next=/download", status_code=302)
    except Exception:
        # Desktop mode / storage not yet initialized  -  let it through.
        pass
    if not _DESKTOP_DOWNLOAD_URL:
        return PlainTextResponse(
            "DripDrop Desktop is coming soon. Email support@dripdripdrop.ai "
            "to be notified when it's ready.",
            status_code=503,
        )
    return RedirectResponse(url=_DESKTOP_DOWNLOAD_URL, status_code=302)


# Server-hosted installer route. Currently the installer lives at
# /opt/dripdrop/downloads/DripDrop-Setup-<version>.exe. This route serves
# files from that directory only, with a strict regex on the filename.
# When traffic gets heavy enough to matter, swap to Cloudflare R2 by
# setting DRIPDROP_DESKTOP_URL to the R2 URL  -  the /download route above
# already handles the redirect path.
_DESKTOP_DOWNLOADS_DIR = Path("/opt/dripdrop/downloads")

# ── Admin usage page (/admin/usage) ───────────────────────────────────────
# Shows per-user Claude API consumption from ai_usage.jsonl. Admin-only
# (checks _is_admin against the signed-in user's email). Read-only.
@app.get("/admin/usage")
def _admin_usage(request: Request):
    # Require signed-in admin
    try:
        email = (app.storage.user.get("email") or "").strip().lower()
    except Exception:
        email = ""
    if not email or not _is_admin(email):
        return HTMLResponse("<h3>Not authorized</h3>", status_code=403)

    # Read log, oldest-first, bounded to the last 30 days so the page
    # stays snappy even after the log grows large.
    from collections import defaultdict
    from datetime import timedelta as _td
    _path = _BASE_DATA_DIR / "ai_usage.jsonl"
    records: list = []
    if _path.exists():
        try:
            cutoff = (datetime.utcnow() - _td(days=30)).strftime("%Y-%m-%dT%H:%M:%SZ")
            with open(_path, "r", encoding="utf-8") as f:
                for line in f:
                    line = line.strip()
                    if not line:
                        continue
                    try:
                        rec = json.loads(line)
                    except Exception:
                        continue
                    if rec.get("ts", "") >= cutoff:
                        records.append(rec)
        except Exception as e:
            return HTMLResponse(f"<h3>Log read error</h3><pre>{e}</pre>", status_code=500)

    # Aggregate by user + by day
    by_user = defaultdict(lambda: {"calls": 0, "in": 0, "out": 0, "cache_r": 0,
                                     "cache_c": 0, "cost": 0.0})
    by_day = defaultdict(lambda: {"calls": 0, "cost": 0.0})
    total = {"calls": 0, "in": 0, "out": 0, "cache_r": 0, "cache_c": 0, "cost": 0.0}
    for r in records:
        u = r.get("user", "unknown")
        by_user[u]["calls"]   += 1
        by_user[u]["in"]      += int(r.get("in", 0) or 0)
        by_user[u]["out"]     += int(r.get("out", 0) or 0)
        by_user[u]["cache_r"] += int(r.get("cache_r", 0) or 0)
        by_user[u]["cache_c"] += int(r.get("cache_c", 0) or 0)
        by_user[u]["cost"]    += float(r.get("cost_usd", 0) or 0)
        d = (r.get("ts", "") or "")[:10]
        by_day[d]["calls"] += 1
        by_day[d]["cost"]  += float(r.get("cost_usd", 0) or 0)
        total["calls"]   += 1
        total["in"]      += int(r.get("in", 0) or 0)
        total["out"]     += int(r.get("out", 0) or 0)
        total["cache_r"] += int(r.get("cache_r", 0) or 0)
        total["cache_c"] += int(r.get("cache_c", 0) or 0)
        total["cost"]    += float(r.get("cost_usd", 0) or 0)

    def _fmt_int(n): return f"{int(n):,}"
    def _fmt_usd(n): return f"${n:,.4f}"

    users_sorted = sorted(by_user.items(), key=lambda kv: kv[1]["cost"], reverse=True)
    days_sorted = sorted(by_day.items(), reverse=True)[:30]

    rows_users = "".join(
        f"<tr><td>{esc(u)}</td>"
        f"<td class='n'>{_fmt_int(v['calls'])}</td>"
        f"<td class='n'>{_fmt_int(v['in'])}</td>"
        f"<td class='n'>{_fmt_int(v['out'])}</td>"
        f"<td class='n'>{_fmt_int(v['cache_r'])}</td>"
        f"<td class='n'>{_fmt_int(v['cache_c'])}</td>"
        f"<td class='n cost'>{_fmt_usd(v['cost'])}</td></tr>"
        for u, v in users_sorted
    ) or "<tr><td colspan='7' class='empty'>No usage recorded yet.</td></tr>"

    rows_days = "".join(
        f"<tr><td>{esc(d or 'unknown')}</td>"
        f"<td class='n'>{_fmt_int(v['calls'])}</td>"
        f"<td class='n cost'>{_fmt_usd(v['cost'])}</td></tr>"
        for d, v in days_sorted
    ) or "<tr><td colspan='3' class='empty'>No usage recorded yet.</td></tr>"

