@app.get("/downloads/{filename}")
def _serve_installer(filename: str):
    # Strict allowlist on filename: only DripDrop installers, no path
    # components, no traversal characters.
    if not re.match(r"^DripDrop-Setup-[\w.\-]+\.exe$", filename):
        return Response(status_code=404)
    target = _DESKTOP_DOWNLOADS_DIR / filename
    if not target.is_file():
        return Response(status_code=404)
    return FileResponse(
        str(target),
        media_type="application/octet-stream",
        filename=filename,
        headers={"Cache-Control": "public, max-age=3600"},
    )


# Landing page demo screenshots  -  served from <project_root>/demos/. Strict
# filename regex (slug-style, png/jpg/webp only) so nothing outside the
# intended files can be requested. Used by the click-to-preview modal on
# the marketing page's feature cards.
_DEMO_IMAGES_DIR = _APP_DIR / "demos"

@app.get("/demos/{filename}")
def _serve_demo_image(filename: str):
    if not re.match(r"^[a-z0-9\-]+\.(png|jpg|jpeg|webp)$", filename):
        return Response(status_code=404)
    target = _DEMO_IMAGES_DIR / filename
    if not target.is_file():
        return Response(status_code=404)
    ext = filename.rsplit(".", 1)[-1].lower()
    mime = {"png": "image/png", "jpg": "image/jpeg", "jpeg": "image/jpeg",
            "webp": "image/webp"}[ext]
    return FileResponse(
        str(target),
        media_type=mime,
        headers={"Cache-Control": "public, max-age=3600"},
    )


# ── In-memory rate limiter ─────────────────────────────────────────────────
# Used on /login and /register to prevent brute-force attacks. Per-IP
# buckets, 5 failed attempts per 60 seconds. In-memory state is fine for a
# single-process deployment; if we ever scale horizontally this needs Redis.
from collections import defaultdict as _defaultdict
_rate_limit_buckets: dict = _defaultdict(list)
_RATE_LIMIT_WINDOW_SEC = 60
_RATE_LIMIT_MAX = 5

def _rate_limit_check(key: str) -> bool:
    """Returns True if the key is currently allowed (under the cap).
    Does NOT record the attempt  -  call _rate_limit_record() to do that."""
    now = time.time()
    bucket = _rate_limit_buckets[key]
    cutoff = now - _RATE_LIMIT_WINDOW_SEC
    bucket[:] = [t for t in bucket if t > cutoff]
    return len(bucket) < _RATE_LIMIT_MAX

def _rate_limit_record(key: str):
    """Record one attempt for this key."""
    _rate_limit_buckets[key].append(time.time())

def _client_ip_from_context() -> str:
    """Best-effort client IP. Reads CF-Connecting-IP first because we run
    behind Cloudflare on the cloud, then X-Forwarded-For, then the raw
    socket peer. Returns 'unknown' if everything fails."""
    try:
        from nicegui import context as _ctx
        req = _ctx.client.request
        ip = req.headers.get("cf-connecting-ip")
        if ip:
            return ip.strip()
        xff = req.headers.get("x-forwarded-for", "")
        if xff:
            return xff.split(",")[0].strip()
        if req.client and req.client.host:
            return req.client.host
    except Exception:
        pass
    return "unknown"

