def _user_data_dir() -> Path:
    explicit = os.getenv("DRIPDROP_DATA_DIR")
    if explicit:
        base = Path(explicit)
    else:
        base = Path(os.getenv("LOCALAPPDATA", str(Path(__file__).resolve().parent))) / "DripDrop"
    base.mkdir(parents=True, exist_ok=True)
    return base

