def _send_email_universal(to: str, subject: str, html_body: str,
                          from_email: str = "", from_name: str = "",
                          attachments: list = None, is_preview: bool = False,
                          _for_user_email: str = "") -> tuple:
    """Send email via best available method: SMTP (server) or Outlook (desktop).
    Returns (success: bool, error: str).

    _for_user_email (optional): if set, rebinds the ContextVar to this user
    before reading signature / config. Caller should pass s._user_email
    when sending on a user's behalf. Safe default: use current ContextVar.
    """
    # Rebind user context if the caller told us explicitly who this is for.
    # This makes signature + config reads correct even if the surrounding
    # async context got clobbered by another user's concurrent render.
    if _for_user_email:
        _CURRENT_USER_EMAIL.set(_for_user_email)
        _switch_to_user_paths(_for_user_email)

    # Preview sends bypass the queue/scheduler, so merge tokens ({FirstName}
    # etc.) were never substituted and the recipient saw a literal "{FirstName}".
    # Fill them from the user's own identity so a preview reads "Hi Michael,".
    if is_preview:
        _pc = _preview_self_contact(None)
        _pitem = {
            "first_name": _pc.get("first_name", ""),
            "last_name": _pc.get("last_name", ""),
            "contact_company": _pc.get("company", ""),
            "contact_title": _pc.get("title", ""),
        }
        subject = _apply_merge_tokens(subject, _pitem)
        html_body = _apply_merge_tokens(html_body, _pitem)

    # Universal em/en-dash scrub  -  catches previews, test sends, and any
    # one-off path that bypasses queue_campaign_emails().
    subject = _strip_dashes(subject)
    html_body = _strip_dashes(html_body)

    # Merge-field cleanup
    if "<" not in html_body or ("<br" not in html_body and "<p" not in html_body and "<div" not in html_body):
        html_body = html_body.replace("\n", "<br>")

    # Append signature  -  mirrors queue_campaign_emails() so previews match
    # what actually gets sent. Production sends bake the signature into the
    # body at queue time; previews bypass the queue so we must add it here.
    _sig = _load_signature_text()
    if _sig:
        _is_html = bool("<" in html_body and ("</p>" in html_body or "</div>" in html_body
                        or "<br" in html_body or "</b>" in html_body))
        if _is_html:
            _sig_html = _sig.replace("\n", "<br>")
            html_body = html_body + "<br><br>" + _sig_html.lstrip("<br>")
        else:
            html_body = html_body + _sig

    # Externalize inline base64 images (logos baked into older bodies, etc.)
    # so Outlook desktop renders them. No-op when there are none / desktop.
    html_body = _externalize_data_uri_images(html_body)

    if is_preview:
        subject = f"[PREVIEW] {subject}"

    # Use async-safe per-user config path so the OAuth token comes from
    # the right user  -  not a global that might have been clobbered.
    _cfg_path = _user_config_path()

    # Try Microsoft Graph first (best for Outlook users)
    if _HAS_MS_EMAIL and _ms_email:
        token = _ms_email.get_valid_token(_cfg_path)
        if token:
            return _ms_email.send_email(
                access_token=token, to=to, subject=subject,
                html_body=html_body, attachments=attachments,
            )

    # Try Gmail OAuth next (best for Gmail / Google Workspace users).
    # Sends through Google's actual mail infrastructure as the authenticated
    # user  -  same deliverability as clicking Send in Gmail itself.
    if _HAS_GMAIL_OAUTH and _gmail_oauth:
        token = _gmail_oauth.get_valid_token(_cfg_path)
        if token:
            _tokens = _gmail_oauth.load_tokens(_cfg_path)
            return _gmail_oauth.send_email(
                access_token=token, to=to, subject=subject,
                html_body=html_body,
                from_email=_tokens.get("email", "") or from_email,
                from_name=_tokens.get("name", "") or from_name,
                attachments=attachments,
            )

    # Try SMTP / SendGrid API / Brevo API next (works everywhere)
    if _HAS_CLOUD_EMAIL and _cloud_email:
        cfg = load_config()
        _from = from_email or cfg.get("smtp_email", "")
        _name = from_name or cfg.get("smtp_from_name", "")
        _pass = cfg.get("smtp_password", "")
        _host = cfg.get("smtp_host", "")
        _port = int(cfg.get("smtp_port", 587) or 587)
        _user = cfg.get("smtp_username", "")  # SendGrid SMTP mode uses "apikey"
        if _from and _pass:
            # Brevo: HTTP API over HTTPS, works behind any SMTP block.
            # Detected by host containing "brevo" or the key starting with
            # the standard Brevo prefix 'xkeysib-'.
            _is_brevo = (
                "brevo" in (_host or "").lower()
                or _pass.startswith("xkeysib-")
            )
            if _is_brevo and hasattr(_cloud_email, "send_via_brevo_api"):
                return _cloud_email.send_via_brevo_api(
                    to=to, subject=subject, html_body=html_body,
                    from_email=_from, from_name=_name,
                    api_key=_pass, attachments=attachments,
                )
            # SendGrid: prefer the HTTP API over SMTP. DigitalOcean and most
            # cloud hosts block outbound SMTP ports by default  -  the API
            # works over HTTPS port 443 which is always allowed. We detect
            # a SendGrid config by the saved host or the key prefix.
            _is_sendgrid = (
                "sendgrid" in (_host or "").lower()
                or (_user == "apikey" and _pass.startswith("SG."))
                or _pass.startswith("SG.")
            )
            if _is_sendgrid and hasattr(_cloud_email, "send_via_sendgrid_api"):
                return _cloud_email.send_via_sendgrid_api(
                    to=to, subject=subject, html_body=html_body,
                    from_email=_from, from_name=_name,
                    api_key=_pass, attachments=attachments,
                )
            return _cloud_email.send_email(
                to=to, subject=subject, html_body=html_body,
                from_email=_from, from_name=_name, password=_pass,
                smtp_host=_host, smtp_port=_port, attachments=attachments,
                smtp_username=_user,
            )

    # Fallback: Outlook COM (Windows only)
    if _HAS_OUTLOOK:
        try:
            import pythoncom, win32com.client.dynamic
            pythoncom.CoInitialize()
            try:
                ol = win32com.client.dynamic.Dispatch("Outlook.Application")
                mail = ol.CreateItem(0)
                mail.To = to
                mail.Subject = subject
                # We've already appended the DripDrop signature above, so
                # don't also preserve Outlook's auto-signature  -  that would
                # double-sign the email on desktop.
                mail.HTMLBody = (
                    '<html><head><meta charset="utf-8"></head>'
                    '<body style="font-family:Calibri,Arial,sans-serif;font-size:11pt;color:#1E293B;">'
                    f'{html_body}</body></html>')
                if attachments:
                    for att in attachments:
                        att_path = _user_pdf_dir() / att if not os.path.isabs(att) else Path(att)
                        if att_path.is_file():
                            mail.Attachments.Add(str(att_path))
                mail.Send()
                return True, ""
            finally:
                pythoncom.CoUninitialize()
        except Exception as e:
            return False, str(e)[:200]

    return False, "No email configured. Go to Email & AI Setup to connect your email."

# ── funnelforge_core availability (checked once at startup, not per call) ──
# On the server, we deliberately disable funnelforge_core because:
#   1. Its queue path is global (not per-user)  -  items go to the wrong place
#   2. Its scheduler requires Outlook COM which doesn't exist on Linux
#   3. Its SMTP fallback is blocked by DigitalOcean's port 587 block
# Instead, the server uses a dedicated scheduler that scans per-user queue
# files and sends via Microsoft Graph API / Gmail API (HTTPS, port 443).
# All queue reads/writes fall through to the direct JSON helpers in this
# file, which respect per-user paths via _switch_to_user_paths().
try:
    import funnelforge_core as _ffc
    _FUNNELFORGE_OK = True
except Exception:
    _ffc = None
    _FUNNELFORGE_OK = False

if _SERVER_MODE:
    _FUNNELFORGE_OK = False
    _ffc = None


# ── In-memory TTL cache (5-second stale window) ────────────────────────────
class _TTLCache:
    """Per-user in-memory cache with a TTL in seconds.

    Keys entries by the CURRENT USER'S EMAIL (via ContextVar). Previously
    keyed by `str(_user_dir())`  -  but that's a mutable module global that
    can be clobbered by concurrent renders. ContextVar is per-task
    isolated, so this cache never leaks data across accounts."""
    def __init__(self, ttl=5):
        self._ttl = ttl
        self._data: dict = {}   # {user_email: (timestamp, value)}
    def _key(self):
        # Prefer the ContextVar (async-safe). Fall back to _user_dir() for
        # desktop mode where the ContextVar is empty.
        try:
            email = _CURRENT_USER_EMAIL.get()
            if email:
                return email.lower().strip()
        except LookupError:
            pass
        return str(_user_dir())
    def get(self):
        k = self._key()
        if k in self._data:
            ts, val = self._data[k]
            if time.monotonic() - ts < self._ttl:
                return True, val
        return False, None
    def set(self, val):
        self._data[self._key()] = (time.monotonic(), val)
        return val
    def invalidate(self):
        self._data.pop(self._key(), None)

_cache_campaigns = _TTLCache(ttl=2)
_cache_responded = _TTLCache(ttl=2)
_cache_queue     = _TTLCache(ttl=2)

# mtime-keyed cache for saved contact list row counts.
# Avoids re-parsing every saved CSV on every Contacts page visit.
_csv_count_cache: dict = {}  # {path_str: (mtime_float, row_count)}

def _get_csv_row_count(path_str: str) -> int:
    """Return row count for a CSV, re-reading only when the file has changed."""
    try:
        p = Path(path_str)
        mtime = p.stat().st_mtime
        cached = _csv_count_cache.get(path_str)
        if cached and cached[0] == mtime:
            return cached[1]
        rows, _ = safe_read_csv_rows(path_str)
        count = len(rows)
        _csv_count_cache[path_str] = (mtime, count)
        return count
    except Exception:
        return 0

