# ═══════════════════════════════════════════════════════════════════════════
#  PRIMARY / SECONDARY INDUSTRY PICKER
# ═══════════════════════════════════════════════════════════════════════════
# Replaces the legacy free-text "Vertical / Niche" field.
#   Primary Industry  = single-select dropdown (from AICB_INDUSTRIES + user
#                       extras), with an "Other..." escape hatch that
#                       reveals a text input for one-off custom values.
#   Secondary Industry = multi-select chips, scoped to the niches of the
#                       chosen Primary, plus user extras + a typed "Other".
# User-added entries persist per-user in industry_extras.json so they can
# build their own taxonomy over time without polluting the shared list.
# Backward compat: campaign data still writes a `Vertical` string (joined
# Primary + Secondaries) so any legacy reader keeps working.

def _user_industry_extras_path() -> Path:
    return _resolve_user_root() / "industry_extras.json"


def _load_industry_extras() -> dict:
    """Per-user extras: extra primaries the user has added, and extra
    secondaries scoped per primary key.
    Schema: {primary_extras: [str], secondary_extras: {primary_key: [str]}}"""
    p = _user_industry_extras_path()
    if not p.exists():
        return {"primary_extras": [], "secondary_extras": {}}
    try:
        d = json.loads(p.read_text(encoding="utf-8"))
        if not isinstance(d, dict):
            return {"primary_extras": [], "secondary_extras": {}}
        d.setdefault("primary_extras", [])
        d.setdefault("secondary_extras", {})
        return d
    except Exception:
        return {"primary_extras": [], "secondary_extras": {}}


def _save_industry_extras(extras: dict) -> None:
    p = _user_industry_extras_path()
    p.parent.mkdir(parents=True, exist_ok=True)
    tmp = p.with_suffix(".tmp")
    tmp.write_text(json.dumps(extras, indent=2), encoding="utf-8")
    tmp.replace(p)


def _industry_key_for_label_or_key(value: str) -> str:
    """Accept either a key ('construction') or a label ('Construction')
    and return the canonical key. Custom labels become their slug."""
    if not value:
        return ""
    v = value.strip()
    if v in AICB_INDUSTRIES:
        return v
    for k, info in AICB_INDUSTRIES.items():
        if info.get("label", "").lower() == v.lower():
            return k
    return f"_custom_{re.sub(r'[^a-z0-9]+', '_', v.lower()).strip('_')}"


def _industry_label_for_key(key: str) -> str:
    if not key:
        return ""
    if key in AICB_INDUSTRIES:
        return AICB_INDUSTRIES[key].get("label", key)
    if key.startswith("_custom_"):
        extras = _load_industry_extras().get("primary_extras", [])
        for label in extras:
            if _industry_key_for_label_or_key(label) == key:
                return label
        return key.replace("_custom_", "").replace("_", " ").title()
    return key


def _industry_primary_options() -> list:
    """List of (key, label) for the Primary dropdown — curated +
    user extras, sorted by label."""
    out = [(k, v.get("label", k)) for k, v in AICB_INDUSTRIES.items()]
    extras = _load_industry_extras().get("primary_extras", [])
    for label in extras:
        key = _industry_key_for_label_or_key(label)
        if not any(k == key for k, _ in out):
            out.append((key, label))
    out.sort(key=lambda kv: kv[1].lower())
    return out


def _industry_secondary_options(primary_key_or_label: str) -> list:
    """Secondary niche options for the given primary, including user
    extras for that primary."""
    pkey = _industry_key_for_label_or_key(primary_key_or_label)
    base = list(AICB_INDUSTRIES.get(pkey, {}).get("niches", []))
    extras = _load_industry_extras().get("secondary_extras", {}).get(pkey, [])
    for e in extras:
        if e not in base:
            base.append(e)
    return base


def _add_personal_primary_industry(label: str) -> None:
    """Persist a typed-in Primary so it appears in this user's dropdown
    next time. No-op for empty / already-known labels."""
    label = (label or "").strip()
    if not label:
        return
    extras = _load_industry_extras()
    known = {info.get("label", "") for info in AICB_INDUSTRIES.values()}
    if label not in extras["primary_extras"] and label not in known:
        extras["primary_extras"].append(label)
        _save_industry_extras(extras)


def _add_personal_secondary_industry(primary_key: str, label: str) -> None:
    label = (label or "").strip()
    if not label or not primary_key:
        return
    extras = _load_industry_extras()
    extras["secondary_extras"].setdefault(primary_key, [])
    base = AICB_INDUSTRIES.get(primary_key, {}).get("niches", [])
    if label not in extras["secondary_extras"][primary_key] and label not in base:
        extras["secondary_extras"][primary_key].append(label)
        _save_industry_extras(extras)


def _migrate_legacy_vertical(variables: dict) -> dict:
    """Convert legacy `Vertical` text into PrimaryIndustry +
    SecondaryIndustries. Idempotent — returns the same dict mutated."""
    if not isinstance(variables, dict):
        return variables
    if (variables.get("PrimaryIndustry") or "").strip():
        return variables
    legacy = (variables.get("Vertical") or "").strip()
    if not legacy:
        return variables
    variables["PrimaryIndustry"] = legacy
    variables.setdefault("SecondaryIndustries", [])
    return variables


def _industry_to_vertical_string(primary: str, secondaries: list) -> str:
    """Compose the legacy `Vertical` string from new fields. Used at
    save time so any code still reading `Vertical` gets a value."""
    primary = (primary or "").strip()
    secs = [s.strip() for s in (secondaries or []) if s and s.strip()]
    if primary and secs:
        return f"{primary} · {', '.join(secs)}"  # · separator
    return primary or (", ".join(secs) if secs else "")


def _render_industry_picker(s, rf, *, primary_state_key: str,
                              secondary_state_key: str,
                              container_style: str = "",
                              label_primary: str = "Primary Industry",
                              label_secondary: str = "Secondary (sub-niche)",
                              required_primary: bool = False):
    """Reusable Primary + Secondary picker. Reads/writes the named
    AppState fields directly so callers don't have to wire bindings.

    primary_state_key   — AppState attr that holds the Primary label (str)
    secondary_state_key — AppState attr that holds the Secondaries (list[str])
    """
    cur_primary = (getattr(s, primary_state_key, "") or "").strip()
    cur_secondaries = list(getattr(s, secondary_state_key, []) or [])

    with ui.element("div").style(container_style or "margin-bottom:16px;"):
        # ── Primary ────────────────────────────────────────────────────
        with ui.element("div").style("display:flex;align-items:center;gap:6px;margin-bottom:4px;"):
            ui.label(label_primary).classes("fd-fl").style("margin:0;")
            if required_primary:
                ui.label("*").style(
                    f"color:{C['danger']};font-size:14px;font-weight:700;line-height:1;")

        primary_opts = _industry_primary_options()
        opt_dict = {label: label for _key, label in primary_opts}
        opt_dict["Other..."] = "Other..."
        all_known_labels = set(opt_dict.keys())
        if cur_primary and cur_primary not in all_known_labels:
            opt_dict = {cur_primary: f"{cur_primary} (custom)", **opt_dict}

        _other_flag_attr = f"_{primary_state_key}_other_mode"
        in_other_mode = bool(getattr(s, _other_flag_attr, False))

        def _on_primary_change(e=None):
            v = (prim_sel.value or "").strip()
            if v == "Other...":
                setattr(s, _other_flag_attr, True)
                rf()
                return
            setattr(s, _other_flag_attr, False)
            setattr(s, primary_state_key, v)
            # Reset Secondaries when Primary changes — old niches
            # don't apply to the new Primary.
            setattr(s, secondary_state_key, [])
            rf()

        prim_sel = ui.select(
            options=list(opt_dict.keys()),
            value=("Other..." if in_other_mode else (cur_primary or None)),
            on_change=_on_primary_change,
        ).classes("fd-input").style("width:100%;")

        if in_other_mode:
            with ui.element("div").style(
                    "display:flex;gap:6px;align-items:center;margin-top:6px;"):
                _other_in = ui.input(
                    value=cur_primary,
                    placeholder="Type a custom industry, e.g. 'Cannabis Manufacturing'",
                ).classes("fd-input").style("flex:1;")

                def _commit_other():
                    val = (_other_in.value or "").strip()
                    if not val:
                        ui.notify("Type a custom industry first.", type="warning")
                        return
                    setattr(s, primary_state_key, val)
                    setattr(s, _other_flag_attr, False)
                    setattr(s, secondary_state_key, [])
                    _add_personal_primary_industry(val)
                    ui.notify(f"✓ Added '{val}' to your list.",
                               type="positive", timeout=2500)
                    rf()
                with ui.element("button").classes("fd-pb").style(
                        "padding:7px 14px;font-size:11px;flex-shrink:0;"
                        ).on("click", _commit_other):
                    ui.label("Add to my list")

        # ── Secondary (multi-select dropdown + Other... text input) ────
        # 2026-05-01: switched back to multi-select per user request to
        # let candidate generation mix position types across niches.
        # Uses Quasar's built-in multi-select (use-chips inside the
        # dropdown bar) instead of the old standalone chip-with-X UI
        # that users found clunky. Capped at 4 picks so prompts stay
        # coherent.
        SEC_MAX = 4
        if cur_primary and not in_other_mode:
            ui.label(label_secondary).classes("fd-fl").style("margin-top:12px;")
            ui.label(
                f"Pick up to {SEC_MAX} under {cur_primary} (mixing helps "
                f"vary candidate position types). Choose Other... to add "
                f"a custom one."
            ).style(f"font-size:10px;color:{C['muted']};margin-bottom:4px;display:block;")

            primary_key = _industry_key_for_label_or_key(cur_primary)
            sec_opts = _industry_secondary_options(primary_key)
            sec_opt_dict = {x: x for x in sec_opts}
            sec_opt_dict["Other..."] = "Other..."
            # Surface any custom values already on the list (e.g. ones
            # the user added via Other... in an earlier session) at the
            # top of the dropdown so they remain selectable.
            for _custom in cur_secondaries:
                _c = (_custom or "").strip()
                if _c and _c not in sec_opt_dict:
                    sec_opt_dict = {_c: f"{_c} (custom)", **sec_opt_dict}

            _sec_other_attr = f"_{secondary_state_key}_other_mode"
            sec_in_other_mode = bool(getattr(s, _sec_other_attr, False))

            def _on_sec_change(e=None):
                vals = list(sec_sel.value or [])
                # If the user picked "Other..." flip into custom-input
                # mode and strip the sentinel from the picks. They commit
                # the custom value via the inline Add button.
                if "Other..." in vals:
                    vals = [v for v in vals if v != "Other..."]
                    setattr(s, _sec_other_attr, True)
                # De-dup, drop empties, cap at SEC_MAX.
                _seen = set()
                _clean = []
                for v in vals:
                    v = (v or "").strip()
                    if v and v not in _seen:
                        _seen.add(v)
                        _clean.append(v)
                if len(_clean) > SEC_MAX:
                    ui.notify(f"Cap is {SEC_MAX} secondary industries — keeping the first {SEC_MAX}.",
                              type="warning", timeout=2500)
                    _clean = _clean[:SEC_MAX]
                setattr(s, secondary_state_key, _clean)
                if getattr(s, _sec_other_attr, False):
                    rf()  # only rerender when toggling Other... mode

            sec_sel = ui.select(
                options=list(sec_opt_dict.keys()),
                value=list(cur_secondaries),
                multiple=True,
                on_change=_on_sec_change,
            ).props("use-chips").classes("fd-input").style("width:100%;")

            if sec_in_other_mode:
                with ui.element("div").style(
                        "display:flex;gap:6px;align-items:center;margin-top:6px;"):
                    _sec_other_in = ui.input(
                        value="",
                        placeholder=f"Type a custom sub-niche under {cur_primary}",
                    ).classes("fd-input").style("flex:1;")

                    def _commit_sec_other():
                        val = (_sec_other_in.value or "").strip()
                        if not val:
                            ui.notify("Type a custom sub-niche first.", type="warning")
                            return
                        _existing = list(getattr(s, secondary_state_key, []) or [])
                        if val in _existing:
                            ui.notify(f"'{val}' is already on the list.",
                                      type="info", timeout=2000)
                        elif len(_existing) >= SEC_MAX:
                            ui.notify(f"You've already picked {SEC_MAX} — remove one first.",
                                      type="warning"); return
                        else:
                            _existing.append(val)
                            setattr(s, secondary_state_key, _existing)
                        setattr(s, _sec_other_attr, False)
                        try:
                            _add_personal_secondary_industry(primary_key, val)
                        except Exception:
                            pass
                        ui.notify(f"✓ Added '{val}' to your list.",
                                   type="positive", timeout=2500)
                        rf()
                    with ui.element("button").classes("fd-pb").style(
                            "padding:7px 14px;font-size:11px;flex-shrink:0;"
                            ).on("click", _commit_sec_other):
                        ui.label("Add to my list")


