def _user_region_extras_path() -> Path:
    return _resolve_user_root() / "region_extras.json"


def _load_region_extras() -> list:
    """Per-user list of typed-in custom locations. Persisted so they
    appear in the dropdown next time."""
    p = _user_region_extras_path()
    if not p.exists():
        return []
    try:
        d = json.loads(p.read_text(encoding="utf-8"))
        if isinstance(d, list):
            return [str(x).strip() for x in d if str(x).strip()]
        return []
    except Exception:
        return []


def _save_region_extras(extras: list) -> None:
    p = _user_region_extras_path()
    p.parent.mkdir(parents=True, exist_ok=True)
    tmp = p.with_suffix(".tmp")
    tmp.write_text(json.dumps(extras, indent=2), encoding="utf-8")
    tmp.replace(p)


def _add_personal_region(label: str) -> None:
    """Persist a typed-in location so it shows in this user's dropdown
    next time. No-op for empty / already-known."""
    label = (label or "").strip()
    if not label:
        return
    extras = _load_region_extras()
    known = (
        set(s for _c, s in US_STATES)
        | set(US_METROS)
        | set(US_REGIONS)
        | set(extras)
    )
    if label not in known:
        extras.append(label)
        _save_region_extras(extras)


def _region_options() -> list:
    """Combined dropdown options. Order: regions first (broadest), then
    metros (most specific), then states (broad), then user extras at the
    bottom labeled distinctly. This is the natural picker order — users
    looking for 'Phoenix, AZ' scroll through metros, users looking for
    'Texas' or 'Northeast US' find them at the top/bottom respectively."""
    out = []
    out.extend(US_REGIONS)            # Regional aggregates first
    out.extend(US_METROS)             # Then metros (most specific lookup)
    out.extend(name for _c, name in US_STATES)  # Then states (broader)
    extras = _load_region_extras()
    out.extend(extras)
    return out


def _render_region_picker(s, rf, *, state_key: str,
                            multi: bool = False,
                            container_style: str = "",
                            label: str = "Location",
                            placeholder: str = "Select a state, metro, or region",
                            required: bool = False):
    """Reusable region picker.

    state_key — AppState attr that holds either a string (multi=False)
                or a list of strings (multi=True)
    multi     — multi-select chips when True
    """
    # Read current value
    if multi:
        cur_values = list(getattr(s, state_key, []) or [])
    else:
        cur_values = (getattr(s, state_key, "") or "").strip()

    with ui.element("div").style(container_style or "margin-bottom:16px;"):
        with ui.element("div").style("display:flex;align-items:center;gap:6px;margin-bottom:4px;"):
            ui.label(label).classes("fd-fl").style("margin:0;")
            if required:
                ui.label("*").style(
                    f"color:{C['danger']};font-size:14px;font-weight:700;line-height:1;")

        # Build options dict. Include any current value(s) that aren't in
        # the curated list so they still render (custom one-offs from
        # earlier or from the typed-Other input).
        opts = _region_options()
        opt_dict = {x: x for x in opts}
        opt_dict["Other..."] = "Other..."

        existing = cur_values if multi else ([cur_values] if cur_values else [])
        for v in existing:
            if v and v not in opt_dict:
                opt_dict = {v: f"{v} (custom)", **opt_dict}

        _other_flag_attr = f"_{state_key}_region_other_mode"
        in_other_mode = bool(getattr(s, _other_flag_attr, False))

        if multi:
            def _on_change(e=None):
                vals = sel.value or []
                if not isinstance(vals, list):
                    vals = [vals] if vals else []
                # Strip empties + dedup
                cleaned = []
                seen = set()
                for v in vals:
                    v = (str(v) or "").strip()
                    if v == "Other...":
                        setattr(s, _other_flag_attr, True)
                        rf()
                        return
                    if v and v not in seen:
                        cleaned.append(v); seen.add(v)
                setattr(s, state_key, cleaned)

            sel = ui.select(
                options=list(opt_dict.keys()),
                value=cur_values,
                multiple=True,
                on_change=_on_change,
            ).props('use-chips use-input input-debounce="200"').classes("fd-input").style("width:100%;")
        else:
            def _on_change(e=None):
                v = (sel.value or "").strip() if sel.value else ""
                if v == "Other...":
                    setattr(s, _other_flag_attr, True)
                    rf()
                    return
                setattr(s, _other_flag_attr, False)
                setattr(s, state_key, v)

            sel = ui.select(
                options=list(opt_dict.keys()),
                value=("Other..." if in_other_mode else (cur_values or None)),
                on_change=_on_change,
            ).props('use-input input-debounce="200"').classes("fd-input").style("width:100%;")

        # "Other..." text input — shown when triggered
        if in_other_mode:
            with ui.element("div").style(
                    "display:flex;gap:6px;align-items:center;margin-top:6px;"):
                _other_in = ui.input(
                    placeholder="Type a custom location, e.g. 'Houston Energy Corridor'",
                ).classes("fd-input").style("flex:1;")

                def _commit_other():
                    val = (_other_in.value or "").strip()
                    if not val:
                        ui.notify("Type a location first.", type="warning")
                        return
                    if multi:
                        cur = list(getattr(s, state_key, []) or [])
                        if val not in cur:
                            cur.append(val)
                            setattr(s, state_key, cur)
                    else:
                        setattr(s, state_key, val)
                    setattr(s, _other_flag_attr, False)
                    _add_personal_region(val)
                    ui.notify(f"✓ Added '{val}' to your locations.",
                               type="positive", timeout=2500)
                    rf()
                with ui.element("button").classes("fd-pb").style(
                        "padding:7px 14px;font-size:11px;flex-shrink:0;"
                        ).on("click", _commit_other):
                    ui.label("Add")


