# ── Template builder ───────────────────────────────────────────────────────
def ms(*, name, subject="", body="", step_type=ST.EMAIL_AUTO, gate=False,
       completed=False, script_notes="", touch_number=0, delay_days=0,
       attachments=None, tags=None, channel="email", **_):
    return dict(name=name, subject=subject, body=body,
                attachments=attachments or [], step_type=step_type,
                gate=gate, completed=completed, script_notes=script_notes,
                touch_number=touch_number, delay_days=delay_days,
                tags=tags or [], channel=channel)

# ═══════════════════════════════════════════════════════════════════════════
