#  OUTLOOK MONITOR
# ═══════════════════════════════════════════════════════════════════════════

_OOO_KEYWORDS = frozenset([
    "out of office", "out of the office", "automatic reply", "auto-reply",
    "autoreply", "on vacation", "on leave", "currently away", "away from",
    "i am currently out", "i'm currently out", "i will be out",
])


def _get_sender_smtp(item) -> str:
    """Extract proper SMTP email from Outlook item, handling Exchange/delegates."""
    try:
        # Try PR_SMTP_ADDRESS first (most reliable for Exchange)
        sender = item.PropertyAccessor.GetProperty(
            "http://schemas.microsoft.com/mapi/proptag/0x39FE001E")
        if sender and "@" in sender:
            return sender.lower().strip()
    except Exception:
        pass
    try:
        # Fallback: SenderEmailType + AddressEntry resolution
        if getattr(item, "SenderEmailType", "") == "EX":
            try:
                entry = item.Sender
                if entry:
                    exch = entry.GetExchangeUser()
                    if exch and exch.PrimarySmtpAddress:
                        return exch.PrimarySmtpAddress.lower().strip()
            except Exception:
                pass
    except Exception:
        pass
    # Final fallback: raw SenderEmailAddress
    return (getattr(item, "SenderEmailAddress", "") or "").lower().strip()


def _is_ooo_reply(item) -> bool:
    """Detect out-of-office / automatic replies.

    H4: scan up to 8000 chars of body (was 500). Real OOO replies often
    have a forwarded thread or long signature ahead of the actual OOO
    marker. 8000 covers virtually all real cases without scanning
    arbitrarily long mail threads.
    """
    try:
        subj = (item.Subject or "").lower()
        body = (item.Body or "")[:8000].lower()
        combined = subj + " " + body
        for kw in _OOO_KEYWORDS:
            if kw in combined:
                return True
    except Exception:
        pass
    return False


_OPT_OUT_KEYWORDS = frozenset([
    "opt out", "opt-out", "optout", "unsubscribe", "remove me",
    "stop emailing", "stop sending", "take me off", "no more emails",
    "do not contact", "don't contact", "don't email", "do not email",
    "leave me alone", "not interested", "hate email", "spam",
    "remove from list", "remove from your list",
])


def _is_opt_out(item) -> bool:
    """Detect opt-out / unsubscribe intent in a reply."""
    try:
        subj = (item.Subject or "").lower()
        body = (item.Body or "")[:1000].lower()
        combined = subj + " " + body
        for kw in _OPT_OUT_KEYWORDS:
            if kw in combined:
                return True
    except Exception:
        pass
    return False


def _cancel_pending_for_email_in_campaign(email_addr: str, campaign_name: str) -> int:
    """Cancel pending queue items for a given email in a specific campaign only.
    Both email and campaign name are normalized (casefold + whitespace
    collapse) so that 'My Campaign' matches 'my  campaign '."""
    email_addr = email_addr.lower().strip()
    def _norm(name: str) -> str:
        return " ".join((name or "").split()).casefold()
    target_camp = _norm(campaign_name)
    cancelled = 0
    if _FUNNELFORGE_OK and _ffc is not None:
        try:
            queue = _ffc.get_queue(_user_queue_path())
            ids_to_cancel = [q["id"] for q in queue
                             if q.get("status") == "pending"
                             and q.get("to", "").lower().strip() == email_addr
                             and _norm(q.get("campaign", "")) == target_camp]
            if ids_to_cancel:
                cancelled = _ffc.cancel_queue_items(ids_to_cancel, _user_queue_path())
                _cache_queue.invalidate()
                return cancelled
        except Exception:
            pass
    try:
        qp = _user_queue_path()  # legacy QUEUE_PATH fallback removed — was a cross-user leak vector on server
        if qp.exists():
            queue = json.loads(qp.read_text(encoding="utf-8"))
            for q in queue:
                if (q.get("status") == "pending"
                        and q.get("to", "").lower().strip() == email_addr
                        and _norm(q.get("campaign", "")) == target_camp):
                    q["status"] = "cancelled"
                    cancelled += 1
            if cancelled:
                _atomic_write_text(qp, json.dumps(queue, indent=2, default=str))
                _cache_queue.invalidate()
    except Exception:
        pass
    return cancelled


def _cancel_pending_for_email(email_addr: str) -> int:
    """Cancel all pending queue items for a given email address."""
    email_addr = email_addr.lower().strip()
    cancelled = 0
    if _FUNNELFORGE_OK and _ffc is not None:
        try:
            queue = _ffc.get_queue(_user_queue_path())
            ids_to_cancel = [q["id"] for q in queue
                             if q.get("status") == "pending"
                             and q.get("to", "").lower().strip() == email_addr]
            if ids_to_cancel:
                cancelled = _ffc.cancel_queue_items(ids_to_cancel, _user_queue_path())
                _cache_queue.invalidate()
                return cancelled
        except Exception:
            pass
    # Fallback: direct JSON manipulation
    try:
        qp = _user_queue_path()  # legacy QUEUE_PATH fallback removed — was a cross-user leak vector on server
        if qp.exists():
            queue = json.loads(qp.read_text(encoding="utf-8"))
            for q in queue:
                if (q.get("status") == "pending"
                        and q.get("to", "").lower().strip() == email_addr):
                    q["status"] = "cancelled"
                    cancelled += 1
            if cancelled:
                tmp = qp.with_suffix(".tmp")
                tmp.write_text(json.dumps(queue, indent=2, default=str), encoding="utf-8")
                tmp.replace(qp)
                _cache_queue.invalidate()
    except Exception:
        pass
    return cancelled


class OutlookMonitor:
    def __init__(self):
        self._running = False
        self._thread = None
        self.last_scan = None
        self._new = []
        self._lock = threading.Lock()

    def start(self):
        if self._running:
            return
        self._running = True
        self._thread = threading.Thread(target=self._loop, daemon=True)
        self._thread.start()

    def stop(self):
        self._running = False

    def pop(self):
        with self._lock:
            r = list(self._new)
            self._new.clear()
            return r

    def scan_now(self):
        threading.Thread(target=self._scan, daemon=True).start()

    def _loop(self):
        while self._running:
            try:
                self._scan()
            except Exception as e:
                print(f"[Outlook] {e}")
            time.sleep(REPLY_POLL_SEC)

    def _scan(self):
        co_initialized = False
        try:
            import pythoncom, win32com.client.dynamic
            pythoncom.CoInitialize()
            co_initialized = True
        except ImportError:
            self.last_scan = datetime.now()
            return
        try:
            ol = win32com.client.dynamic.Dispatch("Outlook.Application")
            ns = ol.GetNamespace("MAPI")
            inbox = ns.GetDefaultFolder(6)
            # Build enrolled map: email → list of {name, campaign, is_evergreen}
            enrolled = {}
            all_camps = load_campaigns()
            for camp in all_camps:
                is_eg = camp.get("evergreen_only", False)
                for c in camp.get("contacts", []):
                    em = c.get("email", "").lower().strip()
                    if em:
                        enrolled.setdefault(em, []).append(dict(
                            name=f"{c.get('first_name', '')} {c.get('last_name', '')}".strip(),
                            campaign=camp.get("name", ""),
                            is_evergreen=is_eg))
            responded = {x["email"].lower() for x in load_responded()}
            # Scan inbox AND all subfolders (replies may be routed by Outlook rules)
            folders_to_scan = [inbox]
            try:
                for fi in range(1, inbox.Folders.Count + 1):
                    folders_to_scan.append(inbox.Folders.Item(fi))
            except Exception:
                pass
            cutoff = datetime.now().timestamp() - 604800  # 7 days
            count = 0
            for folder in folders_to_scan:
                try:
                    items = folder.Items
                    items.Sort("[ReceivedTime]", True)
                except Exception:
                    continue
                for item in items:
                    try:
                        if item.ReceivedTime.timestamp() < cutoff:
                            break
                        sender = _get_sender_smtp(item)
                        if not sender or "@" not in sender:
                            count += 1; continue
                        if _is_ooo_reply(item):
                            count += 1; continue
                        if sender in enrolled and sender not in responded:
                            infos = enrolled[sender]
                            reply_body = ""
                            try:
                                reply_body = (item.Body or "")[:2000]
                            except Exception:
                                pass
                            opt_out = _is_opt_out(item)
                            first_info = infos[0]

                            if opt_out:
                                # Opt-out detected → add to DNC list, remove from everything
                                add_to_dnc(sender, first_info["name"], "",
                                           "Auto-detected opt-out", "auto-opt-out")
                            else:
                                for info in infos:
                                    camp_name = info["campaign"]
                                    if info["is_evergreen"]:
                                        # Slow Drip: keep them enrolled (no opt-out)
                                        continue
                                    # Regular campaign: remove + cancel
                                    _remove_contact_from_campaign_by_name(sender, camp_name)
                                    _cancel_pending_for_email_in_campaign(sender, camp_name)
                                    _add_responder_to_campaign(sender, camp_name)

                            # Log a single global "responded" record (the
                            # function dedups by email — see add_responded).
                            add_responded(sender, first_info["name"], first_info["campaign"],
                                          " - ", item.Subject or "", reply_body)

                            # H6: queue an in-memory notification per
                            # enrolled campaign so the responses page
                            # shows the reply against each affected
                            # campaign, not just the first.
                            with self._lock:
                                for info in infos:
                                    self._new.append(dict(
                                        email=sender, name=info["name"],
                                        subject=item.Subject or "",
                                        reply_body=reply_body,
                                        campaign=info["campaign"]))

                            # H7: update the local responded set so a
                            # second reply from the same sender within
                            # this scan window is filtered out.
                            # add_responded() above writes to disk but
                            # doesn't update this local snapshot.
                            responded.add(sender)
                        count += 1
                        if count > 200:
                            break
                    except Exception:
                        continue
        finally:
            if co_initialized:
                try:
                    pythoncom.CoUninitialize()
                except Exception:
                    pass
        self.last_scan = datetime.now()


def _responder_email(entry) -> str:
    """Normalize a single entry from a campaign's `responders` list to a
    lowercased email string. Tolerates both formats found in the wild:
      - legacy: plain string email
      - current: dict like {"email": "...", "name": ..., "date": ...}
    Returns "" if neither applies."""
    if isinstance(entry, str):
        return entry.lower().strip()
    if isinstance(entry, dict):
        return (entry.get("email") or "").lower().strip()
    return ""


def _add_responder_to_campaign(email: str, campaign_name: str):
    """Add a responder email to the campaign's responders list. Writes the
    dict format (matches OutlookMonitor's writer) so the list stays
    consistent. Reads tolerate both legacy string and new dict entries."""
    email = email.lower().strip()
    if not email:
        return
    for p in _user_campaigns_dir().glob("*.json"):
        if p.name == "responded.json":
            continue
        try:
            d = json.loads(p.read_text(encoding="utf-8"))
            if d.get("name", "") == campaign_name:
                resp = d.get("responders", [])
                # Check existing entries in either format.
                if not any(_responder_email(r) == email for r in resp):
                    resp.append({
                        "email": email,
                        "name": "",
                        "date": date.today().isoformat(),
                    })
                    d["responders"] = resp
                    p.write_text(json.dumps(d, indent=2), encoding="utf-8")
                break
        except Exception:
            pass

outlook_monitor = OutlookMonitor()


