def _reset_wizard_state(s: "AppState") -> None:
    """Reset all wizard inputs to their defaults so a freshly-picked
    flow doesn't inherit Campaign A's research, locations, or steps.

    Auto-discovers fields by prefix (aicb_*, custom_*, rc_*) from a
    fresh AppState instance, so newly-added wizard fields are reset
    automatically. See C2/C3 in
    docs/superpowers/specs/2026-04-26-dripdrop-critical-bug-triage-design.md
    for the failure mode (cross-campaign data contamination).
    """
    fresh = AppState()
    import copy as _copy
    for name, default in vars(fresh).items():
        if name.startswith(("aicb_", "custom_", "rc_")):
            # deep-copy so mutating the fresh default later doesn't
            # leak back into s (relevant when the default is a list/dict)
            try:
                setattr(s, name, _copy.deepcopy(default))
            except Exception:
                setattr(s, name, default)


# H16: clearing computed outputs when stepping back through the AI
# campaign wizard. Without this, stale aicb_research from an earlier
# forward pass leaks into a later forward pass even when the user has
# changed inputs (e.g. typed a new company). User inputs are preserved.
_WIZ_BACK_CLEARED_FIELDS = (
    "aicb_research",
    "aicb_campaign",
    "aicb_docs",
    "aicb_generating",
    "aicb_gen_steps",
    # New step-3 candidate state (2026-04-26 spec)
    "_aicb_cand_text",
    "aicb_cand_count",
    "aicb_cand_source",
    "aicb_cand_cards",
)


def _wiz_back_clear_outputs(s: "AppState") -> None:
    """Reset computed wizard outputs to their AppState defaults so a
    fresh forward pass regenerates instead of replaying stale data.
    Inputs (company, website, niche, industry, locations, roles,
    camp_type) are intentionally NOT cleared."""
    fresh = AppState()
    import copy as _copy
    for name in _WIZ_BACK_CLEARED_FIELDS:
        if hasattr(fresh, name):
            try:
                setattr(s, name, _copy.deepcopy(getattr(fresh, name)))
            except Exception:
                setattr(s, name, getattr(fresh, name))


# ═══════════════════════════════════════════════════════════════════════════
#  NAVIGATION HELPERS
# ═══════════════════════════════════════════════════════════════════════════

def _page_decor(variant: int = 1):
    """Emit a single flowing brand decoration for the page.

    Each variant is ONE coherent organic element (ribbon/wave/blob/orbit/swirl)
    anchored far-right of the main area where content never lives, so it reads
    as ambient background without competing with buttons or text.

    Uses only the brand teal and indigo, low opacity (~.10), all curves  - 
    no grids, hatches, or dot rasters. Variants 1 - 5 give each page a distinct
    look; the variant parameter is moduloed into range so callers can't error.
    """
    teal = "#1AE3D9"
    indigo = "#6366F1"
    v = ((int(variant) - 1) % 5) + 1  # 1..5 regardless of input

    # Shared gradient def, unique id per variant so multiple pages rendered in
    # a single session can't collide.
    grad_id = f"fd-grad-{v}"
    defs = (
        '<defs>'
        f'<linearGradient id="{grad_id}" x1="0%" y1="0%" x2="100%" y2="100%">'
        f'<stop offset="0%" stop-color="{teal}" stop-opacity="1"/>'
        f'<stop offset="100%" stop-color="{indigo}" stop-opacity="1"/>'
        '</linearGradient>'
        '</defs>'
    )

    if v == 1:
        # ── Flowing Ribbon ──
        # Three long stroked bezier curves sweeping across the right side.
        # Reads as a soft flowing river. Positioned mid-right, far from content.
        shape = f'''
          <svg class="fd-flow" width="620" height="620" viewBox="0 0 620 620">
            {defs}
            <path d="M 40,520 C 180,420 120,300 260,240 S 460,180 560,60"
                  fill="none" stroke="url(#{grad_id})" stroke-width="10" stroke-linecap="round"/>
            <path d="M 10,580 C 160,500 110,360 240,300 S 440,240 580,120"
                  fill="none" stroke="{teal}" stroke-width="4" stroke-linecap="round" opacity="0.6"/>
            <path d="M 80,460 C 200,380 160,260 300,200 S 500,140 600,20"
                  fill="none" stroke="{indigo}" stroke-width="3" stroke-linecap="round" opacity="0.5"/>
          </svg>
        '''
    elif v == 2:
        # ── Stacked Waves ──
        # Multiple offset quadratic waves stacking upward in the bottom-right.
        shape = f'''
          <svg class="fd-flow-bot" width="720" height="360" viewBox="0 0 720 360">
            {defs}
            <path d="M 0,340 Q 120,280 240,320 T 480,320 T 720,300"
                  fill="none" stroke="{teal}" stroke-width="5" stroke-linecap="round"/>
            <path d="M 0,280 Q 140,220 260,260 T 500,260 T 720,240"
                  fill="none" stroke="url(#{grad_id})" stroke-width="6" stroke-linecap="round" opacity="0.85"/>
            <path d="M 0,220 Q 160,160 280,200 T 520,200 T 720,180"
                  fill="none" stroke="{teal}" stroke-width="4" stroke-linecap="round" opacity="0.7"/>
            <path d="M 0,160 Q 180,100 300,140 T 540,140 T 720,120"
                  fill="none" stroke="{indigo}" stroke-width="3" stroke-linecap="round" opacity="0.55"/>
          </svg>
        '''
    elif v == 3:
        # ── Orbit ──
        # Concentric thin rings with a couple of orbit dots and a bold arc.
        shape = f'''
          <svg class="fd-flow" width="560" height="560" viewBox="0 0 560 560">
            {defs}
            <circle cx="280" cy="280" r="220" fill="none" stroke="{teal}" stroke-width="3"/>
            <circle cx="280" cy="280" r="150" fill="none" stroke="url(#{grad_id})" stroke-width="2" stroke-dasharray="6 10"/>
            <circle cx="280" cy="280" r="80" fill="none" stroke="{indigo}" stroke-width="2" opacity="0.6"/>
            <circle cx="460" cy="170" r="14" fill="{teal}"/>
            <circle cx="120" cy="380" r="8" fill="{indigo}"/>
            <path d="M 280,60 A 220,220 0 0,1 500,280"
                  fill="none" stroke="url(#{grad_id})" stroke-width="6" stroke-linecap="round"/>
          </svg>
        '''
    elif v == 4:
        # ── Organic Blob ──
        # Soft asymmetric closed curve with a fine outlined echo around it.
        shape = f'''
          <svg class="fd-flow" width="600" height="600" viewBox="0 0 600 600">
            {defs}
            <path d="M 300,80 C 420,60 520,160 510,280 C 540,380 460,500 340,510 C 220,530 100,450 110,320 C 80,200 180,100 300,80 Z"
                  fill="url(#{grad_id})" opacity="0.38"/>
            <path d="M 310,50 C 440,30 560,140 550,280 C 580,400 480,540 340,550 C 200,570 70,470 80,320 C 50,180 180,70 310,50 Z"
                  fill="none" stroke="{teal}" stroke-width="2" opacity="0.6"/>
          </svg>
        '''
    else:  # v == 5
        # ── Swirl / Spiral ──
        # Open bezier spiral that reads as motion/flow.
        shape = f'''
          <svg class="fd-flow" width="560" height="560" viewBox="0 0 560 560">
            {defs}
            <path d="M 280,280 m -200,0 a 200,200 0 1,1 400,0 a 160,160 0 1,0 -320,0 a 120,120 0 1,1 240,0 a 80,80 0 1,0 -160,0 a 40,40 0 1,1 80,0"
                  fill="none" stroke="url(#{grad_id})" stroke-width="5" stroke-linecap="round"/>
            <circle cx="280" cy="280" r="6" fill="{teal}"/>
          </svg>
        '''

    ui.html(f'<div class="fd-decor-layer">{shape}</div>')


def _nav_snapshot(s: AppState) -> dict:
    """Capture current nav state for history."""
    return dict(
        hub=s.hub, sp=s.sp, ep=s.ep,
        loaded_camp=copy.deepcopy(s.loaded_camp) if s.loaded_camp else None,
        loaded_view=s.loaded_view, loaded_tab=s.loaded_tab,
        launch_result=s.launch_result,
        sq=s.sq, sq_review=s.sq_review, _tab=s._tab, stpl=s.stpl,
        custom_editing=s.custom_editing,
        custom_name=s.custom_name,
        svars=copy.deepcopy(getattr(s, 'svars', {})),
        scon=list(getattr(s, 'scon', [])),
    )

def _save_current_page(s: AppState) -> None:
    """Stamp `_last_page_ts` on every render so `_restore_aicb_state`
    can tell a brief WS reconnect (<5 min) apart from a cold open.

    Page identity (hub/sp/ep) is intentionally NOT persisted anymore:
    per 2026-05-25 user directive, root URL always lands on Dashboard
    regardless of last page."""
    try:
        app.storage.user["_last_page_ts"] = datetime.utcnow().strftime("%Y-%m-%dT%H:%M:%SZ")
    except Exception:
        pass


# Fields persisted across reconnects so wizards don't restart at step 1
# every time Cloudflare's ~100s websocket idle-timeout fires or a rapid
# back-and-forth click triggers a reconnect. Originally AICB-only; expanded
# 2026-05-11 to cover the Phase 2 Target-a-Candidate wizard (tc_*),
# Build-from-scratch flow (custom_*), and Recruiting Campaign wizard (rc_*)
# after the user reported "a few resets while I was mid work".
# Keep this list narrow: small primitives + small lists/dicts only. Big
# fields (resumes, generated docs, research blobs) are excluded — they're
# heavy to serialize on every render and cheap to regenerate on demand.
# Transient flags (*_generating, *_error) are also excluded so they
# re-render fresh on reconnect rather than locking the UI in a stale
# loading state.
_AICB_PERSISTED_FIELDS = (
    # AICB ("AI Campaign Builder") wizard
    "aicb_wizard_step", "aicb_wizard_mode", "aicb_step", "aicb_type_picked",
    "aicb_target_mode",
    "aicb_step2_mode",
    "aicb_company", "aicb_website", "aicb_industry", "aicb_niche",
    "aicb_primary_industry", "aicb_secondary_industries",
    "aicb_sel_locations", "aicb_sel_roles",
    "aicb_camp_type", "aicb_byos_desc",
    "aicb_cand_count", "aicb_cand_source", "aicb_cand_cards",
    "aicb_tone",
    # Target-a-Candidate wizard (Phase 2, 2026-05-10). Skip tc_jd_generating
    # and tc_generating — transient spinner flags. Skip tc_error — should
    # re-derive on next render. tc_candidates is bounded (CSV upload).
    "tc_step", "tc_jd_text", "tc_jd_filename", "tc_jd_parsed",
    "tc_candidates", "tc_preset", "tc_contacts",
    # Build-from-scratch / custom wizard
    "custom_steps", "custom_name", "custom_preset_picked",
    "custom_editing", "custom_selected_type", "custom_editing_idx",
    # Recruiting Campaign wizard. Skip rc_ai_generating and rc_ai_error —
    # transient. rc_ai_pitch is a small string, fine to persist.
    "rc_job_title", "rc_company", "rc_location", "rc_selling_points",
    "rc_salary_range", "rc_job_url", "rc_brief", "rc_step",
    "rc_custom_steps", "rc_ai_pitch",
    # Chooser + active-tab context so a reconnect lands the user back
    # in the same chooser branch (Saved vs Custom vs Templates) rather
    # than the bare picker page.
    "_tab", "_chooser_origin", "stpl",
)


def _save_aicb_state(s: AppState) -> None:
    """Snapshot the AICB wizard's persistable fields into session storage.
    Cheap dict serialization called on every render so reconnects can
    rebuild the wizard exactly where the user left off."""
    try:
        snap = {}
        for f in _AICB_PERSISTED_FIELDS:
            if hasattr(s, f):
                snap[f] = getattr(s, f)
        app.storage.user["_aicb_state"] = snap
    except Exception:
        pass


def _restore_aicb_state(s: AppState) -> None:
    """Rehydrate the AICB wizard from session storage onto a fresh
    AppState. No-op if nothing was saved. Defensive: only assigns
    fields that already exist on AppState (so a removed field in a
    future refactor doesn't crash on stale storage).

    TTL guard (2026-05-11): only auto-restore when the save is recent
    (< 5 min old — i.e. a Cloudflare websocket reconnect, not a cold
    cold-open hours later). Older snapshots fall through to the
    Resume banner on the chooser, which is user-initiated and lets
    them pick "go back to my draft" vs "start fresh" rather than
    being silently dropped mid-wizard.

    User complaint 2026-05-11: opening the app the next day landed
    them on an empty results screen (aicb_step=2 was restored but
    aicb_docs intentionally isn't persisted — heavy + cheap to
    regenerate — leaving the results page with no content to render).
    """
    try:
        snap = app.storage.user.get("_aicb_state") or {}
        if not snap:
            return
        # Brief-reconnect TTL: only auto-restore within 5 minutes of
        # the last render. Older = treat as cold open, let the Resume
        # banner offer the draft instead.
        _ts = app.storage.user.get("_last_page_ts", "")
        if _ts:
            try:
                _age_s = (datetime.utcnow() - datetime.strptime(
                    _ts, "%Y-%m-%dT%H:%M:%SZ")).total_seconds()
                if _age_s > 300:  # 5 min
                    return
            except Exception:
                pass
        for f in _AICB_PERSISTED_FIELDS:
            if f in snap and hasattr(s, f):
                setattr(s, f, snap[f])
        # Safety net: if aicb_step came back as 2 (results screen) but
        # aicb_docs is empty (it's not persisted), the results screen
        # would render with no content. Force back to step 1 (editable
        # wizard) so the user lands somewhere coherent.
        if getattr(s, "aicb_step", 1) == 2 and not (getattr(s, "aicb_docs", None) or {}):
            s.aicb_step = 1
    except Exception:
        pass


def nav_go(s: AppState, rf, *, hub=None, page=None,
           loaded_camp=None, loaded_view=None, push=True):
    """Navigate to a new page, pushing current state to history first."""
    if push:
        s._nav_history.append(_nav_snapshot(s))
        # Cap history depth so it doesn't grow forever
        if len(s._nav_history) > 20:
            s._nav_history = s._nav_history[-20:]

    if hub is not None:
        s.hub = hub
    if page is not None:
        if s.hub == "sales":
            s.sp = page
        else:
            s.ep = page
    if loaded_camp is not None:
        s.loaded_camp = loaded_camp
    if loaded_view is not None:
        s.loaded_view = loaded_view
    _save_current_page(s)
    rf()

def nav_back(s: AppState, rf):
    """Pop the nav history stack and restore previous state."""
    if not s._nav_history:
        # Default fallback  -  always safe
        s.hub = "sales"; s.sp = "dashboard"; rf()
        return
    snap = s._nav_history.pop()
    s.hub = snap["hub"]
    s.sp = snap["sp"]
    s.ep = snap["ep"]
    s.loaded_camp = snap.get("loaded_camp")
    s.loaded_view = snap.get("loaded_view", "emails")
    s.loaded_tab = snap.get("loaded_tab", 0)
    s.launch_result = snap.get("launch_result")
    s.sq = snap.get("sq", 1)
    s.sq_review = snap.get("sq_review", False)
    s._tab = snap.get("_tab", "")
    s.stpl = snap.get("stpl")
    s.custom_editing = snap.get("custom_editing", False)
    s.custom_name = snap.get("custom_name", "")
    s.svars = snap.get("svars", {})
    s.scon = snap.get("scon", [])
    _save_current_page(s)
    rf()

def nav_back_label(s: AppState) -> str:
    """Human-readable label for what the back button goes to."""
    if not s._nav_history:
        return ""
    snap = s._nav_history[-1]
    hub = snap.get("hub", "sales")
    sp  = snap.get("sp", "drip")
    ep  = snap.get("ep", "emails_home")
    lc  = snap.get("loaded_camp")
    lv  = snap.get("loaded_view", "emails")

    PAGE_NAMES = {
        "dashboard": "Dashboard", "drip": "Today's Drip", "tasks": "Tasks", "responses": "Campaign Radar",
        "start_seq": "Start a Campaign", "contacts": "Contact Lists",
        "active_camps": "Active Campaigns", "evergreen": "Slow Drip", "evergreen_create": "Slow Drip",
        "queue": "Email Queue",
        "seq_mgr": "Current Campaigns", "signature": "Email Signature",
        "camp_gen": "Campaign Builder",
        "emails_build": "Emails", "sequence": "Sequence",
        "prev_launch": "Preview & Launch", "e_responses": "Campaign Radar",
    }
    LOADED_VIEW_NAMES = {
        "emails": "Edit Emails", "sequence": "Edit Sequence",
        "contacts": "Choose Contacts", "launch": "Preview Campaign",
    }

    if lc:
        lname = lc.get("name", "Campaign") if isinstance(lc, dict) else "Campaign"
        view_label = LOADED_VIEW_NAMES.get(lv, "Campaign")
        return f"{lname}  -  {view_label}"

    page_key = sp if hub == "sales" else ep
    return PAGE_NAMES.get(page_key, "Back")

# ═══════════════════════════════════════════════════════════════════════════
#  EMAIL SEQUENCER WIZARD HEADER
# ═══════════════════════════════════════════════════════════════════════════

# Steps: (page_key, short_label, icon, coaching_tip)
_ES_STEPS = [
    ("emails_build", "Write Emails",      "✉",
     "Write each email in your sequence. Give every email a subject and body. Add as many as you need, then move to sequence."),
    ("sequence",     "Set Sequence",       "⏱",
     "Set how many days apart each email sends. Use a preset or dial in your own spacing. The schedule preview updates live."),
    ("e_contacts",   "Add Contacts",       "👥",
     "Import a CSV or pick a saved list. Your contacts will appear instantly  -  you'll see exactly who gets this campaign."),
    ("prev_launch",  "Preview & Launch",   "🚀",
     "Review everything before it goes out. Check subjects, sequence, and contacts  -  then launch when you're ready."),
]
_ES_PAGE_IDX = {k: i for i, (k, _, _, _) in enumerate(_ES_STEPS)}


def _seq_wizard_header(s: AppState, rf, current_page: str):
    """Renders progress bar + coaching tip + Next button for the Email Sequencer wizard."""
    cur_idx  = _ES_PAGE_IDX.get(current_page, 0)
    _, _, _, tip = _ES_STEPS[cur_idx]

    # ── Progress bar ────────────────────────────────────────────────────────
    with ui.element("div").style(
            f"background:{C['surface']};border:1px solid {C['border']};"
            f"border-radius:12px;padding:14px 20px;margin-bottom:20px;"):

        # Step pills row
        with ui.element("div").style("display:flex;align-items:center;gap:0;margin-bottom:12px;"):
            for i, (key, label, icon, _) in enumerate(_ES_STEPS):
                is_done    = i < cur_idx
                is_current = i == cur_idx
                col   = C["teal"] if is_current else (C["good"] if is_done else C["muted"])
                bg    = f"{C['teal']}20" if is_current else (f"{C['good']}15" if is_done else "transparent")
                bord  = C["teal"] if is_current else (C["good"] if is_done else C["border"])
                pfx   = "✓" if is_done else icon

                def _jump(k=key):
                    s.ep = k; rf()

                with ui.element("button").style(
                        f"display:inline-flex;align-items:center;gap:6px;"
                        f"padding:6px 14px;border-radius:99px;font-size:12px;font-weight:600;"
                        f"font-family:'Nunito','DM Sans',sans-serif;cursor:pointer;"
                        f"background:{bg};border:1px solid {bord};color:{col};"
                        f"transition:all .15s;white-space:nowrap;"
                        ).on("click", _jump):
                    ui.label(pfx).style(f"font-size:11px;pointer-events:none;")
                    ui.label(f"{i+1}. {label}").style("pointer-events:none;")

                # Connector line between steps
                if i < len(_ES_STEPS) - 1:
                    line_col = C["good"] if i < cur_idx else C["border"]
                    ui.element("div").style(
                        f"flex:1;height:1px;background:{line_col};margin:0 4px;")

        # Filled progress bar
        pct = int((cur_idx / (len(_ES_STEPS) - 1)) * 100)
        with ui.element("div").style(
                f"height:3px;background:{C['border']};border-radius:99px;overflow:hidden;"):
            ui.element("div").style(
                f"height:3px;width:{pct}%;background:{C['teal']};border-radius:99px;transition:width .4s;")

        # Coaching tip
        with ui.element("div").style(
                f"display:flex;align-items:flex-start;gap:10px;margin-top:12px;"):
            ui.label("💡").style("font-size:14px;flex-shrink:0;margin-top:1px;")
            ui.label(tip).style(f"font-size:12px;color:{C['muted']};line-height:1.6;")

    # ── Campaign name prompt (first step only, if not named yet) ────────────
    if current_page == "emails_build" and not s.es_campaign_name:
        with ui.element("div").style(
                f"display:flex;align-items:center;gap:12px;padding:10px 16px;"
                f"background:{C['warn']}10;border:1px solid {C['warn']}40;"
                f"border-radius:8px;margin-bottom:16px;"):
            ui.label("📝").style("font-size:16px;flex-shrink:0;")
            ui.label("Give this campaign a name:").style(
                f"font-size:12px;color:{C['warn']};font-weight:600;flex-shrink:0;")
            name_inp = ui.input(
                placeholder="e.g. Denver CNC  -  March",
                value=s.es_campaign_name
            ).style(
                f"flex:1;background:{C['surface']};border:1px solid {C['warn']}60;"
                f"border-radius:6px;padding:5px 10px;font-size:13px;color:{C['text_l']};")
            def _set_name():
                s.es_campaign_name = name_inp.value.strip() or "Untitled Campaign"
                ui.notify(f"✓ Named: {s.es_campaign_name}", type="positive", timeout=1500)
                rf()
            with ui.element("button").classes("fd-pb").style(
                    f"padding:5px 14px;font-size:12px;background:{C['warn']};color:#0D1520;"
                    ).on("click", _set_name):
                ui.label("Save")


def _seq_wizard_footer(s: AppState, rf, current_page: str, can_advance: bool = True,
                       blocked_reason: str = ""):
    """Renders the Next Step / Finish button at the bottom of each wizard step."""
    cur_idx = _ES_PAGE_IDX.get(current_page, 0)
    is_last = cur_idx == len(_ES_STEPS) - 1

    if is_last:
        return  # prev_launch handles its own launch button

    next_key, next_label, next_icon, _ = _ES_STEPS[cur_idx + 1]

    ui.element("div").style(f"height:1px;background:{C['border']};margin:24px 0 16px;")
    with ui.element("div").style("display:flex;align-items:center;justify-content:space-between;"):
        # Left: completion hint
        if can_advance:
            ui.label("✓ Looking good  -  ready to continue.").style(
                f"font-size:12px;color:{C['good']};")
        else:
            ui.label(f"⚠ {blocked_reason}").style(
                f"font-size:12px;color:{C['warn']};")

        # Right: Next button
        def _next():
            s.ep = next_key; rf()
        btn_style = (f"padding:10px 28px;font-size:14px;font-weight:700;"
                     f"font-family:'Nunito',sans-serif;")
        if can_advance:
            with ui.element("button").classes("fd-pb").style(btn_style).on("click", _next):
                ui.label(f"{next_icon} {next_label} →")
        else:
            with ui.element("button").classes("fd-pb").style(
                    btn_style + f"opacity:.4;pointer-events:none;cursor:not-allowed;"):
                ui.label(f"{next_icon} {next_label} →")


