def _show_page_help(s: AppState, rf, page_key: str):
    """No-op as of 2026-05-20 — the "?" help icon next to each page
    title (and the inline guide popup it opened) was retired per user
    feedback. The lightbulb intro strip at the top of each page
    (_render_page_intro_strip) is the surviving on-page help surface.

    Every call site (~20 across this file) is left alone so we can
    re-enable the guide later by reverting just this function. The
    PAGE_HELP dict is preserved as the source of truth.
    """
    return
    # Original implementation kept below for reference / quick revert.
    # ──────────────────────────────────────────────────────────────────
    guide = PAGE_HELP.get(page_key)
    if not guide:
        return
    _help_key = f"_help_{page_key}"
    _is_open = _help_key in s.expanded

    def _toggle_help():
        s.expanded.symmetric_difference_update({_help_key}); rf()

    # Help icon button
    with ui.element("button").style(
            f"font-size:14px;width:28px;height:28px;border-radius:50%;"
            f"background:{C['teal']}15;color:{C['teal']};border:1px solid {C['teal']}30;"
            f"cursor:pointer;display:inline-flex;align-items:center;justify-content:center;"
            f"margin-left:10px;vertical-align:middle;flex-shrink:0;"
            ).on("click", _toggle_help):
        ui.label("?")

    # Help panel (inline, below header)
    if _is_open:
        with ui.element("div").style(
                f"background:{C['card']};border:1px solid {C['teal']}30;"
                f"border-radius:12px;padding:20px 24px;margin:12px 0 16px;"
                f"max-width:800px;"):
            with ui.element("div").style("display:flex;align-items:center;justify-content:space-between;margin-bottom:12px;"):
                ui.label(f"Guide: {guide['title']}").style(
                    f"font-size:16px;font-weight:700;color:{C['teal']};font-family:'Nunito',sans-serif;")
                with ui.element("button").style(
                        f"font-size:16px;color:{C['muted']};background:transparent;border:none;"
                        f"cursor:pointer;padding:4px 8px;").on("click", _toggle_help):
                    ui.label("✕")
            for section_title, section_body in guide["sections"]:
                ui.label(section_title).style(
                    f"font-size:13px;font-weight:700;color:{C['text_l']};margin-top:10px;margin-bottom:4px;")
                # Render body with line breaks preserved
                for line in section_body.split("\n"):
                    _indent = line.startswith("- ") or line.startswith("1.") or line.startswith("2.") or line.startswith("3.") or line.startswith("4.") or line.startswith("5.")
                    ui.label(line).style(
                        f"font-size:12px;color:{C['text']};line-height:1.6;"
                        f"{'padding-left:12px;' if _indent else ''}")


def _is_help_strip_dismissed(page_key: str) -> bool:
    """Return True if the current user has dismissed the page intro strip
    for the given page key. Reads dripdrop_config.json (per-user, async-safe)."""
    try:
        cfg = load_config()
    except Exception:
        return False
    dismissed = cfg.get("dismissed_help_strips") or []
    return page_key in dismissed


def _dismiss_help_strip(page_key: str) -> None:
    """Append page_key to the user's dismissed_help_strips list. Idempotent —
    duplicates are not added."""
    try:
        cfg = load_config()
    except Exception:
        cfg = {}
    dismissed = list(cfg.get("dismissed_help_strips") or [])
    if page_key not in dismissed:
        dismissed.append(page_key)
    cfg["dismissed_help_strips"] = dismissed
    save_config(cfg)


def _clear_all_dismissed_help_strips() -> None:
    """Reset the user's dismissed_help_strips list to []. Used by the
    'Show all page guides again' button on the Settings page."""
    try:
        cfg = load_config()
    except Exception:
        cfg = {}
    cfg["dismissed_help_strips"] = []
    save_config(cfg)


def _render_page_intro_strip(s, rf, page_key: str) -> None:
    """Render the always-visible 'What is this page for / Next:' tinted card
    at the top of a page. Reads PAGE_HELP[page_key] for the summary and
    next_action fields. Renders nothing if:
      - the page key isn't in PAGE_HELP, OR
      - the entry has no summary field (or summary is empty), OR
      - the entry has no next_action field (or next_action is empty), OR
      - the current user has dismissed this strip.

    Dismissing writes page_key to dripdrop_config.json[dismissed_help_strips]
    and triggers a re-render via the rf callable.
    """
    entry = PAGE_HELP.get(page_key)
    if not entry:
        return
    summary = (entry.get("summary") or "").strip()
    next_action = (entry.get("next_action") or "").strip()
    if not summary or not next_action:
        return
    if _is_help_strip_dismissed(page_key):
        return

    def _on_dismiss():
        _dismiss_help_strip(page_key)
        try:
            rf()
        except Exception:
            pass

    primary = C["teal"]
    # Compact 2026-05-20: collapsed from a full-width tinted card to a
    # small lightbulb badge. Right-aligned so it doesn't crowd the page
    # title, and the hover tooltip is themed to match the app's dark
    # surface instead of Quasar's default gray block.
    with ui.element("div").style(
            "display:flex;justify-content:flex-end;align-items:center;"
            "width:100%;margin-bottom:8px;"):
        with ui.element("div").style(
                f"width:28px;height:28px;border-radius:50%;"
                f"background:{primary}18;border:1px solid {primary}40;"
                f"display:inline-flex;align-items:center;justify-content:center;"
                f"font-size:14px;line-height:1;cursor:help;"
                f"font-family:'DM Sans','Segoe UI',sans-serif;"):
            ui.label("💡").style("pointer-events:none;")
            # Quasar tooltip — themed to match the dark surface palette.
            ui.tooltip(f"{summary}\n\nNext: {next_action}").style(
                f"max-width:340px;white-space:pre-wrap;line-height:1.45;"
                f"background:{C['card']} !important;"
                f"color:{C['text_l']} !important;"
                f"border:1px solid {primary}55;"
                f"border-radius:8px;padding:10px 12px;"
                f"font-family:'DM Sans','Segoe UI',sans-serif;font-size:12px;"
                f"box-shadow:0 4px 16px rgba(0,0,0,0.35);")


