def _show_profile_modal(s: AppState, rf):
    """Editable profile modal: name, phone, password, profile photo."""
    _uemail = getattr(s, '_user_email', '')
    if not _uemail:
        return
    _rec = _get_user_record(_uemail)
    _safe_key = _uemail.lower().strip().replace("@", "_at_").replace(".", "_")
    _has_photo = bool(_get_user_photo_path(_uemail))

    with ui.dialog() as dlg, ui.card().style(
            f"background:{C['bg']};border:1px solid {C['border']};border-radius:14px;"
            f"padding:28px 32px;min-width:520px;max-width:580px;"):
        ui.label("My Profile").style(
            f"font-size:22px;font-weight:800;color:{C['text_l']};"
            f"font-family:'Nunito',sans-serif;margin-bottom:4px;")
        ui.label("Update your name, phone, password, or profile photo.").style(
            f"font-size:12px;color:{C['muted']};margin-bottom:20px;")

        # ── Profile photo row ─────────────────────────────────────────
        # The upload widget is hidden in a zero-height wrapper. The big
        # avatar circle is the clickable target  -  clicking it opens the
        # file picker via the upload element's pickFiles() method. Much
        # more intuitive than the previous tiny "Upload a new photo" link.
        def _handle_photo_upload(e):
            try:
                fname = (e.name or "avatar.png").lower()
                ext = fname.rsplit(".", 1)[-1] if "." in fname else "png"
                data = e.content.read() if hasattr(e.content, "read") else bytes(e.content)
                if len(data) > _MAX_IMAGE_BYTES:
                    ui.notify("Photo must be under 5 MB", type="warning"); return
                # _save_user_photo() returns "" if the file is too big or
                # doesn't actually look like an image (magic byte check).
                # Surface that as a clean error.
                saved = _save_user_photo(_uemail, data, ext)
                if not saved:
                    ui.notify(
                        "That file isn't a valid image. Please upload a PNG, JPG, GIF, or WebP.",
                        type="negative",
                    )
                    return
                # bump cache-bust token
                users = _load_users()
                import time as _t
                users[_uemail.lower().strip()]["photo_updated"] = int(_t.time())
                _save_users(users)
                ui.notify("Profile photo updated", type="positive")
                dlg.close()
                rf()
            except Exception as ex:
                ui.notify(f"Upload failed: {str(ex)[:100]}", type="negative")

        # Hidden uploader  -  opens the OS file picker when its pickFiles()
        # method is called from the avatar button below.
        with ui.element("div").style("height:0;overflow:hidden;"):
            _photo_upload = ui.upload(
                label="",
                auto_upload=True,
                on_upload=_handle_photo_upload,
                max_file_size=5 * 1024 * 1024,
            ).props('accept="image/*"')

        with ui.element("div").style(
                "display:flex;align-items:center;gap:18px;margin-bottom:22px;"):
            # Clickable avatar  -  entire circle is the click target.
            # Reuses .fd-avatar-btn class for the hover effect (scales up
            # 6% with a teal glow) so it's visually obvious it's clickable.
            with ui.element("button").classes("fd-avatar-btn").style(
                    f"width:80px;height:80px;border-radius:50%;"
                    f"background:{C['teal_dim']};border:2px solid {C['teal']};"
                    f"display:flex;align-items:center;justify-content:center;"
                    f"overflow:hidden;flex-shrink:0;cursor:pointer;padding:0;"
                    f"font-family:'Nunito',sans-serif;font-weight:800;font-size:26px;"
                    f"color:{C['teal']};position:relative;transition:all .15s;"
                    ).on("click", lambda: _photo_upload.run_method('pickFiles')):
                if _has_photo:
                    _bust = str(_rec.get("photo_updated", ""))
                    ui.html(
                        f'<img src="/avatar/{_safe_key}?v={_bust}" '
                        f'alt="avatar" style="width:100%;height:100%;object-fit:cover;pointer-events:none;" />'
                    )
                else:
                    ui.label(_user_initials(_rec.get("name", ""), _uemail)).style(
                        "pointer-events:none;")
            with ui.element("div").style("flex:1;"):
                # Clickable text button as a secondary trigger so the action
                # is unmistakable for users who don't realize the avatar is a button
                with ui.element("button").style(
                        f"display:inline-flex;align-items:center;gap:6px;padding:8px 16px;"
                        f"background:{C['teal']};color:{C['bg']};border:none;"
                        f"border-radius:7px;font-size:12px;font-weight:700;"
                        f"cursor:pointer;font-family:inherit;margin-bottom:6px;"
                        ).on("click", lambda: _photo_upload.run_method('pickFiles')):
                    ui.label("📷 Choose Photo")
                ui.label("PNG, JPG, GIF, or WebP  -  up to 5 MB. Click the circle or button.").style(
                    f"font-size:11px;color:{C['muted']};display:block;")

        # ── Name + Phone ──────────────────────────────────────────────
        ui.label("Display Name").classes("fd-fl").style("margin-bottom:4px;")
        _name_in = ui.input(
            value=_rec.get("name", ""),
            placeholder="Your full name",
        ).classes("fd-input").style("margin-bottom:12px;")

        ui.label("Phone Number").classes("fd-fl").style("margin-bottom:4px;")
        _phone_in = ui.input(
            value=_rec.get("phone", ""),
            placeholder="e.g. (555) 123-4567",
        ).classes("fd-input").style("margin-bottom:18px;")

        def _save_profile():
            new_name = _name_in.value.strip()
            new_phone = _phone_in.value.strip()
            if not new_name:
                ui.notify("Name cannot be empty", type="warning"); return
            _update_user_profile(_uemail, name=new_name, phone=new_phone)
            # Also update in-session name so the topbar reflects it immediately
            app.storage.user["name"] = new_name
            s._user_name = new_name
            ui.notify("Profile saved", type="positive")
            dlg.close()
            rf()

        with ui.element("div").style(
                f"display:flex;gap:10px;padding-bottom:16px;margin-bottom:18px;"
                f"border-bottom:1px solid {C['border']};"):
            with ui.element("button").classes("fd-pb").style(
                    "padding:9px 22px;font-size:13px;").on("click", _save_profile):
                ui.label("Save Profile")

        # ── Change password ───────────────────────────────────────────
        ui.label("Change Password").style(
            f"font-size:14px;font-weight:700;color:{C['text_l']};"
            f"font-family:'Nunito',sans-serif;margin-bottom:8px;")

        _old_in = ui.input(
            value="", placeholder="Current password",
        ).classes("fd-input").props("type=password").style("margin-bottom:8px;")
        _new_in = ui.input(
            value="", placeholder="New password (at least 6 characters)",
        ).classes("fd-input").props("type=password").style("margin-bottom:8px;")
        _new2_in = ui.input(
            value="", placeholder="Confirm new password",
        ).classes("fd-input").props("type=password").style("margin-bottom:14px;")

        def _save_password():
            old_pw = _old_in.value
            new_pw = _new_in.value
            new_pw2 = _new2_in.value
            if not old_pw or not new_pw:
                ui.notify("Fill in all password fields", type="warning"); return
            if new_pw != new_pw2:
                ui.notify("New passwords don't match", type="warning"); return
            ok, err = _change_user_password(_uemail, old_pw, new_pw)
            if not ok:
                ui.notify(err, type="negative"); return
            ui.notify("Password changed", type="positive")
            _old_in.set_value(""); _new_in.set_value(""); _new2_in.set_value("")

        with ui.element("div").style("display:flex;justify-content:space-between;gap:10px;"):
            with ui.element("button").classes("fd-pb").style(
                    "padding:9px 22px;font-size:13px;").on("click", _save_password):
                ui.label("Update Password")
            with ui.element("button").style(
                    f"padding:9px 22px;font-size:13px;background:transparent;"
                    f"color:{C['muted']};border:1px solid {C['border']};"
                    f"border-radius:8px;cursor:pointer;font-family:inherit;"
                    ).on("click", dlg.close):
                ui.label("Close")

    dlg.open()


def topbar(s: AppState, rf):
    # Clickable logo — click goes Home (Dashboard) and clears history
    # so the Back button next to the page title disappears (nothing to
    # back into on the home page).
    def _topbar_home():
        s._nav_history.clear()
        s.hub = "sales"; s.sp = "dashboard"
        s.launch_result = None
        rf()

    with ui.element("div").classes("fd-topbar"):
        with ui.element("div").classes("fd-logo").style("cursor:pointer;").on(
                "click", _topbar_home):
            ui.html(
                '<img src="/static/dripdrop_logo.png?v=3" alt="DripDripDrop  -  click for Home" title="Home" />'
            )
        def _sales():
            # Land on Dashboard  -  top-level tab, clear history
            s._nav_history.clear()
            s.hub = "sales"; s.sp = "dashboard"
            s.launch_result = None
            rf()
        def _emails():
            # Reset sequencer state so stale emails from a previous campaign don't bleed in
            s._nav_history.clear()
            s.hub = "emails"; s.ep = "emails_build"
            s.es_emails = [{"name": "Email 1", "subject": "", "body": "",
                            "delay_days": 0, "time": "9:00 AM", "attachments": []}]
            s.es_campaign_name = ""
            s.es_active_tab = 0
            s._es_pending_attachments = {}
            s._es_saved_start_date = None
            rf()
        def _camp_mgr():
            s._nav_history.clear()
            s.hub = "sales"; s.sp = "seq_mgr"; rf()
        def _newsletters():
            s._nav_history.clear()
            s.hub = "sales"; s.sp = "newsletters"; rf()
        # Active state: each pill is mutually exclusive. Newsletters
        # replaces the old SlowDrip Sequence pill as the second button
        # (Slow Drip moved to the sidebar 2026-05-10 per user feedback).
        # Sales Hub is the catch-all — anything that's NOT one of the
        # other explicit hub destinations. Forgetting candidate_finder
        # in the exclude list (pre-2026-05-11) caused both Sales Hub
        # and Candidate Pool to highlight together. New hub pages
        # added below MUST also be added to this exclusion tuple.
        _other_hub_pages = ("seq_mgr", "newsletters", "candidate_finder", "ats")
        _on_sales       = s.hub == "sales" and s.sp not in _other_hub_pages
        _on_emails      = s.hub == "emails"
        _on_camp_mgr    = s.hub == "sales" and s.sp == "seq_mgr"
        _on_newsletters = s.hub == "sales" and s.sp == "newsletters"
        with ui.element("button").classes("fd-hub" + (" on" if _on_sales else "")).on("click", _sales):
            ui.label("Sales Hub")
        with ui.element("button").classes("fd-hub" + (" on" if _on_newsletters else "")).on("click", _newsletters):
            ui.label("Newsletters")
        with ui.element("button").classes("fd-hub" + (" on" if _on_camp_mgr else "")).on("click", _camp_mgr):
            ui.label("Current Campaigns")
        # "Top Candidates" hub button removed 2026-06-09 — candidates live in
        # the ATS now. The candidate_finder page handler stays callable.
        # ── ATS (gated). Its own full-screen app at /ats — clicking here
        # leaves the DripDrop chrome entirely. ──
        if (getattr(s, '_user_email', '') or '').strip().lower() in _ATS_ALLOWED_EMAILS:
            with ui.element("button").classes("fd-hub").on(
                    "click", lambda: ui.navigate.to("/ats")):
                ui.label("Pipeline")
        # Market Intel hub button removed 2026-05-02 per user — "remove
        # for now". Page handler p_market_intel and the underlying
        # market_intel route stay in place so anyone with a deep link
        # still works; just no top-nav entry.
        # ── User avatar + dropdown ──
        _uemail = getattr(s, '_user_email', '')
        _uname_full = getattr(s, '_user_name', '') or _uemail
        if _uname_full and _SERVER_MODE:
            _user_rec = _get_user_record(_uemail)
            _has_photo = bool(_get_user_photo_path(_uemail))
            _safe_key = _uemail.lower().strip().replace("@", "_at_").replace(".", "_")
            _initials = _user_initials(_uname_full, _uemail)

            def _logout():
                app.storage.user.clear()
                ui.navigate.to("/login")

            def _open_profile():
                # Navigate to the combined profile page instead of a modal.
                s.hub = "sales"; s.sp = "company_profile"; rf()

            def _go_signature():
                s.hub = "sales"; s.sp = "signature"; rf()

            def _go_ai_settings():
                s.hub = "sales"; s.sp = "ai_settings"; rf()

            # Mutable holder so the button's click handler can access the menu
            _avatar_menu_ref = {"m": None}
            def _toggle_avatar_menu():
                if _avatar_menu_ref["m"]:
                    _avatar_menu_ref["m"].open()

            # 2026-05-02: team logo moved BACK to the sidebar footer
            # (next to v2.0 label) per user preference. MV avatar
            # repositioned to right:50px (was 150px) so it has
            # breathing room from the right edge with the logo gone.
            with ui.element("div").classes("fd-avatar-wrap").style(
                    "position:absolute;right:50px;top:50%;transform:translateY(-50%);"):
                # Avatar button  -  image if uploaded, otherwise initials
                with ui.element("button").classes("fd-avatar-btn").props('data-tour="avatar"').style(
                        f"width:42px;height:42px;border-radius:50%;"
                        f"background:{C['teal_dim']};border:2px solid {C['teal']};"
                        f"cursor:pointer;padding:0;overflow:hidden;position:relative;"
                        f"display:flex;align-items:center;justify-content:center;"
                        f"font-family:'Nunito',sans-serif;font-weight:800;font-size:14px;"
                        f"color:{C['teal']};transition:all .15s;"
                        ).on("click", _toggle_avatar_menu):
                    if _has_photo:
                        # cache-bust with user record's updated timestamp so changes show up
                        _bust = str(_user_rec.get("photo_updated", ""))
                        ui.html(
                            f'<img src="/avatar/{_safe_key}?v={_bust}" '
                            f'alt="avatar" style="width:100%;height:100%;object-fit:cover;pointer-events:none;" />'
                        )
                    else:
                        ui.label(_initials).style("pointer-events:none;")
                    # Quasar menu  -  no-parent-event so we control opening via the click handler
                    with ui.menu().props(
                            "no-parent-event anchor='bottom right' self='top right' "
                            "transition-show='jump-down' transition-hide='jump-up'"
                            ).style(
                            f"background:{C['card']};border:1px solid {C['border']};"
                            f"border-radius:12px;min-width:260px;padding:0;"
                            f"box-shadow:0 10px 32px rgba(0,0,0,0.5);") as _av_menu:
                        _avatar_menu_ref["m"] = _av_menu
                        # Header: name + email
                        with ui.element("div").style(
                                f"padding:14px 16px 12px;"
                                f"border-bottom:1px solid {C['border']};"
                                f"display:flex;align-items:center;gap:12px;"):
                            with ui.element("div").style(
                                    f"width:40px;height:40px;border-radius:50%;"
                                    f"background:{C['teal_dim']};border:1px solid {C['teal']}60;"
                                    f"display:flex;align-items:center;justify-content:center;"
                                    f"overflow:hidden;flex-shrink:0;"
                                    f"font-family:'Nunito',sans-serif;font-weight:800;font-size:13px;"
                                    f"color:{C['teal']};"):
                                if _has_photo:
                                    _bust = str(_user_rec.get("photo_updated", ""))
                                    ui.html(
                                        f'<img src="/avatar/{_safe_key}?v={_bust}" '
                                        f'alt="avatar" style="width:100%;height:100%;object-fit:cover;" />'
                                    )
                                else:
                                    ui.label(_initials)
                            with ui.element("div").style("flex:1;min-width:0;"):
                                ui.label(_uname_full).style(
                                    f"font-size:13px;font-weight:700;color:{C['text_l']};"
                                    f"font-family:'Nunito',sans-serif;"
                                    f"white-space:nowrap;overflow:hidden;text-overflow:ellipsis;")
                                ui.label(_uemail).style(
                                    f"font-size:11px;color:{C['muted']};"
                                    f"white-space:nowrap;overflow:hidden;text-overflow:ellipsis;")

                        def _go_company_profile():
                            s.hub = "sales"; s.sp = "company_profile"; rf()

                        # Menu items
                        _menu_items = [
                            ("👤", "My Profile",         _open_profile),
                            ("✎",  "Signature",         _go_signature),
                            ("✦",  "Email & AI Setup",  _go_ai_settings),
                        ]
                        for icon, lbl, handler in _menu_items:
                            with ui.element("div").classes("fd-menu-item").style(
                                    f"padding:11px 16px;display:flex;align-items:center;gap:12px;"
                                    f"cursor:pointer;color:{C['text']};font-size:13px;"
                                    f"transition:background .12s;"
                                    ).on("click", handler):
                                ui.label(icon).style(
                                    f"font-size:15px;width:18px;text-align:center;color:{C['teal']};")
                                ui.label(lbl)

                        # Divider + logout
                        ui.element("div").style(
                            f"height:1px;background:{C['border']};margin:4px 0;")
                        with ui.element("div").classes("fd-menu-item").style(
                                f"padding:11px 16px;display:flex;align-items:center;gap:12px;"
                                f"cursor:pointer;color:{C['danger']};font-size:13px;"
                                f"transition:background .12s;"
                                ).on("click", _logout):
                            ui.label("↗").style(
                                f"font-size:15px;width:18px;text-align:center;color:{C['danger']};")
                            ui.label("Logout")
        # ── Theme toggle (sun/moon) ──
        with ui.element("button").classes("fd-theme-toggle").on(
                "click", lambda: ui.run_javascript("ddToggleTheme()")):
            ui.label("☀").classes("fd-theme-icon fd-theme-sun")
            ui.label("☾").classes("fd-theme-icon fd-theme-moon")


