def _generate_squeeze_pdfs(v):
    """Generate personalized PDFs for the Squeeze campaign attachments.
    Routes Market Pulse / Scorecard / Tenure Snapshot through the rich
    build_custom_pdf pipeline (full-page content); Bench Snapshot keeps
    its dedicated builder since it renders candidate-profile cards rather
    than a structured one-pager."""
    try:
        import sys as _sys
        _sys.path.insert(0, str(Path(__file__).resolve().parent / "funnel_forge"))
        import importlib, arena_pdfs as _ap; importlib.reload(_ap)
        from arena_pdfs import build_bench_snapshot, build_custom_pdf
    except ImportError:
        ui.notify("reportlab not installed  -  PDFs skipped. Run: pip install reportlab", type="warning")
        return

    role     = v.get("TargetRole", "Project Manager")
    company  = v.get("CompanyName", "Company")
    location = v.get("Geography", "")
    _primary = (v.get("PrimaryIndustry") or "").strip()
    _secondaries = list(v.get("SecondaryIndustries", []) or [])
    _exp_level = (v.get("ExpLevel") or "").strip()
    _cfg     = load_config()
    if not _primary:
        _primary = ((v.get("Vertical") or "").strip()
                    or _cfg.get("company_industry", "") or "")
    prep     = _cfg.get("sig_name", _get_company_name()) or _get_company_name()
    prep_email = _cfg.get("sig_email", "")
    dt       = date.today().strftime("%B %d, %Y")

    # Campaign-specific filenames to avoid cross-client contamination
    slug = re.sub(r'[^\w\s-]', '', company).strip().replace(' ', '_')[:40] or "Campaign"
    v["_pdf_slug"] = slug  # pass slug back so caller can reference filenames

    # Build a Claude client once and route the 3 structured PDFs through
    # the rich pipeline so they're full-page, not the prior hand-coded
    # stub bullets.
    _ctx_sq = {
        "company": company,
        "primary_industry": _primary,
        "secondary_industries": _secondaries,
        "positions": role,
        "location": location,
        "exp_level": _exp_level,
    }
    try:
        import anthropic
        _client_sq = anthropic.Anthropic(api_key=ANTHROPIC_API_KEY) if ANTHROPIC_API_KEY else None
    except Exception:
        _client_sq = None

    def _build_one(_kind: str, _fname: str, _human_label: str):
        if _client_sq is None:
            return False
        try:
            _data = _generate_rich_pdf_data(
                _client_sq, _kind, _ctx_sq,
                research_context="",
                style_guide=_style_guide_prompt(),
            )
            _path = str(_user_pdf_dir() / _fname)
            _build_dict = {
                "title": _data.get("title") or f"{_human_label} - {company}",
                "badge": _data.get("badge") or _human_label.upper(),
                "date": dt,
                "prepared_by": prep,
                "prepared_email": prep_email,
                "logo_path": _get_company_logo_path(),
                "intro": _data.get("intro", ""),
                "sections": _data.get("sections", []),
                "cta": _data.get("cta", ""),
            }
            build_custom_pdf(_path, _build_dict)
            _save_pdf_sidecar(_path, _build_dict)
            _publish_pdf(_path)
            return True
        except Exception as _ex:
            print(f"[Squeeze] {_kind} failed: {_ex}", flush=True)
            return False

    try:
        _build_one("market_pulse", f"Market_Pulse_{slug}.pdf", "Market Pulse")

        # Bench Snapshot (unchanged  -  uses old format which still works)
        _bs_path = str(_user_pdf_dir() / f"Bench_Snapshot_{slug}.pdf")
        build_bench_snapshot(_bs_path, {
            "role": role, "company": company, "location": location,
            "date": dt, "prepared_by": prep, "logo_path": _get_company_logo_path(), "prepared_email": prep_email,
            "intro": (
                f"Both profiles are actively exploring based on project pipeline "
                f"and growth trajectory. Matched to {company}'s delivery environment."
            ),
            "candidates": [
                {
                    "label": "A", "title": f"Senior {role}",
                    "years_exp": "10+ years experience", "location": location,
                    "availability": "Available 30 days", "comp_target": "Market rate",
                    "highlights": [
                        f"Delivered complex projects in environments similar to {company}'s",
                        "Strong track record across last three projects",
                        "Known for clean documentation and proactive sub management",
                        "References who would rehire without hesitation",
                    ],
                    "best_fit": f"Matches {company}'s project complexity and delivery environment",
                },
                {
                    "label": "B", "title": role,
                    "years_exp": "6+ years experience", "location": location,
                    "availability": "Available 45 days", "comp_target": "Market rate",
                    "highlights": [
                        "Strong CPM schedule management",
                        "High-output career trajectory with increasing project complexity",
                        "Consistent sub relationships that follow them to new firms",
                        "Stable tenure pattern with clear project-driven move history",
                    ],
                    "best_fit": f"High-potential profile for {company}'s current pipeline",
                },
            ],
        })
        _publish_pdf(_bs_path)

        _build_one("scorecard",       f"Role_Scorecard_{slug}.pdf",  "Role Scorecard")
        _build_one("tenure_snapshot", f"Tenure_Snapshot_{slug}.pdf", "Tenure Snapshot")

        ui.notify("Generated 4 PDFs (Market Pulse, Bench, Scorecard, Tenure)", type="positive")
    except Exception as e:
        ui.notify(f"PDF generation error: {str(e)[:80]}", type="warning")


def _sub_vars(txt, v):
    for k, val in v.items():
        txt = txt.replace(f"{{{k}}}", val or f"{{{k}}}")
    return txt


def _sq_launch_summary(s: AppState, rf):
    """Post-launch summary page."""
    _page_decor(variant=3)  # Orbit  -  celebratory, feels like "lift-off"
    r = s.launch_result or {}
    camp_name   = r.get("name", "Campaign")
    count       = r.get("count", 0)
    n_contacts  = r.get("contacts", 0)
    n_steps     = r.get("emails", 0)
    launched_at = r.get("launched_at", "")
    start_str   = r.get("start_date", date.today().isoformat())
    steps       = r.get("steps", [])
    try:
        start_dt = date.fromisoformat(start_str)
    except Exception:
        start_dt = date.today()

    # Step type meta
    SUM_META = {
        ST.EMAIL_AUTO:   ("✉",  C["email_col"], "Email"),
        ST.EMAIL_MANUAL: ("✉",  C["email_col"], "Email"),
        ST.CALL:         ("☎",  C["call_col"],  "Call"),
        ST.LINKEDIN:     ("in", C["indigo"],    "LinkedIn"),
        ST.SMS:          ("msg",C["sms_col"],   "SMS"),
        ST.TASK:         ("✓",  C["task_col"],  "Task"),
    }

    # Build per-type counters for step names
    type_counts: dict = {}
    for st in steps:
        stype = st.get("step_type", ST.EMAIL_AUTO) or ST.EMAIL_AUTO
        _, _, tname = SUM_META.get(stype, ("✉", C["email_col"], "Email"))
        type_counts[tname] = type_counts.get(tname, 0) + 1
        st["_display_name"] = f"{tname} {type_counts[tname]}"

    # ── Success header ─────────────────────────────────────────────────────
    with ui.element("div").style("text-align:center;padding:24px 0 20px;"):
        ui.label("✓").style(f"font-size:52px;color:{C['good']};line-height:1;")
        ui.label("Campaign Launched!").style(
            f"font-size:26px;font-weight:800;color:{C['text_l']};"
            f"font-family:'Nunito',sans-serif;margin-top:8px;display:block;")
        ui.label(f"{camp_name}  -  {count} email{'s' if count!=1 else ''} queued at {launched_at}").style(
            f"font-size:13px;color:{C['muted']};margin-top:4px;display:block;")

    # ── Three cards ─────────────────────────────────────────────────────────
    with ui.element("div").style("display:grid;grid-template-columns:1fr 1fr 1fr;gap:16px;margin-top:20px;"):

        # CARD 1: Contacts
        with ui.element("div").classes("fd-gc"):
            with ui.element("div").style("display:flex;align-items:center;gap:8px;margin-bottom:12px;"):
                ui.label("📋").style("font-size:16px;")
                ui.label(f"{n_contacts} Contact{'s' if n_contacts!=1 else ''}").style(
                    f"font-size:14px;font-weight:700;color:{C['text_l']};font-family:'Nunito',sans-serif;")
            for c in r.get("contact_preview", [])[:8]:
                name = f"{c.get('first_name','')} {c.get('last_name','')}".strip() or c.get("email","")
                company = c.get("company","")
                with ui.element("div").style(
                        f"padding:5px 0;border-bottom:1px solid {C['border']};"):
                    ui.label(name).style(f"font-size:12px;color:{C['text_l']};")
                    if company:
                        ui.label(company).style(f"font-size:10px;color:{C['muted']};")
            if n_contacts > 8:
                ui.label(f"+ {n_contacts-8} more").style(
                    f"font-size:11px;color:{C['muted']};margin-top:6px;display:block;")

        # CARD 2: Steps (type-aware names + icons)
        with ui.element("div").classes("fd-gc"):
            with ui.element("div").style("display:flex;align-items:center;gap:8px;margin-bottom:12px;"):
                ui.label("✉").style(f"font-size:16px;color:{C['email_col']};")
                ui.label(f"{n_steps} Step{'s' if n_steps!=1 else ''}").style(
                    f"font-size:14px;font-weight:700;color:{C['text_l']};font-family:'Nunito',sans-serif;")
            for st in steps:
                stype = st.get("step_type", ST.EMAIL_AUTO) or ST.EMAIL_AUTO
                icon, col, _ = SUM_META.get(stype, ("✉", C["email_col"], "Email"))
                display_name = st.get("_display_name", st.get("name",""))
                subj = (st.get("subject") or st.get("script_notes") or "")[:48]
                with ui.element("div").style(
                        f"display:flex;align-items:flex-start;gap:8px;padding:5px 0;"
                        f"border-bottom:1px solid {C['border']};"):
                    ui.label(icon).style(
                        f"color:{col};font-size:11px;font-weight:700;flex-shrink:0;margin-top:2px;")
                    with ui.element("div").style("flex:1;min-width:0;"):
                        ui.label(display_name).style(
                            f"font-size:12px;font-weight:600;color:{C['text_l']};")
                        if subj:
                            ui.label(subj).style(
                                f"font-size:10px;color:{C['muted']};"
                                f"overflow:hidden;text-overflow:ellipsis;white-space:nowrap;")

        # CARD 3: Schedule
        with ui.element("div").classes("fd-gc"):
            with ui.element("div").style("display:flex;align-items:center;gap:8px;margin-bottom:12px;"):
                ui.label("📅").style("font-size:16px;")
                ui.label("Schedule").style(
                    f"font-size:14px;font-weight:700;color:{C['text_l']};font-family:'Nunito',sans-serif;")
            cum = 0
            for st in steps:
                cum += st.get("delay_days", 0)
                send_date = _add_business_days(start_dt, cum)
                stype = st.get("step_type", ST.EMAIL_AUTO) or ST.EMAIL_AUTO
                _, col, _ = SUM_META.get(stype, ("✉", C["email_col"], "Email"))
                with ui.element("div").style(
                        f"display:flex;align-items:center;gap:6px;padding:5px 0;"
                        f"border-bottom:1px solid {C['border']};"):
                    ui.label(f"Day {cum}").style(
                        f"font-size:11px;font-weight:600;color:{col};width:46px;flex-shrink:0;")
                    ui.label(send_date.strftime("%a %b %d")).style(
                        f"font-size:12px;color:{C['text_l']};flex:1;")
                    ui.label(st.get("time","9:00 AM")).style(
                        f"font-size:11px;color:{C['muted']};text-align:right;flex-shrink:0;")

    # ── Stats bar ──────────────────────────────────────────────────────────
    with ui.element("div").classes("fd-stat-strip").style("margin-top:20px;"):
        for n, l, col in [(count, "Emails Queued", C["teal"]),
                          (n_contacts, "Contacts", C["text_l"]),
                          (n_steps, "Steps", C["email_col"])]:
            with ui.element("div").classes("fd-stat-cell"):
                ui.label(str(n)).classes("fd-sn").style(f"color:{col};")
                ui.label(l).classes("fd-sl")

    # ── Action buttons ─────────────────────────────────────────────────────
    with ui.element("div").style("display:flex;gap:12px;justify-content:center;margin-top:24px;"):
        def _go_queue():
            s.loaded_camp = None; s.loaded_tab = 0; s.launch_result = None
            s._nav_history.clear()
            if s.hub != "sales":
                s.ep = "queue"
            else:
                s.sp = "queue"
            rf()
        def _go_active():
            s.loaded_camp = None; s.loaded_tab = 0; s.launch_result = None
            s._nav_history.clear()
            s.hub = "sales"; s.sp = "active_camps"; rf()
        def _start_new():
            s.loaded_camp = None; s.loaded_tab = 0; s.launch_result = None
            s._nav_history.clear()
            s.loaded_view = "emails"; s.hub = "sales"; s.sp = "start_seq"
            s._tab = ""; s.sq = 1; s.sq_review = False; s.stpl = None
            s.custom_steps = []; s.custom_name = ""; s.custom_preset_picked = False
            s.custom_selected_type = ""; s.custom_editing_idx = -1
            s.svars = {}; s.scon = []
            rf()
        with ui.element("button").classes("fd-gb").style("padding:10px 22px;").on("click", _go_queue):
            ui.label("📤 View Email Queue")
        with ui.element("button").classes("fd-gb").style("padding:10px 22px;").on("click", _go_active):
            ui.label("▶ View Active Campaigns")
        with ui.element("button").classes("fd-pb").style("padding:10px 22px;").on("click", _start_new):
            ui.label("＋ Start Another Campaign")




def _sq_loaded_campaign(s: AppState, rf):
    """Edit a loaded saved/community/custom campaign  -  full email & sequence editors."""
    # Check for summary page first
    if s.loaded_view == "summary" and s.launch_result:
        _sq_launch_summary(s, rf)
        return

    camp = s.loaded_camp
    if not camp:
        return

    # Wizard draft (saved mid-build, no emails yet) → resume the builder
    # instead of opening an empty editor.
    if camp.get("_is_wizard_draft") and not (camp.get("emails") or []):
        s.loaded_camp = None
        if _resume_wizard_draft(s, camp):
            rf()
            return

    # Custom PDF modal  -  rendered as a fixed overlay so the "✨ Create Your
    # Own" button on the Generate PDF row can open it from this editor.
    if getattr(s, '_pdf_custom_stage', 'closed') in ("gallery", "outline"):
        _render_custom_pdf_modal(s, rf)
    camp_name = camp.get("name", "Campaign")
    steps = camp.get("emails", [])
    contacts = camp.get("contacts", [])
    start_str = camp.get("start_date", date.today().isoformat())
    try:
        start_dt = date.fromisoformat(start_str)
    except Exception:
        start_dt = date.today()

    # Strip orphan "_pending:Kind" attachments left over from a prior
    # iteration of the AICB placeholder-PDF system. Those entries are no
    # longer produced — the AICB review screen now blocks Import until
    # PDFs are real files. If a legacy campaign still has them, drop them
    # silently so the editor doesn't render dead ⏳ chips and doesn't
    # spin in a 5-second auto-refresh loop trying to replace them.
    for _st in steps:
        _atts = _st.get("attachments")
        if isinstance(_atts, list) and any(
            isinstance(a, str) and a.startswith("_pending:") for a in _atts
        ):
            _st["attachments"] = [
                a for a in _atts
                if not (isinstance(a, str) and a.startswith("_pending:"))
            ]

    # Ensure steps exist
    if not steps:
        steps = [{"name": "Email 1", "subject": "", "body": "", "delay_days": 0,
                  "time": "9:00 AM", "step_type": ST.EMAIL_AUTO, "attachments": []}]
        camp["emails"] = steps

    # Step definitions
    LOADED_STEPS = [("emails", "Edit Emails"), ("sequence", "Edit Sequence"),
                    ("contacts", "Choose Contacts"), ("launch", "Preview Campaign")]
    cur_step = s.loaded_view if s.loaded_view in [x[0] for x in LOADED_STEPS] else "emails"
    cur_idx = next((i for i, (k, _) in enumerate(LOADED_STEPS) if k == cur_step), 0)

    # Step progress indicator + Next button
    with ui.element("div").style(
            "display:flex;align-items:center;justify-content:space-between;margin-bottom:16px;"):
        # Breadcrumb steps  -  each clickable
        with ui.element("div").style("display:flex;gap:6px;align-items:center;"):
            for i, (key, lbl) in enumerate(LOADED_STEPS):
                ws = "done" if i < cur_idx else ("active" if i == cur_idx else "pending")
                pfx = "✓ " if ws == "done" else f"{i+1}. "
                def _go_step(k=key):
                    s.loaded_view = k; rf()
                with ui.element("div").style(
                        f"cursor:pointer;padding:3px 0;").on("click", _go_step):
                    ui.label(f"{pfx}{lbl}").classes(f"fd-ws {ws}")
                if i < len(LOADED_STEPS) - 1:
                    ui.label("›").style(f"color:{C['border']};font-size:14px;")

        # Next button — "Next: <step name> →" framing so the affordance
        # reads clearly as the forward action while still naming where
        # it takes the user. Mirrored at the bottom of the page by the
        # function-level block at the end of _sq_loaded_campaign.
        if cur_idx < len(LOADED_STEPS) - 1:
            def _next_step():
                s.loaded_view = LOADED_STEPS[cur_idx + 1][0]; rf()
            with ui.element("button").classes("fd-pb").style(
                    "padding:6px 18px;font-size:13px;").on("click", _next_step):
                ui.label(f"Next: {LOADED_STEPS[cur_idx + 1][1]} →")

    # Header
    tpl_name = camp.get("template_name", "Custom")
    tpl_col = C["teal"] if "Full" in tpl_name else (C["indigo"] if "Squeeze" in tpl_name else C["muted"])
    with ui.element("div").style("display:flex;gap:12px;align-items:center;margin-bottom:16px;"):
        ui.label(camp_name).style(f"font-size:18px;font-weight:600;color:{C['text_l']};flex:1;")
        ui.label(tpl_name).classes("fd-tag").style(f"background:{tpl_col}20;color:{tpl_col};font-size:12px;")
        ui.label(f"{len(steps)} emails").style(f"font-size:12px;color:{C['muted']};")
        def _exit_campaign():
            s.loaded_camp = None
            s.loaded_view = "emails"
            s.loaded_tab = 0
            s._tab = ""
            rf()
        with ui.element("button").style(
                f"display:inline-flex;align-items:center;gap:5px;padding:6px 14px;"
                f"border-radius:8px;font-size:12px;font-weight:600;cursor:pointer;"
                f"background:{C['danger']}15;color:{C['danger']};"
                f"border:1px solid {C['danger']}40;font-family:inherit;flex-shrink:0;"
                ).on("click", _exit_campaign):
            ui.label("✕ Exit Campaign")

    if s.loaded_view == "emails":
        # ── FULL EMAIL EDITOR (like p_emails_build) ─────────────────────────
        active = s.loaded_tab
        if active >= len(steps):
            active = max(0, len(steps) - 1)
            s.loaded_tab = active

        # Tab bar
        TAB_META = {
            ST.EMAIL_AUTO:   ("✉",  C["email_col"], "Email"),
            ST.EMAIL_MANUAL: ("✉",  C["email_col"], "Email"),
            ST.CALL:         ("☎",  C["call_col"],  "Call"),
            ST.LINKEDIN:     ("in", C["indigo"],    "LinkedIn"),
            ST.SMS:          ("msg",C["sms_col"],   "SMS"),
            ST.TASK:         ("✓",  C["task_col"],  "Task"),
        }
        # Renumber each step's name based on its type
        type_counters: dict = {}
        for st in steps:
            stype = st.get("step_type", ST.EMAIL_AUTO) or ST.EMAIL_AUTO
            _, _, tname = TAB_META.get(stype, ("✉", C["email_col"], "Email"))
            type_counters[tname] = type_counters.get(tname, 0) + 1
            st["name"] = f"{tname} {type_counters[tname]}"

        with ui.element("div").style("display:flex;align-items:flex-end;gap:0;flex-wrap:wrap;"):
            for i, em in enumerate(steps):
                is_on = i == active
                stype = em.get("step_type", ST.EMAIL_AUTO) or ST.EMAIL_AUTO
                tab_icon, tab_col, _ = TAB_META.get(stype, ("✉", C["email_col"], "Email"))
                tab_name = em.get("name", f"Step {i+1}")

                # Active tab gets step-type color border; inactive stays muted
                extra_style = (f"border-color:{tab_col};color:{tab_col};" if is_on
                               else f"")

                def _select(x=i):
                    # Auto-save current tab's content before switching
                    old = s.loaded_tab
                    if old < len(steps):
                        old_type = steps[old].get("step_type", ST.EMAIL_AUTO)
                        if old_type in (ST.EMAIL_AUTO, ST.EMAIL_MANUAL, ""):
                            if subj_inp is not None:
                                steps[old]["subject"] = subj_inp.value or ""
                            if body_area is not None:
                                steps[old]["body"] = body_area.value or ""
                    s.loaded_tab = x; rf()
                with ui.element("div").classes("fd-etab" + (" on" if is_on else "")).style(
                        extra_style).on("click", _select):
                    ui.html(f'<span style="font-size:11px;margin-right:4px;pointer-events:none;">{tab_icon}</span>'
                            f'<span style="pointer-events:none;">{tab_name}</span>')
                    # Move left/right arrows (only on active tab)
                    if is_on and len(steps) > 1:
                        if i > 0:
                            def _move_left(x=i):
                                steps[x], steps[x-1] = steps[x-1], steps[x]
                                s.loaded_tab = x - 1; rf()
                            with ui.element("span").style(
                                    f"color:{C['muted']};cursor:pointer;font-size:10px;padding:1px 3px;"
                                    f"margin-left:2px;").on("click.stop", _move_left):
                                ui.label("◀")
                        if i < len(steps) - 1:
                            def _move_right(x=i):
                                steps[x], steps[x+1] = steps[x+1], steps[x]
                                s.loaded_tab = x + 1; rf()
                            with ui.element("span").style(
                                    f"color:{C['muted']};cursor:pointer;font-size:10px;padding:1px 3px;"
                                    ).on("click.stop", _move_right):
                                ui.label("▶")
                    if len(steps) > 1:
                        def _del(x=i):
                            steps.pop(x)
                            # Re-renumber remaining steps by type
                            tc: dict = {}
                            for j, st in enumerate(steps):
                                stp = st.get("step_type", ST.EMAIL_AUTO) or ST.EMAIL_AUTO
                                _, _, tn = TAB_META.get(stp, ("✉", C["email_col"], "Email"))
                                tc[tn] = tc.get(tn, 0) + 1
                                st["name"] = f"{tn} {tc[tn]}"
                                st["touch_number"] = j + 1
                            if s.loaded_tab >= len(steps):
                                s.loaded_tab = max(0, len(steps) - 1)
                            rf()
                        with ui.element("span").classes("fd-etab-x").on("click.stop", _del):
                            ui.label("✕")
            # Add email tab (always available alongside the step picker below)
            def _add():
                steps.append({"name": f"Email {sum(1 for st in steps if 'email' in st.get('step_type','')) + 1}",
                               "subject": "", "body": "",
                               "delay_days": 0, "time": "9:00 AM",
                               "step_type": ST.EMAIL_AUTO, "attachments": []})
                s.loaded_tab = len(steps) - 1; rf()
            with ui.element("div").classes("fd-etab-add").on("click", _add):
                ui.label("＋")

        # ── Add Step panel ────────────────────────────────────────────────────
        STEP_OPTIONS = [
            (ST.EMAIL_AUTO,  "✉",  "Email",       C["email_col"]),
            (ST.CALL,        "☎",  "Phone Call",   C["call_col"]),
            (ST.LINKEDIN,    "in", "LinkedIn",     C["indigo"]),
            (ST.SMS,         "msg","SMS",           C["sms_col"]),
            (ST.TASK,        "✓",  "Task",         C["task_col"]),
        ]

        with ui.element("div").style(
                f"border:1px dashed {C['border']};border-radius:10px;padding:12px 16px;"
                f"margin:8px 0 12px;background:{C['surface']};"):
            ui.label("STEP TYPES").style(
                f"font-size:9px;font-weight:700;letter-spacing:.1em;color:{C['muted']};"
                f"text-transform:uppercase;margin-bottom:10px;display:block;")
            with ui.element("div").style("display:flex;gap:10px;flex-wrap:wrap;"):
                for stype, icon, label, col in STEP_OPTIONS:
                    is_sel = s._add_step_type == stype
                    def _pick_type(t=stype):
                        s._add_step_type = "" if s._add_step_type == t else t
                        s._add_step_position = -1
                        rf()
                    with ui.element("button").style(
                            f"display:flex;align-items:center;gap:6px;padding:7px 14px;"
                            f"border-radius:8px;font-size:13px;font-weight:600;cursor:pointer;"
                            f"font-family:'Nunito','DM Sans',sans-serif;"
                            f"border:2px solid {col if is_sel else C['border']};"
                            f"background:{'rgba(0,0,0,.25)' if is_sel else 'transparent'};"
                            f"color:{col};transition:all .15s;").on("click", _pick_type):
                        ui.label(icon).style(f"font-size:12px;")
                        ui.label(label)

            # Position chooser  -  only shown after a type is selected
            if s._add_step_type:
                sel_icon = next((ic for st, ic, _, _ in STEP_OPTIONS if st == s._add_step_type), "✉")
                sel_label = next((lb for st, _, lb, _ in STEP_OPTIONS if st == s._add_step_type), "Step")
                sel_col   = next((co for st, _, _, co in STEP_OPTIONS if st == s._add_step_type), C["muted"])

                ui.element("div").style(f"height:1px;background:{C['border']};margin:12px 0 10px;")
                ui.label(f"Insert {sel_label} after:").style(
                    f"font-size:12px;font-weight:600;color:{C['text']};margin-bottom:8px;display:block;")

                with ui.element("div").style("display:flex;gap:8px;flex-wrap:wrap;align-items:center;"):
                    # "At the beginning" option
                    pos_0 = s._add_step_position == 0
                    def _pos_begin():
                        s._add_step_position = 0; rf()
                    with ui.element("button").style(
                            f"padding:5px 12px;border-radius:99px;font-size:11px;cursor:pointer;"
                            f"font-family:inherit;border:1px solid {sel_col if pos_0 else C['border']};"
                            f"background:{sel_col+'22' if pos_0 else 'transparent'};"
                            f"color:{sel_col if pos_0 else C['muted']};").on("click", _pos_begin):
                        ui.label("⬆ Beginning")

                    for i, em in enumerate(steps):
                        pos_sel = s._add_step_position == i + 1
                        st_icon = STEP_META.get(em.get("step_type", ST.EMAIL_AUTO), ("✉", C["email_col"]))[0]
                        def _pos(n=i + 1):
                            s._add_step_position = n; rf()
                        with ui.element("button").style(
                                f"padding:5px 12px;border-radius:99px;font-size:11px;cursor:pointer;"
                                f"font-family:inherit;border:1px solid {sel_col if pos_sel else C['border']};"
                                f"background:{sel_col+'22' if pos_sel else 'transparent'};"
                                f"color:{sel_col if pos_sel else C['muted']};").on("click", _pos):
                            ui.label(f"{st_icon} After {em.get('name', f'Step {i+1}')}")

                # Confirm button  -  only active once position chosen
                if s._add_step_position >= 0:
                    def _confirm_add_step():
                        stype = s._add_step_type
                        pos   = s._add_step_position  # insert AFTER this index (0 = beginning)
                        n     = len(steps) + 1
                        ch_map = {ST.EMAIL_AUTO: "email", ST.EMAIL_MANUAL: "email",
                                  ST.CALL: "call", ST.LINKEDIN: "li",
                                  ST.SMS: "sms", ST.TASK: "task"}
                        new_step = dict(
                            name=f"Step {n}", subject="", body="",
                            step_type=stype, delay_days=1, time="9:00 AM",
                            attachments=[], tags=[], script_notes="",
                            touch_number=0, channel=ch_map.get(stype, "email"),
                        )
                        # LinkedIn placement guardrails (soft warnings, not hard blocks).
                        # Per 2026-05-10 directive: each sequence should have exactly
                        # one LI step at position 2. The wizard lets users override,
                        # but warns first so the convention is visible.
                        if stype == ST.LINKEDIN:
                            existing_emails = sum(1 for st in steps if st.get("step_type") in (ST.EMAIL_AUTO, ST.EMAIL_MANUAL))
                            existing_li = sum(1 for st in steps if st.get("step_type") == ST.LINKEDIN)
                            if existing_li >= 1:
                                ui.notify(
                                    "You already have a LinkedIn touch in this sequence. "
                                    "Adding a second one may dilute response. Continuing "
                                    "anyway — remove it later if you change your mind.",
                                    type="warning", timeout=6000,
                                )
                            # If user is inserting LI at position 0 (Beginning) AND has
                            # at least one email already, warn that LI before email 1
                            # rarely lands well.
                            if pos == 0 and existing_emails >= 1:
                                ui.notify(
                                    "Heads up — placing a LinkedIn touch BEFORE your "
                                    "first email is unusual. Cold LI connects without "
                                    "context typically convert worse than after email 1.",
                                    type="warning", timeout=6000,
                                )
                        insert_idx = pos  # 0 = insert at start, N = insert after index N-1
                        steps.insert(insert_idx, new_step)
                        # Renumber
                        for j, st in enumerate(steps):
                            is_email = st.get("step_type", "") in (ST.EMAIL_AUTO, ST.EMAIL_MANUAL, "")
                            prefix = "Email" if is_email else next(
                                (lb for stt, _, lb, _ in STEP_OPTIONS if stt == st.get("step_type")), "Step")
                            st["name"] = f"{prefix} {j+1}"
                            st["touch_number"] = j + 1
                        s._add_step_type = ""
                        s._add_step_position = -1
                        s.loaded_tab = insert_idx
                        rf()

                    ui.element("div").style("margin-top:10px;")
                    with ui.element("button").classes("fd-pb").style(
                            f"padding:8px 22px;font-size:13px;background:{sel_col};color:#0D1520;"
                            ).on("click", _confirm_add_step):
                        ui.label(f"+ Add {sel_label} Step")

        # Editor area
        em = steps[active]
        step_type = em.get("step_type", ST.EMAIL_AUTO)
        is_email_step = step_type in (ST.EMAIL_AUTO, ST.EMAIL_MANUAL, "")
        step_icon, step_col = STEP_META.get(step_type, ("✉", C["email_col"]))
        step_label_map = {ST.CALL: "Phone Call", ST.LINKEDIN: "LinkedIn",
                          ST.SMS: "SMS Message", ST.TASK: "Task"}
        step_display = step_label_map.get(step_type, "Email")

        # Auto-name based on type + position
        if is_email_step:
            em["name"] = f"Email {active + 1}"
        else:
            em["name"] = f"{step_display} {active + 1}"

        with ui.element("div").classes("fd-editor-area"):
            # Step header row with type badge + delay + time
            with ui.element("div").style("display:flex;gap:16px;margin-bottom:16px;align-items:flex-end;"):
                with ui.element("div").style("flex:1;display:flex;align-items:center;gap:10px;padding-bottom:6px;"):
                    ui.label(step_icon).style(f"font-size:18px;color:{step_col};")
                    ui.label(em["name"]).style(f"font-size:16px;font-weight:600;color:{C['text_l']};")
                    if not is_email_step:
                        ui.label(step_display).style(
                            f"font-size:10px;font-weight:700;padding:2px 8px;border-radius:99px;"
                            f"background:{step_col}22;color:{step_col};text-transform:uppercase;letter-spacing:.05em;")
                with ui.element("div").style("width:120px;"):
                    ui.label("Days after prev").classes("fd-fl")
                    def _save_delay(e, idx=active):
                        try:
                            steps[idx]["delay_days"] = int(e.value) if e.value is not None else 0
                        except (ValueError, TypeError):
                            steps[idx]["delay_days"] = 0
                    delay_inp = ui.number(value=em.get("delay_days", 0), min=0, max=365, step=1,
                                          on_change=_save_delay).style(
                        f"width:100%;background:{C['surface']};border:1px solid {C['border']};"
                        f"border-radius:6px;color:{C['text_l']};")
                with ui.element("div").style("width:120px;"):
                    ui.label("Send Time").classes("fd-fl")
                    def _save_time(e, idx=active):
                        steps[idx]["time"] = e.value or "9:00 AM"
                    time_inp = ui.select(options=TIME_OPTIONS, value=em.get("time", "9:00 AM"),
                                         on_change=_save_time).style("width:100%;")

            subj_inp = None
            body_area = None

            if is_email_step:
                # Subject
                ui.label("Subject").classes("fd-fl")
                subj_inp = ui.input(value=em.get("subject", ""),
                                    placeholder="Enter subject  -  use {FirstName}, {Company} for merge fields"
                                    ).classes("fd-input").style("margin-bottom:12px;")

            # Merge-field insert buttons — single row, inserts wherever the
            # user last had their cursor (subject input OR body editor). The
            # ddInsert JS helper handles the routing.
            _var_btn = (f"font-size:10px;padding:2px 8px;border-radius:99px;"
                        f"background:{C['teal_dim']};color:{C['teal']};border:1px solid {C['teal']};"
                        f"cursor:pointer;font-family:inherit;user-select:none;")

            # Single merge-field insert row — positioned above the body
            # editor. Inserts into whichever field the user last had their
            # cursor in (subject or body).
            if is_email_step:
                with ui.element("div").style("display:flex;gap:6px;margin-bottom:10px;flex-wrap:wrap;align-items:center;"):
                    ui.label("Insert variable:").style(f"font-size:11px;color:{C['muted']};padding-top:4px;")
                    for var in ["{FirstName}", "{LastName}", "{Company}", "{JobTitle}"]:
                        def _ins_var(v=var):
                            ui.run_javascript(f'ddInsert("{v}")')
                        with ui.element("button").style(_var_btn).on("click", _ins_var):
                            ui.label(var)

            # Body  -  rich text editor (strip existing signature from old campaigns)
            ui.label("Email Body").classes("fd-fl")
            body_val = _strip_signature_from_body(em.get("body", ""))
            if body_val and "<" not in body_val:
                body_val = body_val.replace("\n", "<br>")
            body_area = _apply_editor_props(ui.editor(value=body_val), _TOOLBAR_FULL).style("min-height:500px;border-radius:6px;")
            s._register_qeditor(body_area, f"loaded_camp_body_{active}")

            # Attachments display (clickable PDFs)
            # RULE: Never allow attachments on the first email  -  causes spam/blocking
            if active == 0 and em.get("attachments"):
                em["attachments"] = []  # silently strip
            step_atts = em.get("attachments", [])
            if active == 0:
                with ui.element("div").style(
                        f"margin-top:16px;padding:10px 14px;background:{C['warn']}10;"
                        f"border:1px solid {C['warn']}30;border-radius:8px;"
                        f"display:flex;align-items:center;gap:8px;"):
                    ui.label("⚠").style("font-size:14px;")
                    ui.label("Attachments cannot be added to the first email  -  they trigger spam filters and get blocked.").style(
                        f"font-size:12px;color:{C['warn']};")
                # Check for links in first email body
                _body_check = (em.get("body") or "").lower()
                _has_links = ("href=" in _body_check or "http://" in _body_check
                              or "https://" in _body_check or "bit.ly" in _body_check
                              or "bitly" in _body_check)
                if _has_links:
                    with ui.element("div").style(
                            f"margin-top:8px;padding:10px 14px;background:{C['danger']}10;"
                            f"border:1px solid {C['danger']}30;border-radius:8px;"
                            f"display:flex;align-items:center;gap:8px;"):
                        ui.label("⚠").style("font-size:14px;")
                        ui.label("Links in your first email are a major spam signal. Shortened URLs (Bitly, etc.) are even worse. Save links for follow-ups after you've gotten a reply.").style(
                            f"font-size:12px;color:{C['danger']};")
            elif step_atts or (is_email_step and active > 0):
                with ui.element("div").style(
                        f"margin-top:16px;padding:14px 18px;background:{C['surface']};"
                        f"border:1px solid {C['email_col']}30;border-radius:10px;"):
                    ui.label("📎 Attachments  -  sent with this email").style(
                        f"font-size:12px;font-weight:600;color:{C['email_col']};margin-bottom:8px;"
                        f"font-family:'Nunito',sans-serif;")
                    if step_atts:
                        with ui.element("div").style("display:flex;gap:8px;flex-wrap:wrap;margin-bottom:8px;"):
                            for ai_att, att in enumerate(step_atts):
                                # Pending PDF placeholder — show ⏳ + label
                                # while the background PDF generation runs.
                                # No remove × (it'll be replaced by the
                                # actual filename when generation finishes).
                                if isinstance(att, str) and att.startswith("_pending:"):
                                    _pdf_label = att.split(":", 1)[1] or "PDF"
                                    with ui.element("div").style(
                                            f"display:inline-flex;align-items:center;gap:6px;padding:8px 14px;"
                                            f"background:{C['warn']}10;border:1px dashed {C['warn']}55;"
                                            f"border-radius:8px;"):
                                        ui.label("⏳").style("font-size:14px;")
                                        ui.label(f"Generating {_pdf_label}…").style(
                                            f"font-size:12px;font-weight:500;color:{C['warn']};font-style:italic;")
                                    continue
                                pdf_exists = (_user_pdf_dir() / att).is_file()
                                # Missing-file state: file is referenced by
                                # the campaign step but doesn't exist on
                                # disk (PDF generation likely failed silently
                                # mid-run, or the file was deleted). Used to
                                # render as a faded grey box with no link,
                                # which looked identical to a normal
                                # attachment — users had no idea why clicking
                                # did nothing. Now: red border + ⚠ label +
                                # inline Regenerate button so the broken
                                # state is unmistakable and one-click fixable.
                                if pdf_exists:
                                    # Wrap chip + editor body in a block
                                    # container so the editor (when open)
                                    # drops below the chip on its own row,
                                    # taking full width of the flex parent.
                                    # Toggle button is INSIDE the inline-flex
                                    # chip; body is a sibling block element.
                                    with ui.element("div").style("flex-basis:100%;"):
                                        with ui.element("div").style(
                                                f"display:inline-flex;align-items:center;gap:6px;padding:8px 14px;"
                                                f"background:{C['card']};border:1px solid {C['email_col']}30;"
                                                f"border-radius:8px;"):
                                            with ui.link(target=f"/pdfs/{att}", new_tab=True).style("text-decoration:none;display:flex;align-items:center;gap:6px;"):
                                                ui.label("📄").style("font-size:16px;")
                                                ui.label(att).style(f"font-size:12px;font-weight:500;color:{C['email_col']};")
                                            # Remove attachment button
                                            def _rm_att_ok(a=att, idx=active):
                                                steps[idx]["attachments"] = [x for x in steps[idx].get("attachments", []) if x != a]
                                                rf()
                                            with ui.element("span").style(
                                                    f"color:{C['danger']};cursor:pointer;font-size:12px;padding:2px 4px;"
                                                    f"margin-left:4px;").on("click", _rm_att_ok):
                                                ui.label("✕")
                                            # Toggle button — sits in the chip
                                            _render_pdf_editor_toggle(s, rf, att, active)
                                        # Body — sibling of the chip, drops
                                        # full-width below when toggle is open.
                                        # Pass a lambda that defers to
                                        # _gen_pdf_inline so the editor's
                                        # no-sidecar branch can offer
                                        # one-click Regenerate inline. The
                                        # lambda is late-bound — the
                                        # function exists by click time.
                                        _regen_fn = None
                                        if (is_email_step and active > 0
                                                and ANTHROPIC_API_KEY):
                                            _regen_fn = lambda pid, plabel, idx: _gen_pdf_inline(pid, plabel, idx)
                                        _render_pdf_editor_body(s, rf, att, active,
                                                                regenerate_fn=_regen_fn)
                                else:
                                    # Map the saved filename's "<Type>_..." prefix
                                    # back to the PDF type id so Regenerate
                                    # knows which generator to call.
                                    _att_lower = att.lower()
                                    _re_pid, _re_plabel = ("", "")
                                    for _pid_x, _plabel_x in [
                                        ("market_pulse",    "Market Pulse"),
                                        ("scorecard",       "Role Scorecard"),
                                        ("salary_guide",    "Salary Guide"),
                                        ("interview_guide", "Interview Guide"),
                                        ("tenure_snapshot", "Tenure Snapshot"),
                                    ]:
                                        if _att_lower.startswith(_plabel_x.lower().replace(" ", "_") + "_"):
                                            _re_pid, _re_plabel = _pid_x, _plabel_x
                                            break
                                    with ui.element("div").style(
                                            f"display:inline-flex;align-items:center;gap:8px;padding:8px 14px;"
                                            f"background:{C['danger']}10;border:1px solid {C['danger']}80;"
                                            f"border-left:3px solid {C['danger']};border-radius:8px;"):
                                        ui.label("⚠").style(f"font-size:14px;color:{C['danger']};font-weight:700;")
                                        with ui.element("div").style("display:flex;flex-direction:column;gap:1px;"):
                                            ui.label(att).style(
                                                f"font-size:12px;font-weight:600;color:{C['danger']};")
                                            ui.label("File missing on server — generation didn't finish.").style(
                                                f"font-size:10px;color:{C['danger']};opacity:0.85;")
                                        # Regenerate button only renders when
                                        # _gen_pdf_inline will exist in scope
                                        # at click time — same gate as its
                                        # definition further below (email step,
                                        # not the first email, API key set).
                                        if (_re_pid and ANTHROPIC_API_KEY
                                                and is_email_step and active > 0):
                                            def _do_regen(pid=_re_pid, plabel=_re_plabel,
                                                          old_att=att, idx=active):
                                                # Drop the broken attachment ref;
                                                # _gen_pdf_inline will append the
                                                # freshly-generated filename.
                                                steps[idx]["attachments"] = [
                                                    x for x in steps[idx].get("attachments", [])
                                                    if x != old_att
                                                ]
                                                _gen_pdf_inline(pid, plabel, idx)
                                            with ui.element("button").style(
                                                    f"background:{C['teal']};color:{C['bg']};"
                                                    f"border:none;border-radius:6px;padding:4px 10px;"
                                                    f"font-size:11px;font-weight:700;cursor:pointer;"
                                                    f"font-family:inherit;margin-left:4px;"
                                                    ).on("click", _do_regen):
                                                ui.label(f"↻ Regenerate")
                                        # Remove attachment button (always available)
                                        def _rm_att_missing(a=att, idx=active):
                                            steps[idx]["attachments"] = [x for x in steps[idx].get("attachments", []) if x != a]
                                            rf()
                                        with ui.element("span").style(
                                                f"color:{C['danger']};cursor:pointer;font-size:12px;padding:2px 4px;"
                                                f"margin-left:4px;").on("click", _rm_att_missing):
                                            ui.label("✕")
                    # Add attachment  -  primary: upload any file from the user's
                    # computer (PDF/Word/Excel/images/etc). Secondary: pick from
                    # PDFs we've already generated for this campaign.
                    async def _handle_upload(e, idx=active):
                        # NiceGUI's UploadEventArguments exposes the file
                        # via e.file (a SpooledTemporaryFile-like wrapper
                        # whose .read() is async). The older `.content`
                        # attribute pattern doesn't exist in this version
                        # — see _on_attach in the Build-from-scratch flow
                        # for the canonical working pattern.
                        print(f"[Attach] _handle_upload fired for step {idx}", flush=True)
                        try:
                            raw_name = e.file.name if hasattr(e.file, 'name') else "attachment"
                        except Exception:
                            raw_name = "attachment"
                        try:
                            content = await e.file.read()
                        except Exception as ex:
                            print(f"[Attach] read error for {raw_name}: {ex}", flush=True)
                            try:
                                ui.notify(f"Upload failed: {ex}", type="negative", timeout=6000)
                            except Exception:
                                pass
                            return
                        if not content:
                            try:
                                ui.notify(f"{raw_name}: empty file", type="warning")
                            except Exception:
                                pass
                            return
                        if len(content) > _MAX_ATTACHMENT_BYTES:
                            try:
                                ui.notify(f"{raw_name}: file too large (25MB max)",
                                          type="negative")
                            except Exception:
                                pass
                            return
                        dest = _safe_attachment_path(
                            raw_name, _user_pdf_dir(),
                            _ALLOWED_ATTACHMENT_EXTS,
                            fallback="attachment",
                        )
                        if dest is None:
                            try:
                                ui.notify(
                                    f"{raw_name}: file type not allowed (use PDF, "
                                    f"Word, Excel, PowerPoint, text, CSV, or images)",
                                    type="negative", timeout=6000,
                                )
                            except Exception:
                                pass
                            return
                        try:
                            dest.write_bytes(content)
                        except Exception as ex:
                            print(f"[Attach] write_bytes failed: {ex}", flush=True)
                            try:
                                ui.notify(f"Save failed: {ex}", type="negative")
                            except Exception:
                                pass
                            return
                        fname = dest.name
                        steps[idx].setdefault("attachments", []).append(fname)
                        # Persist to disk so the attachment survives any
                        # re-render path that re-reads s.loaded_camp.
                        try:
                            save_campaign(camp)
                        except Exception as ex:
                            print(f"[Attach] save_campaign failed: {ex}", flush=True)
                        print(f"[Attach] Uploaded {fname} "
                              f"({len(content)} bytes) to step {idx}", flush=True)
                        try:
                            ui.notify(f"✓ Attached: {fname}",
                                      type="positive", timeout=4000)
                        except Exception:
                            pass
                        rf()

                    # ── Add Attachment — clean button row ──
                    # Hide the raw ui.upload (its Quasar default rendering is
                    # essentially invisible against the dark theme — users
                    # didn't see it as a button). Trigger pickFiles() from a
                    # styled button instead. Same pattern as Bulk Import.
                    with ui.element("div").style("height:0;overflow:hidden;"):
                        _att_uploader = ui.upload(
                            on_upload=_handle_upload,
                            auto_upload=True,
                            max_files=5,
                        ).props('accept=".pdf,.doc,.docx,.xls,.xlsx,.ppt,.pptx,.txt,.csv,.rtf,.odt,.png,.jpg,.jpeg,.gif,.webp,application/pdf,application/msword,application/vnd.openxmlformats-officedocument.wordprocessingml.document,application/vnd.ms-excel,application/vnd.openxmlformats-officedocument.spreadsheetml.sheet,application/vnd.ms-powerpoint,application/vnd.openxmlformats-officedocument.presentationml.presentation,text/plain,text/csv,application/rtf,image/*"')

                    # Visible action row: Add Attachment + reuse-existing dropdown
                    available_pdfs = sorted(_user_pdf_dir().glob("*.pdf")) if _user_pdf_dir().exists() else []
                    # Redacted résumés get their own picker (below) on candidate
                    # emails, so keep them out of the generic dropdown — no file
                    # should be offered in two places at once.
                    _reusable_pdfs = [p for p in available_pdfs
                                      if p.name not in step_atts
                                      and not _is_redacted_resume_pdf(p.name)]

                    with ui.element("div").style(
                            "display:flex;gap:10px;align-items:center;"
                            "flex-wrap:wrap;margin-top:4px;"):
                        with ui.element("button").classes("fd-pb").style(
                                "padding:7px 18px;font-size:12px;"
                                "border-radius:99px;cursor:pointer;"
                                ).on("click", lambda u=_att_uploader: u.run_method("pickFiles")):
                            ui.label("＋ Upload Attachment").style("pointer-events:none;")
                        ui.label("PDF · Word · Excel · PowerPoint · images · 25MB max").style(
                            f"font-size:11px;color:{C['muted']};")

                    # Secondary: pick from already-generated PDFs (collapsed by default)
                    if _reusable_pdfs:
                        _att_options = {"": f"Or reuse a generated PDF ({len(_reusable_pdfs)} available)...",
                                        **{p.name: p.name for p in _reusable_pdfs}}
                        def _add_att(e, idx=active):
                            if e.value:
                                steps[idx].setdefault("attachments", []).append(e.value)
                                rf()
                        ui.select(options=_att_options, value="", on_change=_add_att).style(
                            "width:100%;font-size:12px;margin-top:8px;")

                    # Candidate Résumés — only on candidate emails (the email
                    # actually features candidate profiles). Lists the redacted
                    # résumés in the user's PDF folder not yet attached to this
                    # step, each with View (preview in a new tab) + Attach. Never
                    # auto-attached. See spec 2026-06-22-candidate-resume-picker.
                    _resume_files = [p for p in available_pdfs
                                     if _is_redacted_resume_pdf(p.name)
                                     and p.name not in step_atts]
                    if _resume_files and _step_features_candidates(steps[active]):
                        ui.label("Candidate résumés").style(
                            f"font-size:11px;font-weight:700;color:{C['muted']};"
                            f"margin-top:12px;text-transform:uppercase;"
                            f"letter-spacing:0.5px;")
                        for _rp in _resume_files:
                            with ui.element("div").style(
                                    "display:flex;align-items:center;gap:10px;"
                                    f"padding:7px 12px;margin-top:6px;"
                                    f"background:{C['card']};"
                                    f"border:1px solid {C['email_col']}30;"
                                    "border-radius:8px;"):
                                ui.label("📄").style("font-size:15px;")
                                ui.label(_redacted_resume_label(_rp.name)).style(
                                    f"font-size:12px;font-weight:500;"
                                    f"color:{C['email_col']};flex:1;")
                                with ui.link(target=f"/pdfs/{_rp.name}",
                                             new_tab=True).style(
                                        "text-decoration:none;font-size:11px;"
                                        f"color:{C['muted']};white-space:nowrap;"):
                                    ui.label("👁 View")
                                def _attach_resume(name=_rp.name, idx=active):
                                    steps[idx].setdefault(
                                        "attachments", []).append(name)
                                    try:
                                        save_campaign(camp)
                                    except Exception as _ex:
                                        print(f"[Attach] save_campaign failed: {_ex}",
                                              flush=True)
                                    rf()
                                with ui.element("button").style(
                                        f"background:{C['email_col']};color:{C['bg']};"
                                        "border:none;border-radius:6px;padding:4px 12px;"
                                        "font-size:11px;font-weight:700;cursor:pointer;"
                                        "font-family:inherit;white-space:nowrap;"
                                        ).on("click", _attach_resume):
                                    ui.label("＋ Attach")

            # Generate PDF buttons (not on first email)  -  inline generation + auto-attach
            if is_email_step and active > 0 and ANTHROPIC_API_KEY:
                _pdf_types_inline2 = [
                    ("market_pulse",    "Market Pulse",    "📊", C["teal"]),
                    ("scorecard",       "Role Scorecard",  "📋", C["email_col"]),
                    ("salary_guide",    "Salary Guide",    "💰", C["warn"]),
                    ("interview_guide", "Interview Guide", "🎯", C["good"]),
                    ("tenure_snapshot", "Tenure Snapshot", "📈", C["indigo"]),
                ]
                # Generating state
                if not hasattr(s, '_pdf_generating'):
                    s._pdf_generating = ""

                def _gen_pdf_inline(pid, plabel, step_idx):
                    """Generate a single PDF type using campaign context, attach it to the step."""
                    # Toast BEFORE the rerender — rf() destroys the click's
                    # parent slot, so any ui.notify() after it raises
                    # RuntimeError("parent slot deleted"), which kills the
                    # websocket and shows 'Reconnecting to DripDrop...' on
                    # the user's screen. Wrapped defensively in case the
                    # context was already torn down.
                    try:
                        ui.notify(f"Generating {plabel}...", type="info", timeout=3000)
                    except Exception:
                        pass
                    s._pdf_generating = pid; rf()
                    def _run():
                        # Background-thread safety: rebind the user-email
                        # ContextVar so load_config(), _user_pdf_dir(),
                        # _get_company_name(), and _get_company_logo_path()
                        # all resolve to THIS user's per-user data instead
                        # of falling back to the legacy global config (which
                        # is empty → "Your Company" / wrong PDF folder).
                        # Same fix as _aicb_generate_pdfs.
                        try:
                            if getattr(s, "_user_email", ""):
                                _CURRENT_USER_EMAIL.set(s._user_email)
                        except Exception as _ex:
                            print(f"[PDF inline] ContextVar rebind failed: {_ex}", flush=True)
                        try:
                            import sys as _sys, importlib
                            _sys.path.insert(0, str(Path(__file__).resolve().parent / "funnel_forge"))
                            import arena_pdfs as _ap; importlib.reload(_ap)
                            from arena_pdfs import build_custom_pdf
                            import anthropic
                            client = anthropic.Anthropic(api_key=ANTHROPIC_API_KEY)

                            # Extract campaign context — Company / Primary /
                            # Secondary / Positions come straight from the
                            # campaign variables the user typed in the wizard.
                            v = camp.get("variables", {})
                            company, roles_str, location_str, _np = _pdf_campaign_subject(camp)
                            _ns = list(v.get("SecondaryIndustries", []) or [])
                            # Fallback to legacy Vertical text if Primary not set
                            if not _np:
                                _np = (v.get("Vertical", "")
                                       or load_config().get("company_industry", "")
                                       or "")
                            _exp_level = v.get("ExpLevel", "") or ""
                            dt = date.today().strftime("%B %d, %Y")
                            _cfg = load_config()
                            prep = _cfg.get("sig_name", _get_company_name()) or _get_company_name()
                            prep_email = _cfg.get("sig_email", "")
                            slug = re.sub(r'[^\w\s-]', '', company).strip().replace(' ', '_')[:40] or "Campaign"

                            # Generate rich content via the same pipeline as
                            # the form-flow page so all 6 types produce
                            # full-page PDFs (no strait-jacket).
                            _ctx_dict = {
                                "company": company,
                                "primary_industry": _np,
                                "secondary_industries": _ns,
                                "positions": roles_str,
                                "location": location_str,
                                "exp_level": _exp_level,
                            }
                            data = _generate_rich_pdf_data(
                                client, pid, _ctx_dict,
                                research_context="",
                                style_guide=_style_guide_prompt(),
                            )

                            # Build the PDF
                            pdf_name = f"{plabel.replace(' ', '_')}_{slug}.pdf"
                            pdf_path = str(_user_pdf_dir() / pdf_name)
                            _user_pdf_dir().mkdir(parents=True, exist_ok=True)

                            _inline_build_dict = {
                                "title": data.get("title") or f"{plabel} - {company}",
                                "badge": data.get("badge") or plabel.upper(),
                                "date": dt,
                                "prepared_by": prep,
                                "prepared_email": prep_email,
                                "logo_path": _get_company_logo_path(),
                                "intro": data.get("intro", ""),
                                "sections": data.get("sections", []),
                                "cta": data.get("cta", ""),
                            }
                            build_custom_pdf(pdf_path, _inline_build_dict)
                            _save_pdf_sidecar(pdf_path, _inline_build_dict)

                            _publish_pdf(pdf_path)
                            # Auto-attach to the current step
                            atts = steps[step_idx].setdefault("attachments", [])
                            if pdf_name not in atts:
                                atts.append(pdf_name)
                            print(f"[PDF] Generated and attached {pdf_name}")
                        except Exception as e:
                            print(f"[PDF] Inline generation error: {e}")
                            _log_exception(e, context="pdf.inline_generation")
                        finally:
                            s._pdf_generating = ""
                    _run_as_user(getattr(s, "_user_email", "") or "", _run, name="pdf_inline_gen_worker")
                    # (The pre-rerender toast above is the user-facing
                    # feedback. The spinner block below also renders
                    # "Generating ..." once rf() rebuilds the page.)

                if s._pdf_generating:
                    with ui.element("div").style("display:flex;align-items:center;gap:8px;margin-top:12px;"):
                        ui.spinner("dots", size="16px", color=C["teal"])
                        _gen_label = next((l for p, l, *_ in _pdf_types_inline2 if p == s._pdf_generating), "PDF")
                        ui.label(f"Generating {_gen_label}...").style(f"font-size:12px;color:{C['warn']};")
                        ui.timer(3.0, rf, once=True)
                else:
                    with ui.element("div").style("display:flex;align-items:center;gap:6px;flex-wrap:wrap;margin-top:12px;"):
                        ui.label("Generate PDF:").style(f"font-size:11px;color:{C['muted']};")
                        for _pid, _plabel, _picon, _pcol in _pdf_types_inline2:
                            def _click_gen(pid=_pid, plabel=_plabel, idx=active):
                                _gen_pdf_inline(pid, plabel, idx)
                            with ui.element("button").style(
                                    f"font-size:10px;padding:4px 10px;border-radius:6px;"
                                    f"background:{_pcol}15;color:{_pcol};border:1px solid {_pcol}40;"
                                    f"cursor:pointer;font-family:inherit;display:inline-flex;"
                                    f"align-items:center;gap:3px;").on("click", _click_gen):
                                ui.label(f"{_picon} {_plabel}")
                        # ✨ Create Your Own  -  opens the gallery of 15+ custom
                        # PDF ideas. Generated files auto-attach to this step
                        # via s._pdf_custom_attach_step_idx.
                        def _open_custom_pdf(idx=active):
                            s._pdf_custom_stage = "gallery"
                            s._pdf_custom_prompt = ""
                            s._pdf_custom_outline = None
                            s._pdf_custom_previewing = False
                            # Remember which step to auto-attach the result to
                            s._pdf_custom_attach_step_idx = idx
                            # Pre-populate company context so AI has something to work with
                            v = camp.get("variables", {})
                            _pc, _pr, _pl, _pi = _pdf_campaign_subject(camp)
                            s._pdf_company = _pc
                            s._pdf_role = _pr
                            s._pdf_location = _pl
                            s._pdf_industry = _pi
                            s._pdf_exp_level = v.get("ExpLevel", "") or ""
                            rf()
                        with ui.element("button").style(
                                f"font-size:10px;padding:4px 10px;border-radius:6px;"
                                f"background:linear-gradient(135deg,{C['indigo']}20,{C['indigo']}40);"
                                f"color:{C['indigo']};border:1px solid {C['indigo']}60;"
                                f"cursor:pointer;font-family:inherit;display:inline-flex;"
                                f"align-items:center;gap:3px;font-weight:700;"
                                ).on("click", _open_custom_pdf):
                            ui.label("✨ Create Your Own (15+)")

            # Signature preview
            sig_text = ""
            if _user_sig_path().exists():
                try:
                    sig_text = _user_sig_path().read_text(encoding="utf-8").strip()
                except Exception:
                    pass
            def _go_sig():
                if s.hub == "sales": s.sp = "signature"
                else: s.ep = "e_signature"
                rf()
            with ui.element("div").style(
                    f"margin-top:16px;padding:14px 18px;background:{C['surface']};"
                    f"border:1px solid {C['border']};border-radius:10px;cursor:pointer;"
                    f"transition:border-color .15s;").on("click", _go_sig):
                with ui.element("div").style("display:flex;align-items:center;justify-content:space-between;margin-bottom:8px;"):
                    ui.label("✉ Signature  -  auto-appended to every email").style(
                        f"font-size:12px;font-weight:600;color:{C['muted']};font-family:'Nunito',sans-serif;")
                    ui.label("✎ Edit Signature →").style(
                        f"font-size:11px;color:{C['teal']};font-weight:500;flex-shrink:0;")
                if sig_text:
                    sig_html = sig_text.replace("\n", "<br>")
                    ui.html(f'<div style="font-size:12px;color:{C["muted"]};line-height:1.6;opacity:.6;'
                            f'border-top:1px solid {C["border"]};padding-top:8px;">'
                            f'{sig_html}</div>')
                else:
                    ui.label("No signature set  -  click here to add one.").style(
                        f"font-size:12px;color:{C['warn']};font-style:italic;")

            script_area = None
            if not is_email_step:
                # Non-email step  -  show script/notes editor
                script_label = {ST.CALL: "Call Script", ST.LINKEDIN: "LinkedIn Message / Notes",
                                ST.SMS: "SMS Message", ST.TASK: "Task Instructions"}.get(step_type, "Notes")
                ui.label(script_label).classes("fd-fl")
                script_area = ui.textarea(
                    value=em.get("script_notes", em.get("body", "")),
                    placeholder=f"Write your {script_label.lower()} here. Use {{FirstName}}, {{Company}} for merge fields."
                ).style(
                    f"width:100%;min-height:220px;background:{C['surface']};border:1px solid {C['border']};"
                    f"border-radius:6px;padding:12px;font-size:13px;color:{C['text_l']};"
                    f"font-family:'DM Sans','Segoe UI',sans-serif;line-height:1.7;resize:none;")

            # Save + Preview buttons (save works for both email and non-email)
            def _save_email(idx=active, di=delay_inp, ti=time_inp):
                steps[idx]["delay_days"] = int(di.value) if di.value is not None else 0
                steps[idx]["time"] = ti.value or "9:00 AM"
                if is_email_step and subj_inp and body_area:
                    steps[idx]["subject"] = subj_inp.value or ""
                    steps[idx]["body"] = body_area.value or ""
                elif not is_email_step:
                    steps[idx]["script_notes"] = script_area.value or ""
                ui.notify("✓ Saved", type="positive", timeout=1500)

            def _preview_email(idx=active):
                if not is_email_step or subj_inp is None or body_area is None:
                    ui.notify("Preview only available for email steps.", type="warning")
                    return
                steps[idx]["subject"] = subj_inp.value or ""
                steps[idx]["body"] = body_area.value or ""
                subj = subj_inp.value or "(no subject)"
                body_html = body_area.value or ""
                # Merge variables using the user's own identity — previews
                # go to the user, so they read "Hi <you>," instead of
                # leaking the first contact in the list.
                _pc = _preview_self_contact(s)
                for _k, _v in [("{FirstName}", _pc.get("first_name","[FirstName]")), ("{LastName}", _pc.get("last_name","[LastName]")),
                               ("{Company}", _pc.get("company","[Company]")), ("{CompanyName}", _pc.get("company","[Company]")), ("{JobTitle}", _pc.get("title","[JobTitle]"))]:
                    subj = subj.replace(_k, _v)
                    body_html = body_html.replace(_k, _v)
                # Get recipient (sender's own email for preview)
                cfg = load_config()
                to_addr = cfg.get("smtp_email", "") or getattr(s, '_user_email', '')
                if not to_addr:
                    ui.notify("Set up your email in Email & AI Setup first", type="warning")
                    return
                atts = [str(_user_pdf_dir() / a) if not os.path.isabs(a) else a for a in steps[idx].get("attachments", [])]
                ui.notify("Sending preview…", type="info")
                _for_user = getattr(s, '_user_email', '')
                def _send():
                    ok, err = _send_email_universal(
                        to=to_addr, subject=subj, html_body=body_html,
                        attachments=atts, is_preview=True,
                        _for_user_email=_for_user,
                    )
                    if not ok:
                        print(f"[Preview] Failed: {err}")
                threading.Thread(target=_send, daemon=True).start()

            with ui.element("div").style("display:flex;gap:12px;justify-content:flex-end;margin-top:12px;align-items:center;"):
                with ui.element("button").classes("fd-gb").style("padding:8px 20px;").on("click", _save_email):
                    ui.label("💾 Save")
                if is_email_step:
                    with ui.element("button").classes("fd-pb").style("padding:8px 20px;").on("click", _preview_email):
                        ui.label("📧 Preview Email")
                    # AI Assist button
                    if ANTHROPIC_API_KEY:
                        def _polish():
                            _ai_assist_email(body_area, subj_inp, rf)
                        with ui.element("button").style(
                                f"display:inline-flex;align-items:center;gap:5px;padding:8px 16px;"
                                f"border-radius:8px;font-size:12px;font-weight:600;cursor:pointer;"
                                f"background:{C['indigo']}18;color:{C['indigo']};"
                                f"border:1px solid {C['indigo']}40;font-family:inherit;"
                                ).on("click", _polish):
                            ui.label("✦ Rewrite with AI")
                    # Remember Style button  -  learns from user's edits
                    _original_body = body_val  # captured before editor loaded
                    def _teach_ai(orig=_original_body):
                        if body_area:
                            _teach_ai_from_edit(orig, body_area.value or "", rf, s_email=getattr(s, "_user_email", "") or "")
                    if ANTHROPIC_API_KEY and body_val.strip():
                        with ui.element("button").style(
                                f"display:inline-flex;align-items:center;gap:5px;padding:8px 16px;"
                                f"border-radius:8px;font-size:12px;font-weight:600;cursor:pointer;"
                                f"background:{C['warn']}18;color:{C['warn']};"
                                f"border:1px solid {C['warn']}40;font-family:inherit;"
                                ).on("click", _teach_ai):
                            ui.label("🧠 Remember Style")

    elif cur_step == "sequence":
        # ── SEQUENCE EDITOR ──────────────────────────────────────────────────
        seq_mode = s._loaded_seq_mode
        # [LEAK FIX 2026-06-25] Stamp campaign owner at render time (valid
        # request context) so the sequence-editor autosave handlers can never
        # fall through to the shared-root LEAK_GUARD when their async event
        # context lacks a bound user. Covers _save_now / _upd_delay /
        # _on_date_input and the bare save_campaign(camp) in this editor.
        try:
            if isinstance(camp, dict) and not camp.get("_owner_email"):
                _leakfix_owner = (getattr(s, "_user_email", "") or "").strip()
                if not _leakfix_owner:
                    try:
                        _leakfix_owner = (_CURRENT_USER_EMAIL.get() or app.storage.user.get("email") or "").strip()
                    except Exception:
                        _leakfix_owner = ""
                if _leakfix_owner:
                    camp["_owner_email"] = _leakfix_owner
        except Exception:
            pass

        # Mode toggle
        ui.label("Sequence Mode").classes("fd-fl")
        with ui.element("div").style("display:flex;gap:8px;margin-bottom:20px;"):
            for mode, label in [("days", "By Days Apart"), ("dates", "Pick Exact Dates")]:
                on = seq_mode == mode
                def _set_mode(m=mode):
                    s._loaded_seq_mode = m; rf()
                with ui.element("button").classes("fd-hub" + (" on" if on else "")).style(
                        "border-radius:6px;padding:6px 14px;font-size:12px;").on("click", _set_mode):
                    ui.label(label)

        cumulative_delay = 0
        for i, em in enumerate(steps):
            delay = em.get("delay_days", 0)
            cumulative_delay += delay
            fixed = em.get("fixed_date", "")
            if seq_mode == "dates" and fixed:
                try:
                    send_date = date.fromisoformat(fixed)
                except Exception:
                    send_date = _add_business_days(start_dt, cumulative_delay)
            else:
                send_date = _add_business_days(start_dt, cumulative_delay)
            icon, color = STEP_META.get(em.get("step_type", ST.EMAIL_AUTO), ("✉", C["email_col"]))

            with ui.element("div").style(
                    f"background:{C['card']};border:1px solid {C['border']};border-left:3px solid {color};"
                    f"border-radius:0 10px 10px 0;padding:12px 14px;margin-bottom:8px;"):
                with ui.element("div").style("display:flex;align-items:center;gap:12px;"):
                    ui.label(str(i + 1)).style(f"font-size:14px;font-weight:600;color:{C['teal']};width:24px;text-align:center;flex-shrink:0;")
                    ui.label(icon).style(f"color:{color};font-size:14px;flex-shrink:0;")
                    with ui.element("div").style("flex:1;min-width:0;"):
                        ui.label(em.get("name", f"Email {i+1}")).style(f"font-size:13px;font-weight:500;color:{C['text_l']};")
                        if em.get("subject"):
                            ui.label(em["subject"]).style(f"font-size:11px;color:{C['muted']};overflow:hidden;text-overflow:ellipsis;white-space:nowrap;")
                        # Show attachments as clickable links
                        if em.get("attachments"):
                            with ui.element("div").style("display:flex;gap:4px;flex-wrap:wrap;margin-top:3px;"):
                                for att in em["attachments"]:
                                    pdf_exists = (_user_pdf_dir() / att).is_file()
                                    if pdf_exists:
                                        with ui.link(target=f"/pdfs/{att}", new_tab=True).style("text-decoration:none;"):
                                            ui.label(f"📎 {att}").style(
                                                f"font-size:10px;padding:2px 8px;border-radius:99px;"
                                                f"background:{C['email_col']}15;color:{C['email_col']};"
                                                f"border:1px solid {C['email_col']}30;cursor:pointer;")
                                    else:
                                        ui.label(f"📎 {att}").style(
                                            f"font-size:10px;padding:2px 8px;border-radius:99px;"
                                            f"background:{C['surface']};color:{C['muted']};"
                                            f"border:1px solid {C['border']};")

                    # Autosave helper for this editor — every per-step
                    # mutation (delay / fixed_date / time) writes to disk
                    # so the user can navigate away (Preview Campaign tab,
                    # back-button, etc.) without losing edits. Without
                    # this, dates set in "Pick Exact Dates" mode reverted
                    # to "today + delay" the moment the user came back
                    # from the Preview tab — the bug Elizabeth reported
                    # 2026-04-25.
                    def _save_now(_c=camp):
                        try:
                            save_campaign(_c)
                            _cache_campaigns.invalidate()
                        except Exception as _ex:
                            print(f"[Sequence editor] autosave failed: {_ex}", flush=True)

                    if seq_mode == "days":
                        # Days mode  -  editable delay + computed date
                        with ui.element("div").style("width:80px;flex-shrink:0;"):
                            def _upd_delay(val, idx=i):
                                try:
                                    steps[idx]["delay_days"] = int(val) if val is not None else 0
                                except: pass
                                _save_now()
                                rf()
                            ui.number(value=delay, min=0, max=365, step=1,
                                      on_change=lambda e, idx=i: _upd_delay(e.value, idx)).style(
                                f"width:100%;background:{C['surface']};border:1px solid {C['border']};border-radius:4px;color:{C['text_l']};")
                            ui.label("days").style(f"font-size:10px;color:{C['muted']};text-align:center;")
                    else:
                        # Dates mode  -  calendar date picker + manual input
                        with ui.element("div").style("width:170px;flex-shrink:0;"):
                            _init_date = fixed or send_date.isoformat()

                            def _shift_subsequent(idx, old_iso, new_iso):
                                """When the user moves step `idx`'s date,
                                shift every later step's fixed_date by the
                                same delta so the campaign's spacing is
                                preserved. Skips steps that don't have a
                                fixed_date set (those run on delay_days).
                                Editing step 1 ("the start date") cascades
                                through every later step — what the user
                                expects when they push the campaign back
                                a week."""
                                try:
                                    if not old_iso or not new_iso or old_iso == new_iso:
                                        return
                                    _old_d = date.fromisoformat(old_iso)
                                    _new_d = date.fromisoformat(new_iso)
                                    _delta = _new_d - _old_d
                                    if not _delta:
                                        return
                                    for _j in range(idx + 1, len(steps)):
                                        _f = (steps[_j].get("fixed_date") or "").strip()
                                        if not _f:
                                            continue
                                        try:
                                            _shifted = (date.fromisoformat(_f) + _delta).isoformat()
                                            steps[_j]["fixed_date"] = _shifted
                                        except Exception:
                                            continue
                                except Exception as _ex:
                                    print(f"[Sequence editor] shift-subsequent failed: {_ex}",
                                          flush=True)

                            def _on_date_input(e, idx=i):
                                # Capture both typed input AND clears (empty
                                # string is now stored explicitly so the
                                # field doesn't silently fall back to "today
                                # + delay" on the next render).
                                val = (e.value or "").strip()
                                _old = (steps[idx].get("fixed_date") or "").strip()
                                steps[idx]["fixed_date"] = val
                                _shift_subsequent(idx, _old, val)
                                _save_now()
                                rf()
                            date_input = ui.input(value=_init_date,
                                                  placeholder="YYYY-MM-DD").style("width:100%;")
                            # Listen on BOTH change (blur/Enter) AND
                            # update:model-value (per-keystroke debounce)
                            # so navigation immediately after typing still
                            # captures the date — the bug was the user
                            # typing then clicking a tab before blur fired.
                            date_input.on("change", lambda e, idx=i: _on_date_input(e, idx))
                            date_input.on("update:model-value",
                                          lambda e, idx=i: _on_date_input(e, idx))
                            with date_input.add_slot('append'):
                                _menu_ref = {"m": None}
                                def _open_menu(mr=_menu_ref):
                                    if mr["m"]: mr["m"].open()
                                ui.icon('edit_calendar').on('click', _open_menu).classes('cursor-pointer')
                            with ui.menu().props('no-parent-event') as _m:
                                _menu_ref["m"] = _m
                                def _pick_date(e, inp=date_input, idx=i, menu=_m):
                                    _old = (steps[idx].get("fixed_date") or "").strip()
                                    _new = e.value or ""
                                    inp.set_value(_new)
                                    steps[idx]["fixed_date"] = _new
                                    _shift_subsequent(idx, _old, _new)
                                    _save_now()
                                    menu.close()
                                    rf()
                                with ui.date(value=_init_date, on_change=_pick_date):
                                    pass

                    # Time picker (both modes)
                    with ui.element("div").style("width:120px;flex-shrink:0;"):
                        def _upd_time(val, idx=i):
                            steps[idx]["time"] = val
                            _save_now()
                        ui.select(options=TIME_OPTIONS, value=em.get("time", "9:00 AM"),
                                  on_change=lambda e, idx=i: _upd_time(e.value, idx)).style("width:100%;")
                    # Computed send date display
                    ui.label(send_date.strftime("%a %b %d")).style(
                        f"font-size:13px;font-weight:500;color:{C['teal']};width:90px;text-align:right;flex-shrink:0;")

        # Presets (only in days mode)
        if seq_mode == "days":
            ui.label("Quick Presets").classes("fd-sec").style("margin-top:16px;")
            with ui.element("div").style("display:flex;gap:8px;"):
                def _apply_loaded_preset(delays):
                    for i, d in enumerate(delays):
                        if i < len(steps):
                            steps[i]["delay_days"] = d
                    rf()
                for label, delays in [("Aggressive (0-1-3-7)", [0, 1, 2, 4]),
                                      ("Standard (0-2-5-14-30)", [0, 2, 3, 9, 16]),
                                      ("Nurture (0-3-7-14...90)", [0, 3, 4, 7, 16, 30, 30])]:
                    def _p(d=delays):
                        _apply_loaded_preset(d)
                    with ui.element("button").classes("fd-gb").style("font-size:11px;padding:5px 12px;").on("click", _p):
                        ui.label(label)

        # ── Save Sequence button ──────────────────────────────────────────
        def _save_sequence():
            save_campaign(camp)
            _cache_campaigns.invalidate()
            ui.notify(f"Sequence saved for '{camp_name}'!", type="positive")
        with ui.element("div").style("display:flex;justify-content:flex-end;margin-top:20px;"):
            with ui.element("button").classes("fd-pb").style(
                    "padding:10px 24px;font-size:13px;font-weight:700;").on("click", _save_sequence):
                ui.label("💾 Save Sequence")

    elif cur_step == "contacts":
        # ── CHOOSE CONTACTS ──────────────────────────────────────────────────
        ui.label("Choose Contacts").style(
            f"font-size:20px;font-weight:700;color:{C['text_l']};margin-bottom:4px;"
            f"font-family:'Nunito',sans-serif;")
        ui.label("Upload a CSV or pick a saved list.").style(
            f"font-size:13px;color:{C['muted']};margin-bottom:20px;")

        # ── Status banner when contacts already loaded ────────────────────────
        if contacts:
            with ui.element("div").style(
                    f"display:flex;align-items:center;justify-content:space-between;"
                    f"background:{C['teal_dim']};border:1px solid {C['teal']}40;"
                    f"border-radius:10px;padding:12px 18px;margin-bottom:20px;"):
                with ui.element("div").style("display:flex;align-items:center;gap:10px;"):
                    ui.label("✓").style(f"font-size:18px;color:{C['teal']};")
                    ui.label(f"{len(contacts)} contacts loaded").style(
                        f"font-size:14px;font-weight:600;color:{C['teal']};")
                def _clear_contacts():
                    camp["contacts"] = []
                    camp["contact_count"] = 0
                    camp["contact_emails"] = []
                    rf()
                with ui.element("button").style(
                        f"padding:5px 14px;border-radius:8px;cursor:pointer;font-family:inherit;"
                        f"background:transparent;border:1px solid {C['teal']}60;"
                        f"color:{C['teal']};font-size:12px;font-weight:600;").on(
                        "click", _clear_contacts):
                    ui.label("✕ Clear & Change").style("pointer-events:none;")

        # ── Active Clients red-flag banner ────────────────────────────────
        # Wizard step 3 has this gate (_sq_contacts L16691); the loaded-
        # campaign editor skipped it. Result: user uploads a list of
        # contacts at a protected client, sees no warning, hits Launch,
        # queue_campaign_emails silently filters them all out, and the
        # user has no idea why nothing sent (user report 2026-05-04:
        # "I did a trial run on a current client - it didnt give any
        # red flags anywhere and was going to let me run the campaign").
        if contacts:
            try:
                _ac_blocklist_now = load_client_blocklist()
                _flagged_pairs = (
                    blocklisted_contacts(contacts, _ac_blocklist_now)
                    if _ac_blocklist_now else []
                )
            except Exception:
                _flagged_pairs = []
            if _flagged_pairs:
                # Group by client/domain for a tidy summary
                _by_dom: dict = {}
                for _c, _entry in _flagged_pairs:
                    _dom = _normalize_domain(_entry.get("domain", "")) or _entry.get("domain", "")
                    _cname = (_entry.get("client_name", "") or "").strip()
                    _bucket = _by_dom.setdefault(_dom, {"name": _cname, "count": 0})
                    _bucket["count"] += 1
                    if _cname and not _bucket["name"]:
                        _bucket["name"] = _cname
                _n_flag = len(_flagged_pairs)
                _kept_lc = max(0, len(contacts) - _n_flag)
                with ui.element("div").style(
                        f"background:{C['danger']}12;border:1px solid {C['danger']}60;"
                        f"border-left:4px solid {C['danger']};border-radius:8px;"
                        f"padding:14px 18px;margin-bottom:18px;"):
                    with ui.element("div").style(
                            "display:flex;align-items:flex-start;gap:10px;"):
                        ui.label("⚠").style(
                            f"font-size:20px;color:{C['danger']};flex-shrink:0;"
                            f"line-height:1.1;")
                        with ui.element("div").style("flex:1;min-width:0;"):
                            ui.label(
                                f"{_n_flag} contact{'s' if _n_flag != 1 else ''} "
                                f"at active client{'s' if len(_by_dom) != 1 else ''}"
                            ).style(
                                f"font-size:14px;font-weight:800;color:{C['danger']};"
                                f"font-family:'Nunito',sans-serif;display:block;"
                                f"margin-bottom:4px;")
                            ui.label(
                                "These contacts work at companies on your team's "
                                "Active Clients list. They will be SKIPPED at launch "
                                "(default behavior). If you intentionally want to "
                                "send anyway, use the gate at Preview Campaign."
                            ).style(
                                f"font-size:12px;color:{C['text_l']};line-height:1.5;"
                                f"display:block;margin-bottom:10px;")
                            with ui.element("div").style(
                                    f"background:{C['surface']};"
                                    f"border:1px solid {C['border']};border-radius:6px;"
                                    f"padding:8px 12px;max-height:140px;overflow-y:auto;"):
                                for _dom, _info in sorted(
                                        _by_dom.items(),
                                        key=lambda kv: (-kv[1]["count"], kv[0]))[:10]:
                                    with ui.element("div").style(
                                            "display:flex;align-items:center;"
                                            "justify-content:space-between;padding:2px 0;"):
                                        ui.label(_info["name"] or _dom).style(
                                            f"font-size:12px;color:{C['text_l']};"
                                            f"font-weight:600;")
                                        ui.label(
                                            f"{_info['count']} "
                                            f"contact{'s' if _info['count'] != 1 else ''} "
                                            f"({_dom})"
                                        ).style(
                                            f"font-size:11px;color:{C['muted']};"
                                            f"font-family:monospace;")
                            ui.label(
                                f"Effective send: {_kept_lc} of {len(contacts)} "
                                f"contact{'s' if len(contacts) != 1 else ''}."
                            ).style(
                                f"font-size:11px;color:{C['muted']};"
                                f"margin-top:8px;font-style:italic;display:block;")

        # ── Two option cards ──────────────────────────────────────────────────
        show_saved = getattr(s, "_show_saved_lists", False)
        saved = list_saved_contact_lists()

        # Resolve border color in Python  -  not in f-string (avoids broken CSS)
        saved_border = C["teal"] if show_saved else C["border"]
        saved_bg     = C["teal_dim"] if show_saved else C["surface"]

        with ui.element("div").style("display:flex;gap:14px;margin-bottom:20px;"):

            # ── Card 1: Upload CSV ────────────────────────────────────────────
            def _on_uploaded_lc(new_contacts):
                camp["contacts"] = new_contacts
                camp["contact_count"] = len(new_contacts)
                camp["contact_emails"] = [c.get("email", "") for c in new_contacts]
                rf()
            _lc_upload_ref = _contact_upload_and_name(s, rf, _on_uploaded_lc)
            with ui.element("div").style(
                    f"flex:1;background:{C['surface']};border:1px solid {C['border']};"
                    f"border-left:4px solid {C['email_col']};border-radius:0 12px 12px 0;"
                    f"padding:20px 22px;cursor:pointer;transition:background .15s;"
                    ).on("click", lambda: _lc_upload_ref.run_method('pickFiles') if _lc_upload_ref else None):
                with ui.element("div").style("display:flex;align-items:center;gap:12px;margin-bottom:8px;"):
                    with ui.element("div").style(
                            f"width:36px;height:36px;border-radius:8px;flex-shrink:0;"
                            f"background:{C['email_col']}20;display:flex;align-items:center;"
                            f"justify-content:center;font-size:18px;"):
                        ui.html("📤")
                    with ui.element("div"):
                        ui.label("Upload CSV").style(
                            f"font-size:15px;font-weight:700;color:{C['text_l']};"
                            f"font-family:'Nunito',sans-serif;display:block;")
                        ui.label("ZoomInfo, LinkedIn, or any CSV").style(
                            f"font-size:12px;color:{C['muted']};display:block;")
                with ui.element("div").style(
                        f"display:inline-flex;align-items:center;gap:5px;margin-top:6px;"
                        f"padding:4px 12px;border-radius:99px;"
                        f"background:{C['email_col']}15;border:1px solid {C['email_col']}40;"):
                    ui.label("↑ Click to browse").style(
                        f"font-size:11px;color:{C['email_col']};font-weight:600;")

            # ── Card 2: Saved List ────────────────────────────────────────────
            def _toggle_saved():
                s._show_saved_lists = not getattr(s, "_show_saved_lists", False)
                rf()
            with ui.element("div").style(
                    f"flex:1;background:{saved_bg};"
                    f"border:1px solid {saved_border};"
                    f"border-left:4px solid {C['indigo']};border-radius:0 12px 12px 0;"
                    f"padding:20px 22px;cursor:pointer;transition:background .15s;"
                    ).on("click", _toggle_saved):
                with ui.element("div").style("display:flex;align-items:center;gap:12px;margin-bottom:8px;"):
                    with ui.element("div").style(
                            f"width:36px;height:36px;border-radius:8px;flex-shrink:0;"
                            f"background:{C['indigo']}20;display:flex;align-items:center;"
                            f"justify-content:center;font-size:18px;"):
                        ui.html("📋")
                    with ui.element("div"):
                        ui.label("Saved List").style(
                            f"font-size:15px;font-weight:700;color:{C['text_l']};"
                            f"font-family:'Nunito',sans-serif;display:block;")
                        n_saved = len(saved)
                        ui.label(
                            f"{n_saved} list{'s' if n_saved != 1 else ''} available"
                        ).style(f"font-size:12px;color:{C['muted']};display:block;")
                with ui.element("div").style(
                        f"display:inline-flex;align-items:center;gap:5px;margin-top:6px;"
                        f"padding:4px 12px;border-radius:99px;"
                        f"background:{C['indigo']}15;border:1px solid {C['indigo']}40;"):
                    ui.label("▾ Select a list" if show_saved else "▸ Select a list").style(
                        f"font-size:11px;color:{C['indigo']};font-weight:600;")

        # ── Saved list dropdown (when open) ──────────────────────────────────
        if show_saved:
            if not saved:
                ui.label("No saved lists yet  -  upload a CSV first.").style(
                    f"font-size:13px;color:{C['muted']};margin-bottom:16px;")
            else:
                with ui.element("div").style(
                        f"background:{C['surface']};border:1px solid {C['border']};"
                        f"border-radius:12px;overflow:hidden;margin-bottom:16px;"):
                    for list_name, list_path in sorted(saved.items()):
                        cnt = _get_csv_row_count(list_path)
                        is_active = False
                        if contacts:
                            try:
                                loaded_emails = {(c.get("email","") or c.get("Email","")).lower() for c in contacts}
                                file_rows, _ = safe_read_csv_rows(list_path)
                                file_emails  = {(r.get("email","") or r.get("Email","")).lower() for r in file_rows}
                                is_active = bool(loaded_emails & file_emails) and len(loaded_emails) == len(file_emails)
                            except Exception:
                                pass
                        def _pick_saved(path=list_path, nm=list_name):
                            import shutil
                            shutil.copy2(path, str(_user_contacts_csv_path()))
                            loaded = load_contacts()
                            camp["contacts"] = loaded
                            camp["contact_count"] = len(loaded)
                            camp["contact_emails"] = [c.get("email", "") for c in loaded]
                            s._show_saved_lists = False
                            rf()
                        border_t = f"border-top:1px solid {C['border']};" if list_name != sorted(saved.keys())[0] else ""
                        row_bg   = C["teal_dim"] if is_active else C["surface"]
                        with ui.element("button").style(
                                f"display:flex;align-items:center;justify-content:space-between;"
                                f"width:100%;padding:12px 18px;font-size:13px;"
                                f"font-family:inherit;cursor:pointer;text-align:left;"
                                f"background:{row_bg};{border_t}"
                                f"color:{C['text']};").on("click", _pick_saved):
                            with ui.element("div").style("display:flex;align-items:center;gap:10px;"):
                                if is_active:
                                    ui.label("✓").style(
                                        f"color:{C['teal']};font-weight:700;font-size:14px;"
                                        f"pointer-events:none;")
                                ui.label(list_name).style(
                                    f"font-weight:600;pointer-events:none;"
                                    f"color:{C['teal'] if is_active else C['text_l']};")
                            ui.label(f"{cnt} contacts").style(
                                f"font-size:12px;color:{C['muted']};pointer-events:none;")

        # ── Contact preview ────────────────────────────────────────────────────
        if contacts:
            ui.element("div").style(f"height:1px;background:{C['border']};margin-bottom:16px;")
            responded_emails = {x["email"].lower() for x in load_responded()}
            active_contacts  = [c for c in contacts if (c.get("email","") or c.get("Email","")).lower() not in responded_emails]
            skipped          = len(contacts) - len(active_contacts)
            with ui.element("div").style("display:flex;gap:12px;margin-bottom:12px;flex-wrap:wrap;"):
                for val, lbl, col in [
                    (len(contacts),       "Total",            C["text"]),
                    (len(active_contacts),"Will Receive",     C["teal"]),
                    (skipped,             "Skipped (responded)", C["warn"]) if skipped else (None, None, None),
                ]:
                    if val is None:
                        continue
                    with ui.element("div").style(
                            f"background:{C['card']};border:1px solid {C['border']};"
                            f"border-radius:8px;padding:8px 16px;"):
                        ui.label(str(val)).style(f"font-size:20px;font-weight:700;color:{col};line-height:1;")
                        ui.label(lbl).style(
                            f"font-size:10px;color:{C['muted']};text-transform:uppercase;"
                            f"letter-spacing:.06em;margin-top:2px;")

            ui.label("Contact Preview").classes("fd-sec")
            # Support both lowercase (load_contacts) and capitalized (AICB) key formats
            def _cg(c, *keys):
                for k in keys:
                    v = c.get(k, "")
                    if v: return v
                return ""
            cols_fn  = [
                lambda c: _cg(c, "first_name", "FirstName"),
                lambda c: _cg(c, "last_name", "LastName"),
                lambda c: _cg(c, "email", "Email"),
                lambda c: _cg(c, "company", "Company"),
                lambda c: _cg(c, "title", "JobTitle"),
            ]
            col_hdrs = ["First", "Last", "Email", "Company", "Title"]
            html_rows = ""
            for c in contacts[:100]:
                em_l = _cg(c, "email", "Email").lower()
                skip = em_l in responded_emails
                row_style = "opacity:.4;" if skip else ""
                skip_badge = (f' <span style="font-size:9px;color:{C["warn"]};background:{C["warn"]}15;'
                              f'padding:1px 6px;border-radius:99px;border:1px solid {C["warn"]}40;">responded</span>') if skip else ""
                cells = ""
                for i, fn in enumerate(cols_fn):
                    val = fn(c)
                    badge = skip_badge if i == 2 else ""  # badge on email column
                    cells += (f'<td style="color:{C["text"]};font-size:12px;padding:7px 10px;{row_style}">'
                              f'{esc(str(val))}{badge}</td>')
                html_rows += f"<tr>{cells}</tr>"
            header = "".join(f'<th style="padding:8px 10px;">{h}</th>' for h in col_hdrs)
            ui.html(f"""<div style="background:{C['card']};border:1px solid {C['border']};
                border-radius:10px;overflow:hidden;max-height:340px;overflow-y:auto;">
              <table class="fd-tbl" style="table-layout:auto;"><thead><tr>{header}</tr></thead>
              <tbody>{html_rows}</tbody></table></div>""")
            if len(contacts) > 100:
                ui.label(f"Showing first 100 of {len(contacts)} contacts.").style(
                    f"font-size:11px;color:{C['muted']};margin-top:6px;")
        else:
            with ui.element("div").classes("fd-empty").style("padding:32px 0;"):
                ui.label("📭").style("font-size:32px;margin-bottom:8px;display:block;")
                ui.label("No contacts yet  -  upload a CSV or pick a saved list above.").style(
                    f"font-size:13px;color:{C['muted']};")


    elif cur_step == "launch":
        # ── PREVIEW & LAUNCH ─────────────────────────────────────────────────
        responded_emails = {x["email"].lower() for x in load_responded()}
        active_contacts  = [c for c in contacts if c.get("email","").lower() not in responded_emails]
        email_steps      = [e for e in steps if e.get("step_type","") in (ST.EMAIL_AUTO, ST.EMAIL_MANUAL, "")]
        other_steps      = [e for e in steps if e.get("step_type","") not in (ST.EMAIL_AUTO, ST.EMAIL_MANUAL, "")]

        # ── Send Preview Emails ────────────────────────────────────────────
        _preview_state = {"dialog": None, "email_inp": None}

        def _build_preview_dialog():
            """Build the dialog lazily on first click."""
            if _preview_state["dialog"]:
                return
            with ui.dialog() as dlg, ui.card().style(
                    f"background:{C['card']};border:1px solid {C['border']};min-width:420px;padding:24px;"):
                ui.label("Send Preview Emails").style(
                    f"font-size:16px;font-weight:700;color:{C['text_l']};margin-bottom:4px;"
                    f"font-family:'Nunito',sans-serif;")
                ui.label(f"Send all {len(email_steps)} email steps as previews to review before launching.").style(
                    f"font-size:12px;color:{C['muted']};margin-bottom:16px;")
                ui.label("Send to").classes("fd-fl")
                email_inp = ui.input(value="", placeholder="email@something.com").style(
                    f"width:100%;background:{C['surface']};border:1px solid {C['border']};"
                    f"border-radius:6px;padding:10px 14px;font-size:13px;color:{C['text_l']};"
                    f"font-family:inherit;margin-bottom:16px;outline:none;")

                async def _do_send():
                    to_addr = email_inp.value.strip()
                    if not to_addr or "@" not in to_addr:
                        ui.notify("Please enter a valid email address.", type="warning")
                        return
                    # Guard: catch unfilled [PLACEHOLDER] tokens BEFORE
                    # sending so the user fixes them instead of shipping
                    # "[CANDIDATE NAME]" to a real recipient (Elizabeth
                    # Simonov preview incident, 2026-04-26).
                    _all_problems: dict = {}
                    for i, step in enumerate(email_steps, 1):
                        for field, val in (("subject", step.get("subject", "")),
                                            ("body", step.get("body", ""))):
                            for ph in _detect_unfilled_placeholders(val):
                                _all_problems.setdefault(ph, []).append(f"Step {i} {field}")
                    if _all_problems:
                        _examples = ", ".join(list(_all_problems.keys())[:4])
                        ui.notify(
                            f"Can't send preview — {len(_all_problems)} unfilled "
                            f"placeholder(s) in your campaign: {_examples}. "
                            "Fill them in (or regenerate) and try again.",
                            type="negative", timeout=10000,
                        )
                        return
                    dlg.close()
                    _snap = list(email_steps)
                    ui.notify(f"Sending {len(_snap)} preview emails to {to_addr}...", type="info")
                    _for_user = getattr(s, '_user_email', '')
                    try:
                        def _send():
                            for i, step in enumerate(_snap, 1):
                                subj = step.get("subject", "") or f"(Step {i})"
                                body_html = step.get("body", "")
                                _pc = _preview_self_contact(s)
                                for _k, _v in [("{FirstName}", _pc.get("first_name","[FirstName]")), ("{LastName}", _pc.get("last_name","[LastName]")),
                                               ("{Company}", _pc.get("company","[Company]")), ("{CompanyName}", _pc.get("company","[Company]")), ("{JobTitle}", _pc.get("title","[JobTitle]"))]:
                                    subj = subj.replace(_k, _v)
                                    body_html = body_html.replace(_k, _v)
                                atts = [str(_user_pdf_dir() / a) if not os.path.isabs(a) else a for a in step.get("attachments", [])]
                                ok, err = _send_email_universal(
                                    to=to_addr, subject=f"[PREVIEW {i}/{len(_snap)}] {subj}",
                                    html_body=body_html, attachments=atts, is_preview=False,
                                    _for_user_email=_for_user,
                                )
                                if not ok:
                                    raise Exception(err)
                        await asyncio.get_event_loop().run_in_executor(None, _send)
                        ui.notify(f"All {len(_snap)} previews sent to {to_addr}!", type="positive")
                    except Exception as e:
                        ui.notify(f"Preview failed: {str(e)[:120]}", type="negative")

                with ui.element("div").style("display:flex;gap:10px;justify-content:flex-end;"):
                    ui.button("Cancel", on_click=dlg.close).props("flat").style(
                        f"color:{C['muted']};font-family:inherit;")
                    ui.button(f"Send {len(email_steps)} Previews",
                        on_click=_do_send).props("unelevated").style(
                        f"background:{C['teal']};color:#fff;font-family:inherit;font-weight:600;"
                        f"border-radius:8px;padding:8px 20px;")
            _preview_state["dialog"] = dlg
            _preview_state["email_inp"] = email_inp

        def _open_preview():
            _build_preview_dialog()
            # Try to pre-fill sender email from config (avoids blocking Outlook COM call)
            inp = _preview_state["email_inp"]
            if inp and not inp.value:
                _acct = ""
                # Check MS tokens first
                if _HAS_MS_EMAIL and _ms_email:
                    try:
                        _tk = _ms_email.load_ms_tokens(_user_config_path())
                        _acct = _tk.get("email", "")
                    except Exception:
                        pass
                # Fall back to SMTP config or user email
                if not _acct:
                    _cfg_p = load_config()
                    _acct = _cfg_p.get("smtp_email", "") or getattr(s, '_user_email', '')
                if not _acct:
                    # Last resort: try Outlook COM in background
                    try:
                        import pythoncom, win32com.client.dynamic
                        pythoncom.CoInitialize()
                        ol = win32com.client.dynamic.Dispatch("Outlook.Application")
                        _acct = ol.GetNamespace("MAPI").Accounts.Item(1).SmtpAddress or ""
                    except Exception:
                        pass
                if _acct:
                    inp.set_value(_acct)
            _preview_state["dialog"].open()

        # Newsletter first-issue generating / preview banner. When the user
        # spins a newsletter up from this campaign (the card lower down), the
        # dialog closes and this banner shows the live "Generating…" state and
        # then an inline preview — right here on the campaign page. Rendered
        # at page level (not in the dialog) so it survives re-renders.
        _render_nl_first_gen_status(s, rf)

        with ui.element("div").style("display:flex;justify-content:flex-end;margin-bottom:16px;"):
            ui.button(f"📧 Send Preview Emails ({len(email_steps)})",
                on_click=_open_preview).classes("fd-pb").style(
                "padding:10px 24px;font-size:14px;")

        # ── Top stat bar ───────────────────────────────────────────────────
        stat_items = [
            (len(contacts),       "Contacts",      C["teal"]         if contacts else C["danger"]),
            (len(active_contacts),"Will Receive",  C["good"]         if active_contacts else C["danger"]),
            (len(steps),          "Total Steps",   C["text_l"]),
            (len(email_steps),    "Emails",        C["email_col"]),
            (len(other_steps),    "Other Steps",   C["indigo"])      if other_steps else (None, None, None),
            (camp.get("start_date", date.today().isoformat()), "Start Date", C["muted"]),
        ]
        with ui.element("div").style(
                f"display:flex;gap:0;border:1px solid {C['border']};border-radius:10px;"
                f"overflow:hidden;margin-bottom:20px;"):
            for val, lbl, col in stat_items:
                if val is None:
                    continue
                with ui.element("div").style(
                        f"flex:1;padding:14px 16px;background:{C['card']};"
                        f"border-right:1px solid {C['border']};"):
                    ui.label(str(val)).style(
                        f"font-size:20px;font-weight:800;color:{col};"
                        f"font-family:'Nunito',sans-serif;line-height:1;")
                    ui.label(lbl).style(
                        f"font-size:10px;font-weight:600;color:{C['muted']};"
                        f"text-transform:uppercase;letter-spacing:.06em;margin-top:3px;")

        # ── Two-column layout ──────────────────────────────────────────────
        with ui.element("div").style("display:grid;grid-template-columns:1fr 1fr;gap:20px;margin-bottom:20px;"):

            # LEFT: Full sequence timeline
            with ui.element("div"):
                ui.label("Sequence").classes("fd-sec")
                # Use the SAME date-resolution logic as the Edit Sequence
                # tab: honor per-step fixed_date when set (the user's
                # "Pick Exact Dates" picks), and fall back to the
                # campaign's start_date + cumulative_delay otherwise.
                # Previously this used date.today() + cumulative_delay
                # for every step — completely ignoring fixed_date AND
                # the campaign's start_date — so the preview showed
                # different dates than what the queue would actually
                # use at send time. (Elizabeth's bug, 2026-04-25.)
                cum = 0
                LAUNCH_STEP_META = {
                    ST.EMAIL_AUTO:   ("✉",  C["email_col"]),
                    ST.EMAIL_MANUAL: ("✉",  C["email_col"]),
                    ST.CALL:         ("☎",  C["call_col"]),
                    ST.LINKEDIN:     ("in", C["indigo"]),
                    ST.SMS:          ("msg",C["sms_col"]),
                    ST.TASK:         ("✓",  C["task_col"]),
                }
                for i, em in enumerate(steps):
                    cum += em.get("delay_days", 0)
                    _fixed = (em.get("fixed_date") or "").strip()
                    if _fixed:
                        try:
                            send_date = date.fromisoformat(_fixed)
                        except Exception:
                            send_date = _add_business_days(start_dt, cum)
                    else:
                        send_date = _add_business_days(start_dt, cum)
                    stype = em.get("step_type", ST.EMAIL_AUTO) or ST.EMAIL_AUTO
                    icon, col = LAUNCH_STEP_META.get(stype, ("✉", C["email_col"]))
                    subj = em.get("subject", "") or em.get("script_notes", "") or em.get("name", "")
                    att_count = len(em.get("attachments", []))
                    with ui.element("div").style(
                            f"display:flex;align-items:flex-start;gap:10px;padding:10px 0;"
                            f"border-bottom:1px solid {C['border']};"):
                        # Step number bubble
                        with ui.element("div").style(
                                f"width:26px;height:26px;border-radius:50%;"
                                f"background:{col}22;border:1px solid {col}60;"
                                f"display:flex;align-items:center;justify-content:center;"
                                f"flex-shrink:0;margin-top:1px;"):
                            ui.label(icon).style(f"font-size:10px;color:{col};font-weight:700;")
                        with ui.element("div").style("flex:1;min-width:0;"):
                            with ui.element("div").style("display:flex;align-items:center;gap:8px;flex-wrap:wrap;"):
                                ui.label(em.get("name","")).style(
                                    f"font-size:13px;font-weight:600;color:{C['text_l']};")
                                ui.label(send_date.strftime("%a %b %d")).style(
                                    f"font-size:11px;color:{col};font-weight:600;")
                                if em.get("time"):
                                    ui.label(em["time"]).style(f"font-size:10px;color:{C['muted']};")
                                if att_count:
                                    ui.label(f"📎 {att_count}").style(
                                        f"font-size:10px;color:{C['email_col']};")
                            if subj:
                                ui.label(subj[:80] + ("…" if len(subj) > 80 else "")).style(
                                    f"font-size:11px;color:{C['muted']};margin-top:2px;"
                                    f"overflow:hidden;text-overflow:ellipsis;white-space:nowrap;")

            # RIGHT: Contact list preview
            with ui.element("div"):
                ui.label(f"Contacts ({len(contacts)})").classes("fd-sec")
                if not contacts:
                    with ui.element("div").style(
                            f"background:{C['danger']}10;border:1px solid {C['danger']}40;"
                            f"border-radius:8px;padding:14px 16px;"):
                        ui.label("⚠ No contacts  -  go back to Choose Contacts.").style(
                            f"font-size:13px;color:{C['danger']};font-weight:500;")
                else:
                    skipped = len(contacts) - len(active_contacts)
                    if skipped:
                        ui.label(f"⚠ {skipped} contact{'s' if skipped>1 else ''} already responded  -  will be skipped.").style(
                            f"font-size:11px;color:{C['warn']};margin-bottom:8px;display:block;")
                    cols_c   = ["first_name","last_name","email","company"]
                    hdrs_c   = ["First","Last","Email","Company"]
                    html_c = ""
                    for c in contacts[:50]:
                        em_l = c.get("email","").lower()
                        skip = em_l in responded_emails
                        rs   = "opacity:.35;" if skip else ""
                        cells = "".join(
                            f'<td style="font-size:11px;color:{C["text"]};padding:5px 8px;{rs}">'
                            f'{esc(str(c.get(k,"")))}</td>' for k in cols_c)
                        html_c += f"<tr>{cells}</tr>"
                    hdr_c = "".join(f'<th style="padding:6px 8px;font-size:10px;">{h}</th>' for h in hdrs_c)
                    ui.html(f"""<div style="background:{C['card']};border:1px solid {C['border']};
                        border-radius:8px;overflow:hidden;max-height:340px;overflow-y:auto;">
                      <table class="fd-tbl"><thead><tr>{hdr_c}</tr></thead>
                      <tbody>{html_c}</tbody></table></div>""")
                    if len(contacts) > 50:
                        ui.label(f"Showing 50 of {len(contacts)} contacts.").style(
                            f"font-size:10px;color:{C['muted']};margin-top:4px;")

        # ── Email content preview ──────────────────────────────────────────
        if email_steps:
            ui.label("Email Content").classes("fd-sec")
            for i, em in enumerate(email_steps):
                subj = em.get("subject", "") or "(no subject)"
                body_raw = em.get("body", "")
                # Strip HTML tags for plain preview
                import re as _re
                body_plain = _re.sub(r"<[^>]+>", " ", body_raw).strip()
                body_plain = _re.sub(r"\s+", " ", body_plain)[:300]
                att_count = len(em.get("attachments", []))
                has_subj = bool(em.get("subject","").strip())
                has_body = bool(body_raw.strip())
                status_col  = C["good"] if (has_subj and has_body) else (C["warn"] if has_subj else C["danger"])
                status_icon = "✓" if (has_subj and has_body) else ("⚠" if has_subj else "✕")
                with ui.element("div").style(
                        f"background:{C['card']};border:1px solid {C['border']};"
                        f"border-left:3px solid {status_col};"
                        f"border-radius:0 8px 8px 0;padding:12px 16px;margin-bottom:8px;"):
                    with ui.element("div").style("display:flex;align-items:center;gap:10px;margin-bottom:4px;"):
                        ui.label(status_icon).style(f"font-size:13px;color:{status_col};flex-shrink:0;")
                        ui.label(em.get("name","")).style(f"font-size:12px;font-weight:700;color:{C['muted']};")
                        ui.label(subj).style(
                            f"font-size:13px;font-weight:500;color:{C['text_l']};flex:1;"
                            f"overflow:hidden;text-overflow:ellipsis;white-space:nowrap;")
                        if att_count:
                            ui.label(f"📎 {att_count}").style(f"font-size:11px;color:{C['email_col']};flex-shrink:0;")
                    if body_plain:
                        ui.label(body_plain + ("…" if len(body_raw) > 300 else "")).style(
                            f"font-size:11px;color:{C['muted']};line-height:1.5;"
                            f"margin-left:23px;")
                    elif not has_body:
                        ui.label("⚠ No body written yet  -  go back to Edit Emails to fill this in.").style(
                            f"font-size:11px;color:{C['danger']};margin-left:23px;")

        # ── Checklist + launch ─────────────────────────────────────────────
        ui.element("div").style(f"height:1px;background:{C['border']};margin:20px 0 16px;")
        ui.label("Ready Checklist").classes("fd-sec")

        sig_ok = False
        try:
            if _user_sig_path().exists():
                sig_ok = len(_user_sig_path().read_text(encoding="utf-8").strip()) > 10
        except Exception:
            pass
        missing_subj  = sum(1 for e in email_steps if not e.get("subject","").strip())
        missing_body  = sum(1 for e in email_steps if not e.get("body","").strip())
        checks = [
            ("✓" if contacts        else "✕", f"{len(contacts)} contacts loaded" if contacts else "No contacts added",       C["good"]   if contacts        else C["danger"]),
            ("✓" if active_contacts else "✕", f"{len(active_contacts)} will receive emails",                                  C["good"]   if active_contacts  else C["danger"]),
            ("✓" if len(steps)>0    else "✕", f"{len(steps)} steps in sequence",                                             C["good"]   if steps            else C["danger"]),
            ("✓" if not missing_subj else "⚠", "All subjects filled" if not missing_subj else f"{missing_subj} missing subject{'s' if missing_subj>1 else ''}", C["good"] if not missing_subj else C["warn"]),
            ("✓" if not missing_body else "✕", "All email bodies written" if not missing_body else f"{missing_body} empty email bod{'ies' if missing_body>1 else 'y'}", C["good"] if not missing_body else C["danger"]),
            ("✓" if sig_ok           else "⚠", "Email signature set"   if sig_ok           else "No signature set",          C["good"]   if sig_ok           else C["warn"]),
        ]
        with ui.element("div").style("display:grid;grid-template-columns:1fr 1fr;gap:6px;margin-bottom:16px;"):
            for icon, text, col in checks:
                with ui.element("div").style("display:flex;align-items:center;gap:8px;padding:4px 0;"):
                    ui.label(icon).style(f"font-size:14px;color:{col};flex-shrink:0;")
                    ui.label(text).style(f"font-size:12px;color:{C['text']};")

        if not sig_ok:
            def _go_sig_cg():
                s._nav_history.append(_nav_snapshot(s))
                if s.hub == "sales": s.sp = "signature"
                else: s.ep = "e_signature"
                rf()
            with ui.element("button").classes("fd-gb").style(
                    f"border-color:{C['warn']}50;color:{C['warn']};margin-bottom:14px;"
                    f"font-size:12px;padding:6px 16px;").on("click", _go_sig_cg):
                ui.label("⚠ Set Email Signature →")

        all_good = not contacts or (not missing_body and not missing_subj)
        if all_good and contacts:
            ui.label("✅ Everything looks good  -  ready to launch!").style(
                f"font-size:13px;color:{C['good']};font-weight:600;margin-bottom:16px;display:block;")

        # ── Evergreen enroll option (multi-select dropdown) ─────────────────
        _eg_camps = [c for c in load_campaigns() if c.get("evergreen_only")]
        _eg_selected = set()  # names of selected evergreen campaigns

        if _eg_camps:
            # Build labeled options: "Name (7 emails · 3 enrolled)"
            _eg_options = []
            for ec in _eg_camps:
                n = ec.get("name", "")
                _eg_options.append(n)

            with ui.element("div").style(
                    f"background:{C['surface']};border:1px solid {C['border']};"
                    f"border-radius:10px;padding:14px 18px;margin-bottom:10px;"):
                with ui.element("div").style("display:flex;align-items:center;gap:10px;margin-bottom:10px;"):
                    ui.label("🌱").style("font-size:16px;flex-shrink:0;")
                    with ui.element("div"):
                        ui.label("Enroll in Slow Drip After Launch").style(
                            f"font-size:13px;font-weight:600;color:{C['text_l']};"
                            f"font-family:'Nunito',sans-serif;")
                        ui.label("Contacts will be added to selected drips when you launch.").style(
                            f"font-size:11px;color:{C['muted']};")
                for eg_name in _eg_options:
                    def _toggle_eg(e, n=eg_name):
                        if e.value:
                            _eg_selected.add(n)
                        else:
                            _eg_selected.discard(n)
                    ui.checkbox(eg_name, on_change=_toggle_eg).style(
                        f"color:{C['text_l']};font-size:13px;"
                        f"--q-color-primary:{C['teal']};")

        # ── Spin up Newsletter from this campaign ─────────────────────────────
        # Replaced the always-on Opt-Out Footer disclaimer (which was just
        # informational chrome) with an actionable cross-sell: "all this
        # campaign's info is already here — turn it into a monthly newsletter
        # in one click." Pre-fills name, sector, niche, region, and the full
        # contact list. The opt-out logic itself is still always on; it just
        # doesn't need a banner advertising itself.
        def _spin_up_from_launch():
            # Multi-source prefill: many campaigns don't have market_sector_key
            # / market_niche / market_region set directly. Fall back through:
            #   1. campaign top-level fields
            #   2. _effective_target(s) — the live campaign-builder context
            #      (AICB AppState) for the campaign being launched
            #   3. campaign's `variables` block — AICB writes Industry / Niche
            #      / Location / Company there
            #   4. AICB AppState directly (aicb_industry, aicb_niche, etc.)
            try:
                _eff = _effective_target(s)
            except Exception:
                _eff = {}
            _vars = camp.get("variables", {}) or {}

            def _first_nonblank(*vals):
                for v in vals:
                    sv = (str(v) if v is not None else "").strip()
                    if sv:
                        return sv
                return ""

            def _label_to_key(label: str) -> str:
                _ll = (label or "").strip().lower()
                if not _ll:
                    return ""
                for _k, _v in AICB_INDUSTRIES.items():
                    if (_v.get("label", "") or "").strip().lower() == _ll:
                        return _k
                return ""

            # ── Sector key ───────────────────────────────────────────────
            _sec_key = (camp.get("market_sector_key") or "").strip().lower()
            if not _sec_key or _sec_key not in AICB_INDUSTRIES:
                _sec_key = _label_to_key(camp.get("market_sector", "") or "")
            if not _sec_key:
                _sec_key = (_eff.get("industry_key") or "").strip().lower()
                if _sec_key and _sec_key not in AICB_INDUSTRIES:
                    _sec_key = ""
            if not _sec_key:
                _sec_key = _label_to_key(_eff.get("industry_label", "") or "")
            if not _sec_key:
                _sec_key = _label_to_key(
                    _vars.get("Industry") or _vars.get("industry") or "")
            if not _sec_key:
                _sec_key = (getattr(s, "aicb_industry", "") or "").strip().lower()
                if _sec_key and _sec_key not in AICB_INDUSTRIES:
                    _sec_key = ""

            # ── Niche ────────────────────────────────────────────────────
            _niche = _first_nonblank(
                camp.get("market_niche"),
                _eff.get("niche"),
                _vars.get("Niche"),
                _vars.get("niche"),
                getattr(s, "aicb_niche", ""),
            )

            # ── Region (city/state or comma-joined locations) ────────────
            _region = _first_nonblank(
                camp.get("market_region"),
                ", ".join(_eff.get("locations") or []),
                _vars.get("Location"),
                _vars.get("location"),
                _vars.get("Locations"),
                ", ".join(getattr(s, "aicb_sel_locations", []) or []),
            )

            _cn = camp.get("name", "Campaign")
            _last_send = _campaign_last_send_date(camp)
            _create_newsletter_dialog(s, rf, prefill={
                "name": f"{_cn} - Monthly Newsletter",
                "sector_key": _sec_key,
                "niche": _niche,
                "region": _region,
                "contacts": camp.get("contacts", []) or [],
                "source_campaign_name": _cn,
                "start_after": _last_send.isoformat() if _last_send else "",
            })

        # Whole-card click target (no side button). User feedback 2026-05-20:
        # the "Create Newsletter →" pill was redundant — the entire card
        # describes the same action, so the whole card is the affordance now.
        # A small arrow on the right hints at its actionable nature.
        with ui.element("div").style(
                f"background:{C['indigo']}10;border:1px solid {C['indigo']}40;"
                f"border-left:3px solid {C['indigo']};"
                f"border-radius:0 10px 10px 0;padding:14px 18px;margin-bottom:16px;"
                f"display:flex;align-items:center;justify-content:space-between;"
                f"gap:14px;flex-wrap:wrap;cursor:pointer;"
                f"transition:background .15s ease, border-color .15s ease;"
                ).on("click", _spin_up_from_launch):
            with ui.element("div").style("flex:1;min-width:240px;pointer-events:none;"):
                ui.label("📰 Create a Newsletter from this campaign").style(
                    f"font-size:13px;font-weight:700;color:{C['indigo']};"
                    f"font-family:'Nunito',sans-serif;margin-bottom:2px;")
                ui.label(
                    "Your industry, niche, region, and contact list are "
                    "already set — turn this campaign into a monthly "
                    "branded newsletter in one click."
                ).style(
                    f"font-size:11px;color:{C['muted']};line-height:1.5;")
            ui.label("→").style(
                f"font-size:22px;font-weight:700;color:{C['indigo']};"
                f"flex-shrink:0;pointer-events:none;line-height:1;"
                f"padding-right:6px;")

        # Launch buttons
        with ui.element("div").style("display:flex;gap:12px;flex-wrap:wrap;align-items:center;"):
            def _save_camp():
                # Opt-out footer is always on now  -  flag kept for backwards compat.
                # Store owner email (str|None) so downstream builds a proper mailto header.
                camp["unsubscribe_email"] = camp.get("_owner_email") or None
                save_campaign(camp)
                ui.notify(f"✓ Sequence '{camp_name}' saved!", type="positive")
            with ui.element("button").classes("fd-gb").style(
                    f"border-color:{C['email_col']}40;padding:10px 22px;").on("click", _save_camp):
                ui.label("💾 Save Campaign")

            # Launch dialog  -  prompts for campaign name before launching
            _launch_state = {"dialog": None, "card": None, "in_flight": False}

            def _open_launch_dialog():
                if not contacts:
                    ui.notify("No contacts  -  go back and add a contact list.", type="warning")
                    return
                if _launch_state["dialog"]:
                    _launch_state["dialog"].open()
                    return
                with ui.dialog() as dlg, ui.card().style(
                        f"background:{C['card']};border:1px solid {C['border']};"
                        f"min-width:440px;padding:24px;border-radius:14px;") as _dlg_card:
                    _launch_state["card"] = _dlg_card
                    ui.label("Name Your Campaign").style(
                        f"font-size:18px;font-weight:700;color:{C['text_l']};"
                        f"font-family:'Nunito',sans-serif;margin-bottom:4px;")
                    ui.label("Give this campaign a name before launching.").style(
                        f"font-size:12px;color:{C['muted']};margin-bottom:16px;")
                    launch_name_inp = ui.input(
                        value=camp_name,
                        placeholder="Campaign name"
                    ).classes("fd-input").style("margin-bottom:16px;")

                    # Start-sending-on date picker. Defaults to TODAY
                    # since 2026-05-10. Previously defaulted to TOMORROW as
                    # a workaround for the silent-fire bug that hit
                    # Elizabeth's James Fisher campaign on 2026-04-25 —
                    # but that bug was fixed at the source in commit
                    # aca2963 (_roll_past_send_forward preserves today's
                    # date when only the time-of-day has passed; jitter +
                    # scheduler tick handle the actual fire moment).
                    # Multiple users reported their campaigns going out
                    # 1-2 days later than the wizard preview showed —
                    # root cause was this stale TOMORROW default
                    # systematically shifting all sends +1 day from what
                    # the preview computed (which uses date.today()).
                    # Weekend amplifies to +2.
                    _default_start = date.today().isoformat()
                    ui.label("Start sending on").classes("fd-fl").style("margin-bottom:4px;")
                    ui.label(
                        "Step 1 fires this day at its configured time. "
                        "Subsequent steps follow their delay_days from this date."
                    ).style(f"font-size:10px;color:{C['muted']};margin-bottom:6px;line-height:1.4;")
                    launch_start_inp = ui.input(
                        value=_default_start,
                        placeholder="YYYY-MM-DD"
                    ).style("width:100%;margin-bottom:6px;")
                    with launch_start_inp.add_slot('append'):
                        _menu_ref = {"m": None}
                        def _open_start_menu(mr=_menu_ref):
                            if mr["m"]:
                                mr["m"].open()
                        ui.icon('edit_calendar').on('click', _open_start_menu).classes('cursor-pointer')
                    with ui.menu().props('no-parent-event') as _start_menu:
                        _menu_ref["m"] = _start_menu
                        def _pick_start_date(e, inp=launch_start_inp, menu=_start_menu):
                            inp.set_value(e.value)
                            menu.close()
                        with ui.date(value=_default_start, on_change=_pick_start_date):
                            pass
                    ui.element("div").style("height:14px;")

                    # Daily send limit warning
                    _lcfg = load_config()
                    _daily_lim = _lcfg.get("daily_send_limit", 250)
                    _email_steps = [st for st in steps if st.get("step_type", "") in (ST.EMAIL_AUTO, ST.EMAIL_MANUAL, "email", "")]
                    # How many emails would queue for day 1 (delay_days=0)?
                    _day1_steps = sum(1 for st in _email_steps if st.get("delay_days", 0) == 0)
                    _day1_volume = _day1_steps * len(active_contacts)
                    if _day1_volume > _daily_lim:
                        with ui.element("div").style(
                                f"padding:10px 14px;background:{C['warn']}10;border:1px solid {C['warn']}30;"
                                f"border-radius:8px;margin-bottom:14px;display:flex;align-items:flex-start;gap:8px;"):
                            ui.label("⚠").style("font-size:14px;flex-shrink:0;margin-top:1px;")
                            ui.label(
                                f"This campaign will queue {_day1_volume} emails on day 1, but your daily "
                                f"limit is {_daily_lim}/day. Overflow emails will automatically send the "
                                f"next business day. You can adjust this in Email & AI Setup."
                            ).style(f"font-size:11px;color:{C['warn']};line-height:1.5;")
                    elif _day1_volume > _daily_lim * 0.8:
                        with ui.element("div").style(
                                f"padding:10px 14px;background:{C['warn']}08;border:1px solid {C['warn']}20;"
                                f"border-radius:8px;margin-bottom:14px;display:flex;align-items:center;gap:8px;"):
                            ui.label(
                                f"{_day1_volume} emails queued for day 1 (limit: {_daily_lim}/day)"
                            ).style(f"font-size:11px;color:{C['muted']};")

                    with ui.element("div").style("display:flex;gap:10px;justify-content:flex-end;"):
                        ui.button("Cancel", on_click=dlg.close).props("flat").style(
                            f"color:{C['muted']};font-family:inherit;")
                        async def _confirm_launch():
                            # Async because PDF generation makes 4 sequential
                            # Anthropic API calls (~30-60s total). Running
                            # that synchronously blocked the asyncio event
                            # loop and killed NiceGUI's WebSocket heartbeat,
                            # producing the "Connection lost. Trying to
                            # reconnect..." banner that users reported on
                            # 2026-05-10 / 2026-05-11. Heavy work is now
                            # offloaded to a thread pool via run_in_executor
                            # so the loop stays responsive.
                            new_name = launch_name_inp.value.strip()
                            if not new_name:
                                ui.notify("Enter a sequence name.", type="warning")
                                return
                            # Validate the picked start date — accept ISO,
                            # refuse past dates so the user can't accidentally
                            # blast emails for days they've already missed.
                            _picked = (launch_start_inp.value or "").strip()
                            try:
                                _picked_dt = date.fromisoformat(_picked)
                            except Exception:
                                ui.notify("Invalid start date — use YYYY-MM-DD.", type="warning")
                                return
                            if _picked_dt < date.today():
                                ui.notify(
                                    f"Start date {_picked} is in the past. "
                                    f"Pick today or a future date.",
                                    type="warning",
                                )
                                return
                            # ── Active Clients gate ────────────────────────
                            # If any contacts are at protected clients AND
                            # the user hasn't already made a per-launch
                            # decision, block the launch and surface the
                            # warning. queue_campaign_emails will silently
                            # filter at queue time otherwise — better to
                            # confront the user explicitly so they can
                            # consciously choose Skip vs Send-Anyway.
                            try:
                                _ac_block = load_client_blocklist()
                                _ac_flagged = (
                                    blocklisted_contacts(contacts, _ac_block)
                                    if _ac_block else []
                                )
                            except Exception:
                                _ac_flagged = []
                            if _ac_flagged and not (camp.get("_ac_decision") or "").strip():
                                _n_flagged = len(_ac_flagged)
                                _by_dom_l: dict = {}
                                for _fc, _fe in _ac_flagged:
                                    _fdom = _normalize_domain(_fe.get("domain", "")) or _fe.get("domain", "")
                                    _fcname = (_fe.get("client_name", "") or "").strip()
                                    _b = _by_dom_l.setdefault(_fdom, {"name": _fcname, "count": 0})
                                    _b["count"] += 1
                                    if _fcname and not _b["name"]:
                                        _b["name"] = _fcname
                                _kept = max(0, len(contacts) - _n_flagged)
                                with ui.dialog() as _ac_dlg, ui.card().style(
                                        f"background:{C['card']};border:1px solid {C['danger']}60;"
                                        f"min-width:480px;max-width:580px;padding:24px 28px;"):
                                    ui.label(
                                        f"⚠ {_n_flagged} contact"
                                        f"{'s' if _n_flagged != 1 else ''} at active clients"
                                    ).style(
                                        f"font-size:18px;font-weight:800;color:{C['danger']};"
                                        f"font-family:'Nunito',sans-serif;margin-bottom:6px;")
                                    ui.label(
                                        "These contacts work at companies on your team's "
                                        "Active Clients list. Pick how to handle them before "
                                        "launching."
                                    ).style(
                                        f"font-size:12px;color:{C['muted']};line-height:1.5;"
                                        f"margin-bottom:14px;")
                                    with ui.element("div").style(
                                            f"background:{C['surface']};border:1px solid {C['border']};"
                                            f"border-radius:8px;padding:10px 14px;margin-bottom:18px;"
                                            f"max-height:160px;overflow-y:auto;"):
                                        for _bd, _bi in sorted(
                                                _by_dom_l.items(),
                                                key=lambda kv: (-kv[1]["count"], kv[0]))[:10]:
                                            with ui.element("div").style(
                                                    "display:flex;align-items:center;"
                                                    "justify-content:space-between;padding:3px 0;"):
                                                ui.label(_bi["name"] or _bd).style(
                                                    f"font-size:12px;color:{C['text_l']};"
                                                    f"font-weight:600;")
                                                ui.label(
                                                    f"{_bi['count']} contact"
                                                    f"{'s' if _bi['count'] != 1 else ''} ({_bd})"
                                                ).style(
                                                    f"font-size:11px;color:{C['muted']};"
                                                    f"font-family:monospace;")
                                    with ui.element("div").style(
                                            "display:flex;flex-wrap:wrap;justify-content:flex-end;"
                                            "gap:8px;align-items:center;"):
                                        with ui.element("button").classes("fd-gb").style(
                                                "padding:8px 16px;font-size:12px;").on(
                                                "click", _ac_dlg.close):
                                            ui.label("← Cancel launch")

                                        async def _decide_skip():
                                            camp["_ac_decision"] = "skip"
                                            _ac_dlg.close()
                                            ui.notify(
                                                f"✓ {_n_flagged} active-client contact"
                                                f"{'s' if _n_flagged != 1 else ''} will be skipped.",
                                                type="positive", timeout=3500)
                                            await _confirm_launch()
                                        with ui.element("button").classes("fd-pb").style(
                                                "padding:8px 18px;font-size:12px;font-weight:700;"
                                                ).on("click", _decide_skip):
                                            ui.label(f"Skip {_n_flagged} — Launch with {_kept} →")

                                        async def _decide_send_all():
                                            camp["_ac_decision"] = "send_all"
                                            _ac_dlg.close()
                                            ui.notify(
                                                f"⚠ Sending to ALL {len(contacts)} contacts including "
                                                f"{_n_flagged} active-client contact"
                                                f"{'s' if _n_flagged != 1 else ''}.",
                                                type="warning", timeout=4500)
                                            await _confirm_launch()
                                        with ui.element("button").style(
                                                f"padding:8px 16px;font-size:12px;"
                                                f"background:transparent;border:1px solid {C['danger']}80;"
                                                f"color:{C['danger']};border-radius:8px;cursor:pointer;"
                                                f"font-family:inherit;font-weight:600;"
                                                ).on("click", _decide_send_all):
                                            ui.label("Send to them anyway")
                                _ac_dlg.open()
                                return
                            # Double-click guard. The button stays in the
                            # dialog during the entire async run; without
                            # this a second click would queue a second
                            # _confirm_launch and double-fire everything.
                            if _launch_state.get("in_flight"):
                                return
                            _launch_state["in_flight"] = True

                            # Swap the dialog content to a "Generating…"
                            # view so the user sees obvious progress
                            # instead of a frozen-looking form (the heavy
                            # PDF + queue work takes ~30-60s). The dialog
                            # auto-closes when the async work finishes and
                            # the user lands on the launch summary.
                            try:
                                _card = _launch_state.get("card")
                                if _card is not None:
                                    _card.clear()
                                    with _card:
                                        with ui.element("div").style(
                                                "display:flex;flex-direction:column;"
                                                "align-items:center;gap:14px;"
                                                "padding:18px 6px;min-width:380px;"):
                                            ui.spinner(size="44px", color=C["teal"])
                                            ui.label("Generating your campaign…").style(
                                                f"font-size:17px;font-weight:700;"
                                                f"color:{C['text_l']};"
                                                f"font-family:'Nunito',sans-serif;")
                                            ui.label(
                                                "Claude is building your sales assets and "
                                                "scheduling the email queue. This usually "
                                                "takes 30 to 60 seconds — please don't "
                                                "close this tab."
                                            ).style(
                                                f"font-size:12px;color:{C['muted']};"
                                                f"line-height:1.5;text-align:center;"
                                                f"max-width:340px;")
                            except Exception:
                                pass

                            camp["name"] = new_name
                            camp["status"] = "active"
                            camp["start_date"] = _picked_dt.isoformat()
                            # Always-on opt-out footer (CAN-SPAM). Store owner email
                            # (str|None) so downstream builds a proper mailto header.
                            camp["unsubscribe_email"] = camp.get("_owner_email") or None
                            save_campaign(camp)
                            # Auto-generate PDFs and attach to matching steps.
                            # Offloaded to a thread because _generate_squeeze_pdfs
                            # makes 4 sequential Anthropic calls (~30-60s) and
                            # was blocking the asyncio loop, killing the
                            # WebSocket connection mid-launch.
                            _loop = asyncio.get_event_loop()
                            try:
                                v = {"TargetRole": camp.get("variables", {}).get("TargetRole", ""),
                                     "CompanyName": camp.get("variables", {}).get("CompanyName", new_name),
                                     "Geography": camp.get("variables", {}).get("Geography", "")}
                                if v["TargetRole"]:
                                    await _loop.run_in_executor(
                                        None, _generate_squeeze_pdfs, v
                                    )
                                    _slug = v.get("_pdf_slug", "Campaign")
                                    _mp = f"Market_Pulse_{_slug}.pdf"
                                    _sc = f"Role_Scorecard_{_slug}.pdf"
                                    _tn = f"Tenure_Snapshot_{_slug}.pdf"
                                    # Auto-attach PDFs across email steps in order
                                    _pdf_q = [_mp, _sc, _tn]
                                    _qi = 0
                                    for ei, em in enumerate(steps):
                                        if _qi >= len(_pdf_q):
                                            break
                                        if ei == 0:
                                            continue
                                        if em.get("step_type", "") not in ("email_auto", "email", ST.EMAIL_AUTO):
                                            continue
                                        if em.get("attachments"):
                                            continue
                                        em["attachments"] = [_pdf_q[_qi]]
                                        _qi += 1
                                    save_campaign(camp)
                            except Exception:
                                pass  # non-fatal
                            # queue_campaign_emails can raise ValueError if
                            # the placeholder guard finds unfilled tokens
                            # ([CANDIDATE NAME] etc.) in any email body.
                            # Surface it as a notify instead of letting the
                            # exception bubble up (NiceGUI propagates
                            # unhandled handler errors and that disconnects
                            # the websocket — user sees 'Reconnecting to
                            # DripDrop...' instead of a useful message).
                            # Also offloaded to thread for safety even
                            # though queue_campaign_emails is mostly file I/O.
                            try:
                                count = await _loop.run_in_executor(
                                    None, queue_campaign_emails, camp
                                )
                            except ValueError as _ve:
                                try:
                                    ui.notify(str(_ve)[:300], type="negative", timeout=10000)
                                except Exception:
                                    pass
                                # Reset state + close the dialog. The cached
                                # _launch_state["dialog"] is now stale (we
                                # rebuilt its card content to the spinner
                                # view); drop the cache so the next launch
                                # attempt builds a fresh dialog.
                                _launch_state["in_flight"] = False
                                _launch_state["dialog"] = None
                                _launch_state["card"] = None
                                try:
                                    dlg.close()
                                except Exception:
                                    pass
                                return
                            except Exception as _le:
                                print(f"[Launch] queue_campaign_emails failed: {_le}", flush=True)
                                try:
                                    ui.notify(f"Launch failed: {str(_le)[:200]}",
                                              type="negative", timeout=10000)
                                except Exception:
                                    pass
                                _launch_state["in_flight"] = False
                                _launch_state["dialog"] = None
                                _launch_state["card"] = None
                                try:
                                    dlg.close()
                                except Exception:
                                    pass
                                return
                            # Enroll into all selected evergreen campaigns.
                            # 2026-05-25 — wrapped each ui.notify in
                            # try/except. Prior bug: when the page slot
                            # had been deleted (user navigated, dialog
                            # rebuilt to spinner view, etc.), the notify
                            # raised RuntimeError 'parent slot deleted'
                            # which killed the background task before the
                            # final state reset + summary transition
                            # below ran. Result: spinner frozen forever.
                            if _eg_selected:
                                try:
                                    all_eg = load_campaigns()
                                    for eg_name in _eg_selected:
                                        eg_target = next((c for c in all_eg if c.get("name") == eg_name), None)
                                        if eg_target:
                                            enrolled = sum(1 for ct in contacts
                                                           if enroll_contact_in_evergreen(ct, eg_target) == "enrolled")
                                            if enrolled:
                                                try:
                                                    ui.notify(f"✓ {enrolled} contact{'s' if enrolled!=1 else ''} added to "
                                                              f"'{eg_name}'", type="positive", timeout=4000)
                                                except Exception:
                                                    pass
                                except Exception as _ee:
                                    print(f"[Launch] eg-enroll failed: {_ee}", flush=True)
                            # Final state reset + summary transition.
                            # Wrapped so any failure here still flips
                            # in_flight=False (otherwise a future launch
                            # is silently blocked by the double-click guard).
                            try:
                                dlg.close()
                            except Exception:
                                pass
                            # Drop the cached dialog — its card now holds
                            # the spinner view, not the form. A future
                            # launch must build a fresh one.
                            _launch_state["in_flight"] = False
                            _launch_state["dialog"] = None
                            _launch_state["card"] = None
                            try:
                                s.launch_result = dict(
                                    name=new_name, count=count, contacts=len(contacts),
                                    emails=len(steps), steps=copy.deepcopy(steps),
                                    contact_preview=contacts[:10],
                                    start_date=camp.get("start_date", date.today().isoformat()),
                                    launched_at=datetime.now().strftime("%I:%M %p").lstrip("0"),
                                )
                                s.loaded_view = "summary"
                                rf()
                            except Exception as _fe:
                                print(f"[Launch] summary transition failed: {_fe}", flush=True)
                        with ui.element("button").classes("fd-pb").style(
                                f"padding:10px 24px;font-size:14px;background:{C['good']};").on(
                                "click", _confirm_launch):
                            ui.label(f"🚀 Launch Campaign")
                _launch_state["dialog"] = dlg
                dlg.open()

            if contacts:
                launch_label = (f"🚀 Launch  -  {len(active_contacts)} contact{'s' if len(active_contacts)!=1 else ''}"
                                + (f"  (skipping {len(contacts)-len(active_contacts)} responded)" if len(contacts) != len(active_contacts) else ""))
                with ui.element("button").classes("fd-pb").style(
                        f"padding:12px 28px;font-size:14px;background:{C['good']};").on("click", _open_launch_dialog):
                    ui.label(launch_label)
            else:
                with ui.element("div").style(
                        f"padding:10px 18px;border-radius:8px;background:{C['danger']}15;"
                        f"border:1px solid {C['danger']}40;"):
                    ui.label("⚠ Add contacts before launching").style(
                        f"font-size:12px;color:{C['danger']};font-weight:500;")

    # ── Bottom "Next: <step> →" button (2026-05-23) ──────────────────────
    # User feedback: long emails / sequences / contacts views forced users
    # to scroll back up to the breadcrumb to advance. This mirrors the top
    # Next button at the bottom of every non-launch view so the forward
    # action is always one click away. Launch view skips it (its own
    # Launch button IS the forward action).
    if cur_idx < len(LOADED_STEPS) - 1:
        def _next_step_bottom():
            s.loaded_view = LOADED_STEPS[cur_idx + 1][0]; rf()
        with ui.element("div").style(
                "display:flex;justify-content:flex-end;margin-top:28px;"
                "padding-top:18px;border-top:1px solid var(--fd-border, #2A3654);"):
            with ui.element("button").classes("fd-pb").style(
                    "padding:10px 24px;font-size:14px;").on(
                    "click", _next_step_bottom):
                ui.label(f"Next: {LOADED_STEPS[cur_idx + 1][1]} →")


def _sq_campaign_wizard_header(s: AppState, rf):
    """Wizard progress header for the Start a Campaign flow (templates + custom).

    Also renders a "neutral" preview header when no tab is picked yet (the
    landing/picker screen) so users always see where they are in the flow.
    """

    # Determine which step type we're in
    is_custom    = s._tab == "custom"
    is_templates = s._tab == "templates"
    is_intro     = not (is_custom or is_templates)  # picker / no flow chosen

    # ── Step definitions ──────────────────────────────────────────────────
    if is_intro:
        # Generic 4-step preview shown on the type-picker screen so the
        # user sees the whole journey before committing to a flow. Steps
        # aren't clickable yet — they're a preview, not a navigator.
        steps = [
            ("pick",     "✦", "Choose Type",       "Pick how you want to build this sequence — template, from scratch, or saved."),
            ("prompts",  "✎", "Personalise",       "Tell Claude about the role, market, and company so it can write targeted emails."),
            ("contacts", "👥","Add Contacts",       "Import a CSV or pick a saved list."),
            ("launch",   "🚀","Review & Launch",   "Generate the emails, review the sequence, then fire."),
        ]
        cur_idx = 0
    elif is_templates:
        steps = [
            ("pick",     "✦", "Choose Template",  "Pick a pre-built sequence  -  Long-Game Nurture, Quick Sprint, Candidate-Led Pitch, and more."),
            ("prompts",  "✎", "Personalise",       "Tell Claude about the role, market, and company so it can write targeted emails."),
            ("contacts", "👥","Add Contacts",       "Import a CSV or pick a saved list  -  contacts preview instantly."),
            ("launch",   "🚀","Review & Launch",    "Check everything looks right, then fire the campaign."),
        ]
        cur_idx = (0 if s.sq == 1
                   else 1 if s.sq == 2
                   else 2 if s.sq == 3 and not s.sq_review
                   else 3)
    else:  # custom
        steps = [
            ("build",    "✦", "Build Steps",        "Add emails, calls, LinkedIn touches  -  build the sequence your way."),
            ("sequence", "⏱", "Set Sequence",         "Set delays between each step so they go out at the right pace."),
            ("contacts", "👥","Add Contacts",         "Import a CSV or pick a saved list  -  contacts preview instantly."),
            ("launch",   "🚀","Review & Launch",      "Check everything looks right, then fire the campaign."),
        ]
        # custom maps sq=1 → build, loaded_view="sequence"→1, "contacts"→2, "launch"→3
        if s.loaded_camp:
            lv = s.loaded_view or "emails"
            cur_idx = (1 if lv == "sequence"
                       else 2 if lv == "contacts"
                       else 3 if lv in ("launch","summary")
                       else 0)
        else:
            cur_idx = 0

    tip = steps[cur_idx][3]

    with ui.element("div").style(
            f"background:{C['surface']};border:1px solid {C['border']};"
            f"border-radius:12px;padding:14px 20px;margin-bottom:20px;"):

        # Step pills row  -  clickable for completed + current steps
        # (intro mode: nothing clickable; pills are just a preview)
        with ui.element("div").style("display:flex;align-items:center;gap:0;"):
            for i, (key, icon, label, _) in enumerate(steps):
                is_done    = i < cur_idx
                is_current = i == cur_idx
                can_click  = (is_done or is_current) and not is_intro
                col  = C["teal"] if is_current else (C["good"] if is_done else C["muted"])
                bg   = f"{C['teal']}20" if is_current else (f"{C['good']}15" if is_done else "transparent")
                bord = C["teal"] if is_current else (C["good"] if is_done else C["border"])
                pfx  = "✓" if is_done else icon

                def _jump_step(idx=i, k=key):
                    if is_templates:
                        # Template flow: pick=sq1, prompts=sq2, contacts=sq3, launch=sq3+review
                        if idx == 0:
                            s.sq = 1; s.sq_review = False
                            s.loaded_camp = None; s.loaded_view = None
                        elif idx == 1:
                            s.sq = 2; s.sq_review = False
                        elif idx == 2:
                            s.sq = 3; s.sq_review = False
                        elif idx == 3:
                            s.sq = 3; s.sq_review = True
                    else:
                        # Custom flow: build=no loaded, sequence/contacts/launch via loaded_view
                        if idx == 0:
                            s.loaded_camp = None; s.loaded_view = None
                        elif s.loaded_camp:
                            view_map = {1: "sequence", 2: "contacts", 3: "launch"}
                            s.loaded_view = view_map.get(idx, "sequence")
                    rf()

                # Cursor + opacity rules: clickable pills get pointer; the
                # current pill stays at full opacity even when not clickable
                # (intro mode); future/unreachable pills get dimmed.
                if can_click:
                    cursor = "cursor:pointer;"
                elif is_current:
                    cursor = "cursor:default;"
                else:
                    cursor = "cursor:default;opacity:0.6;"
                with ui.element("button").style(
                        f"display:inline-flex;align-items:center;gap:6px;"
                        f"padding:7px 16px;border-radius:99px;font-size:12px;font-weight:600;"
                        f"font-family:'Nunito','DM Sans',sans-serif;"
                        f"background:{bg};border:1px solid {bord};color:{col};"
                        f"white-space:nowrap;transition:all .15s;{cursor}"
                        ).on("click", _jump_step if can_click else lambda: None):
                    ui.label(pfx).style(f"font-size:11px;pointer-events:none;")
                    ui.label(f"{i+1}. {label}").style("pointer-events:none;")

                if i < len(steps) - 1:
                    line_col = C["good"] if i < cur_idx else C["border"]
                    ui.element("div").style(
                        f"flex:1;height:1px;background:{line_col};margin:0 4px;min-width:12px;")

        # Progress bar
        pct = int((cur_idx / (len(steps) - 1)) * 100)
        with ui.element("div").style(
                f"height:3px;background:{C['border']};border-radius:99px;"
                f"overflow:hidden;margin-top:12px;"):
            ui.element("div").style(
                f"height:3px;width:{pct}%;background:{C['teal']};"
                f"border-radius:99px;transition:width .4s;")

        # Coaching tip
        with ui.element("div").style(
                "display:flex;align-items:flex-start;gap:10px;margin-top:10px;"):
            ui.label("💡").style("font-size:13px;flex-shrink:0;margin-top:1px;")
            ui.label(tip).style(f"font-size:12px;color:{C['muted']};line-height:1.6;")


def p_seq(s: AppState, rf):
    _render_page_intro_strip(s, rf, "start_seq")
    # If a saved campaign is loaded, show the campaign viewer
    if s.loaded_camp or (s.loaded_view == "summary" and s.launch_result):
        _sq_loaded_campaign(s, rf)
        return

    _page_decor(variant=1)  # Flowing Ribbon  -  the main Start a Campaign picker

    with ui.element("div").style("display:flex;align-items:center;"):
        ui.label("Start a Sequence").classes("fd-h1")
        _show_page_help(s, rf, "start_seq")

    # ── Wizard header ────────────────────────────────────────────────────
    # Always shown for templates/custom flows AND for the intro picker
    # (so users see "Step 1 of 4" before they even pick a flow). The
    # saved/community flow uses a simpler 3-step text indicator.
    if s._tab in ("templates", "custom") or not s._tab:
        _sq_campaign_wizard_header(s, rf)
    elif s._tab and s.sq > 1:
        # simple text fallback for saved/community
        labels = ["Pick campaign", "Fill prompts", "Choose contacts"]
        with ui.element("div").style("display:flex;gap:8px;align-items:center;margin-bottom:16px;"):
            for i, l in enumerate(labels, 1):
                cur = s.sq if not s.sq_review else 4
                ws = "done" if cur > i else ("active" if cur == i else "pending")
                ui.label(f"{'✓ ' if ws=='done' else str(i)+'. '}{l}").classes(f"fd-ws {ws}")
                if i < len(labels):
                    ui.label("›").style(f"color:{C['border']};font-size:16px;")
        ui.element("div").style(f"height:1px;background:{C['border']};margin-bottom:20px;")

    if s.sq == 1:
        _sq_pick(s, rf)
    elif s.sq == 2:
        _sq_prompts(s, rf)
    elif s.sq == 3:
        if s.sq_review:
            _sq_review_split(s, rf)
        else:
            _sq_contacts(s, rf)
    else:
        # Invalid state  -  reset to step 1
        s.sq = 1; _sq_pick(s, rf)

STEP_TYPE_OPTIONS = [
    (ST.EMAIL_AUTO,   "✉ Email",        C["email_col"]),
    (ST.CALL,         "☎ Phone Call",   C["call_col"]),
    (ST.LINKEDIN,     "in LinkedIn",    C["indigo"]),
    (ST.SMS,          "msg SMS",        C["sms_col"]),
    (ST.TASK,         "✓ Task",         C["task_col"]),
]

def _sq_pick(s, rf):
    """Landing: pick a sequence type  -  legacy-style big cards then into content."""

    # ── Strategy Chooser — 5 starting places ──────────────────────────────
    if not s._tab:
        # Resume-draft banner removed 2026-05-11 per user feedback. The
        # autosave continues silently in the background; in-progress
        # wizards now surface under the "Drafts & Saved" card instead
        # of a separate top-of-page banner.
        ui.label("Choose a Sequence Type").style(
            f"font-size:20px;font-weight:700;color:{C['text_l']};margin-bottom:8px;"
            f"font-family:'Nunito',sans-serif;")
        ui.label(
            "Every sequence starts here. Pick the option that matches "
            "what you're trying to do today, and the next page will walk "
            "you through the rest. Not sure? Read the description on each "
            "card — the icon color hints at the type of outreach. You can "
            "always change direction or come back to this page later."
        ).style(
            f"font-size:13px;color:{C['muted']};margin-bottom:6px;line-height:1.55;")
        ui.label(
            "Going to a single company? Pick Target a Company. "
            "Working a vertical or region? Target a Market. "
            "Working a specific role? Find Candidates. "
            "Re-running something that worked? Campaign Library. "
            "Want full manual control? Build from scratch."
        ).style(
            f"font-size:12px;color:{C['muted']};margin-bottom:24px;line-height:1.55;"
            f"font-style:italic;")

        CHOOSER_OPTIONS = [
            {
                "key": "client",
                "icon": "🎯",
                "title": "Target a Company",
                "subtitle": "Land a specific account",
                "desc": ("AI deep-research on a single named company. Reads their open roles, "
                         "recent news, and project pipeline. Generates a hyper-personalized "
                         "7-week sequence aimed at one specific company."),
                "best_for": ["Named accounts", "Account expansion", "Single-target outreach"],
                "border": C["teal"],
            },
            {
                "key": "market",
                "icon": "📊",
                "title": "Target a Market",
                "subtitle": "Cover an industry or region",
                "desc": ("Build a sequence template for a market segment. Pick an industry, "
                         "region, and role family. Reusable across many similar companies. "
                         "Best for prospect-list campaigns."),
                "best_for": ["Industry plays", "Regional sweeps", "Bulk outreach"],
                "border": "#A78BFA",
            },
            {
                "key": "candidate",
                "icon": "👤",
                "title": "Find Candidates",
                "subtitle": "Build outreach for a role you're filling",
                "desc": ("Guided wizard. Optionally paste a job description, then pick "
                         "a cadence. AI generates outreach tuned to the role and drops "
                         "you in the email editor where you can add the candidates "
                         "you've sourced on your own."),
                "best_for": ["Specific role hiring", "Candidate placement", "MPC outreach"],
                "border": "#F472B6",
            },
            {
                "key": "mpc",
                "icon": "⭐",
                "title": "Start with an MPC",
                "subtitle": "Most Placeable Candidate — pitch them to fitting companies",
                "desc": ("Pick a candidate from your Top Candidates roster. AI "
                         "builds a 5-step placement outreach targeting hiring managers "
                         "at relevant companies and drops you straight in the email "
                         "editor — no in-between review page."),
                "best_for": ["Hot candidates", "Direct-hire placement", "Candidate-first outreach"],
                "border": "#34D399",
            },
            {
                "key": "fourbyfour",
                "icon": "⚡",
                "title": "Arena 4×4",
                "subtitle": "Market a 4–5 candidate slate to companies hiring your role",
                "desc": ("Pick an anchor candidate (matches a real advertised role) plus "
                         "3–4 supporting profiles. AI builds the 4-email cadence — role "
                         "intro, market insights, proven results, market trends — with "
                         "live BLS stats and full candidate highlights."),
                "best_for": ["Slate outreach", "Hot roles", "Team playbook"],
                "border": "#7C3AED",
            },
            {
                "key": "saved",
                "icon": "📁",
                "title": "Campaign Library",
                "subtitle": "Resume a draft or re-use a finished sequence",
                "desc": ("Pick up a draft you started earlier, or load a sequence "
                         "from your library. Swap in a fresh contact list and send. "
                         "Fast path for repeat outreach and unfinished work."),
                "best_for": ["Resume drafts", "Repeat outreach", "Proven cadences"],
                "border": "#60A5FA",
            },
            {
                "key": "scratch",
                "icon": "✏️",
                "title": "Build from scratch",
                "subtitle": "Build your own with AI assistance",
                "desc": ("Open the AI Guided Sequence Builder. Add steps "
                         "(email, LinkedIn, call, SMS, task) in any order, drag "
                         "to reorder, and give AI direction OR write each step "
                         "yourself — AI polishes either way."),
                "best_for": ["Hand-crafted outreach", "Personal voice", "Non-standard cadences"],
                "border": "#F59E0B",
            },
        ]

        with ui.element("div").style("display:flex;flex-direction:column;gap:10px;max-width:860px;"):
            for opt in CHOOSER_OPTIONS:
                key = opt["key"]
                def _pick(k=key):
                    if k == "client":
                        s._nav_history.append(_nav_snapshot(s))
                        _reset_wizard_state(s)
                        s._chooser_origin = "client"
                        s.aicb_camp_type = "blitz"
                        s.sp = "ai_campaign"
                        s.aicb_step = 1
                        # Chooser already asked "client vs market" — pre-set
                        # aicb_target_mode and skip past the wizard's redundant
                        # "Pick who you're targeting" step. Land on Step 2
                        # (Target details) directly.
                        s.aicb_target_mode = "company"
                        s.aicb_wizard_step = 2
                        s.aicb_type_picked = True
                        s.aicb_contacts = []
                    elif k == "market":
                        s._nav_history.append(_nav_snapshot(s))
                        _reset_wizard_state(s)
                        s._chooser_origin = "market"
                        s.aicb_camp_type = "talentdrop"
                        s.sp = "ai_campaign"
                        s.aicb_step = 1
                        # Same logic as 'client' — chooser already covered
                        # this question; skip the AICB picker.
                        s.aicb_target_mode = "market"
                        s.aicb_wizard_step = 2
                        s.aicb_type_picked = True
                        s.aicb_contacts = []
                    elif k == "candidate":
                        _reset_wizard_state(s)
                        s.tc_step = 0
                        s.tc_jd_text = ""
                        s.tc_jd_parsed = {}
                        s.tc_candidates = []
                        s.tc_contacts = []
                        app.storage.user.pop("_pending_campaign_contacts", None)
                        s.tc_preset = ""
                        s.sp = "target_candidate"
                    elif k == "mpc":
                        # Most Placeable Candidate flow: candidates now live
                        # in the Pipeline (ATS) as of 2026-06-09. Route
                        # allowlisted users straight to the Pipeline to pick
                        # candidate(s); the ATS per-row / multi-select "Start
                        # an MPC Campaign" button hands the slate back to the
                        # MPC builder and lands them in the email editor.
                        # Non-ATS users (/ats bounces them to /) keep the
                        # legacy Top Candidates roster fallback.
                        _ue = (getattr(s, "_user_email", "") or "").strip().lower()
                        if _ue in _ATS_ALLOWED_EMAILS:
                            ui.navigate.to("/ats")
                            return
                        s._nav_history.append(_nav_snapshot(s))
                        _reset_wizard_state(s)
                        s.cpc_mode = "mpc"
                        s.sp = "candidate_finder"
                    elif k == "fourbyfour":
                        # Arena 4×4 — straight into the AI campaign builder with the
                        # 4×4 style pre-selected. No Top Candidates roster.
                        s._nav_history.append(_nav_snapshot(s))
                        _reset_wizard_state(s)
                        s._chooser_origin = "fourbyfour"
                        s.aicb_camp_type = "fourbyfour"
                        # The 4×4 is a fixed cadence — the user already chose
                        # the style by picking this tile, so lock it and skip
                        # the wizard's Campaign Style step (no re-asking).
                        s.aicb_style_locked = True
                        s.sp = "ai_campaign"
                        s.aicb_step = 1
                        s.aicb_target_mode = "market"
                        s.aicb_wizard_step = 2
                        s.aicb_type_picked = True
                        s.aicb_contacts = []
                    elif k == "saved":
                        _reset_wizard_state(s)
                        s._tab = "saved"
                    elif k == "scratch":
                        # 2026-05-23: Custom Build now lands on the
                        # AI Guided Sequence Builder (s.sp = "seq_builder")
                        # instead of the old textarea-only _sq_custom_builder.
                        # Old path stays in the file for any deep-link
                        # to ?tab=custom.
                        _reset_wizard_state(s)
                        s.sp = "seq_builder"
                        # Don't set _tab; the page handler reads sb_* state.
                    rf()
                with ui.element("div").style(
                        f"background:{C['card']};border:1px solid {opt['border']}60;"
                        f"border-left:4px solid {opt['border']};"
                        f"border-radius:0 12px 12px 0;padding:18px 20px;"
                        f"cursor:pointer;transition:background .15s;"
                        ).on("click", _pick):
                    with ui.element("div").style("display:flex;align-items:flex-start;gap:16px;"):
                        # Icon badge
                        with ui.element("div").style(
                                f"width:44px;height:44px;border-radius:10px;"
                                f"background:{opt['border']}22;border:1px solid {opt['border']}60;"
                                f"display:flex;align-items:center;justify-content:center;flex-shrink:0;"):
                            ui.label(opt["icon"]).style("font-size:20px;")
                        with ui.element("div").style("flex:1;min-width:0;"):
                            with ui.element("div").style(
                                    "display:flex;align-items:center;gap:12px;margin-bottom:4px;"):
                                ui.label(opt["title"]).style(
                                    f"font-size:15px;font-weight:700;color:{opt['border']};"
                                    f"font-family:'Nunito',sans-serif;")
                                ui.label(opt["subtitle"]).style(
                                    f"font-size:12px;color:{C['muted']};")
                            ui.label(opt["desc"]).style(
                                f"font-size:12px;color:{C['text']};line-height:1.6;margin-bottom:4px;")
                            with ui.element("div").style(
                                    "display:flex;align-items:center;gap:6px;flex-wrap:wrap;"):
                                ui.label("Best for:").style(f"font-size:11px;color:{C['muted']};")
                                for tag in opt["best_for"]:
                                    ui.label(tag).style(
                                        f"font-size:11px;color:{opt['border']};font-weight:500;")
                                    if tag != opt["best_for"][-1]:
                                        ui.label("·").style(
                                            f"font-size:11px;color:{C['muted']};")
                        ui.label("→").style(
                            f"font-size:20px;color:{opt['border']};font-weight:700;"
                            f"flex-shrink:0;align-self:center;")

        return

    # ── INSIDE A TAB  -  back button + tab label ──────────────────────────────
    label_map = {
        "custom":    "Build from scratch",
        "saved":     "Campaign Library",
        "community": "Community",
        "templates": "Templates",
    }
    with ui.element("div").style("display:flex;align-items:center;gap:12px;margin-bottom:20px;"):
        def _back_to_picker():
            _reset_wizard_state(s)
            s._tab = ""
            s.stpl = None
            rf()
        with ui.element("button").classes("fd-pb").style(
                "padding:9px 20px;font-size:13px;font-weight:700;"
                "border-radius:8px;").on("click", _back_to_picker):
            ui.label("\u2190 Back to Start a Campaign")
        ui.label(label_map.get(s._tab, "")).style(
            f"font-size:16px;font-weight:700;color:{C['text_l']};font-family:'Nunito',sans-serif;")

    # ── CUSTOM TAB ─────────────────────────────────────────────────────────
    if s._tab == "custom":
        _sq_custom_builder(s, rf)
        return

    # ── TEMPLATES TAB ────────────────────────────────────────────────────────
    if s._tab == "templates":
        for key, tpl in TEMPLATES.items():
            sel = s.stpl == key
            def _pick(k=key):
                s.stpl = k; s.custom_editing = False; rf()
            with ui.element("div").classes("fd-tc" + (" sel" if sel else "")).on("click", _pick):
                with ui.element("div").style("display:flex;align-items:center;justify-content:space-between;"):
                    ui.label(tpl["name"]).style(f"font-size:15px;font-weight:600;color:{C['text_l']};")
                    ui.label(tpl["description"]).style(f"font-size:12px;color:{C['teal']};")
                sts = [x.get("channel", "email") for x in tpl["steps"]]
                em = sum(1 for t in sts if t == "email"); cl = sts.count("call"); li = sts.count("li")
                with ui.element("div").style("display:flex;gap:10px;margin-top:10px;"):
                    if em: ui.label(f"✉ {em} emails").style(f"font-size:11px;color:{C['email_col']};")
                    if cl: ui.label(f"☎ {cl} call{'s' if cl > 1 else ''}").style(f"font-size:11px;color:{C['call_col']};")
                    if li: ui.label(f"in {li} LinkedIn").style(f"font-size:11px;color:{C['indigo']};")
                if sel and "months_data" in tpl:
                    _cum_day = 0

    # ── SAVED CAMPAIGNS TAB ────────────────────────────────────────────────
    elif s._tab == "saved":
        saved_camps = load_campaigns()
        saved_camps = [c for c in saved_camps
                       if not c.get("evergreen_only")
                       and c.get("emails")]
        # In-progress wizard draft surfaces here as a special entry so
        # users can pick up where they left off without us needing a
        # top-of-page Resume banner (removed 2026-05-11 per user
        # feedback). The wizard autosaves to a single per-user JSON;
        # if it exists, render it above the saved-campaigns list.
        _wiz_draft = _load_wizard_draft()
        if _wiz_draft:
            _wd_label = _wiz_draft.get("_label", "Untitled draft")
            try:
                _wd_saved_at = datetime.fromisoformat(_wiz_draft.get("_saved_at", ""))
                _wd_mins = max(1, int((datetime.now() - _wd_saved_at).total_seconds() / 60))
                _wd_ago = (f"{_wd_mins} min ago" if _wd_mins < 60
                           else f"{_wd_mins // 60} hr ago" if _wd_mins < 1440
                           else f"{_wd_mins // 1440} day(s) ago")
            except Exception:
                _wd_ago = "earlier"
            def _resume_wiz_draft(d=_wiz_draft):
                _restore_wizard_draft(s, d)
                # Force the editable wizard branch (aicb_step==2 = results
                # screen needs aicb_docs which isn't persisted — landing
                # there shows just the header). Clamp the internal step
                # and clear stale per-attempt state.
                s.aicb_step = 1
                s.aicb_wizard_step = _aicb_clamp_wizard_step(
                    getattr(s, "aicb_wizard_step", 1))
                s.aicb_docs = {}
                s.aicb_research = None
                s.aicb_analysis = {}
                s.aicb_auto_imported = False
                s.sp = "ai_campaign"
                rf()
            def _discard_wiz_draft():
                _clear_wizard_draft()
                rf()
            with ui.element("div").style(
                    f"background:{C['warn']}10;border:1px solid {C['warn']}40;"
                    f"border-left:3px solid {C['warn']};border-radius:0 10px 10px 0;"
                    f"padding:14px 18px;margin-bottom:14px;max-width:860px;"
                    f"display:flex;align-items:center;justify-content:space-between;"
                    f"gap:12px;flex-wrap:wrap;"):
                with ui.element("div").style("flex:1;min-width:200px;cursor:pointer;"
                        ).on("click", _resume_wiz_draft):
                    ui.label(f"📝 Draft in progress: {_wd_label}").style(
                        f"font-size:14px;font-weight:600;color:{C['warn']};"
                        f"font-family:'Nunito',sans-serif;")
                    ui.label(f"Saved {_wd_ago} · click to resume the wizard.").style(
                        f"font-size:11px;color:{C['muted']};margin-top:2px;")
                with ui.element("div").style("display:flex;gap:8px;flex-shrink:0;"):
                    with ui.element("span").style(
                            f"color:{C['danger']};cursor:pointer;font-size:11px;padding:4px 8px;"
                            f"border-radius:6px;border:1px solid {C['danger']}30;"
                            f"background:{C['danger']}10;"
                            ).on("click.stop", _discard_wiz_draft):
                        ui.label("Discard")
                    with ui.element("span").style(
                            f"color:{C['warn']};cursor:pointer;font-size:16px;font-weight:700;"
                            ).on("click", _resume_wiz_draft):
                        ui.label("→")
        if not saved_camps and not _wiz_draft:
            ui.label("No saved campaigns yet.").style(
                f"font-size:13px;color:{C['muted']};padding:20px 0;")
        elif not saved_camps:
            # Draft exists but no full saved campaigns — still skip the
            # sort/list block below.
            pass
        else:
            ui.label("Pick a saved campaign to re-use its sequence with new contacts.").style(
                f"font-size:13px;color:{C['muted']};margin-bottom:12px;")

            # Sort toggle — default to "recent" since users almost always
            # want to find the campaign they just worked on, not scroll
            # alphabetically. Mode persists on AppState so it survives
            # rerenders. Recency uses file mtime (set by save_campaign on
            # every write), which matches what users intuit as "recent".
            if not hasattr(s, "_saved_sort"):
                s._saved_sort = "recent"
            with ui.element("div").style(
                    "display:flex;align-items:center;gap:6px;margin-bottom:14px;max-width:860px;"):
                ui.label("Sort:").style(
                    f"font-size:11px;color:{C['muted']};font-weight:600;"
                    f"text-transform:uppercase;letter-spacing:.06em;margin-right:4px;")
                for _sk, _sl in [("recent", "Most Recent"), ("name", "A → Z")]:
                    _sac = (s._saved_sort == _sk)
                    def _set_sort(kk=_sk):
                        s._saved_sort = kk; rf()
                    with ui.element("button").style(
                            f"padding:5px 12px;border-radius:6px;cursor:pointer;"
                            f"font-size:11px;font-weight:600;font-family:inherit;"
                            f"background:{C['teal'] + '18' if _sac else 'transparent'};"
                            f"border:1px solid {C['teal'] if _sac else C['border']};"
                            f"color:{C['teal'] if _sac else C['muted']};"
                            ).on("click", _set_sort):
                        ui.label(_sl).style("pointer-events:none;")

            # Apply selected sort. file mtime is the right "recent" signal —
            # save_campaign() rewrites the file on every edit, so mtime
            # tracks "last modified" naturally. Falls back to 0 if the
            # file disappeared between load and sort (rare race).
            if s._saved_sort == "recent":
                def _mtime_of(_c):
                    try:
                        return Path(_c.get("_path", "")).stat().st_mtime
                    except Exception:
                        return 0.0
                saved_camps = sorted(saved_camps, key=_mtime_of, reverse=True)
            else:
                saved_camps = sorted(saved_camps, key=lambda _c: (_c.get("name", "") or "").lower())

            with ui.element("div").style("display:flex;flex-direction:column;gap:8px;max-width:860px;"):
                for c in saved_camps:
                    cname = c.get("name", "")
                    n_emails = len(c.get("emails", []))
                    n_contacts = len(c.get("contacts", []))
                    def _load_saved(camp=c):
                        s._nav_history.append(_nav_snapshot(s))
                        s.loaded_camp = camp
                        s.loaded_view = "emails"
                        s.loaded_tab = 0
                        s._tab = "custom"
                        rf()
                    with ui.element("div").style(
                            f"background:{C['card']};border:1px solid {C['border']};"
                            f"border-left:3px solid {C['teal']};border-radius:0 10px 10px 0;"
                            f"padding:14px 18px;transition:background .15s;"):
                        with ui.element("div").style(
                                "display:flex;align-items:center;justify-content:space-between;"):
                            with ui.element("div").style("flex:1;cursor:pointer;").on("click", _load_saved):
                                ui.label(cname).style(
                                    f"font-size:14px;font-weight:600;color:{C['text_l']};"
                                    f"font-family:'Nunito',sans-serif;")
                            with ui.element("div").style("display:flex;align-items:center;gap:8px;flex-shrink:0;"):
                                # Delete button with confirmation
                                with ui.dialog() as _del_dlg, ui.card().style(
                                        f"background:{C['card']};border:1px solid {C['border']};min-width:340px;padding:20px;"):
                                    ui.label("Delete Campaign?").style(
                                        f"font-size:15px;font-weight:700;color:{C['text_l']};margin-bottom:6px;")
                                    ui.label(f'Permanently delete "{cname}"?').style(
                                        f"font-size:12px;color:{C['muted']};margin-bottom:4px;")
                                    ui.label("This cannot be undone.").style(
                                        f"font-size:11px;color:{C['danger']};font-weight:600;margin-bottom:16px;")
                                    with ui.element("div").style("display:flex;gap:8px;justify-content:flex-end;"):
                                        with ui.element("button").style(
                                                f"padding:6px 14px;border-radius:6px;font-size:12px;cursor:pointer;"
                                                f"background:transparent;border:1px solid {C['border']};"
                                                f"color:{C['muted']};font-family:inherit;").on("click", _del_dlg.close):
                                            ui.label("Cancel")
                                        def _do_delete(camp=c, dlg=_del_dlg):
                                            path = camp.get("_path", "")
                                            if path:
                                                delete_campaign(path)
                                            dlg.close()
                                            _cache_campaigns.invalidate()
                                            ui.notify(f"Deleted '{camp.get('name','')}'", type="warning")
                                            rf()
                                        with ui.element("button").style(
                                                f"padding:6px 14px;border-radius:6px;font-size:12px;cursor:pointer;"
                                                f"background:{C['danger']};color:white;border:none;"
                                                f"font-weight:600;font-family:inherit;").on("click", _do_delete):
                                            ui.label("Delete")
                                with ui.element("span").style(
                                        f"color:{C['danger']};cursor:pointer;font-size:11px;padding:4px 8px;"
                                        f"border-radius:6px;border:1px solid {C['danger']}30;"
                                        f"background:{C['danger']}10;").on("click.stop", _del_dlg.open):
                                    ui.label("Delete")
                                with ui.element("span").style(
                                        f"color:{C['teal']};cursor:pointer;font-size:16px;font-weight:700;"
                                        ).on("click", _load_saved):
                                    ui.label("→")
                        with ui.element("div").style("display:flex;gap:12px;margin-top:4px;cursor:pointer;").on("click", _load_saved):
                            ui.label(f"✉ {n_emails} emails").style(
                                f"font-size:11px;color:{C['teal']};")
                            if n_contacts:
                                ui.label(f"👥 {n_contacts} contacts").style(
                                    f"font-size:11px;color:{C['muted']};")

    # ── COMMUNITY CAMPAIGNS TAB ───────────────────────────────────────────
    elif s._tab == "community":
        comm_camps = load_community_campaigns()
        if not comm_camps:
            ui.label("No community campaigns shared yet.").style(
                f"font-size:13px;color:{C['muted']};padding:20px 0;")
        else:
            ui.label("Browse campaigns shared by your team  -  click to load one.").style(
                f"font-size:13px;color:{C['muted']};margin-bottom:16px;")
            with ui.element("div").style("display:flex;flex-direction:column;gap:8px;max-width:860px;"):
                for c in comm_camps:
                    cname = c.get("name", "")
                    n_emails = len(c.get("emails", []))
                    def _load_comm(camp=c):
                        # Deep copy so edits don't affect the community original
                        local = copy.deepcopy(camp)
                        local.pop("_community", None)
                        local.pop("_path", None)
                        s._nav_history.append(_nav_snapshot(s))
                        s.loaded_camp = local
                        s.loaded_view = "emails"
                        s.loaded_tab = 0
                        s._tab = "custom"
                        rf()
                    with ui.element("div").style(
                            f"background:{C['card']};border:1px solid {C['border']};"
                            f"border-left:3px solid #1D9E75;border-radius:0 10px 10px 0;"
                            f"padding:14px 18px;cursor:pointer;transition:background .15s;"
                            ).on("click", _load_comm):
                        with ui.element("div").style(
                                "display:flex;align-items:center;justify-content:space-between;"):
                            ui.label(cname).style(
                                f"font-size:14px;font-weight:600;color:{C['text_l']};"
                                f"font-family:'Nunito',sans-serif;")
                            ui.label("→").style(
                                f"font-size:16px;color:#1D9E75;font-weight:700;")
                        ui.label(f"✉ {n_emails} emails").style(
                            f"font-size:11px;color:#1D9E75;margin-top:4px;")


