#  PAGE: CONTACT LIST
# ═══════════════════════════════════════════════════════════════════════════

def p_contacts(s, rf):
    _render_page_intro_strip(s, rf, "contacts")
    contacts = load_contacts()
    saved = list_saved_contact_lists()

    # First-time empty state: no saved lists AND no active contacts.
    # Renders only outside the Email Sequencer wizard flow — the wizard
    # header has its own context cues and shouldn't be replaced.
    is_sequencer_flow = s.hub == "emails" and s.ep == "e_contacts"
    if not is_sequencer_flow and not saved and not contacts:
        def _on_uploaded(_):
            rf()
        _upload_el = _contact_upload_and_name(s, rf, _on_uploaded)
        s._empty_state_handlers = {
            "@contacts_import": lambda: _upload_el.run_method("pickFiles"),
        }
        _render_empty_state(s, rf, "contacts")
        return

    # ── Wizard header when accessed from Email Sequencer flow ───────────────
    if is_sequencer_flow:
        _seq_wizard_header(s, rf, "e_contacts")
        ui.label("Add Contacts").classes("fd-h1")
        ui.label("Pick who gets this campaign. Import a new list or use a saved one  -  contacts appear instantly.").classes("fd-sub")

        # Auto-advance banner when contacts are loaded
        if contacts:
            with ui.element("div").style(
                    f"display:flex;align-items:center;justify-content:space-between;"
                    f"background:{C['teal_dim']};border:1px solid {C['teal']}40;"
                    f"border-radius:10px;padding:12px 18px;margin-bottom:16px;"):
                with ui.element("div").style("display:flex;align-items:center;gap:10px;"):
                    ui.label("✓").style(f"font-size:18px;color:{C['teal']};")
                    ui.label(f"{len(contacts)} contacts loaded  -  ready to launch!").style(
                        f"font-size:14px;font-weight:600;color:{C['teal']};")
                def _go_preview():
                    s.ep = "prev_launch"; rf()
                with ui.element("button").classes("fd-pb").style(
                        "padding:8px 20px;font-size:13px;font-weight:700;").on("click", _go_preview):
                    ui.label("🚀 Preview & Launch →")
    else:
        with ui.element("div").style("display:flex;align-items:center;"):
            ui.label("Contacts").classes("fd-h1")
            _show_page_help(s, rf, "contacts")
        ui.label("Import, manage, and browse your contact lists.").classes("fd-sub")

    def _save_contacts_to_csv(contact_list):
        """Write contacts back to the active CSV atomically (write tmp, replace)."""
        import csv as csv_mod
        import io as _io
        buf = _io.StringIO()
        w = csv_mod.DictWriter(buf, fieldnames=CONTACT_FIELDS)
        w.writeheader()
        for c in contact_list:
            w.writerow({"Email": c.get("email", ""), "FirstName": c.get("first_name", ""),
                        "LastName": c.get("last_name", ""), "Company": c.get("company", ""),
                        "JobTitle": c.get("title", ""), "MobilePhone": c.get("phone_mobile", ""),
                        "WorkPhone": c.get("phone_office", ""), "LinkedInPage": c.get("linkedin", ""),
                        "City": c.get("city", ""), "State": c.get("state", "")})
        _atomic_write_text(_user_contacts_csv_path(), buf.getvalue())

    with ui.element("div").style("display:grid;grid-template-columns:260px 1fr;gap:20px;"):
        # ── LEFT: Import + Saved Lists ──────────────────────────────────────
        with ui.element("div"):
            ui.label("Contact Lists").style(
                f"font-size:15px;font-weight:700;color:{C['text_l']};margin-bottom:16px;"
                f"font-family:'Nunito',sans-serif;")

            def _on_uploaded(new_contacts):
                rf()
            _upload_el = _contact_upload_and_name(s, rf, _on_uploaded)

            # Visible "Import New List" button  -  the upload widget itself is
