def p_preview(s, rf):
    camps = load_campaigns()
    ui.label("Preview").classes("fd-h1")
    ui.label("Review all emails before they go out  -  click any step to see full content.").classes("fd-sub")

    if not camps:
        with ui.element("div").classes("fd-empty"):
            ui.label("No campaigns to preview. Start a sequence first.")
        return

    for camp in camps:
        steps = camp.get("emails", [])
        contacts = camp.get("contacts", [])
        total = len(steps)
        done_count = sum(1 for x in steps if x.get("completed"))
        pct = round(done_count / total * 100) if total else 0
        start_str = camp.get("start_date", date.today().isoformat())
        try:
            start_dt = date.fromisoformat(start_str)
        except Exception:
            start_dt = date.today()

        with ui.element("div").classes("fd-gc"):
            # Header
            with ui.element("div").style("display:flex;align-items:center;justify-content:space-between;margin-bottom:10px;"):
                with ui.element("div"):
                    ui.label(camp.get("name", "")).style(f"font-size:15px;font-weight:600;color:{C['text_l']};")
                    ui.label(f"{len(contacts)} contacts · {total} emails · Started {start_str}").style(
                        f"font-size:12px;color:{C['muted']};margin-top:2px;")
                tpl_name = camp.get("template_name", "Custom")
                tpl_col = C["teal"] if "Full" in tpl_name else (C["indigo"] if "Squeeze" in tpl_name else C["muted"])
                ui.label(tpl_name).classes("fd-tag").style(f"background:{tpl_col}20;color:{tpl_col};font-size:11px;padding:4px 12px;")

            # Progress
            with ui.element("div").classes("fd-progress"):
                ui.element("div").classes("fd-progress-fill").style(f"width:{pct}%")
            ui.label(f"{done_count} of {total} steps complete").style(f"font-size:11px;color:{C['muted']};margin:4px 0 12px;")

            # Schedule table
            html_rows = ""
            cumulative_delay = 0
            _today_sched = date.today()
            for i, step in enumerate(steps):
                icon, color = STEP_META.get(step.get("step_type", ""), ("✉", C["email_col"]))
                cumulative_delay += step.get("delay_days", 0)
                _hkey_s = step.get("holiday", "")
                _fd_s = step.get("fixed_date", "")
                if _hkey_s:
                    _hd_s = _next_holiday_date(_hkey_s, _today_sched)
                    send_date = _hd_s if _hd_s else start_dt + timedelta(days=cumulative_delay)
                elif _fd_s:
                    try:
                        send_date = date.fromisoformat(_fd_s)
                    except Exception:
                        send_date = start_dt + timedelta(days=cumulative_delay)
                else:
                    send_date = start_dt + timedelta(days=cumulative_delay)
                date_str = send_date.strftime("%b %d")
                day_name = send_date.strftime("%a")
                subj = esc(step.get("subject", " - "))
                name = esc(step.get("name", f"Step {i+1}"))
                gate_html = f' <span class="fd-tag" style="background:#2E1E0A;color:#F0A030;">GATE</span>' if step.get("gate") else ""
                att_html = f' <span style="color:{C["email_col"]};font-size:11px;">📎 {len(step.get("attachments",[]))}</span>' if step.get("attachments") else ""
                html_rows += f"""<tr>
                  <td style="color:{color};text-align:center;font-size:14px;width:36px;">{icon}</td>
                  <td style="font-weight:500;color:{C['text_l']}">{name}{gate_html}</td>
                  <td style="color:{C['muted']};font-size:12px;max-width:280px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">{subj}</td>
                  <td style="color:{C['text']};font-size:12px;white-space:nowrap">{day_name} {date_str}</td>
                  <td style="color:{C['muted']};font-size:12px">Day {delay}</td>
                  <td>{att_html}</td></tr>"""

            ui.html(f"""<div style="overflow-x:auto;">
              <table class="fd-tbl"><thead><tr>
                <th style="width:36px"></th><th>Step</th><th>Subject</th><th>Date</th><th>Delay</th><th></th>
              </tr></thead><tbody>{html_rows}</tbody></table></div>""")


