def p_launch(s, rf):
    camps = load_campaigns()
    ui.label("Launch Campaign").classes("fd-h1")
    ui.label("Final review and send via Outlook.").classes("fd-sub")

    if not camps:
        with ui.element("div").classes("fd-empty"):
            ui.label("No campaigns ready. Create one in Start a Campaign.")
        return

    for camp in camps:
        steps = camp.get("emails", [])
        contacts = camp.get("contacts", [])
        total = len(steps)
        done_count = sum(1 for x in steps if x.get("completed"))
        email_steps = [x for x in steps if "email" in x.get("step_type", "")]

        with ui.element("div").classes("fd-gc"):
            # Two-column: left=review, right=actions
            with ui.element("div").style("display:flex;gap:24px;"):
                # Left: campaign info + checklist
                with ui.element("div").style("flex:1;"):
                    ui.label(camp.get("name", "")).style(f"font-size:15px;font-weight:600;color:{C['text_l']};margin-bottom:8px;")

                    # Summary stats row
                    with ui.element("div").style("display:flex;gap:24px;margin-bottom:16px;"):
                        for val, lbl in [(len(contacts), "Contacts"), (len(email_steps), "Emails"),
                                         (total, "Total Steps"), (camp.get("start_date", " - "), "Start Date")]:
                            with ui.element("div"):
                                ui.label(str(val)).style(f"font-size:18px;font-weight:600;color:{C['teal']};")
                                ui.label(lbl).style(f"font-size:11px;color:{C['muted']};text-transform:uppercase;letter-spacing:.04em;")

                    # Checklist
                    ui.label("Launch Checklist").classes("fd-sec")
                    checks = []
                    checks.append(("✓" if contacts else "✕", f"{len(contacts)} contacts loaded",
                                   C["good"] if contacts else C["danger"]))
                    checks.append(("✓" if email_steps else "✕", f"{len(email_steps)} email steps",
                                   C["good"] if email_steps else C["danger"]))
                    missing_subj = sum(1 for e in email_steps if not e.get("subject"))
                    checks.append(("✓" if not missing_subj else "⚠",
                                   f"All subjects filled" if not missing_subj else f"{missing_subj} missing subjects",
                                   C["good"] if not missing_subj else C["warn"]))
                    ai_placeholders = sum(1 for e in email_steps if "[AI:" in e.get("body", ""))
                    checks.append(("✓" if not ai_placeholders else "⚠",
                                   f"All bodies written" if not ai_placeholders else f"{ai_placeholders} need AI generation",
                                   C["good"] if not ai_placeholders else C["warn"]))
                    checks.append(("✓", f"Campaign: {camp.get('name', '')}", C["good"]))

                    with ui.element("div").style("display:grid;grid-template-columns:1fr 1fr;gap:6px;"):
                        for icon, text, col in checks:
                            with ui.element("div").style(f"display:flex;align-items:center;gap:6px;padding:4px 0;"):
                                ui.label(icon).style(f"color:{col};font-size:14px;flex-shrink:0;")
                                ui.label(text).style(f"font-size:12px;color:{C['text']};")

                    all_good = all(c[0] == "✓" for c in checks)
                    if all_good:
                        ui.label("✅ Ready to launch.").style(
                            f"font-size:13px;color:{C['good']};font-weight:500;margin-top:12px;")
                    else:
                        ui.label("Fix checklist items above before launching.").style(
                            f"font-size:12px;color:{C['warn']};margin-top:12px;")

                # Right: action buttons
                with ui.element("div").style("width:260px;flex-shrink:0;"):
                    # Preview button
                    def _preview_test(c=camp):
                        ui.notify("Sending preview to your inbox…", type="info")
                    with ui.element("button").classes("fd-gb").style(
                            f"width:100%;margin-bottom:8px;border-color:{C['teal']}40;").on("click", _preview_test):
                        ui.label("📧 Preview Emails")

                    # Save button
                    def _save(c=camp):
                        save_campaign(c)
                        ui.notify("Sequence saved!", type="positive")
                    with ui.element("button").classes("fd-gb").style(
                            f"width:100%;margin-bottom:8px;border-color:{C['email_col']}40;").on("click", _save):
                        ui.label("💾 Save Campaign")

                    # Launch button
                    def _go(c=camp):
                        count = queue_campaign_emails(c)
                        c["status"] = "active"
                        save_campaign(c)
                        ui.notify(f"🚀 Queued {count} emails for {c.get('name', '')} via Outlook", type="positive")
                        rf()
                    with ui.element("button").classes("fd-pb").style("width:100%;padding:14px;font-size:14px;").on("click", _go):
                        ui.label("🚀 Launch via Outlook")

                    # Evergreen enrollment option
                    with ui.element("div").style(f"margin-top:20px;padding:12px;background:{C['surface']};"
                                                 f"border:1px solid {C['border']};border-radius:8px;"):
                        ui.label("After Launch").classes("fd-fl")
                        ui.label("Enroll contacts in Slow Drip campaign after sequence completes.").style(
                            f"font-size:12px;color:{C['muted']};margin-top:4px;")

                    # Delete campaign
                    def _delete(c=camp):
                        delete_campaign(c.get("_path", ""))
                        ui.notify("Sequence deleted.", type="warning")
                        rf()
                    with ui.element("button").classes("fd-db").style("width:100%;margin-top:12px;").on("click", _delete):
                        ui.label("🗑 Delete Campaign")


