#  CURATED PDF PROMPTS
# ═══════════════════════════════════════════════════════════════════════════
# One dedicated prompt per PDF type, each with web_search tool access.
# Common pattern across all 5: take (target company, market/niche,
# positions, location), web-research the target + their market live,
# return strict JSON tailored to a hiring manager AT that company.
# Voice modeled on the Utah Mfg Market Scan output — specific stats,
# cited where possible, "so what for hiring this quarter" framing.
# Each prompt's JSON schema matches the corresponding builder in
# funnel_forge/arena_pdfs.py exactly.

_PDF_RESEARCH_SYSTEM = (
    "You are a market intelligence analyst writing a one-page hiring-decision "
    "briefing for a recruiting firm's client. Use the web_search tool aggressively "
    "to gather:\n"
    "  - what the target company actually does, their size, recent news, hiring patterns\n"
    "  - current comp data + market signals for the listed positions in the target geography\n"
    "  - recent industry events (closures, expansions, layoffs, contracts) relevant to the role\n"
    "Voice: direct, factual, no fluff. Specific stats over generalizations — when you have "
    "a number, use it. Avoid 'competitive comp' platitudes. Every bullet must pass the "
    "'so what for a hiring decision this quarter' test.\n\n"
    "Return ONLY valid JSON in the exact shape requested. No markdown fences, no commentary, "
    "no tool-use chatter outside the JSON."
)


# ─────────────────────────────────────────────────────────────────────────
# Rich PDF generator — replaces the per-type strait-jacket prompts/builders.
# All 6 form-driven types now route through build_custom_pdf with per-kind
# outline templates that mirror the structure of a McKinsey-style 1-pager:
# title + badge + paragraph + benchmark table + insight bullets + Q&A.
# ─────────────────────────────────────────────────────────────────────────

def _rich_industry_str(primary: str, secondaries) -> str:
    """Compose 'Primary - Secondary1, Secondary2' for use in prompts."""
    primary = (primary or "").strip()
    secs = [s.strip() for s in (secondaries or []) if s and s.strip()]
    if primary and secs:
        return f"{primary} (with secondary focus on {', '.join(secs)})"
    return primary or (", ".join(secs) if secs else "")


def _rich_positions_str(positions) -> str:
    """Accept str or list, return comma-joined string."""
    if isinstance(positions, (list, tuple)):
        return ", ".join(str(p).strip() for p in positions if str(p).strip())
    return (positions or "").strip()


def _rich_pdf_prompt(kind: str, ctx: dict) -> str:
    """Build a rich, full-page-content prompt for the given PDF kind.

    ctx keys: company, primary_industry, secondary_industries (list),
              positions (str or list), location, exp_level (optional).
    """
    company = (ctx.get("company") or "").strip() or "(target company)"
    primary = (ctx.get("primary_industry") or "").strip()
    secondaries = ctx.get("secondary_industries") or []
    positions_str = _rich_positions_str(ctx.get("positions"))
    location = (ctx.get("location") or "").strip() or "their market"
    exp_level = (ctx.get("exp_level") or "").strip()
    industry_str = _rich_industry_str(primary, secondaries) or "(infer from research)"
    role_label = positions_str or "the open roles"
    exp_phrase = f"{exp_level} " if exp_level else ""

    common_header = (
        f"TARGET COMPANY: {company}\n"
        f"PRIMARY MARKET / INDUSTRY: {primary or '(infer)'}\n"
        f"SECONDARY MARKETS: {', '.join(secondaries) if secondaries else '(none)'}\n"
        f"POSITIONS HIRING FOR: {positions_str or '(infer)'}\n"
        f"LOCATION: {location}\n"
        f"TARGET EXPERIENCE LEVEL: {exp_level or '(unspecified)'}\n\n"
    )

    # Resolve the prepared-by company / brand — the staffing firm sending
    # the document. Falls back to a neutral phrase if missing.
    _prep_company = (ctx.get("prepared_by_company") or
                     ctx.get("brand") or
                     "your staffing partner").strip() or "your staffing partner"

    common_rules = (
        "\nAUDIENCE & VOICE:\n"
        f"- This document is sent BY {_prep_company} TO an executive or hiring "
        f"manager at {company}. Write for them, not for our internal team.\n"
        "- Voice is strategic, authoritative, helpful. You are the market expert "
        "giving the client a one-page advantage. You are NOT writing a job "
        "description, a training plan, or a staffing-firm playbook.\n"
        "- Frame every section in terms of business outcomes the CLIENT cares "
        "about — fill rate, time-to-fill, retention, quality of hire, revenue "
        "enabled by the hire, risk reduced — not internal ops the role-doer "
        "performs day-to-day.\n"
        "\nDO NOT:\n"
        "- Use procedural / ops language: 'build a sourcing pipeline', "
        "'document sourcing channel effectiveness', 'establish weekly touchpoints', "
        "'develop standard operating procedures', 'attend weekly jobsite visits'. "
        "These read as internal training content, not client value.\n"
        "- Address the role-doer in second person ('You'll own…'). Always speak "
        "TO the hiring manager ABOUT what the hire delivers: 'This hire owns…', "
        "'Within 90 days, expect…', 'The client should see…'.\n"
        "- Reference any internal tools, budget cycles, vendor contracts, or "
        "back-office workflows. The client doesn't run those.\n"
        "\nRULES:\n"
        "- Fill the page. Each section must carry real, specific content tied to the inputs above.\n"
        "- Use REAL numbers, comp ranges, and named events/trends — no 'Market Rate', no 'Competitive', no placeholders.\n"
        "- Paragraph sections: 3-5 sentences each. Bullet sections: each bullet ~2 sentences with a stat or specific.\n"
        "- Q&A answers: 2-3 sentences each — substantive, not one-liners.\n"
        "- Tables: include header row first, then 4-6 data rows. Every cell concrete.\n"
        "- No em dashes, no markdown, no asterisks. Plain text in JSON strings only.\n"
        "- Return ONLY valid JSON. No fences, no commentary outside the JSON.\n"
    )

    common_shape = (
        "\nReturn JSON in this exact shape:\n"
        '{\n'
        '  "title": "Location + Industry + document type ONLY. Example: '
        '\\"Sacramento Healthcare Construction Market Pulse\\". DO NOT '
        'list job titles, roles, or position names in the title — those '
        'belong in the body. Keep it short (6-10 words).",\n'
        '  "badge": "UPPERCASE BADGE 2-4 WORDS",\n'
        '  "intro": "1-2 sentence opener establishing the market context.",\n'
        '  "sections": [ ... see required sections below ... ],\n'
        '  "cta": "1 sentence closing call-to-action."\n'
        '}\n'
        'Each section is one of:\n'
        '  {"heading": "...", "type": "paragraph", "items": ["multi-sentence paragraph"]}\n'
        '  {"heading": "...", "type": "bullets",   "items": ["bullet 1", "bullet 2", ...]}\n'
        '  {"heading": "...", "type": "table",     "items": [["Col1","Col2",...], ["row1c1","row1c2",...], ...]}\n'
        '  {"heading": "...", "type": "qa",        "items": [{"q":"...","a":"..."}, ...]}\n'
    )

    if kind == "market_pulse":
        body = (
            f"Build a rich one-page Market Pulse / Salary Guide for a hiring manager at {company}. "
            f"Reader wants the market reality for {exp_phrase}{role_label} in {location} "
            f"({industry_str}) right now, plus what they should be paying.\n"
            f"\nREQUIRED SECTIONS (in this order, all four):\n"
            f"  1. heading 'Market Overview' — type 'paragraph' — 4-5 sentences on the {location} "
            f"{primary or 'industry'} market for {role_label} right now: drivers, time-to-fill, "
            f"talent supply, what's pressuring this market this quarter.\n"
            f"  2. heading 'Compensation Benchmarks' — type 'table' — header row plus 4-5 data rows. "
            f"Columns: ['Position','Experience Level','Base Salary Range','Total Comp (with bonus/benefits)','Market Tier']. "
            f"Cover entry/junior, mid (3-5 yrs), senior (5+ yrs), and principal/lead bands for {role_label}. "
            f"Use concrete dollar ranges (e.g. '$92,000 - $115,000').\n"
            f"  3. heading 'Talent Market Trends' — type 'bullets' — exactly 3 bullets, each ~2 sentences "
            f"with a specific stat, premium percentage, or trend (e.g. '12-15 percent premium for...').\n"
            f"  4. heading 'Key Hiring Insights' — type 'qa' — exactly 4 Q&A pairs answering: "
            f"current supply/demand dynamic for {role_label} in {location}; geographic hotspots within {location}; "
            f"benefits/perks moving the needle in offers; how hybrid/remote arrangements affect recruitment. "
            f"Each answer 2-3 sentences with concrete numbers.\n"
            f"  Optional 5th heading 'Want to learn more?' — type 'bullets' — 1 bullet inviting a market call.\n"
        )

    elif kind == "salary_guide":
        body = (
            f"Build a rich one-page Salary Guide for a hiring manager at {company} hiring "
            f"{exp_phrase}{role_label} in {location} ({industry_str}).\n"
            f"\nREQUIRED SECTIONS:\n"
            f"  1. heading 'Comp Landscape' — type 'paragraph' — 3-4 sentences on the comp environment "
            f"for {role_label} in {location} right now, with at least two specific data points.\n"
            f"  2. heading 'Salary Benchmarks' — type 'table' — header + 5-6 data rows. "
            f"Columns: ['Position','Experience Level','Base Salary Range','Total Comp','Market Tier']. "
            f"Concrete dollar ranges per row.\n"
            f"  3. heading 'What is Driving Comp Right Now' — type 'bullets' — 4 bullets, each ~2 sentences, "
            f"each citing a specific event, trend, or named competitor pressure in {location}.\n"
            f"  4. heading 'Near-Term Comp Trends' — type 'bullets' — 3 bullets with specific stats or "
            f"projections for the next 6-12 months.\n"
            f"  5. heading 'Negotiation Insights' — type 'qa' — 3 Q&A pairs covering: how counter-offers "
            f"are trending; which non-cash levers candidates value most; biggest comp mistakes "
            f"hiring managers make. Each answer 2-3 sentences.\n"
        )

    elif kind == "interview_guide":
        body = (
            f"Build a rich one-page Interview Guide for {company}'s hiring managers interviewing "
            f"{exp_phrase}{role_label} candidates ({industry_str}, {location}).\n"
            f"\nREQUIRED SECTIONS:\n"
            f"  1. heading 'What Strong Looks Like at {company}' — type 'paragraph' — 3-4 sentences "
            f"describing what a high-signal hire looks like in this specific environment "
            f"(scale, complexity, customer base of {company}).\n"
            f"  2. heading 'Must-Ask Questions' — type 'qa' — 5 Q&A pairs where q is the question to ask "
            f"and a is what a strong answer sounds like (2-3 sentences each, specific to {role_label}).\n"
            f"  3. heading 'Green Flags' — type 'bullets' — 4 bullets, each ~2 sentences, on positive "
            f"signals weighted heavily for this role at this kind of company.\n"
            f"  4. heading 'Red Flags' — type 'bullets' — 4 bullets, each ~2 sentences, on warning "
            f"signs specific to {role_label} in {industry_str}.\n"
            f"  5. heading 'Strong Closing Questions' — type 'bullets' — 3 closing questions a hiring "
            f"manager should ask to gauge real interest and fit.\n"
        )

    elif kind == "scorecard":
        body = (
            f"Build a rich one-page Role Scorecard the hiring manager at {company} can use to "
            f"benchmark the {role_label} hire ({industry_str}, {location}). The reader is the "
            f"hiring decision-maker, not the candidate or the role-doer.\n"
            f"\nREQUIRED SECTIONS:\n"
            f"  1. heading 'What Great Looks Like at {company}' — type 'paragraph' — 3-4 sentences "
            f"describing what a high-performing hire delivers TO {company} (business impact, scale "
            f"served, customer/jobsite outcomes), referencing their actual scale/work. Speak to the "
            f"hiring manager about the hire's contribution, never to the candidate about their tasks.\n"
            f"  2. heading 'First-90-Day Outcomes' — type 'bullets' — 5 measurable outcomes the "
            f"hiring manager will be able to point to at the 90-day mark. Each in the form "
            f"'<X> delivered / <Y%> improved / <Z> is in place'. Frame each as a deliverable to "
            f"{company}, NOT a task the hire performs day-to-day. NO procedural language "
            f"('build a pipeline', 'document a process', 'attend weekly meetings'). Each bullet "
            f"~2 sentences with a concrete metric.\n"
            f"  3. heading 'Core Competencies' — type 'table' — header + 4-5 rows. "
            f"Columns: ['Competency','What It Looks Like at {company}','Why It Matters to the Business']. "
            f"The third column is the BUSINESS reason — revenue, risk, retention — not internal ops.\n"
            f"  4. heading 'Fit Markers vs. Red Flags' — type 'qa' — 3 Q&A pairs where q names a fit "
            f"dimension and a contrasts the strong vs weak signal in candidate behavior (2-3 sentences each).\n"
            f"  5. heading 'High-Signal Interview Questions' — type 'bullets' — 5 questions the "
            f"hiring manager should ask candidates, tied to the outcomes above, each ~1 sentence.\n"
        )

    elif kind == "why_staffing":
        body = (
            f"Build a rich one-page partnership case for {company} on why a staffing firm beats "
            f"DIY hiring for {role_label} in {industry_str} ({location}).\n"
            f"\nREQUIRED SECTIONS:\n"
            f"  1. heading 'The Hidden Cost of DIY Hiring' — type 'paragraph' — 3-4 sentences with "
            f"specific cost-per-hire and time-to-fill numbers for {role_label} in {industry_str}.\n"
            f"  2. heading 'The Real Math' — type 'table' — header + 4-5 rows. "
            f"Columns: ['Cost Category','In-House DIY','With a Staffing Partner']. "
            f"Cover sourcing time, screening cost, time-to-fill, vacancy cost, mis-hire risk.\n"
            f"  3. heading 'What We Do Differently' — type 'bullets' — 4 bullets, each ~2 sentences, "
            f"on specific differentiators (passive-talent reach, pre-qualification, market intel, etc.).\n"
            f"  4. heading 'Risk Transfer and Guarantees' — type 'bullets' — 3 bullets on "
            f"replacement guarantees, no-fee-until-start, outcome-based pricing.\n"
            f"  5. heading 'When to Use a Staffing Partner' — type 'qa' — 3 Q&A pairs covering: when we add "
            f"the most value; when in-house is better; how engagements typically start. 2-3 sentences each.\n"
        )

    elif kind == "tenure_snapshot":
        body = (
            f"Build a rich one-page Tenure Snapshot for {company}'s hiring filters on {role_label} "
            f"in {industry_str} ({location}).\n"
            f"\nREQUIRED SECTIONS:\n"
            f"  1. heading 'Tenure Reality in This Market' — type 'paragraph' — 3-4 sentences on median "
            f"tenure data for {role_label} in {location} right now, citing BLS or industry surveys.\n"
            f"  2. heading 'Tenure Data' — type 'table' — header + 4-5 rows. "
            f"Columns: ['Position','Market','Talent Pool','Median Tenure','Hiring Demand'].\n"
            f"  3. heading 'What This Means for Hiring Filters' — type 'bullets' — 4 bullets, each ~2 sentences, "
            f"showing how hard tenure cutoffs shrink the qualified pool for this role in this market.\n"
            f"  4. heading 'Better-Than-Tenure Stability Signals' — type 'bullets' — 4 bullets on signals "
            f"that actually predict retention (delivery patterns, references, growth track).\n"
            f"  5. heading 'Hiring Manager Q&A' — type 'qa' — 3 Q&A pairs answering common pushback "
            f"on relaxing tenure cutoffs. 2-3 sentences each.\n"
        )

    else:
        # Unknown kind — caller should have validated, but fall back gracefully.
        body = (
            f"Build a rich one-page market briefing for {company} on {role_label} in {location} "
            f"({industry_str}). 4-5 sections: paragraph overview, benchmark table, trend bullets, "
            f"and a Q&A block. Fill the page with real, specific content.\n"
        )

    return common_header + body + common_shape + common_rules


def _pdf_sidecar_path(pdf_path) -> Path:
    """Return the path to the JSON sidecar that holds the structured data
    a PDF was built from. Convention: Foo.pdf → Foo.pdf.json, alongside
    the PDF in the same directory. Used by the in-page PDF editor to
    re-load `{title, badge, intro, sections, cta, ...}` so the user can
    tweak fields, ask AI for revisions, then re-render the PDF in place."""
    p = Path(str(pdf_path))
    return p.with_suffix(p.suffix + ".json")


def _save_pdf_sidecar(pdf_path, build_data: dict) -> bool:
    """Write the structured build_data dict to the PDF's JSON sidecar.
    Best-effort — failures only log + return False (sidecar is for the
    editor; missing one falls back to "regenerate from scratch").
    `build_data` should be the same dict passed to build_custom_pdf:
    {title, badge, prepared_by, prepared_email, date, logo_path, intro,
    sections, cta}. Logo path is intentionally included so the re-render
    keeps using the same asset."""
    try:
        sp = _pdf_sidecar_path(pdf_path)
        sp.write_text(json.dumps(build_data, indent=2, default=str),
                      encoding="utf-8")
        return True
    except Exception as ex:
        print(f"[PDF sidecar] save failed for {pdf_path}: {ex}", flush=True)
        return False


def _load_pdf_sidecar(pdf_filename: str):
    """Load the structured build data for an existing PDF by filename.
    Resolves the filename against the per-user PDFs dir + reads the
    Foo.pdf.json sidecar. Returns the parsed dict on success, or None
    if the sidecar doesn't exist or can't be parsed (the editor can
    show a "no editable data — regenerate to enable editing" notice)."""
    try:
        pdf_dir = _user_pdf_dir()
        pdf_path = pdf_dir / pdf_filename
        sidecar = _pdf_sidecar_path(pdf_path)
        if not sidecar.exists():
            return None
        return json.loads(sidecar.read_text(encoding="utf-8"))
    except Exception as ex:
        print(f"[PDF sidecar] load failed for {pdf_filename}: {ex}", flush=True)
        return None


def _rebuild_pdf_from_sidecar_data(pdf_filename: str, build_data: dict) -> bool:
    """Re-run build_custom_pdf for an existing PDF using the edited
    structured data. Re-saves the sidecar so subsequent edits start
    from the latest state. Returns True on success.
    Used by the in-page PDF editor's Save button (manual edits) and
    the AI-revise flow (Claude-generated edits)."""
    try:
        import sys as _sys, importlib
        _sys.path.insert(0, str(Path(__file__).resolve().parent / "funnel_forge"))
        import arena_pdfs as _ap; importlib.reload(_ap)
        from arena_pdfs import build_custom_pdf
    except ImportError:
        print(f"[PDF rebuild] reportlab not installed", flush=True)
        return False
    try:
        pdf_dir = _user_pdf_dir()
        pdf_dir.mkdir(parents=True, exist_ok=True)
        pdf_path = str(pdf_dir / pdf_filename)
        # Run salary post-processor again in case the user changed cells
        _format_pdf_table_salaries(build_data)
        build_custom_pdf(pdf_path, build_data)
        _save_pdf_sidecar(pdf_path, build_data)
        try:
            _publish_pdf(pdf_path)
        except Exception:
            pass
        print(f"[PDF rebuild] re-rendered {pdf_filename}", flush=True)
        return True
    except Exception as ex:
        print(f"[PDF rebuild] failed for {pdf_filename}: {ex}", flush=True)
        return False


def _ai_revise_pdf_data(client, build_data: dict, instruction: str) -> dict:
    """Send the current PDF data + a natural-language edit instruction to
    Claude, parse the revised JSON back. Returns the new data dict on
    success or raises on parse failure (caller shows a friendly error)."""
    sections_json = json.dumps({
        "title":    build_data.get("title", ""),
        "badge":    build_data.get("badge", ""),
        "intro":    build_data.get("intro", ""),
        "sections": build_data.get("sections", []),
        "cta":      build_data.get("cta", ""),
    }, indent=2)
    prompt = (
        "You are revising a one-page recruiting PDF for a hiring manager. "
        "The current PDF content is below as JSON. Apply the user's edit "
        "instruction and return the FULL revised JSON in the SAME shape — "
        "do not drop any keys, do not change types of section items.\n\n"
        f"CURRENT PDF JSON:\n{sections_json}\n\n"
        f"USER'S EDIT INSTRUCTION:\n{instruction}\n\n"
        "Rules:\n"
        "- Return ONLY valid JSON matching the same shape (title, badge, "
        "intro, sections[], cta). No markdown fences, no preface.\n"
        "- For tables: keep header row first, preserve column count.\n"
        "- For salary cells use '$XX,XXX - $XX,XXX' format.\n"
        "- No em dashes, no markdown asterisks inside strings.\n"
    )
    msg = _claude_create_with_retry(client,
        model="claude-haiku-4-5-20251001",
        max_tokens=2400,
        messages=[{"role": "user", "content": prompt}],
    )
    text = msg.content[0].text
    clean = text.replace("```json", "").replace("```", "").strip()
    match = re.search(r'\{.*\}', clean, re.DOTALL)
    if not match:
        raise ValueError("AI response was not valid JSON.")
    revised = json.loads(match.group())
    # Carry forward fields the AI doesn't own (date, prepared_by, etc.)
    for _k in ("date", "prepared_by", "prepared_email", "logo_path"):
        if _k in build_data:
            revised[_k] = build_data[_k]
    revised.setdefault("sections", build_data.get("sections", []))
    return revised


def _pdf_editor_state(s):
    """Lazy-init the AppState scratch attrs the PDF editor uses.
    Called by both the toggle and the body renderers so neither
    crashes if invoked first."""
    if not hasattr(s, "_pdf_editor_open"):
        s._pdf_editor_open = set()
    if not hasattr(s, "_pdf_editor_data"):
        s._pdf_editor_data = {}
    if not hasattr(s, "_pdf_editor_busy"):
        s._pdf_editor_busy = set()


def _render_pdf_editor_toggle(s, rf, pdf_filename: str, step_idx: int):
    """Renders just the ✎ Edit / ▴ Hide editor button. Call this
    INSIDE the inline-flex attachment chip so the button sits
    alongside the link and the ✕ remove icon. The body itself
    must be rendered separately via _render_pdf_editor_body so
    it lays out as a block element below the chip, not as an
    inline-flex sibling that gets squished into the chip row."""
    _pdf_editor_state(s)
    _key = (step_idx, pdf_filename)
    _is_open = _key in s._pdf_editor_open

    def _toggle_open():
        if _is_open:
            s._pdf_editor_open.discard(_key)
            s._pdf_editor_data.pop(_key, None)
        else:
            data = _load_pdf_sidecar(pdf_filename)
            s._pdf_editor_data[_key] = data
            s._pdf_editor_open.add(_key)
        rf()

    with ui.element("button").style(
            f"background:transparent;border:1px solid {C['teal']}40;"
            f"color:{C['teal']};border-radius:6px;padding:3px 10px;"
            f"font-size:11px;font-weight:600;cursor:pointer;"
            f"font-family:inherit;margin-left:6px;"
            ).on("click", _toggle_open):
        ui.label(("▴ Hide editor" if _is_open else "✎ Edit"))


def _render_pdf_editor_body(s, rf, pdf_filename: str, step_idx: int,
                              regenerate_fn=None):
    """Renders the editable form when the toggle is open, or nothing
    when it's closed. Call this OUTSIDE the inline-flex chip (as a
    sibling block element) so the form lays out full-width below
    the chip instead of being squished inline.

    `regenerate_fn` is an optional callable taking (pid, plabel, step_idx)
    used by the no-sidecar branch to regenerate a pre-editor PDF in place.
    Pass `_gen_pdf_inline` from the campaign editor's scope. If omitted
    or the PDF type can't be inferred from the filename, the no-sidecar
    branch falls back to a textual instruction."""
    _pdf_editor_state(s)
    _key = (step_idx, pdf_filename)
    _is_open = _key in s._pdf_editor_open
    if not _is_open:
        return

    data = s._pdf_editor_data.get(_key)

    # No sidecar = old PDF generated before sidecars existed
    if data is None:
        # Try to infer the PDF type from the filename prefix so we can
        # offer one-click Regenerate inline (no need to scroll up to the
        # chip's Regenerate button — and the chip's button only shows
        # when the file is missing, not when the sidecar is missing,
        # which left the user stranded).
        _att_lower = pdf_filename.lower()
        _re_pid, _re_plabel = ("", "")
        for _pid_x, _plabel_x in [
            ("market_pulse",    "Market Pulse"),
            ("scorecard",       "Role Scorecard"),
            ("salary_guide",    "Salary Guide"),
            ("interview_guide", "Interview Guide"),
            ("tenure_snapshot", "Tenure Snapshot"),
        ]:
            if _att_lower.startswith(_plabel_x.lower().replace(" ", "_") + "_"):
                _re_pid, _re_plabel = _pid_x, _plabel_x
                break
        with ui.element("div").style(
                f"margin-top:10px;padding:14px 18px;"
                f"background:{C['warn']}08;border:1px solid {C['warn']}40;"
                f"border-left:3px solid {C['warn']};border-radius:8px;"
                f"display:flex;align-items:center;gap:12px;flex-wrap:wrap;"):
            with ui.element("div").style("flex:1;min-width:200px;"):
                ui.label("This PDF was generated before the editor was available.").style(
                    f"font-size:12px;color:{C['warn']};font-weight:600;margin-bottom:4px;")
                ui.label(
                    "Click Regenerate below to recreate it — the new version "
                    "will be editable from this panel."
                ).style(f"font-size:11px;color:{C['muted']};line-height:1.5;")
            if _re_pid and regenerate_fn and ANTHROPIC_API_KEY:
                def _do_regen_inline(pid=_re_pid, plabel=_re_plabel,
                                     idx=step_idx, fn=regenerate_fn):
                    # Close the editor for this PDF — when the new one
                    # finishes generating, the user can re-open it and
                    # the sidecar will be present.
                    s._pdf_editor_open.discard(_key)
                    s._pdf_editor_data.pop(_key, None)
                    fn(pid, plabel, idx)
                with ui.element("button").style(
                        f"background:{C['teal']};color:{C['bg']};"
                        f"border:none;border-radius:6px;padding:7px 16px;"
                        f"font-size:12px;font-weight:700;cursor:pointer;"
                        f"font-family:inherit;flex-shrink:0;"
                        ).on("click", _do_regen_inline):
                    ui.label("↻ Regenerate")
            elif not ANTHROPIC_API_KEY:
                ui.label("(Set up your API key to enable regeneration.)").style(
                    f"font-size:10px;color:{C['muted']};font-style:italic;")
        return

    _busy = _key in s._pdf_editor_busy

    # ── Editor body ─────────────────────────────────────────────────
    with ui.element("div").style(
            f"margin-top:10px;padding:16px 18px;background:{C['surface']};"
            f"border:1px solid {C['teal']}40;border-radius:10px;"
            f"display:flex;flex-direction:column;gap:14px;"):

        # Save-time field flush. Every input below registers a zero-arg
        # commit fn into `_commits`; `_do_save` runs all commits before
        # reading `data`. Belt-and-suspenders over the per-input blur
        # handlers — blur only fires when focus *leaves* an input, so
        # if a user types and clicks Save before focus moves, blur may
        # not fire in time and the keystroke never lands in `data`.
        # Running commits at save time is idempotent and guarantees
        # every visible field value is written back before the rebuild.
        _commits = []
        def _bind(elem, fn):
            elem.on("blur", fn)
            _commits.append(fn)
            return elem

        # ── AI revise box (top) ─────────────────────────────────────
        # Lives at the top of the editor so the fastest path — describe
        # a change, click Apply — is the first thing the user sees.
        # Manual field-by-field editing is the fallback below.
        if ANTHROPIC_API_KEY:
            with ui.element("div").style(
                    f"padding:12px 14px;background:{C['teal']}08;"
                    f"border:1px solid {C['teal']}40;border-left:3px solid {C['teal']};"
                    f"border-radius:8px;display:flex;flex-direction:column;gap:8px;"):
                ui.label("✨ Ask AI to revise").style(
                    f"font-size:11px;font-weight:700;color:{C['teal']};"
                    f"font-family:'Nunito',sans-serif;")
                _ai_in = ui.textarea(
                    placeholder=(
                        "e.g. 'Increase salary ranges 10%', "
                        "'Add a section on safety culture', "
                        "'Make the tone more direct'"
                    ),
                ).style(
                    f"width:100%;min-height:50px;background:{C['card']};"
                    f"border:1px solid {C['border']};border-radius:6px;padding:7px 10px;"
                    f"font-size:12px;color:{C['text_l']};font-family:inherit;"
                    f"line-height:1.5;resize:vertical;")
                def _do_ai_revise(k=_key):
                    instr = (_ai_in.value or "").strip()
                    if not instr:
                        ui.notify("Type an edit instruction first.", type="warning")
                        return
                    if k in s._pdf_editor_busy:
                        return
                    s._pdf_editor_busy.add(k)
                    rf()
                    def _run():
                        try:
                            import anthropic
                            client = anthropic.Anthropic(api_key=ANTHROPIC_API_KEY)
                            revised = _ai_revise_pdf_data(client, s._pdf_editor_data[k], instr)
                            s._pdf_editor_data[k] = revised
                            ui.notify("✓ AI revised the PDF data — review and Save.",
                                       type="positive")
                        except Exception as ex:
                            print(f"[PDF AI revise] {ex}", flush=True)
                            ui.notify(f"AI revise failed: {str(ex)[:90]}", type="negative")
                        finally:
                            s._pdf_editor_busy.discard(k)
                            rf()
                    _run_as_user(getattr(s, "_user_email", "") or "", _run, name="pdf_ai_revise_worker")
                with ui.element("button").classes("fd-pb").style(
                        f"padding:7px 18px;font-size:12px;align-self:flex-start;"
                        + ("opacity:0.6;pointer-events:none;" if _busy else "")
                        ).on("click", _do_ai_revise):
                    ui.label("Apply AI revision" if not _busy else "Working...")

        # Header line — title + badge
        with ui.element("div").style(
                "display:grid;grid-template-columns:2fr 1fr;gap:10px;"):
            with ui.element("div"):
                ui.label("Title").style(
                    f"font-size:9px;font-weight:700;color:{C['muted']};"
                    f"text-transform:uppercase;letter-spacing:.06em;margin-bottom:3px;")
                _title_in = ui.input(value=data.get("title", "")).classes("fd-input")
                _bind(_title_in, lambda: data.update({"title": _title_in.value or ""}))
            with ui.element("div"):
                ui.label("Badge").style(
                    f"font-size:9px;font-weight:700;color:{C['muted']};"
                    f"text-transform:uppercase;letter-spacing:.06em;margin-bottom:3px;")
                _badge_in = ui.input(value=data.get("badge", "")).classes("fd-input")
                _bind(_badge_in, lambda: data.update({"badge": _badge_in.value or ""}))

        # Intro
        with ui.element("div"):
            ui.label("Intro").style(
                f"font-size:9px;font-weight:700;color:{C['muted']};"
                f"text-transform:uppercase;letter-spacing:.06em;margin-bottom:3px;")
            _intro_in = ui.textarea(value=data.get("intro", "")).style(
                f"width:100%;min-height:60px;background:{C['card']};border:1px solid {C['border']};"
                f"border-radius:6px;padding:8px 10px;font-size:12px;color:{C['text_l']};"
                f"font-family:inherit;line-height:1.5;resize:vertical;")
            _bind(_intro_in, lambda: data.update({"intro": _intro_in.value or ""}))

        # Sections — render per type
        sections = data.get("sections", []) or []
        for _si, sec in enumerate(sections):
            _stype = (sec.get("type") or "paragraph").lower()
            with ui.element("div").style(
                    f"padding:12px 14px;background:{C['card']};"
                    f"border:1px solid {C['border']};border-radius:8px;"
                    f"display:flex;flex-direction:column;gap:8px;"):
                # Heading row + section type badge
                with ui.element("div").style(
                        "display:flex;align-items:center;gap:8px;"):
                    _heading_in = ui.input(
                        value=sec.get("heading", ""),
                        placeholder="Section heading"
                    ).classes("fd-input").style("flex:1;")
                    def _commit_heading(_in=_heading_in, _s=sec):
                        _s["heading"] = _in.value or ""
                    _bind(_heading_in, _commit_heading)
                    ui.label(_stype.upper()).style(
                        f"font-size:9px;font-weight:800;color:{C['teal']};"
                        f"background:{C['teal']}18;padding:2px 8px;border-radius:99px;"
                        f"letter-spacing:.06em;flex-shrink:0;")

                items = sec.get("items", []) or []

                if _stype == "paragraph":
                    _para_text = "\n\n".join(items) if isinstance(items, list) else str(items)
                    _para_in = ui.textarea(value=_para_text).style(
                        f"width:100%;min-height:80px;background:{C['surface']};"
                        f"border:1px solid {C['border']};border-radius:6px;padding:8px 10px;"
                        f"font-size:12px;color:{C['text_l']};font-family:inherit;"
                        f"line-height:1.55;resize:vertical;")
                    def _commit_para(_in=_para_in, _s=sec):
                        _s["items"] = [p.strip() for p in (_in.value or "").split("\n\n") if p.strip()]
                    _bind(_para_in, _commit_para)

                elif _stype == "bullets":
                    for _bi, _bullet in enumerate(items):
                        with ui.element("div").style(
                                "display:flex;gap:6px;align-items:start;"):
                            _b_in = ui.textarea(value=str(_bullet)).style(
                                f"flex:1;min-height:40px;background:{C['surface']};"
                                f"border:1px solid {C['border']};border-radius:6px;"
                                f"padding:6px 9px;font-size:12px;color:{C['text_l']};"
                                f"font-family:inherit;line-height:1.5;resize:vertical;")
                            def _commit_bullet(_in=_b_in, _s=sec, _idx=_bi):
                                if _idx < len(_s["items"]):
                                    _s["items"][_idx] = _in.value or ""
                            _bind(_b_in, _commit_bullet)
                            def _del_bullet(_s=sec, _idx=_bi):
                                if _idx < len(_s["items"]):
                                    _s["items"].pop(_idx)
                                rf()
                            with ui.element("button").style(
                                    f"background:transparent;border:1px solid {C['danger']}40;"
                                    f"color:{C['danger']};border-radius:6px;padding:2px 8px;"
                                    f"font-size:11px;cursor:pointer;font-family:inherit;"
                                    f"flex-shrink:0;").on("click", _del_bullet):
                                ui.label("×")
                    def _add_bullet(_s=sec):
                        _s.setdefault("items", []).append("New bullet")
                        rf()
                    with ui.element("button").style(
                            f"background:transparent;border:1px dashed {C['teal']}55;"
                            f"color:{C['teal']};border-radius:6px;padding:5px 12px;"
                            f"font-size:11px;font-weight:600;cursor:pointer;"
                            f"font-family:inherit;align-self:flex-start;"
                            ).on("click", _add_bullet):
                        ui.label("＋ Add bullet")

                elif _stype == "table":
                    rows = items if isinstance(items, list) else []
                    if rows:
                        _ncols = max((len(r) for r in rows if isinstance(r, list)), default=0)
                        for _ri, row in enumerate(rows):
                            if not isinstance(row, list):
                                continue
                            with ui.element("div").style(
                                    f"display:grid;"
                                    f"grid-template-columns:repeat({_ncols},1fr) 32px;"
                                    f"gap:6px;align-items:center;"):
                                for _ci in range(_ncols):
                                    _cell_val = row[_ci] if _ci < len(row) else ""
                                    _cell_in = ui.input(value=str(_cell_val)).classes("fd-input").style(
                                        f"font-size:11px;font-weight:{'700' if _ri == 0 else '400'};")
                                    def _commit_cell(_in=_cell_in, _r=row, _idx=_ci):
                                        while len(_r) <= _idx:
                                            _r.append("")
                                        _r[_idx] = _in.value or ""
                                    _bind(_cell_in, _commit_cell)
                                if _ri == 0:
                                    ui.label("HDR").style(
                                        f"font-size:8px;font-weight:700;color:{C['muted']};"
                                        f"text-align:center;")
                                else:
                                    def _del_row(_s=sec, _idx=_ri):
                                        if _idx < len(_s["items"]):
                                            _s["items"].pop(_idx)
                                        rf()
                                    with ui.element("button").style(
                                            f"background:transparent;border:1px solid {C['danger']}40;"
                                            f"color:{C['danger']};border-radius:6px;padding:2px 6px;"
                                            f"font-size:11px;cursor:pointer;font-family:inherit;"
                                            ).on("click", _del_row):
                                        ui.label("×")
                        def _add_row(_s=sec, _ncols=_ncols):
                            _s.setdefault("items", []).append([""] * _ncols)
                            rf()
                        with ui.element("button").style(
                                f"background:transparent;border:1px dashed {C['teal']}55;"
                                f"color:{C['teal']};border-radius:6px;padding:5px 12px;"
                                f"font-size:11px;font-weight:600;cursor:pointer;"
                                f"font-family:inherit;align-self:flex-start;"
                                ).on("click", _add_row):
                            ui.label("＋ Add row")

                elif _stype == "qa":
                    for _qi, qa in enumerate(items):
                        if not isinstance(qa, dict):
                            continue
                        with ui.element("div").style(
                                f"padding:8px 10px;background:{C['surface']};"
                                f"border:1px solid {C['border']};border-radius:6px;"
                                f"display:flex;flex-direction:column;gap:5px;"):
                            _q_in = ui.input(
                                value=qa.get("q", ""),
                                placeholder="Question",
                            ).classes("fd-input")
                            def _commit_q(_in=_q_in, _qa=qa):
                                _qa["q"] = _in.value or ""
                            _bind(_q_in, _commit_q)
                            _a_in = ui.textarea(value=qa.get("a", "")).style(
                                f"width:100%;min-height:55px;background:{C['card']};"
                                f"border:1px solid {C['border']};border-radius:6px;"
                                f"padding:7px 9px;font-size:12px;color:{C['text_l']};"
                                f"font-family:inherit;line-height:1.5;resize:vertical;")
                            def _commit_a(_in=_a_in, _qa=qa):
                                _qa["a"] = _in.value or ""
                            _bind(_a_in, _commit_a)
                            with ui.element("div").style("display:flex;justify-content:flex-end;"):
                                def _del_qa(_s=sec, _idx=_qi):
                                    if _idx < len(_s["items"]):
                                        _s["items"].pop(_idx)
                                    rf()
                                with ui.element("button").style(
                                        f"background:transparent;border:1px solid {C['danger']}40;"
                                        f"color:{C['danger']};border-radius:6px;padding:2px 10px;"
                                        f"font-size:10px;cursor:pointer;font-family:inherit;"
                                        ).on("click", _del_qa):
                                    ui.label("× Remove")
                    def _add_qa(_s=sec):
                        _s.setdefault("items", []).append({"q": "New question", "a": ""})
                        rf()
                    with ui.element("button").style(
                            f"background:transparent;border:1px dashed {C['teal']}55;"
                            f"color:{C['teal']};border-radius:6px;padding:5px 12px;"
                            f"font-size:11px;font-weight:600;cursor:pointer;"
                            f"font-family:inherit;align-self:flex-start;"
                            ).on("click", _add_qa):
                        ui.label("＋ Add Q&A pair")

        # CTA
        with ui.element("div"):
            ui.label("Closing CTA").style(
                f"font-size:9px;font-weight:700;color:{C['muted']};"
                f"text-transform:uppercase;letter-spacing:.06em;margin-bottom:3px;")
            _cta_in = ui.textarea(value=data.get("cta", "")).style(
                f"width:100%;min-height:44px;background:{C['card']};"
                f"border:1px solid {C['border']};border-radius:6px;padding:8px 10px;"
                f"font-size:12px;color:{C['text_l']};font-family:inherit;"
                f"line-height:1.5;resize:vertical;")
            _bind(_cta_in, lambda: data.update({"cta": _cta_in.value or ""}))

        # ── Save / Cancel row ───────────────────────────────────────
        with ui.element("div").style(
                "display:flex;gap:10px;justify-content:flex-end;align-items:center;"):
            if _busy:
                ui.label("Working...").style(
                    f"font-size:11px;color:{C['muted']};font-style:italic;margin-right:auto;")
            def _do_save(k=_key, fname=pdf_filename):
                if k in s._pdf_editor_busy:
                    return
                # Flush every visible field into `data` BEFORE we read
                # it for the rebuild. Each input also has a blur
                # handler, but blur only fires when focus leaves —
                # users routinely click Save while still focused on a
                # textarea, and the latest keystroke can be lost. The
                # commit list is built top-down during render so this
                # mirrors the form's display order. Idempotent:
                # running it when nothing changed just rewrites the
                # same value into the same key.
                for _c in _commits:
                    try:
                        _c()
                    except Exception as _ex:
                        print(f"[PDF editor] commit failed: {_ex}", flush=True)
                s._pdf_editor_busy.add(k)
                rf()
                def _run():
                    try:
                        ok = _rebuild_pdf_from_sidecar_data(fname, s._pdf_editor_data[k])
                        if ok:
                            ui.notify("✓ PDF saved & re-rendered.", type="positive")
                            # Collapse the editor so the user lands back
                            # on a clean chip view instead of staring at
                            # the form they just saved (looked confusing —
                            # users couldn't tell if save had completed).
                            s._pdf_editor_open.discard(k)
                            s._pdf_editor_data.pop(k, None)
                        else:
                            ui.notify("Save failed — see logs.", type="negative")
                    finally:
                        s._pdf_editor_busy.discard(k)
                        rf()
                _run_as_user(getattr(s, "_user_email", "") or "", _run, name="pdf_editor_save_worker")
            with ui.element("button").classes("fd-pb").style(
                    f"padding:8px 20px;font-size:12px;"
                    + ("opacity:0.6;pointer-events:none;" if _busy else "")
                    ).on("click", _do_save):
                ui.label("\U0001F4BE Save & Re-render PDF")


def _format_salary_cell(cell):
    """If a table cell looks like a salary number or salary range, return
    it reformatted with dollar signs and thousands separators
    ('48000 - 58000' → '$48,000 - $58,000'). Otherwise return the cell
    unchanged. Heuristic guard: both numbers must be >= 10,000 so we
    don't mangle non-salary numerics like '1-5 yrs' or '12-15 percent'."""
    if not isinstance(cell, str):
        return cell
    s = cell.strip()
    if not s:
        return cell
    # Range pattern: "48000 - 58000", "$48,000-58000", "$48k - $58k"
    m = re.match(r'^\$?\s*([\d,]+)\s*[-–—]\s*\$?\s*([\d,]+)\s*$', s)
    if m:
        try:
            n1 = int(m.group(1).replace(",", ""))
            n2 = int(m.group(2).replace(",", ""))
            if n1 >= 10000 and n2 >= 10000:
                return f"${n1:,} - ${n2:,}"
        except (ValueError, OverflowError):
            pass
    # Single number: "48000", "$48,000"
    m2 = re.match(r'^\$?\s*([\d,]+)\s*$', s)
    if m2:
        try:
            n = int(m2.group(1).replace(",", ""))
            if n >= 10000:
                return f"${n:,}"
        except (ValueError, OverflowError):
            pass
    return cell


def _format_pdf_table_salaries(data: dict) -> None:
    """Walk every table section in the PDF data and reformat any cell that
    looks like a raw salary number or range. The AI prompt already asks
    for '$92,000 - $115,000' formatting but compliance is inconsistent —
    cells often come back as '48000 - 58000'. This post-processor is the
    safety net so the rendered PDF always has dollar signs + commas.
    Mutates `data` in place. Skips header rows (the first row of each
    table) so column titles like 'Base Salary Range' aren't touched."""
    for sec in data.get("sections", []) or []:
        if (sec.get("type") or "").lower() != "table":
            continue
        rows = sec.get("items") or []
        for ri, row in enumerate(rows):
            if ri == 0:  # header row — never reformat
                continue
            if isinstance(row, list):
                rows[ri] = [_format_salary_cell(c) for c in row]


def _generate_rich_pdf_data(client, kind: str, ctx: dict, research_context: str = "",
                             style_guide: str = "") -> dict:
    """Run the rich-PDF prompt for `kind` against Claude and return parsed
    build_custom_pdf data ({title, badge, intro, sections, cta}).

    Raises on parse failure so the caller can show a friendly error.
    Retries ONCE on JSON parse failure with a more explicit "valid JSON
    only" reminder — Claude occasionally drops a comma in long table
    rows (the bug that produced Elizabeth's blank Salary Guide PDF on
    2026-04-25). Two attempts at most so we don't burn tokens forever.
    """
    prompt = _rich_pdf_prompt(kind, ctx)
    full = prompt + (research_context or "") + (style_guide or "")
    last_err = None
    for _attempt in range(2):
        if _attempt == 1:
            # Second attempt: prepend a hard reminder. Claude responds
            # well to format-correction prompts after a parse failure.
            full = (
                "CRITICAL: Your previous response had invalid JSON "
                "(missing comma or unterminated string). Return ONLY a "
                "single valid JSON object — no markdown fences, no text "
                "before or after the braces, every key/value separated "
                "by a comma, every string properly quoted.\n\n"
            ) + full
        msg = _claude_create_with_retry(client,
            model="claude-haiku-4-5-20251001",
            max_tokens=2400,
            messages=[{"role": "user", "content": full}],
        )
        text = msg.content[0].text
        clean = text.replace("```json", "").replace("```", "").strip()
        match = re.search(r'\{.*\}', clean, re.DOTALL)
        if not match:
            last_err = ValueError("Could not parse rich PDF JSON from AI response.")
            continue
        try:
            data = json.loads(match.group())
            break
        except json.JSONDecodeError as _je:
            last_err = _je
            print(f"[PDF data] {kind} attempt {_attempt+1} JSON parse failed: {_je}", flush=True)
            continue
    else:
        # both attempts failed
        raise last_err or ValueError("Rich PDF JSON generation failed after retry.")
    # Normalize: ensure required keys exist.
    data.setdefault("title", "Market Briefing")
    data.setdefault("badge", "MARKET INTELLIGENCE")
    data.setdefault("intro", "")
    data.setdefault("sections", [])
    data.setdefault("cta", "")
    # Format salary cells in every table section ($XX,XXX - $XX,XXX).
    # Centralized here so every PDF code path benefits — no need to wire
    # the formatter into each call site.
    _format_pdf_table_salaries(data)
    return data


def _pdf_prompt_market_pulse(company, niche, positions, location):
    return (
        f"TARGET COMPANY: {company}\n"
        f"MARKET / NICHE: {niche or '(infer from web research on the target)'}\n"
        f"POSITIONS THEY'RE HIRING: {positions}\n"
        f"LOCATION: {location}\n\n"
        f"Research steps:\n"
        f"  1. Web-search {company} — confirm what they do, size, recent news, broader market context.\n"
        f"  2. Web-search current market conditions for {positions} in {location} — comp ranges, "
        f"time-to-fill, talent supply/demand, what's pressuring the market right now.\n"
        f"  3. Find at least 2 specific recent data points (announcements, layoffs, contracts, "
        f"comp shifts) that would matter to a hiring manager AT {company} this quarter.\n\n"
        f"Translate findings into a market briefing tailored to {company}. Reader = a hiring "
        f"manager at that company. Every bullet must connect a market fact to a hiring "
        f"decision they need to make. Designed to make them want a 12-minute call.\n\n"
        f"Return strict JSON:\n"
        f"{{\n"
        f'  "market_temp_bullets": ["3 bullets summarizing market conditions for these roles in this geography. Lead with specific stats or recent events. Each ~2 sentences."],\n'
        f'  "comp_bullets": ["3 bullets on what these positions actually pay in this market right now. Use real $ ranges. Note what drives the high end."],\n'
        f'  "timing_bullets": ["3 bullets on hiring velocity: typical time-to-fill, counteroffer rates, why first conversations matter."],\n'
        f'  "what_wins": ["3 bullets on what closes candidates in THIS market right now (specific to the role/region, not generic)."],\n'
        f'  "cta": "One sentence: invite a low-friction next step (e.g., 12-minute market pulse call)."\n'
        f"}}"
    )


