def _render_custom_pdf_modal(s: AppState, rf):
    """Modal for 'Create Your Own' PDFs. Two stages:
      - gallery: pick from 15 ideas OR type a free-form description
      - outline: preview the AI-generated outline before committing credits
    """
    # Backdrop + centered card
    with ui.element("div").style(
            "position:fixed;inset:0;background:rgba(10,20,40,.78);"
            "z-index:9998;display:flex;align-items:center;justify-content:center;"
            "backdrop-filter:blur(3px);"):
        with ui.element("div").style(
                f"background:{C['card']};border:1px solid {C['teal']}40;"
                f"border-radius:14px;padding:28px 32px;"
                f"width:720px;max-width:94vw;max-height:88vh;overflow-y:auto;"
                f"box-shadow:0 12px 40px rgba(0,0,0,.5);"):

            # ── STAGE 1: gallery + free-form prompt ─────────────────────
            if s._pdf_custom_stage == "gallery":
                with ui.element("div").style("display:flex;align-items:center;justify-content:space-between;margin-bottom:6px;"):
                    ui.label("✨ Create Your Own PDF").style(
                        f"font-size:19px;font-weight:800;color:{C['text_l']};"
                        f"font-family:'Nunito',sans-serif;")
                    def _close_modal():
                        s._pdf_custom_stage = "closed"
                        s._pdf_custom_outline = None
                        rf()
                    with ui.element("button").style(
                            f"background:transparent;border:none;font-size:20px;"
                            f"color:{C['muted']};cursor:pointer;padding:0 8px;"
                            ).on("click", _close_modal):
                        ui.label("✕").style("pointer-events:none;")

                ui.label(
                    "Describe any PDF you need for your clients or hiring managers. "
                    "Free flow - type it in your own words. Or pick from the gallery below to get started."
                ).style(f"font-size:12px;color:{C['muted']};margin-bottom:14px;display:block;line-height:1.5;")

                # Free-form textarea
                ui.label("Describe your PDF").style(
                    f"font-size:11px;font-weight:700;color:{C['teal']};"
                    f"text-transform:uppercase;letter-spacing:.06em;margin-bottom:6px;")
                _prompt_in = ui.textarea(
                    value=s._pdf_custom_prompt,
                    placeholder=(
                        "e.g. \"A one-pager showing why unionized HVAC candidates cost 30% "
                        "more but produce better quality work  -  for convincing skeptical GCs.\""
                    ),
                ).props("outlined rows=3").style(
                    f"width:100%;margin-bottom:6px;")

                # Preview-outline button
                def _do_preview():
                    p = (_prompt_in.value or "").strip()
                    if not p or len(p) < 10:
                        ui.notify("Give me a sentence or two describing what you want.", type="warning")
                        return
                    s._pdf_custom_prompt = p
                    s._pdf_custom_previewing = True
                    s._pdf_custom_stage = "outline"
                    rf()
                    # Kick off outline generation in background
                    _config_path = Path(str(_user_config_path()))
                    _company = s._pdf_company
                    _role = s._pdf_role
                    _location = s._pdf_location
                    _industry = s._pdf_industry
                    _primary_industry = (getattr(s, "_pdf_primary_industry", "") or "").strip()
                    _secondary_industries = list(getattr(s, "_pdf_secondary_industries", []) or [])
                    _exp = s._pdf_exp_level

                    def _run_outline():
                        try:
                            import anthropic
                            client = anthropic.Anthropic(api_key=ANTHROPIC_API_KEY)
                            # Build the campaign-context block. Primary +
                            # Secondary mirror what the user typed in the
                            # campaign wizard so every Create Your Own PDF
                            # is grounded in those exact fields.
                            _ctx = f"Company: {_company}\nPositions hiring for: {_role}\nLocation: {_location}\n"
                            if _primary_industry:
                                _ctx += f"Primary market / industry: {_primary_industry}\n"
                            if _secondary_industries:
                                _ctx += f"Secondary markets: {', '.join(_secondary_industries)}\n"
                            if _industry and not _primary_industry:
                                _ctx += f"Industry: {_industry}\n"
                            if _exp:
                                _ctx += f"Experience level: {_exp}\n"
                            prompt = (
                                f"You are designing a one-page branded PDF for a staffing "
                                f"recruiter's email outreach. The recruiter described it as:\n\n"
                                + _wrap_untrusted("user_description", p, max_chars=600) + "\n\n"
                                f"CONTEXT (use to ground the outline in this specific company / market / role):\n{_ctx}\n"
                                f"Propose an outline that fills a full page with rich content. Return ONLY valid JSON:\n"
                                f'{{"title": "Location + Industry/market + document type ONLY. Example: \\"Denver Manufacturing Market Snapshot\\". DO NOT list job titles, roles, or position names in the title — those go in the body. Keep it short (6-10 words).",\n'
                                f' "badge": "UPPERCASE TAG, 2-4 words",\n'
                                f' "sections": [\n'
                                f'   {{"heading": "Section name", "type": "paragraph", "item_count": 1}},\n'
                                f'   {{"heading": "Section name", "type": "table", "item_count": 5}},\n'
                                f'   {{"heading": "Section name", "type": "bullets", "item_count": 4}},\n'
                                f'   {{"heading": "Section name", "type": "qa", "item_count": 4}}\n'
                                f' ]}}\n\n'
                                f"Rules:\n"
                                f"- 4 to 5 sections total. Mix at least 3 different types (paragraph + table + bullets + qa) so the page is varied, not a wall of bullets.\n"
                                f"- Open with a 'paragraph' overview section. Include either a 'table' or a 'qa' block in the body.\n"
                                f"- For tables: item_count is rows of data (excluding header), aim for 4-6 rows.\n"
                                f"- For bullets: item_count 3-5. For qa: 3-5 pairs.\n"
                                f"- Headings should be specific and reference the company/market/role, not generic ('Compensation Benchmarks' beats 'Pay').\n"
                                f"- No fluff. Each section must earn its space and tie back to the user's request and the context above.\n"
                            )
                            msg = _claude_create_with_retry(client,
                                model="claude-haiku-4-5-20251001",
                                max_tokens=600,
                                messages=[{"role": "user", "content": prompt}],
                            )
                            text = msg.content[0].text
                            clean = text.replace("```json", "").replace("```", "").strip()
                            match = re.search(r'\{.*\}', clean, re.DOTALL)
                            if match:
                                s._pdf_custom_outline = json.loads(match.group())
                            else:
                                s._pdf_custom_outline = {"error": "Couldn't parse outline."}
                        except Exception as ex:
                            s._pdf_custom_outline = {"error": _friendly_ai_error(ex)}
                        finally:
                            s._pdf_custom_previewing = False

                    threading.Thread(target=_run_outline, daemon=True).start()

                with ui.element("div").style("display:flex;gap:10px;margin-bottom:22px;"):
                    with ui.element("button").classes("fd-pb").style(
                            "padding:9px 22px;font-size:13px;").on("click", _do_preview):
                        ui.label("Preview outline →")

                # Gallery label
                ui.element("div").style(f"height:1px;background:{C['border']};margin-bottom:14px;")
                ui.label("OR PICK AN IDEA FROM THE GALLERY").style(
                    f"font-size:10px;font-weight:700;color:{C['muted']};"
                    f"text-transform:uppercase;letter-spacing:.06em;margin-bottom:10px;display:block;")

                with ui.element("div").style(
                        "display:grid;grid-template-columns:1fr 1fr;gap:8px;"):
                    for _gt, _gd in _CUSTOM_PDF_GALLERY:
                        def _pick(gt=_gt, gd=_gd):
                            _prompt_in.set_value(f"{gt}. {gd}")
                            # also persist to state in case they click Preview next
                            s._pdf_custom_prompt = f"{gt}. {gd}"
                        with ui.element("div").style(
                                f"background:{C['surface']};border:1px solid {C['border']};"
                                f"border-radius:8px;padding:10px 14px;cursor:pointer;"
                                f"transition:all .15s;"
                                ).on("click", _pick):
                            ui.label(_gt).style(
                                f"font-size:12px;font-weight:700;color:{C['teal']};"
                                f"font-family:'Nunito',sans-serif;margin-bottom:2px;")
                            ui.label(_gd).style(
                                f"font-size:11px;color:{C['muted']};line-height:1.4;")

            # ── STAGE 2: outline preview ─────────────────────────────
            elif s._pdf_custom_stage == "outline":
                with ui.element("div").style("display:flex;align-items:center;justify-content:space-between;margin-bottom:14px;"):
                    ui.label("📋 Outline Preview").style(
                        f"font-size:19px;font-weight:800;color:{C['text_l']};"
                        f"font-family:'Nunito',sans-serif;")
                    def _back_to_gallery():
                        s._pdf_custom_stage = "gallery"
                        s._pdf_custom_outline = None
                        rf()
                    with ui.element("button").style(
                            f"background:transparent;border:1px solid {C['border']};"
                            f"color:{C['muted']};border-radius:7px;padding:6px 14px;"
                            f"font-size:11px;cursor:pointer;font-family:inherit;"
                            ).on("click", _back_to_gallery):
                        ui.label("← Edit prompt").style("pointer-events:none;")

                # User's prompt as a reminder
                with ui.element("div").style(
                        f"background:{C['surface']};border-left:3px solid {C['teal']};"
                        f"padding:10px 14px;border-radius:0 6px 6px 0;margin-bottom:18px;"):
                    ui.label("Your request").style(
                        f"font-size:10px;font-weight:700;color:{C['teal']};"
                        f"text-transform:uppercase;letter-spacing:.06em;margin-bottom:4px;")
                    ui.label(s._pdf_custom_prompt).style(
                        f"font-size:12px;color:{C['text']};line-height:1.5;font-style:italic;")

                # Loading spinner while outline generates
                if s._pdf_custom_previewing or s._pdf_custom_outline is None:
                    with ui.element("div").style(
                            "text-align:center;padding:40px 0;"):
                        ui.spinner("dots", size="36px", color=C["teal"])
                        ui.label("Drafting the outline... this is cheap (~$0.002).").style(
                            f"font-size:12px;color:{C['muted']};margin-top:10px;")
                    # Auto-refresh until ready
                    async def _poll_outline():
                        while s._pdf_custom_previewing:
                            await asyncio.sleep(1)
                        rf()
                    asyncio.ensure_future(_poll_outline())

                elif s._pdf_custom_outline.get("error"):
                    with ui.element("div").style(
                            f"background:{C['danger']}15;border:1px solid {C['danger']}40;"
                            f"border-radius:8px;padding:14px 18px;margin-bottom:14px;"):
                        ui.label("⚠ Couldn't draft an outline").style(
                            f"font-size:13px;font-weight:700;color:{C['danger']};margin-bottom:4px;")
                        ui.label(s._pdf_custom_outline["error"]).style(
                            f"font-size:11px;color:{C['text']};line-height:1.5;")

                else:
                    _outline = s._pdf_custom_outline
                    # Title + badge
                    ui.label(_outline.get("title", "Untitled PDF")).style(
                        f"font-size:18px;font-weight:800;color:{C['text_l']};"
                        f"font-family:'Nunito',sans-serif;margin-bottom:4px;")
                    if _outline.get("badge"):
                        ui.label(_outline["badge"]).style(
                            f"font-size:10px;font-weight:700;color:{C['teal']};"
                            f"text-transform:uppercase;letter-spacing:.08em;margin-bottom:14px;display:block;")

                    # Sections
                    ui.label(f"{len(_outline.get('sections', []))} SECTIONS").style(
                        f"font-size:10px;font-weight:700;color:{C['muted']};"
                        f"text-transform:uppercase;letter-spacing:.06em;margin-bottom:8px;display:block;")
                    for i, sec in enumerate(_outline.get("sections", []), 1):
                        _stype = sec.get("type", "bullets")
                        _count = sec.get("item_count", 3)
                        _type_label = {
                            "bullets": f"{_count} bullets",
                            "paragraph": "paragraph",
                            "table": f"{_count}-row table",
                            "qa": f"{_count} Q&A pairs",
                        }.get(_stype, _stype)
                        with ui.element("div").style(
                                f"display:flex;align-items:center;gap:12px;padding:10px 14px;"
                                f"background:{C['surface']};border:1px solid {C['border']};"
                                f"border-radius:6px;margin-bottom:6px;"):
                            ui.label(str(i)).style(
                                f"width:24px;height:24px;border-radius:50%;background:{C['teal']}20;"
                                f"color:{C['teal']};font-size:11px;font-weight:700;"
                                f"display:flex;align-items:center;justify-content:center;flex-shrink:0;")
                            with ui.element("div").style("flex:1;"):
                                ui.label(sec.get("heading", "Section")).style(
                                    f"font-size:13px;font-weight:600;color:{C['text_l']};"
                                    f"font-family:'Nunito',sans-serif;")
                            ui.label(_type_label).style(
                                f"font-size:10px;color:{C['muted']};flex-shrink:0;"
                                f"background:{C['card']};padding:3px 9px;border-radius:10px;"
                                f"border:1px solid {C['border']};")

                    # Action buttons
                    ui.element("div").style(f"height:1px;background:{C['border']};margin:18px 0;")
                    with ui.element("div").style("display:flex;gap:10px;justify-content:flex-end;"):
                        with ui.element("button").classes("fd-gb").style(
                                "padding:9px 18px;font-size:12px;").on("click", _back_to_gallery):
                            ui.label("Edit outline")

                        def _generate_custom():
                            # Close the modal and kick off the full PDF build
                            s._pdf_custom_stage = "closed"
                            s._pdf_generating = True
                            s._pdf_result = ""
                            _outline_snapshot = s._pdf_custom_outline
                            _prompt_snapshot = s._pdf_custom_prompt
                            _pdf_dir = Path(str(_user_pdf_dir()))
                            _config_path = Path(str(_user_config_path()))
                            _company = s._pdf_company
                            _role = s._pdf_role
                            _location = s._pdf_location
                            _industry_fill = s._pdf_industry
                            _primary_fill = (getattr(s, "_pdf_primary_industry", "") or "").strip()
                            _secondary_fill = list(getattr(s, "_pdf_secondary_industries", []) or [])
                            _exp_fill = s._pdf_exp_level
                            rf()

                            def _run():
                                try:
                                    import sys as _sys
                                    _sys.path.insert(0, str(Path(__file__).resolve().parent / "funnel_forge"))
                                    import importlib, arena_pdfs as _ap; importlib.reload(_ap)
                                    from arena_pdfs import build_custom_pdf
                                    import anthropic
                                    client = anthropic.Anthropic(api_key=ANTHROPIC_API_KEY)
                                    dt = date.today().strftime("%B %d, %Y")
                                    _cfg = json.loads(_config_path.read_text(encoding="utf-8")) if _config_path.exists() else {}
                                    prep = _cfg.get("sig_name", _get_company_name()) or _get_company_name()
                                    prep_email = _cfg.get("sig_email", "")

                                    # Build the content from the approved outline
                                    outline_str = json.dumps(_outline_snapshot, indent=2)
                                    _ctx_block = (
                                        f"Company: {_company}\n"
                                        f"Positions hiring for: {_role}\n"
                                        f"Location: {_location}\n"
                                    )
                                    if _primary_fill:
                                        _ctx_block += f"Primary market / industry: {_primary_fill}\n"
                                    if _secondary_fill:
                                        _ctx_block += f"Secondary markets: {', '.join(_secondary_fill)}\n"
                                    if _industry_fill and not _primary_fill:
                                        _ctx_block += f"Industry: {_industry_fill}\n"
                                    if _exp_fill:
                                        _ctx_block += f"Experience level: {_exp_fill}\n"
                                    fill_prompt = (
                                        f"You're writing content for a branded PDF the user already approved. "
                                        f"Stay inside the outline  -  fill each section with real, specific content "
                                        f"that fills a full page (no thin one-liner sections).\n\n"
                                        f"USER'S ORIGINAL REQUEST:\n"
                                        + _wrap_untrusted("user_description", _prompt_snapshot, max_chars=600) + "\n\n"
                                        f"CONTEXT (ground every section in these fields, the same Company / Primary / Secondary / Positions the user typed in the campaign wizard):\n{_ctx_block}\n"
                                        f"OUTLINE (fill this exactly):\n{outline_str}\n\n"
                                        f"Return ONLY valid JSON matching this shape:\n"
                                        f'{{"title": "...", "badge": "...", "intro": "1-2 sentence opener establishing context",\n'
                                        f' "sections": [\n'
                                        f'   {{"heading":"...", "type":"bullets", "items":["bullet 1", "bullet 2", ...]}},\n'
                                        f'   {{"heading":"...", "type":"paragraph", "items":["paragraph text"]}},\n'
                                        f'   {{"heading":"...", "type":"table", "items":[["Header1","Header2"],["row1col1","row1col2"], ...]}},\n'
                                        f'   {{"heading":"...", "type":"qa", "items":[{{"q":"Question","a":"Answer"}}, ...]}}\n'
                                        f' ],\n'
                                        f' "cta": "1 sentence closing CTA"}}\n\n'
                                        f"Rules:\n"
                                        f"- Fill the page. Paragraph sections: 3-5 sentences each. Bullet sections: each bullet ~2 sentences with a stat or specific.\n"
                                        f"- Q&A answers: 2-3 sentences each, substantive (not one-liners).\n"
                                        f"- Tables: include header row first, then 4-6 data rows. Every cell concrete (no 'Varies', 'Market Rate', 'TBD').\n"
                                        f"- Use REAL numbers, real comp ranges, real named events/trends. No placeholders.\n"
                                        f"- Match the item_count from the outline (or one or two more is fine if the page benefits).\n"
                                        f"- No em dashes, no markdown, no asterisks. Plain text in JSON strings only.\n"
                                    )
                                    msg = _claude_create_with_retry(client,
                                        model="claude-haiku-4-5-20251001",
                                        max_tokens=2400,
                                        messages=[{"role": "user", "content": fill_prompt + _style_guide_prompt()}],
                                    )
                                    text = msg.content[0].text
                                    clean = text.replace("```json", "").replace("```", "").strip()
                                    match = re.search(r'\{.*\}', clean, re.DOTALL)
                                    if not match:
                                        s._pdf_result = "Could not parse AI response for custom PDF."
                                        return
                                    data = json.loads(match.group())

                                    # Slug the title for the filename
                                    _title = data.get("title", "Custom_PDF")
                                    _slug = re.sub(r'[^A-Za-z0-9]+', '_', _title).strip('_')[:40] or "Custom_PDF"
                                    fname = f"{_slug}.pdf"
                                    _pdf_dir.mkdir(parents=True, exist_ok=True)
                                    fpath = str(_pdf_dir / fname)

                                    _custom_build_dict = {
                                        "title": data.get("title", "Custom One-Pager"),
                                        "badge": data.get("badge", "CUSTOM"),
                                        "date": dt,
                                        "prepared_by": prep,
                                        "prepared_email": prep_email,
                                        "logo_path": _get_company_logo_path(),
                                        "intro": data.get("intro", ""),
                                        "sections": data.get("sections", []),
                                        "cta": data.get("cta", ""),
                                    }
                                    build_custom_pdf(fpath, _custom_build_dict)
                                    _save_pdf_sidecar(fpath, _custom_build_dict)
                                    _publish_pdf(fpath)
                                    s._pdf_result = f"done:{fname}"
                                    # If the modal was opened from the email
                                    # editor, auto-attach the PDF to that step.
                                    _att_idx = getattr(s, '_pdf_custom_attach_step_idx', None)
                                    if _att_idx is not None:
                                        try:
                                            _loaded = getattr(s, 'loaded_camp', None)
                                            _target_steps = (
                                                (_loaded.get("emails") if _loaded else None)
                                                or getattr(s, 'es_emails', None)
                                            )
                                            if _target_steps and 0 <= _att_idx < len(_target_steps):
                                                _atts = _target_steps[_att_idx].setdefault("attachments", [])
                                                if fname not in _atts:
                                                    _atts.append(fname)
                                                print(f"[CustomPDF] Auto-attached {fname} to step {_att_idx}")
                                        except Exception as ex2:
                                            print(f"[CustomPDF] Auto-attach error: {ex2}")
                                        s._pdf_custom_attach_step_idx = None
                                except Exception as ex:
                                    s._pdf_result = _friendly_ai_error(ex)
                                finally:
                                    s._pdf_generating = False

                            _run_as_user(getattr(s, "_user_email", "") or "", _run, name="custom_pdf_gen_worker")

                        with ui.element("button").classes("fd-pb").style(
                                "padding:9px 22px;font-size:12px;").on("click", _generate_custom):
                            ui.label("✓ Generate the PDF")


# ── Target-a-Candidate Wizard ────────────────────────────────────────────────

def p_target_candidate(s: AppState, rf):
    """Find Candidates guided wizard. 3 steps:
    0. JD paste / upload (OPTIONAL — can skip)
    1. Sequence preset choice (cadence)
    2. AI generation + handoff to email editor

    The user adds candidates to the campaign LATER via the email editor's
    contacts step, not in this wizard. The legacy Step 2 "upload
    candidates CSV" was removed 2026-05-12 per user direction — users
    were sourcing candidates outside DripDrop and didn't want to also
    re-format and upload a CSV.

    Each step uses an `_tc_render_step_*` helper. Wizard state lives
    in s.tc_step (0..2) and the s.tc_* AppState slots."""
    with ui.element("div").style("max-width:920px;margin:0 auto;padding:24px;"):
        # Stepper UI
        steps_meta = [
            {"label": "The role (optional)"},
            {"label": "Cadence"},
            {"label": "Generate"},
        ]
        with ui.element("div").style(
                "display:flex;gap:8px;margin-bottom:24px;align-items:center;"):
            for i, meta in enumerate(steps_meta):
                is_done = i < s.tc_step
                is_current = i == s.tc_step
                bg = C["teal"] if is_current else (C["good"] if is_done else C["border"])
                fg = "#fff" if (is_current or is_done) else C["muted"]
                with ui.element("div").style(
                        "display:flex;align-items:center;gap:8px;"):
                    ui.html(
                        f"<div style='width:28px;height:28px;border-radius:50%;"
                        f"background:{bg};color:{fg};display:flex;align-items:center;"
                        f"justify-content:center;font-size:12px;font-weight:700;'>"
                        f"{'&#10003;' if is_done else i+1}</div>"
                    )
                    ui.label(meta["label"]).style(
                        f"font-size:12px;color:{C['text_l'] if is_current else C['muted']};"
                        f"font-weight:{600 if is_current else 400};")
                if i < len(steps_meta) - 1:
                    ui.html(
                        f"<div style='flex:0 0 30px;height:1px;background:var(--dd-border);'></div>"
                    )

        # Render current step. 3 steps now (was 4 — Candidates upload
        # step removed 2026-05-12). Step 2 is the legacy index for
        # Generate; old `tc_step == 3` saves get clamped on restore.
        _ts = int(getattr(s, "tc_step", 0) or 0)
        if _ts >= 3:
            _ts = 2  # legacy: step 3 was Generate in the old 4-step flow
            s.tc_step = _ts
        if _ts == 0:
            _tc_render_step_jd(s, rf)
        elif _ts == 1:
            _tc_render_step_preset(s, rf)
        else:
            _tc_render_step_generate(s, rf)


def _tc_render_step_jd(s: AppState, rf):
    """Step 1: JD upload/paste with AI parsing — OPTIONAL.
    Users can skip and proceed straight to cadence.

    Cleaned 2026-05-16: choose-one cards (Upload | Paste) instead of
    showing both inputs simultaneously. ``s.tc_jd_mode`` selects the
    active input ("", "upload", or "paste") and defaults from existing
    data on revisit."""
    ui.label("Step 1 - What are you recruiting for?").style(
        f"font-size:18px;font-weight:700;color:{C['text_l']};margin-bottom:6px;")
    ui.label("Pick whichever's easiest — describe the role in your own words, paste a "
             "job description, or upload one. Not sure? Skip and AI writes a solid "
             "generic sequence you can edit.").style(
        f"font-size:13px;color:{C['muted']};margin-bottom:18px;")

    # Default mode from any prior data so revisits land on the right input;
    # otherwise start on the friendliest option ("describe").
    if not getattr(s, "tc_jd_mode", "") or s.tc_jd_mode not in ("describe", "paste", "upload"):
        if s.tc_jd_filename:
            s.tc_jd_mode = "upload"
        elif (s.tc_jd_text or "").strip():
            s.tc_jd_mode = "paste"
        else:
            s.tc_jd_mode = "describe"

    def _set_mode(mode: str):
        s.tc_jd_mode = mode
        s.tc_error = ""
        rf()

    def _on_upload(e):
        import tempfile, os as _os
        try:
            data = e.content.read() if hasattr(e.content, "read") else bytes(e.content)
            fname = getattr(e, "name", None) or "jd.pdf"
            ext = ("." + fname.rsplit(".", 1)[-1].lower()) if "." in fname else ".pdf"
            s.tc_jd_filename = fname
            s.tc_jd_generating = True
            rf()
            # _extract_resume_text takes a file path, not bytes — write to temp
            fd, tmp_path = tempfile.mkstemp(suffix=ext, prefix="dd_jd_")
            try:
                with _os.fdopen(fd, "wb") as fh:
                    fh.write(data)
                extracted = _extract_resume_text(tmp_path)
            finally:
                try:
                    _os.unlink(tmp_path)
                except Exception:
                    pass
            s.tc_jd_text = (extracted or "").strip()
            if s.tc_jd_text:
                s.tc_jd_parsed = _tc_parse_jd(s.tc_jd_text)
            s.tc_jd_generating = False
            rf()
        except Exception as ex:
            s.tc_error = f"Upload failed: {ex}"
            s.tc_jd_generating = False
            rf()

    def _on_paste_change(e):
        val = ""
        if isinstance(e.args, str):
            val = e.args
        elif hasattr(e, "value"):
            val = e.value or ""
        s.tc_jd_text = val.strip()

    # Three clear ways to start — a mode chooser drives one focused input.
    _MODES = [("describe", "✍️ Describe the role"),
              ("paste", "📋 Paste a JD"),
              ("upload", "📎 Upload a file")]
    with ui.element("div").style("display:flex;gap:8px;margin-bottom:14px;flex-wrap:wrap;"):
        for _mk, _ml in _MODES:
            _on = (s.tc_jd_mode == _mk)
            with ui.element("button").style(
                    f"padding:9px 18px;font-size:13px;font-weight:700;border-radius:9px;"
                    f"cursor:pointer;font-family:inherit;border:1.5px solid "
                    f"{C['teal'] if _on else C['border']};"
                    f"background:{(C['teal'] + '22') if _on else 'transparent'};"
                    f"color:{C['teal'] if _on else C['text']};"
                    ).on("click", lambda _e, m=_mk: _set_mode(m)):
                ui.label(_ml).style("pointer-events:none;")

    with ui.element("div").style(
            f"background:{C['card']};border:1px solid {C['border']};"
            f"border-radius:10px;padding:18px;margin-bottom:14px;"):
        if s.tc_jd_mode == "upload":
            ui.label("Upload a job description").style(
                f"font-size:13px;font-weight:700;color:{C['text_l']};margin-bottom:4px;")
            ui.label("PDF or DOCX — AI reads it and tailors the outreach.").style(
                f"font-size:12px;color:{C['muted']};margin-bottom:14px;")
            with ui.element("div").style("display:flex;align-items:center;gap:14px;flex-wrap:wrap;"):
                # Hidden uploader driven by a visible button (NiceGUI's default
                # uploader renders nearly invisibly on this theme).
                with ui.element("div").style("height:0;overflow:hidden;"):
                    _jd_upload = ui.upload(on_upload=_on_upload, max_files=1,
                                           auto_upload=True).props('accept=".pdf,.docx,.doc"')
                with ui.element("button").classes("fd-pb").style(
                        "padding:11px 22px;font-size:13px;").on(
                        "click", lambda: _jd_upload.run_method("pickFiles")):
                    ui.label("⬆ Choose PDF / DOCX")
                if s.tc_jd_filename:
                    ui.label(f"✓ {s.tc_jd_filename}").style(
                        f"font-size:12px;color:{C['good']};font-weight:600;")
        else:
            _describe = (s.tc_jd_mode == "describe")
            ui.label("Tell AI what you're recruiting for" if _describe
                     else "Paste the job description").style(
                f"font-size:13px;font-weight:700;color:{C['text_l']};margin-bottom:4px;")
            ui.label("A sentence or two is plenty — role, location, and must-haves."
                     if _describe else
                     "Paste the full posting; AI pulls the title, skills, comp, and "
                     "location.").style(
                f"font-size:12px;color:{C['muted']};margin-bottom:12px;")
            _ph = ("e.g. Senior Superintendent for ground-up healthcare / OSHPD work in "
                   "Denver. 10+ years, $150–180k." if _describe
                   else "Paste the full job description here…")
            _ta = ui.textarea(value=s.tc_jd_text, placeholder=_ph).props(
                "rows=8 outlined dense").style("width:100%;")
            _ta.on("update:model-value", _on_paste_change)

    if s.tc_jd_generating:
        with ui.element("div").style(
                "display:flex;align-items:center;gap:8px;margin-bottom:12px;"):
            ui.spinner("dots", size="14px", color=C["teal"])
            ui.label("Parsing JD...").style(f"font-size:12px;color:{C['teal']};")

    if s.tc_jd_parsed:
        meta = s.tc_jd_parsed
        with ui.element("div").style(
                f"background:{C['teal_dim']};border:1px solid {C['teal']}40;"
                f"border-radius:8px;padding:12px 16px;margin-bottom:18px;"):
            ui.label(f"AI extracted: {meta.get('role_title', '?')} "
                     f"({meta.get('seniority', '?')})").style(
                f"font-size:13px;font-weight:600;color:{C['teal']};")
            if meta.get("key_skills"):
                ui.label("Skills: " + ", ".join(meta["key_skills"][:6])).style(
                    f"font-size:12px;color:{C['text_l']};margin-top:4px;")
            if meta.get("comp_range"):
                ui.label(f"Comp: {meta['comp_range']}").style(
                    f"font-size:12px;color:{C['text_l']};")
            if meta.get("location"):
                ui.label(f"Location: {meta['location']}").style(
                    f"font-size:12px;color:{C['text_l']};")

    if s.tc_error:
        ui.label(s.tc_error).style(
            f"font-size:12px;color:{C['danger']};margin-bottom:8px;")

    # Footer: Skip text link (left), Continue button (right — always
    # shown). The generation step branches on tc_jd_text/tc_jd_parsed so
    # Skip vs Continue both just advance to step 1.
    def _skip():
        # Wipe any half-typed JD so generation doesn't pick up a
        # one-line "asdf" by accident, then advance.
        s.tc_jd_text = ""
        s.tc_jd_filename = ""
        s.tc_jd_parsed = {}
        s.tc_jd_mode = ""
        s.tc_error = ""
        s.tc_step = 1
        rf()

    def _continue():
        s.tc_error = ""
        s.tc_step = 1
        rf()

    with ui.element("div").style(
            "display:flex;justify-content:space-between;align-items:center;"
            "margin-top:20px;gap:8px;"):
        with ui.element("a").style(
                f"font-size:13px;color:{C['muted']};cursor:pointer;"
                f"text-decoration:underline;"
                ).on("click", lambda _e: _skip()):
            ui.label("Skip — I'll let AI write a generic sequence →").style(
                "pointer-events:none;")
        # Continue is ALWAYS shown so there's always a next step. Pasting
        # the JD updates s.tc_jd_text via update:model-value but doesn't
        # re-render the page (we don't rerender per keystroke), so gating
        # this button on _has_jd left pasted JDs with no way forward.
        # _continue() keeps whatever JD text is present; the generate step
        # falls back to a generic sequence when it's empty.
        with ui.element("button").classes("fd-pb").style(
                "padding:10px 22px;font-size:13px;"
                ).on("click", lambda _e: _continue()):
            ui.label("Continue →").style("pointer-events:none;")


def _tc_render_step_candidates(s: AppState, rf):
    ui.label("Step 2 - Candidates").style(
        f"font-size:18px;font-weight:700;color:{C['text_l']};margin-bottom:6px;")
    ui.label("Upload a CSV of candidates to reach out to. Required columns: "
             "name, email. Optional: current_company, current_title, linkedin_url.").style(
        f"font-size:13px;color:{C['muted']};margin-bottom:18px;")

    def _on_csv(e):
        try:
            content = e.content.read() if hasattr(e.content, "read") else e.content
            text = content.decode("utf-8", errors="replace") if isinstance(content, bytes) else content
            # Try to reuse the Contacts page parser if it exists; otherwise
            # fall back to csv.DictReader.
            rows = None
            try:
                rows = _parse_contacts_csv(text)
            except (NameError, TypeError):
                rows = None
            if rows is None:
                import io as _io
                rdr = csv.DictReader(_io.StringIO(text))
                rows = [dict(r) for r in rdr]
            # Normalize keys (lowercase) and require name+email
            normalized = []
            for r in rows:
                rk = {k.lower().strip(): (v or "").strip() for k, v in r.items() if k}
                if rk.get("name") and rk.get("email"):
                    normalized.append({
                        "name": rk["name"],
                        "email": rk["email"],
                        "current_company": rk.get("current_company") or rk.get("company") or "",
                        "current_title": rk.get("current_title") or rk.get("title") or "",
                        "linkedin_url": rk.get("linkedin_url") or rk.get("linkedin") or "",
                    })
            s.tc_candidates = normalized
            s.tc_error = "" if normalized else "No valid rows found (need name + email columns)."
            rf()
        except Exception as ex:
            s.tc_error = f"CSV parse failed: {ex}"
            rf()

    ui.upload(on_upload=_on_csv, max_files=1,
              auto_upload=True).props('accept=".csv"').style("margin-bottom:14px;")

    if s.tc_error:
        ui.label(s.tc_error).style(
            f"font-size:12px;color:{C['danger']};margin-bottom:8px;")

    # Preview table (first 10 rows + count)
    if s.tc_candidates:
        ui.label(f"{len(s.tc_candidates)} candidates loaded").style(
            f"font-size:13px;font-weight:600;color:{C['text_l']};margin-bottom:8px;")
        with ui.element("table").style(
                f"width:100%;border-collapse:collapse;background:{C['card']};"
                f"border:1px solid {C['border']};border-radius:8px;overflow:hidden;"):
            with ui.element("thead").style(f"background:{C['surface']};"):
                with ui.element("tr"):
                    for col in ("Name", "Email", "Company", "Title", ""):
                        ui.html(
                            f"<th style='text-align:left;padding:8px 12px;"
                            f"font-size:11px;color:{C['muted']};font-weight:600;'>"
                            f"{col}</th>"
                        )
            with ui.element("tbody"):
                for i, cand in enumerate(s.tc_candidates[:10]):
                    with ui.element("tr").style(
                            "border-top:1px solid #F3F4F6;"):
                        for field in ("name", "email", "current_company", "current_title"):
                            val = (cand.get(field, "") or "").replace("<", "&lt;").replace(">", "&gt;")
                            ui.html(
                                f"<td style='padding:8px 12px;font-size:12px;"
                                f"color:{C['text_l']};'>{val}</td>"
                            )
                        def _remove(idx=i):
                            if 0 <= idx < len(s.tc_candidates):
                                del s.tc_candidates[idx]
                                rf()
                        with ui.element("td").style("padding:8px 12px;"):
                            with ui.element("button").style(
                                    f"padding:2px 8px;font-size:11px;"
                                    f"border:1px solid {C['muted']};"
                                    f"border-radius:4px;background:transparent;"
                                    f"color:{C['muted']};cursor:pointer;"
                                    ).on("click", _remove):
                                ui.label("&times;").style("pointer-events:none;")
        if len(s.tc_candidates) > 10:
            ui.label(f"... and {len(s.tc_candidates) - 10} more").style(
                f"font-size:11px;color:{C['muted']};margin-top:6px;")

    # Back / Continue
    with ui.element("div").style(
            "display:flex;justify-content:space-between;margin-top:20px;"):
        def _back():
            s.tc_step = 0
            rf()
        with ui.element("button").classes("fd-gb").style(
                "padding:10px 22px;font-size:13px;").on("click", _back):
            ui.label("<- Back").style("pointer-events:none;")
        def _continue():
            if len(s.tc_candidates) == 0:
                s.tc_error = "Upload a CSV with at least one candidate before continuing."
                rf()
                return
            s.tc_error = ""
            s.tc_step = 2
            rf()
        with ui.element("button").classes("fd-pb").style(
                "padding:10px 22px;font-size:13px;").on("click", _continue):
            ui.label("Continue ->").style("pointer-events:none;")


