def _slugify_holiday_name(name: str) -> str:
    """'Mother's Day' → 'mothers-day'. Used for override keys."""
    import re as _re
    s = name.lower()
    s = _re.sub(r"[^\w\s-]", "", s)
    s = _re.sub(r"\s+", "-", s).strip("-")
    return s


def _resolve_holiday_day(year: int, month: int, rule: tuple) -> int | None:
    """Resolve a holiday's date rule to a concrete day-of-month for the given
    year. Returns None if the rule doesn't apply to this month/year."""
    from datetime import date as _date, timedelta as _td
    kind = rule[0]
    if kind == "fixed":
        return int(rule[1])
    if kind == "nth-weekday":
        n, target_wd = int(rule[1]), int(rule[2])
        d = _date(year, month, 1)
        count = 0
        while d.month == month:
            if d.weekday() == target_wd:
                count += 1
                if count == n:
                    return d.day
            d += _td(days=1)
        return None
    if kind == "last-weekday":
        target_wd = int(rule[1])
        from calendar import monthrange as _mr
        last = _mr(year, month)[1]
        d = _date(year, month, last)
        while d.weekday() != target_wd:
            d -= _td(days=1)
        return d.day
    if kind == "easter":
        if month != 4:
            return None
        a = year % 19
        b = year // 100
        c = year % 100
        d_ = b // 4
        e = b % 4
        f = (b + 8) // 25
        g = (b - f + 1) // 3
        h = (19 * a + b - d_ - g + 15) % 30
        i = c // 4
        k = c % 4
        l = (32 + 2 * e + 2 * i - h - k) % 7
        m = (a + 11 * h + 22 * l) // 451
        em_month = (h + l - 7 * m + 114) // 31
        em_day = ((h + l - 7 * m + 114) % 31) + 1
        if em_month != 4:
            return 1
        return em_day
    return None


def _holidays_for_month(year: int, month: int,
                        overrides: dict | None = None) -> list[tuple]:
    """Return a list of (day_int, name, note) for the given month/year,
    sorted ascending by day. Empty list if no holidays.

    Overrides dict keys (in priority order):
      "MM-{slug}"  → applies only to that specific holiday
      "MM"         → legacy: applies to every holiday that month
    """
    out: list[tuple[int, str, str]] = []
    overrides = overrides or {}
    month_key = f"{month:02d}"
    for h in _HOLIDAYS:
        if h["month"] != month:
            continue
        day = _resolve_holiday_day(year, month, h["rule"])
        if day is None:
            continue
        slug_key = f"{month_key}-{_slugify_holiday_name(h['name'])}"
        if slug_key in overrides:
            note = overrides[slug_key]
        elif month_key in overrides:
            note = overrides[month_key]
        else:
            note = h["note"]
        out.append((day, h["name"], note))
    out.sort(key=lambda t: t[0])
    return out


def _render_holiday_calendar(year: int, month: int,
                              holidays: list[tuple]) -> str:
    """Render the left-rail mini calendar HTML for a newsletter footer.

    `holidays` is a list of (day_int, name, note) — typically from
    _holidays_for_month. Holiday days get a filled circle in the grid;
    a legend below the grid lists them in day order.

    Outlook desktop strips border-radius, so circles render as filled
    squares — acceptable degradation; the highlight color is still visible.
    """
    import calendar as _cal
    import html as _html
    from datetime import date as _date

    primary = _NL_COLORS["primary"]
    text = _NL_COLORS["text"]
    muted = _NL_COLORS.get("muted", "#888888")
    font = _NL_FONT

    month_name = _date(year, month, 1).strftime("%B")
    holiday_days = {h[0] for h in holidays}

    # Build the 7-column grid. Sunday-first ordering matches the mockup.
    cal = _cal.Calendar(firstweekday=6)
    weeks = cal.monthdayscalendar(year, month)

    # Zero-day cells = days from prev/next month. We fill those with the
    # actual day number rendered in muted color so the grid feels complete.
    from calendar import monthrange as _mr
    prev_month = 12 if month == 1 else month - 1
    prev_year = year - 1 if month == 1 else year
    prev_last = _mr(prev_year, prev_month)[1]

    rows_html: list[str] = []
    # Header row
    header_cells = "".join(
        f'<td style="padding:3px;text-align:center;color:{muted};'
        f'font-weight:700;font-size:9px;">{wd}</td>'
        for wd in ["S", "M", "T", "W", "T", "F", "S"]
    )
    rows_html.append(f"<tr>{header_cells}</tr>")

    # Build a flat list of (day, in_month) tuples for the whole grid.
    # `weeks` rows have zeros for cells outside the month.
    flat: list[tuple[int, bool]] = []
    for w in weeks:
        for d in w:
            flat.append((d, d != 0))
    # Replace leading zeros with prev-month tail.
    leading_zeros = next((i for i, (d, _) in enumerate(flat) if d != 0), 0)
    trailing_zeros = 0
    for i in range(len(flat) - 1, -1, -1):
        if flat[i][0] != 0:
            break
        trailing_zeros += 1
    for i in range(leading_zeros):
        flat[i] = (prev_last - leading_zeros + 1 + i, False)
    for i in range(trailing_zeros):
        flat[-trailing_zeros + i] = (i + 1, False)

    # Emit week rows from `flat`.
    for wk_idx in range(0, len(flat), 7):
        wk = flat[wk_idx:wk_idx + 7]
        cells = []
        for day, in_month in wk:
            if not in_month:
                cells.append(
                    f'<td style="padding:3px;text-align:center;color:{muted};'
                    f'font-size:9px;">{day}</td>'
                )
                continue
            if day in holiday_days:
                cells.append(
                    f'<td data-pc-day="{day}" '
                    f'style="padding:3px;text-align:center;'
                    f'background:{primary};color:#FFFFFF;'
                    f'border-radius:50%;font-weight:700;font-size:10px;">'
                    f'{day}</td>'
                )
            else:
                cells.append(
                    f'<td style="padding:3px;text-align:center;color:{text};'
                    f'font-size:10px;">{day}</td>'
                )
        rows_html.append(f"<tr>{''.join(cells)}</tr>")

    grid_html = (
        f'<div style="font-family:{font};font-size:10px;font-weight:700;'
        f'letter-spacing:1.6px;text-transform:uppercase;color:{primary};'
        f'text-align:center;margin-bottom:6px;">{month_name} {year}</div>'
        f'<table cellpadding="0" cellspacing="0" '
        f'style="width:100%;border-collapse:collapse;'
        f'font-family:Arial,sans-serif;">{"".join(rows_html)}</table>'
    )

    if not holidays:
        return grid_html

    def _legend_item(day, name, note):
        head = (
            f'<div><strong style="color:{primary};">{day}</strong> '
            f'{_html.escape(name, quote=False)}</div>'
        )
        if note:
            head += (
                f'<div style="font-style:italic;color:{muted};font-size:9px;'
                f'line-height:1.4;margin:1px 0 0 0;">'
                f'{_html.escape(note, quote=False)}</div>'
            )
        return f'<div style="margin-bottom:6px;">{head}</div>'

    legend_items = "".join(
        _legend_item(day, name, note)
        for day, name, note in sorted(holidays, key=lambda h: h[0])
    )
    legend_html = (
        f'<div data-pc-legend="1" '
        f'style="font-family:{font};font-size:10px;color:{text};'
        f'margin-top:8px;line-height:1.5;">{legend_items}</div>'
    )
    return grid_html + legend_html


def _render_corner_inner(data: dict) -> str:
    """Render the inner HTML for the Personal Corner column based on the
    issue's `personal_corner_mode`. Returns "&nbsp;" for empty/missing
    content. Output is the inner HTML — caller wraps it in
    <span data-pc="start"></span> / <span data-pc="end"></span> markers
    (span-based, not HTML comments, because _strip_dashes mangles `--`)."""
    import html as _html

    mode = (data.get("personal_corner_mode") or "").strip().lower()
    primary = _NL_COLORS["primary"]
    text = _NL_COLORS["text"]
    font = _NL_FONT
    display_font = _NL_DISPLAY_FONT

    label_style = (
        f"font-family:{font};font-size:10px;font-weight:700;"
        f"color:{primary};text-transform:uppercase;letter-spacing:1.6px;"
        f"margin:0 0 8px;"
    )
    body_style = (
        f"font-family:{display_font};font-size:12px;color:{text};"
        f"line-height:1.55;font-style:italic;"
    )

    if mode == "note":
        note = (data.get("personal_corner_note") or "").strip()
        if not note:
            return "&nbsp;"
        return (
            f'<div style="{label_style}">💭 ON MY MIND</div>'
            f'<div style="{body_style}">{_html.escape(note, quote=False)}</div>'
        )

    if mode == "photo":
        photo = (data.get("personal_corner_photo_b64") or "").strip()
        if not photo:
            return "&nbsp;"
        photo_src = _email_img_src(photo, "corner", mime="image/jpeg")
        if not photo_src:
            return "&nbsp;"
        caption = (data.get("personal_corner_caption") or "").strip()
        caption_html = (
            f'<div style="{body_style};margin-top:8px;">'
            f'{_html.escape(caption, quote=False)}</div>'
        ) if caption else ""
        return (
            f'<div style="{label_style}">📸 OUTSIDE THE OFFICE</div>'
            f'<img src="{photo_src}" '
            f'alt="" style="display:block;width:100%;max-width:200px;'
            f'height:auto;border-radius:6px;border:1px solid #E0E0E0;"/>'
            f'{caption_html}'
        )

    # mode == "" or unrecognized
    return "&nbsp;"


def _splice_corner_into_body(body_html: str, new_inner: str) -> str:
    """Replace the content between the first <span data-pc="start"></span> and
    <span data-pc="end"></span> marker pair with `new_inner`. If markers are
    absent, returns body_html unchanged (legacy issues without markers stay
    as-is until regenerated)."""
    if not body_html:
        return body_html
    import re as _re
    pattern = _re.compile(
        r'(<span data-pc="start"></span>)(.*?)(<span data-pc="end"></span>)',
        _re.DOTALL,
    )
    if not pattern.search(body_html):
        return body_html
    return pattern.sub(
        lambda m: f'{m.group(1)}{new_inner}{m.group(3)}',
        body_html, count=1,
    )


