# Generic manager+ fallback for sectors not yet in the map above.
# Intentionally bland so it's obvious in the AI output that a sector
# entry needs to be added.
_SPOTLIGHT_GENERIC_ADJACENCY = [
    "Director", "VP", "General Manager", "Operations Manager",
    "Senior Manager",
]


def _spotlight_prompt_block(sector: str, n: int,
                            target_roles: list,
                            recommendations: str = "") -> tuple:
    """Return (instruction_text, schema_text) for the spotlight section
    of the newsletter generation prompt. Returns ('', '') when n is 0.

    Pure function — no I/O, no AI calls — so the unit tests can hit it
    directly without mocking Anthropic.

    `recommendations` (2026-05-25): free-text guidance the user typed
    in the Create Newsletter dialog ("Focus on Senior PMs and OSHPD
    experience", "Skip junior roles", etc.). When non-empty, it
    overrides the default selection rules — the AI must follow the
    user's recommendation first, then fall back to the adjacent /
    target-role logic for any slots the recommendation doesn't fill.

    Spec: docs/superpowers/specs/2026-05-20-newsletter-spotlight-adjacent-roles-design.md
    """
    if not n or n <= 0:
        return ("", "")
    sector_key = (sector or "").strip().lower()
    adjacency = _SPOTLIGHT_ADJACENT_ROLES.get(
        sector_key, _SPOTLIGHT_GENERIC_ADJACENCY)
    adj_csv = ", ".join(adjacency)

    _recs_clean = (recommendations or "").strip()
    recs_block = ""
    if _recs_clean:
        # Truncate to keep token count sane — long blocks add noise.
        if len(_recs_clean) > 600:
            _recs_clean = _recs_clean[:600].rsplit(" ", 1)[0] + "…"
        recs_block = (
            f"USER RECOMMENDATIONS (highest priority — follow these "
            f"before the default selection rules below):\n"
            f"  {_recs_clean}\n\n"
        )

    target_clean = [str(r).strip() for r in (target_roles or [])
                    if str(r).strip()]
    if target_clean:
        target_block = (
            f"CAMPAIGN TARGET ROLES (must be reflected when possible):\n"
            f"  {', '.join(target_clean)}\n\n"
        )
        if len(target_clean) >= 3:
            mix_rule = (
                "  - About half the spotlights should reflect the target "
                "roles above; the rest should come from the adjacent "
                "manager+ roles for this sector."
            )
        else:
            mix_rule = (
                "  - Include every target role above; fill the remaining "
                "spotlight slots from the adjacent manager+ roles for "
                "this sector."
            )
    else:
        target_block = "CAMPAIGN TARGET ROLES: (none specified — draw from adjacent roles)\n\n"
        mix_rule = (
            "  - No target roles are set; draw all spotlights from the "
            "adjacent manager+ roles for this sector."
        )

    instruction = (
        f"\n\nCANDIDATE SPOTLIGHTS — auto-populate {n} anonymized "
        f"candidate profiles for this sector and region.\n\n"
        f"{recs_block}"
        f"{target_block}"
        f"ADJACENT MANAGER+ ROLES FOR THIS SECTOR:\n"
        f"  {adj_csv}\n\n"
        f"SELECTION RULES:\n"
        f"  - Every spotlight must be a SENIOR-level role. The bar is "
        f"seniority/experience (5+ years, hands-on senior practitioner), "
        f"NOT whether the title contains \"Manager.\" Both senior "
        f"individual contributors who DO the work (Senior Engineer, "
        f"Senior Architect, Senior Designer, Senior Estimator, Senior "
        f"Superintendent, Project Engineer with 5+ yrs, Principal "
        f"Engineer, Lead BIM Modeler, Senior PM) AND management roles "
        f"(Manager, Director, VP, Principal) are valid. Do NOT include "
        f"entry-level, junior, trades, apprentice, or field/labor "
        f"positions.\n"
        f"  - BALANCE: do NOT make every spotlight a Manager / Director "
        f"/ VP. At least HALF of the {n} spotlights MUST be senior "
        f"practitioners (senior ICs at the SAME seniority level as the "
        f"managers — pulled from across the sector's disciplines, not "
        f"just one). The output should NOT read as multiple variations "
        f"on \"Manager.\"\n"
        f"  - At least one spotlight must be a tech-flavored senior role "
        f"appropriate to the sector (BIM Manager, IT Director, "
        f"Engineering Tech Lead, Manufacturing Systems Manager, etc.).\n"
        f"{mix_rule}\n"
        f"  - Each profile is a composite (NOT a real person), labeled "
        f"\"Candidate A\", \"Candidate B\", etc. Titles + comp must "
        f"reflect real local market pricing — use web search if needed "
        f"to verify."
    )

    # JSON schema block — UNCHANGED from the pre-refactor version
    # (lines 39393–39410 in flowdrip_app.py before this change). The
    # downstream renderer reads the same fields.
    bpc = {0: 0, 3: 3, 6: 3}.get(n, 0)
    schema = (
        '\nCANDIDATE SPOTLIGHTS — these are CANDIDATES looking for work, '
        'NOT job postings. The salary_ask field is what the candidate '
        'wants to earn, expressed as a single hourly range OR a single '
        'annual base salary range. Do NOT tack on "plus $X bonus", '
        '"plus benefits", "(eligible for...)", "OTE", "+ stock", or '
        'anything that frames it like a job offer. Plain comp range only.\n'
        '  "spotlights": [\n    '
        + ",\n    ".join(
            f'{{"name": "Candidate {chr(65 + i)}", '
            f'"title": "manager+ role + years + key cred", '
            f'"location": "this region", '
            f'"salary_ask": "$XXk - $YYk (annual base only) OR $XX/hr - $YY/hr (hourly only) — real local range, NO bonuses, NO benefits, NO OTE, NO \\"plus $X\\"", '
            f'"bullets": [{bpc} short single-sentence bullets, each a concrete skill or result]}}'
            for i in range(n)
        )
        + '\n  ],\n'
    )

    return (instruction, schema)


def _jway_render(d: dict, contact_name: str) -> str:
    """Plain-text-style HTML for 'The J's Way' newsletter — simple paragraphs and
    bullets, no graphics/branding. Reads like a personal note."""
    def _esc(x):
        return (str(x or "").replace("&", "&amp;").replace("<", "&lt;").replace(">", "&gt;"))

    def _md(x):
        # Escape first (so user/AI text can't inject HTML), then honor the
        # **bold** emphasis the AI marks on key phrases/numbers.
        s = _esc(x)
        return re.sub(r"\*\*(.+?)\*\*", r"<strong>\1</strong>", s)

    def _ul(items):
        # Market bullets: dotted list with inline **bold** honored.
        lis = "".join(f"<li style='margin:3px 0;'>{_md(x)}</li>" for x in (items or []) if x)
        return (f"<ul style='margin:4px 0 14px 0;padding-left:20px;'>{lis}</ul>") if lis else ""

    P = ("margin:0 0 12px 0;font-family:Arial,Helvetica,sans-serif;font-size:14px;"
         "line-height:1.6;color:#222;")
    # Section headers: bold + underlined, per the house newsletter style.
    H = ("margin:18px 0 4px 0;font-family:Arial,Helvetica,sans-serif;font-size:14px;"
         "font-weight:bold;text-decoration:underline;color:#111;")
    # Candidate detail line style (tight dash bullets).
    DL = ("margin:2px 0;font-family:Arial,Helvetica,sans-serif;font-size:14px;"
          "line-height:1.5;color:#222;")

    def _detail_line(s):
        # "Label: value" -> "- <strong>Label:</strong> value". Strips any dash
        # the AI already prefixed; plain dash line when there is no label.
        t = str(s or "").strip().lstrip("-").strip()
        if not t:
            return ""
        if ":" in t:
            lbl, _, val = t.partition(":")
            return (f"<p style='{DL}'>- <strong>{_esc(lbl.strip())}:</strong> "
                    f"{_md(val.strip())}</p>")
        return f"<p style='{DL}'>- {_md(t)}</p>"

    _sector = (d.get("sector") or "").strip()
    _lc_sfx = f" (What matters for {_sector})" if _sector else ""
    _tk_sfx = f" for {_sector} and Skilled Trades" if _sector else ""

    out = []
    # Personal greeting — {FirstName} is substituted per recipient at send
    # time (_apply_merge_tokens); falls back to "Hi there," when unknown.
    out.append(f"<p style='{P}'>Hi {{FirstName}},</p>")
    if d.get("intro"):
        out.append(f"<p style='{P}'>{_md(d['intro'])}</p>")
    out.append(f"<p style='{P}'>If I missed anything or you want to dig into something "
               f"further, just let me know - happy to discuss.</p>")
    # Fixed Arena "Recruitment Rundown" banner — J's Way is Arena-only, so this
    # branded image is bundled (not user-pickable) and served via /static/.
    # Sits between the personal intro note and the Highlights block.
    out.append(
        "<img src='https://dripdripdrop.ai/static/jway_banner.png' width='600' "
        "style='display:block;width:100%;max-width:600px;height:auto;border:0;"
        "margin:6px 0 14px 0;' alt='Arena Direct Hire - Recruitment Rundown' />")
    if d.get("highlights"):
        mo = _esc(d.get("highlights_label") or "Highlights")
        out.append(f"<p style='{H}'>{mo}:</p>{_ul(d['highlights'])}")
    if d.get("snapshot_title"):
        out.append(f"<p style='{H}'>{_esc(d['snapshot_title'])}</p>")
        if (d.get("source_url") or "").strip():
            out.append(f"<p style='{P}'>Source: U.S. Bureau of Labor Statistics - "
                       f"<a href='{_esc(d['source_url'])}'>Article here</a></p>")
    for _key, _lbl in (("key_highlights", "Key Highlights"),
                       ("sector_strength", f"Sector Strength ({_sector})" if _sector else "Sector Strength"),
                       ("labor_context", f"Labor Market Context{_lc_sfx}"),
                       ("takeaway", f"Takeaway: What This Means{_tk_sfx}")):
        if d.get(_key):
            out.append(f"<p style='{H}'>{_lbl}:</p>{_ul(d[_key])}")
    cands = d.get("candidates") or []
    if cands:
        out.append(f"<p style='{H}'>Top Talent Currently Available:</p>")
        for c in cands:
            _hdr = c.get("label") or "Candidate"
            if c.get("role"):
                _hdr += f": {c['role']}"
            # Candidate name: bold + underlined.
            out.append(f"<p style='{P}margin-bottom:2px;'>"
                       f"<strong><u>{_esc(_hdr)}</u></strong></p>")
            for _b in (c.get("bullets") or []):
                out.append(_detail_line(_b))
            if (c.get("salary") or "").strip():
                _sv = c["salary"].strip()
                if ":" in _sv:
                    _sl, _, _svv = _sv.partition(":")
                    out.append(f"<p style='{DL}margin-top:6px;'>"
                               f"<strong>{_esc(_sl.strip())}:</strong> {_md(_svv.strip())}</p>")
                else:
                    out.append(f"<p style='{DL}margin-top:6px;'><strong>{_md(_sv)}</strong></p>")
    out.append(f"<p style='{P}margin-top:14px;'>"
               f"{_md(d.get('signoff') or 'Thank you, and I hope this was helpful!')}</p>")
    out.append(f"<p style='{P}margin-top:2px;'>Warm regards,</p>")
    return _strip_dashes("".join(out))


def _generate_jway_newsletter(client, camp: dict, nl_name: str, company: str,
                              sector: str, niche: str, region: str,
                              month_year: str, contact_name: str,
                              spot_n: int, spot_recs: str) -> tuple:
    """Generate 'The J's Way' (plain-text) newsletter content for one issue:
    personal market snapshot + live BLS data + available-talent list."""
    n_cand = spot_n if spot_n in (3, 6) else 4
    _picked = camp.get("newsletter_candidates") or []
    if _picked:
        _lines = []
        for i, c in enumerate(_picked[:6]):
            _role = (c.get("current_title") or c.get("role")
                     or c.get("target_role") or "Candidate")
            _info = (c.get("summary") or c.get("redacted_resume")
                     or c.get("resume_text") or "")[:600]
            _sal = c.get("salary") or ""
            _lines.append(f"Candidate {chr(65 + i)} ({_role}; target {_sal or 'market rate'}): {_info}")
        _cand_instr = ("Build 'Top Talent Currently Available' from THESE real candidates "
                       "(anonymize names; keep role, skills, proficiencies, industry, salary):\n"
                       + "\n".join(_lines))
    else:
        _cand_instr = (f"Generate {n_cand} realistic, anonymized 'Top Talent Currently "
                       f"Available' profiles relevant to {niche or sector} in {region}. "
                       + (f"Bias toward: {spot_recs}. " if spot_recs else "")
                       + "Each with experience, skills, proficiencies/tools, industry "
                       "background, and a target salary.")
    prompt = (
        f"Write a PLAIN, PERSONAL recruiting market newsletter — a warm, low-key note from "
        f"{contact_name or 'a recruiter'} at {company}. NO marketing fluff, NO emoji, NO "
        f"markdown. Sector: {sector or 'the market'}. Niche: {niche}. Region: {region}. "
        f"Month: {month_year}.\n"
        f"Use web search to pull the most recent REAL U.S. BLS jobs-report figures (total "
        f"jobs added, unemployment rate, year-over-year wage growth, average workweek). "
        f"Never fabricate stats — if a number isn't found, drop that bullet.\n"
        f"{_cand_instr}\n\n"
        f"Return ONLY valid JSON:\n"
        f'{{"subject":"plain, specific subject for this issue",'
        f'"intro":"1-2 SHORT, personable sentences: open with a warm seasonal touch tied to {month_year} (the month, the season, or a nearby holiday), then a brief nod to the {sector} market snapshot below. Warm and human, not corporate. Do NOT greet by name; a Hi {{FirstName}}, line is added automatically",'
        f'"highlights_label":"Highlights ({month_year})",'
        f'"highlights":["4 short bullets of REAL BLS data: jobs added, unemployment, wage growth YoY, average workweek"],'
        f'"snapshot_title":"{(sector or "Labor").title()} Labor Market Snapshot - {month_year}",'
        f'"source_url":"the real BLS jobs-report URL, or empty string",'
        f'"key_highlights":["EXACTLY 4 substantive bullets, each a full sentence with a real number AND why it matters; wrap the single key stat or phrase in **double asterisks**"],'
        f'"sector_strength":["EXACTLY 4 substantive bullets specific to {niche or sector} - name real sub-sectors and dynamics (supply chain, OEMs, defense, etc.); **bold** the key phrase in each"],'
        f'"labor_context":["EXACTLY 4 substantive bullets on what matters for {niche or sector} hiring right now; **bold** the key phrase in each"],'
        f'"takeaway":["EXACTLY 4 substantive bullets on what this means for {sector} and skilled trades; **bold** the key phrase in each"],'
        f'"candidates":[{{"label":"Candidate A","role":"specific job title","bullets":["Experience: N+ years ...","Skills: ...","Proficiencies: (name real tools/software) ...","Additional Skills: ...","Industry Background: ...","Preferred Shift: Open"],"salary":"Target Salary: $.."}}],'
        f'"signoff":"Thank you, and I hope this was helpful!"}}\n'
        f"No HTML, no emoji. Plain text EXCEPT you may wrap a few key phrases "
        f"in **double asterisks** for bold emphasis (no other markdown).")
    try:
        msg = _claude_create_with_retry(
            client, model="claude-haiku-4-5-20251001", max_tokens=4000,
            tools=[{"type": "web_search_20250305", "name": "web_search", "max_uses": 3}],
            messages=[{"role": "user", "content": prompt}])
        text = "".join(b.text for b in msg.content if hasattr(b, "text"))
        clean = text.replace("```json", "").replace("```", "").strip()
        m = re.search(r"\{.*\}", clean, re.DOTALL)
        if not m:
            return (None, None)
        try:
            d = json.loads(m.group())
        except json.JSONDecodeError:
            d = json.loads(re.sub(r",(\s*[}\]])", r"\1", m.group()))
    except Exception as e:
        print(f"[JWayNewsletter] AI call failed: {e}", flush=True)
        return (None, None)
    subject = (d.get("subject") or "").strip() or f"{(sector or 'Market').title()} Snapshot - {month_year}"
    # Sector label for the section headers (e.g. "Sector Strength (Manufacturing)").
    d.setdefault("sector", (niche or sector or "").strip().title())
    return (_strip_dashes(subject), _jway_render(d, contact_name))


def _generate_newsletter_content_for_step(camp: dict, step_idx: int) -> tuple:
    """Standalone newsletter content generator  -  no UI coupling.
    Used by both the manual Refresh flow and the auto-refresh scheduler.

    Returns (subject, body_html) or (None, None) on failure.
    """
    if not ANTHROPIC_API_KEY:
        return (None, None)
    try:
        from anthropic import Anthropic
        client = Anthropic(api_key=ANTHROPIC_API_KEY)
    except Exception as e:
        print(f"[NewsletterAutoRefresh] Anthropic init failed: {e}", flush=True)
        return (None, None)

    steps = camp.get("emails", []) or []
    if step_idx < 0 or step_idx >= len(steps):
        return (None, None)
    step = steps[step_idx]
    sector = camp.get("market_sector", "") or ""
    niche = camp.get("market_niche", "") or ""
    region = camp.get("market_region", "") or ""
    # Newsletter name fallback chain — newsletter_name first, then a
    # sector-derived title, then the campaign's own name (always present),
    # then a last-resort literal. Without the campaign-name step, older
    # newsletter campaigns that predate the newsletter_name field rendered
    # a giant generic "Newsletter" header in customer inboxes
    # (Denver Water/Wastewater issue, 2026-05-04).
    nl_name = (camp.get("newsletter_name") or "").strip()
    if not nl_name and sector:
        nl_name = sector.title() + " Report"
    if not nl_name:
        nl_name = (camp.get("name") or "").strip()
    if not nl_name:
        nl_name = "Newsletter"

    # Resolve user context from the campaign owner so config/signature are right
    _owner = camp.get("_owner_email") or _email_from_user_path(camp.get("_path", ""))
    if _owner:
        _CURRENT_USER_EMAIL.set(_owner)
        _switch_to_user_paths(_owner)

    # 2026-05-25 — newsletter month rolls forward on the 15th, not the
    # 1st. Recruiters draft / send their monthly newsletter mid-month
    # for the UPCOMING month — so on May 25 the content prompt must
    # tell Claude "write June content," not May. Mirrors the calendar
    # rollover rule in _render_newsletter_html.
    _today_nl = date.today()
    if _today_nl.day >= 15:
        if _today_nl.month == 12:
            _nl_year, _nl_month = _today_nl.year + 1, 1
        else:
            _nl_year, _nl_month = _today_nl.year, _today_nl.month + 1
    else:
        _nl_year, _nl_month = _today_nl.year, _today_nl.month
    month_year = date(_nl_year, _nl_month, 1).strftime("%B %Y")
    cfg = load_config()
    company = _get_company_name()
    contact_name = cfg.get("sig_name", "")
    # Fallback: pull name from signature file if sig_name is empty
    if not contact_name:
        try:
            _sig_p = _user_sig_path()
            if _sig_p.exists():
                _sig_lines = _sig_p.read_text(encoding="utf-8").strip().split("\n")
                if _sig_lines and _sig_lines[0].strip():
                    contact_name = _sig_lines[0].strip()
        except Exception:
            pass
    contact_email = cfg.get("sig_email", "") or (_owner or "")
    contact_phone = _get_signature_phone() or cfg.get("company_phone", "")
    website = (cfg.get("company_website") or "").strip()

    # Candidate spotlights — number of anonymized "hot in market" profiles
    # to auto-populate per issue. Set when the user creates the newsletter
    # ("None" / "3 per issue" / "6 per issue"). Helper builds the prompt
    # block; see _spotlight_prompt_block() for the seniority + adjacency
    # rules. Spec:
    # docs/superpowers/specs/2026-05-20-newsletter-spotlight-adjacent-roles-design.md
    try:
        _spot_n = int(camp.get("newsletter_spotlight_count", 0) or 0)
    except Exception:
        _spot_n = 0
    if _spot_n not in (0, 3, 6):
        _spot_n = 0
    _target_roles = camp.get("aicb_sel_roles") or []
    _spot_recs = (camp.get("newsletter_spotlight_recommendations") or "").strip()
    _spot_instruction, _spot_schema_block = _spotlight_prompt_block(
        sector=sector, n=_spot_n, target_roles=_target_roles,
        recommendations=_spot_recs)

    # "The J's Way" — plain-text personal newsletter (vs the rich "Full Send").
    if (camp.get("newsletter_style") or "").strip() == "j_way":
        return _generate_jway_newsletter(
            client, camp, nl_name, company, sector, niche, region,
            month_year, contact_name, _spot_n, _spot_recs)

    prompt = (
        f'You are writing content for a branded monthly newsletter.\n\n'
        f'NEWSLETTER: {nl_name}\n'
        f'COMPANY: {company}\n'
        f'SECTOR: {sector.title()}\n'
        f'REGION: {region}\n'
        f'MONTH: {month_year}\n\n'
        f'Generate CONCISE newsletter content as structured JSON. Keep everything SHORT:\n'
        f'- intro_text: 2 sentences max\n'
        f'- around_town: exactly 3 blurbs about the CITY (not the industry). '
        f'  MIX the content: one industry-adjacent item PLUS at least one fun/'
        f'  cultural item (new restaurant, park, sports story, event). 2 short sentences each.\n'
        f'- market_update: EXACTLY 3 bullets, each one sentence, '
        f'specifically about the {(niche or sector).strip()} market in {region} '
        f'(comp moves, talent supply, what offers are winning  -  no generic news).\n'
        f'Be specific  -  name real companies, projects, places, salary ranges. '
        f'Use web search for current data.'
        + _spot_instruction +
        f'\n\nReturn ONLY valid JSON:\n'
        f'{{\n'
        f'  "subject": "compelling subject line for this month",\n'
        f'  "jolts": {{\n'
        f'    "source_note": "BLS JOLTS + CES, <month year> release",\n'
        f'    "stats": [\n'
        f'      {{"label":"Job Openings","value":"REAL NUMBER like 8.1M or 12.4K  -  NO \'e.g.\'","change":"REAL % like +2.1% MoM","trend":"up|down|flat"}},\n'
        f'      {{"label":"Hire Rate","value":"REAL %","change":"REAL %","trend":"up|down|flat"}},\n'
        f'      {{"label":"Quit Rate","value":"REAL %","change":"REAL %","trend":"up|down|flat"}},\n'
        f'      {{"label":"Layoff Rate","value":"REAL %","change":"REAL %","trend":"up|down|flat"}},\n'
        f'      {{"label":"Unemployment","value":"national unemployment %","change":"MoM or YoY %","trend":"up|down|flat"}}\n'
        f'    ]\n'
        f'  }},\n'
        f'  "intro_text": "1-2 sentences max.",\n'
        f'  "around_town": [\n'
        f'    {{"category":"NEW|DEVELOPMENT|HAPPENING|EVENT|CULTURE|FOOD|SPORTS|NEIGHBORHOOD","headline":"5-10 word headline","blurb":"2 short sentences","link":"REAL full https:// URL of the source article (local news, press release, business journal). Empty string if no real URL."}},\n'
        f'    {{"category":"...","headline":"...","blurb":"...","link":"..."}},\n'
        f'    {{"category":"...","headline":"...","blurb":"...","link":"..."}}\n'
        f'  ],\n'
        f'  "market_update": "EXACTLY 3 bullet points on comp, talent supply, what offers are winning  -  niche-specific, NOT paragraphs.",\n'
        f'  "personal_corner_note": "2-3 first-person sentences (~25-50 words) reflecting on the month in the sender\'s voice. NO greeting, NO sign-off, NO link, NO CTA. Just a short reflection.",\n'
        + _spot_schema_block +
        f'  "top_news": ["2-3 ONE-SENTENCE headlines"]\n'
        f'}}\n\n'
        f'For JOLTS: use web search to pull the most recent NATIONAL BLS JOLTS data. '
        f'These are always national-level numbers (Job Openings in millions, rates as %). '
        f'Values should be compact (e.g. "8.1M", "3.6%"). "change" should be MoM or YoY.\n\n'
        f'CRITICAL: "value" must be a concrete number like "187K", "3.2%", "$42/hr". '
        f'If you cannot find a real number for a stat, OMIT that entire stat object from the array. '
        f'Never put prose like "Not separately published", "Regional data only", "N/A", "See note", '
        f'"Below national average" in the value field. Better 2 real numbers than 5 with placeholders.'
    )
    try:
        msg = _claude_create_with_retry(client,
            model="claude-haiku-4-5-20251001",
            max_tokens=4000,
            tools=[{"type": "web_search_20250305", "name": "web_search", "max_uses": 3}],
            messages=[{"role": "user", "content": prompt}])
        text = "".join(b.text for b in msg.content if hasattr(b, "text"))
        clean = text.replace("```json", "").replace("```", "").strip()
        m = re.search(r'\{.*\}', clean, re.DOTALL)
        if not m:
            return (None, None)
        try:
            result = json.loads(m.group())
        except json.JSONDecodeError:
            result = json.loads(re.sub(r',(\s*[}\]])', r'\1', m.group()))
    except Exception as e:
        print(f"[NewsletterAutoRefresh] AI call failed: {e}", flush=True)
        return (None, None)

    _corner_note_text = (result.get("personal_corner_note") or "").strip()
    _corner_mode = "note" if _corner_note_text else ""
    _stash_owner = (camp.get("_owner_email")
                    or _email_from_user_path(camp.get("_path", ""))
                    or "")
    _last_generated_corner[(_stash_owner, camp.get("name", ""), int(step_idx))] = {
        "mode": _corner_mode,
        "note": _corner_note_text,
    }

    # Prefer niche (more specific) over sector when available, so taglines
    # like "Construction — Healthcare Construction Intelligence for SoCal"
    # collapse to the cleaner "Healthcare Construction Intelligence for
    # SoCal". The \n splits into a bold main line + muted subtitle.
    _industry_lbl = (niche or "").strip() or (sector or "").strip()
    nl_data = {
        "company": company,
        "newsletter_name": nl_name,
        "tagline": (f"Market Pulse & Top {_industry_lbl.title()} Candidates"
                    if _industry_lbl else ""),
        "location": region,
        "website": website,
        "date": month_year,
        "intro_text": result.get("intro_text", ""),
        "top_news": result.get("top_news", []),
        "jolts": result.get("jolts", {}),
        "local_labor": result.get("local_labor", {}),
        "around_town": result.get("around_town", []),
        "market_update": result.get("market_update", ""),
        # Auto-generated anonymized candidate spotlights. The renderer at
        # _render_newsletter_html already knows how to render this key; we
        # just had to pass it through. Empty when newsletter_spotlight_count = 0.
        "spotlights": result.get("spotlights", []) if _spot_n > 0 else [],
        "contact_name": contact_name,
        "contact_email": contact_email,
        "contact_phone": contact_phone,
        "cta_text": "Let's Talk",
        "cta_url": f"mailto:{contact_email}" if contact_email else "#",
        "personal_corner_mode": _corner_mode,
        "personal_corner_note": _corner_note_text,
        "personal_corner_caption": "",
        "personal_corner_photo_b64": "",
    }
    # City Life toggle: defaults to True for legacy campaigns that
    # predate the field. Off only when the user explicitly unchecked
    # "Include City Life section" in the create dialog.
    _show_city_life = bool(camp.get("newsletter_show_city_life", True))
    _show_map = {
        "show_intro":         True,
        "show_jolts":         True,
        "show_market_update": True,
        "show_top_news":      True,
        "show_spotlight":     True,
        "show_around_town":   _show_city_life,
        "show_cta":           True,
    }
    try:
        body_html = _render_newsletter_html(nl_data, show=_show_map)
    except Exception as e:
        print(f"[NewsletterAutoRefresh] Render failed: {e}", flush=True)
        return (None, None)
    subject = _title_case_subject(
        result.get("subject", "") or f"{nl_name}  -  {month_year}")
    return (subject, body_html)


# ── Concurrency cap on Today-page AI generations ──────────────────────
# Each call briefing spawns 2 Claude calls (web search + walkthrough).
# When a user lands on /today with many campaigns, all bg threads kick
# off simultaneously, holding HTTP connections + response buffers in
# memory. On the 1GB droplet this can saturate memory and stall the
# NiceGUI WebSocket event loop ("Reconnecting to DripDrop…" overlay).
# Cap simultaneous AI work to 2 — campaigns waiting for a slot just
# show the spinner longer; their bg threads block on .acquire() until
# a slot frees. Shared between the call briefing + LI message threads.
_AI_GEN_SEMAPHORE = threading.Semaphore(2)


def _first_contact_company(camp: dict) -> str:
    """Return the company name of the first contact in the campaign,
    or empty string if none. Handles both CSV-import casing (Company)
    and normalized casing (company)."""
    contacts = camp.get("contacts", []) or []
    for c in contacts:
        if not isinstance(c, dict):
            continue
        name = (c.get("Company") or c.get("company") or "").strip()
        if name:
            return name
    return ""


_CALL_BRIEFING_SCHEMA_VERSION = 6  # bumped 2026-07-16: company overview replaces the walkthrough; market variants dropped


def _generate_call_briefing_for_campaign(camp: dict, force_refresh: bool = False) -> dict | None:
    """AI-generate a cold call briefing for the campaign's first contact's
    company. Uses web search to surface real open jobs, recent news, and
    the company overview / HQ / offices, plus talking points and candidate
    spotlights extracted from the email body.

    The overview/HQ/offices come from the SAME web-search step as jobs and
    news (schema v6, 2026-07-16) rather than from an unsearched model call.
    These are facts the recruiter says out loud on a live call, so they are
    grounded in search results under the same never-fabricate rules.

    Returns a dict like:
        {
            "_schema_version": 6,
            "company_name": "Brannan Companies",
            "company_overview": "...",
            "hq": "Denver, CO",
            "offices": ["Salt Lake City, UT", "Boise, ID"],  # never repeats hq
            "open_jobs": [{"title": "...", "location": "...", "url": "..."}, ...],
            "news": [{"headline": "...", "date": "...", "url": "..."}, ...],
            "candidates": [{"label": "...", "highlight": "..."}, ...],
            "talking_points": ["...", "...", "..."],
            "conversation_flow": {"opener": "..."},
        }
    or None on failure / missing API key.

    conversation_flow keeps only `opener`, and it is not rendered — it is
    retained solely to stay in sync with variants[0] for briefings that
    predate the variant pills. The discovery/pitch/close walkthrough was
    removed in v6 in favor of the company overview.

    Cached on `camp["call_briefing"]` and persisted via save_campaign().
    Pass force_refresh=True to bypass cache (used by the Refresh button
    in the UI). Old-schema cached briefings are auto-invalidated by
    checking _schema_version. Safe to call from a background thread.
    """
    # Cached? (unless force_refresh)
    if not force_refresh:
        cached = camp.get("call_briefing")
        # Schema check: only return cache if it matches current version.
        # Old briefings (no _schema_version, or schema_version=1) get
        # regenerated automatically on first view.
        if (isinstance(cached, dict)
                and cached.get("_schema_version") == _CALL_BRIEFING_SCHEMA_VERSION
                and (cached.get("open_jobs") or cached.get("news") or cached.get("candidates")
                     or cached.get("talking_points") or cached.get("conversation_flow")
                     or cached.get("company_overview") or cached.get("hq")
                     or cached.get("offices"))):
            return cached
    if not ANTHROPIC_API_KEY:
        return None
    try:
        from anthropic import Anthropic
        client = Anthropic(api_key=ANTHROPIC_API_KEY)
    except Exception as e:
        print(f"[CallBriefing] Anthropic init failed: {e}", flush=True)
        return None

    sector = camp.get("market_sector", "") or ""
    niche = camp.get("market_niche", "") or ""
    region = camp.get("market_region", "") or ""
    company = _first_contact_company(camp)

    # Resolve user context from campaign owner so save_campaign writes
    # to the correct per-user folder when called from a bg thread.
    _owner = camp.get("_owner_email") or _email_from_user_path(camp.get("_path", ""))
    if _owner:
        try:
            _CURRENT_USER_EMAIL.set(_owner)
            _switch_to_user_paths(_owner)
        except Exception:
            pass

    # Pull a sample of the email body so Claude can extract the candidate
    # spotlights the recruiter referenced in the original email.
    steps = camp.get("emails", []) or []
    sample_subject = ""
    sample_body = ""
    if steps:
        first = steps[0] or {}
        sample_subject = (first.get("subject") or "").strip()
        sample_body = (first.get("body") or "").strip()
        sample_body = re.sub(r'<[^>]+>', ' ', sample_body)
        sample_body = re.sub(r'\s+', ' ', sample_body).strip()
        sample_body = sample_body[:600]

    # ── Step 1: Web search for company overview + open jobs + news ──
    # The overview/HQ/offices live HERE rather than in the Step 2 writing
    # call on purpose: they are facts the recruiter reads aloud mid-call,
    # so they must come from search results, not model recall. Small
    # private companies (the bulk of our targets) are exactly where an
    # unsearched model invents a plausible-but-wrong HQ city.
    open_jobs: list = []
    news: list = []
    company_overview: str = ""
    hq: str = ""
    offices: list = []
    if company:
        search_prompt = (
            f"You are prepping a recruiter for a cold call to {company} "
            f"in {region}. Use web_search to find:\n\n"
            f"1) A company overview for {company} — search for "
            f"\"{company}\" and \"{company} about\" or their website. "
            f"Cover what the company actually does, roughly how big it "
            f"is, and what it's known for. 2-3 sentences, plain and "
            f"factual, no sales language.\n\n"
            f"2) Headquarters location for {company} — city and state "
            f"(and country if outside the US).\n\n"
            f"3) Other office / plant / branch locations for {company} — "
            f"city and state each. Up to 6. Do NOT include the HQ again.\n\n"
            f"4) Open jobs / current hiring at {company} — search for "
            f"\"{company} careers\" or \"{company} hiring\". Focus on "
            f"{sector} / {niche} roles if relevant. Surface 2-3 specific "
            f"open positions if you find any.\n\n"
            f"5) Recent news about {company} from the last ~60 days — "
            f"funding, expansion, project wins, layoffs, leadership "
            f"changes, M&A. Surface 1-3 items if you find any.\n\n"
            f"After searching, return ONLY valid JSON in this exact shape "
            f"(omit items you couldn't find — don't fabricate):\n"
            f'{{\n'
            f'  "company_overview": "...",\n'
            f'  "hq": "Denver, CO",\n'
            f'  "offices": ["Salt Lake City, UT", "Boise, ID"],\n'
            f'  "open_jobs": [\n'
            f'    {{"title": "Project Manager", "location": "Denver, CO", "url": "https://..."}}\n'
            f'  ],\n'
            f'  "news": [\n'
            f'    {{"headline": "...", "date": "April 2026", "url": "https://..."}}\n'
            f'  ]\n'
            f'}}\n\n'
            f"If nothing found for a list category, return that key as []. "
            f"If you cannot find the overview or HQ, return that key as \"\" "
            f"— an empty string is ALWAYS better than a guess. The recruiter "
            f"says these out loud to the prospect, so a wrong HQ city is "
            f"worse than no HQ city. Do NOT infer the HQ from the region "
            f"above ({region}) — that's the campaign's target market, not "
            f"necessarily where the company is based.\n"
            f"Never fabricate URLs — only use URLs you actually saw in "
            f"the search results."
        )
        try:
            ws_msg = _claude_create_with_retry(client,
                model="claude-haiku-4-5-20251001",
                max_tokens=2000,
                # 5 (was 3): schema v6 added overview/HQ/offices, so this
                # step now covers 5 topics instead of 2. At 3 the model
                # spent its budget on jobs+news and returned "" overviews.
                tools=[_safe_web_search_tool(max_uses=5)],
                messages=[{"role": "user", "content": search_prompt}])
            ws_text = "".join(b.text for b in ws_msg.content if hasattr(b, "text"))
            ws_clean = ws_text.replace("```json", "").replace("```", "").strip()
            m = re.search(r'\{.*\}', ws_clean, re.DOTALL)
            if m:
                try:
                    ws_result = json.loads(m.group())
                except json.JSONDecodeError:
                    ws_result = json.loads(re.sub(r',(\s*[}\]])', r'\1', m.group()))
                for j in (ws_result.get("open_jobs") or []):
                    if not isinstance(j, dict):
                        continue
                    title = str(j.get("title", "")).strip()
                    loc = str(j.get("location", "")).strip()
                    url = str(j.get("url", "")).strip()
                    if title:
                        open_jobs.append({"title": title, "location": loc, "url": url})
                for n in (ws_result.get("news") or []):
                    if not isinstance(n, dict):
                        continue
                    headline = str(n.get("headline", "")).strip()
                    date_str = str(n.get("date", "")).strip()
                    url = str(n.get("url", "")).strip()
                    if headline:
                        news.append({"headline": headline, "date": date_str, "url": url})
                # Strip <cite index="..."> markup before storing: these
                # render via ui.label(), which escapes HTML, so the tags
                # would show up as literal text on the call card. Observed
                # live — the overview is prose, so it comes back cited.
                company_overview = _strip_cite_tags(
                    str(ws_result.get("company_overview", "") or "")).strip()
                hq = _strip_cite_tags(str(ws_result.get("hq", "") or "")).strip()
                _offices_seen = []
                for o in (ws_result.get("offices") or []):
                    _o = _strip_cite_tags(str(o or "")).strip()
                    if _o and _o.lower() != hq.lower():
                        _offices_seen.append(_o)
                offices = _offices_seen[:6]
        except Exception as e:
            print(f"[CallBriefing] web search failed: {e}", flush=True)

    # ── Step 2: Generate the call walkthrough, talking points, and
    # extract candidate spotlights. The prompt has access to the web
    # search results from Step 1 so the script can reference real
    # open jobs and news items at the company. ──────────────────────
    candidates: list = []
    talking_points: list = []
    conversation_flow: dict = {}

    # Render Step 1 results as compact context for Step 2's prompt.
    if open_jobs:
        _jobs_ctx = "OPEN JOBS AT THIS COMPANY (from web search):\n" + "\n".join(
            f"- {j['title']}" + (f" — {j['location']}" if j.get("location") else "")
            for j in open_jobs
        )
    else:
        _jobs_ctx = "OPEN JOBS AT THIS COMPANY: none surfaced via web search."
    if news:
        _news_ctx = "RECENT NEWS ABOUT THIS COMPANY (from web search):\n" + "\n".join(
            f"- {n['headline']}" + (f" ({n['date']})" if n.get("date") else "")
            for n in news
        )
    else:
        _news_ctx = "RECENT NEWS ABOUT THIS COMPANY: none surfaced via web search."

    extract_prompt = (
        f"You are prepping a recruiter for a cold call to {company or 'a prospect company'} "
        f"in {region}. The recruiter has already sent the email below. Generate a "
        f"complete call-prep package as JSON.\n\n"
        f"CAMPAIGN CONTEXT:\n"
        f"- Sector: {sector}\n"
        f"- Niche: {niche}\n"
        f"- Region: {region}\n"
        f"- Company being called: {company or 'unknown'}\n\n"
        f"EMAIL ALREADY SENT:\n"
        f"- Subject: {sample_subject}\n"
        f"- Body excerpt: {sample_body}\n\n"
        f"{_jobs_ctx}\n\n"
        f"{_news_ctx}\n\n"
        f"Produce JSON with FOUR keys:\n\n"
        f"1) candidates: anonymized candidate spotlights the recruiter "
        f"can reference. CRITICAL — match the count to what's referenced "
        f"in the email body. If the email mentions 'six profiles' / "
        f"'5 candidates' / 'three PMs' (or labels like 'Candidate A, B, "
        f"C, D, E, F'), produce EXACTLY that many spotlights, in order, "
        f"so the recruiter can say \"I'm interested in Candidate C\" "
        f"and look up the right one. Cap at 8. If the email doesn't "
        f"reference any candidates, generate 3 representative ones. "
        f"Each candidate's 'label' MUST start with 'Candidate A:' / "
        f"'Candidate B:' / etc. in order, followed by role + years + "
        f"1 cred (e.g. 'Candidate A: Sr. PM, 12 yrs healthcare construction'). "
        f"'highlight' is 1 short sentence. Use {region} comp ranges. "
        f"NEVER use real names.\n\n"
        f"2) talking_points: 3-5 short, punchy bullets the recruiter can "
        f"weave into the call. Each is one sentence. Tie at least one "
        f"to the open jobs / news above when present.\n\n"
        f"3) conversation_flow.opener: 1-2 sentences. Reference the email "
        f"already sent. Acknowledge their time. Sound human, not scripted.\n\n"
        f"Return ONLY valid JSON in this exact shape:\n"
        f'{{\n'
        f'  "candidates": [\n'
        f'    {{"label": "Sr. PM, 12 yrs healthcare construction", "highlight": "..."}}\n'
        f'  ],\n'
        f'  "talking_points": ["...", "...", "..."],\n'
        f'  "conversation_flow": {{\n'
        f'    "opener": "..."\n'
        f'  }}\n'
        f'}}\n'
    )
    try:
        ex_msg = _claude_create_with_retry(client,
            model="claude-haiku-4-5-20251001",
            max_tokens=2000,
            messages=[{"role": "user", "content": extract_prompt}])
        ex_text = "".join(b.text for b in ex_msg.content if hasattr(b, "text"))
        ex_clean = ex_text.replace("```json", "").replace("```", "").strip()
        m = re.search(r'\{.*\}', ex_clean, re.DOTALL)
        if m:
            try:
                ex_result = json.loads(m.group())
            except json.JSONDecodeError:
                ex_result = json.loads(re.sub(r',(\s*[}\]])', r'\1', m.group()))
            for c in (ex_result.get("candidates") or []):
                if not isinstance(c, dict):
                    continue
                lbl = str(c.get("label", "")).strip()
                hi = str(c.get("highlight", "")).strip()
                if lbl and hi:
                    candidates.append({"label": lbl, "highlight": hi})
            talking_points = [
                str(t).strip() for t in (ex_result.get("talking_points") or [])
                if str(t).strip()
            ]
            cf = ex_result.get("conversation_flow") or {}
            if isinstance(cf, dict):
                # v6: opener only. discovery/pitch/close are deliberately
                # dropped — the walkthrough was replaced by the company
                # overview. opener stays for the variants[0] sync below.
                conversation_flow = {
                    "opener": str(cf.get("opener", "")).strip(),
                }
    except Exception as e:
        print(f"[CallBriefing] step-2 generation failed: {e}", flush=True)

    # ── Step 3: Generate 2 cold-call opener variants in Leigh's pitch DNA ──
    # Styles: Brief Diagnostic / Project-Anchored Direct.
    # Brief is FIRST because the pill row defaults to index 0 (see
    # _render_call_briefing_card) — order here is what selects the default.
    # The Market-Data Contrarian variant was dropped 2026-07-16 per user.
    # Single Claude call → one JSON response parsed into 2 variants.
    # Market stats pulled from the per-industry cache (Task 5) so scripts
    # use real fill-window data without hallucinating numbers.
    mkt = _market_stats_for_industry(sector or niche)
    variant_context = (
        f"- Company: {company}\n"
        f"- Sector / niche: {sector or '?'} / {niche or '?'}\n"
        f"- Open jobs at this company: {open_jobs[:2] if open_jobs else 'none surfaced'}\n"
        f"- Recent news: {news[:1] if news else 'none surfaced'}\n"
        f"- Industry market stats: {mkt or 'unavailable — do NOT invent stats'}\n"
    )
    variant_prompt = (
        f"You are writing 3 cold-call openers for a recruiter calling "
        f"{company} about {sector or niche or 'their hiring needs'}.\n\n"
        f"CONTEXT:\n{variant_context}\n"
        f"EMAIL ALREADY SENT (the recruiter just emailed this person):\n"
        f"- Subject: {sample_subject}\n"
        f"- Body excerpt: {sample_body}\n\n"
        f"WRITE EXACTLY 2 OPENERS. The HARDEST part of any cold call is "
        f"the opening line — give the user 2 options to test against "
        f"each other. BOTH must be tied to the same context as the "
        f"email above (same company, same sector, same project hooks); "
        f"variant 2 is an alternative angle on the same call.\n\n"
        f"VARIANT 1 — Brief Diagnostic\n"
        f"  ONE question only. Reference a specific company project or "
        f"open role. End with: 'what's harder right now: finding the "
        f"right people, or getting them to say yes?'\n\n"
        f"VARIANT 2 — Project-Anchored Direct\n"
        f"  Self-aware honesty (acknowledge it's a cold call but a "
        f"researched one). Anchor on a specific project / open role / "
        f"news item — IDEALLY the same hook the email above used so the "
        f"prospect feels continuity. Two questions ending in something "
        f"like 'who's owning the hiring, and is it you?'\n\n"
        f"STRICT RULES:\n"
        f"- Each variant under 80 words.\n"
        f"- Do NOT lead with a market statistic. That style was removed.\n"
        f"- Use the recruiter's actual name (placeholder {{recruiter_name}}) "
        f"and firm name (placeholder {{firm_name}}). The UI will substitute "
        f"these at display time.\n"
        f"- Address the prospect by first name only (use placeholder {{first_name}}).\n"
        f"- Do NOT fabricate market stats. If mkt is empty, drop the stat.\n"
        f"- Do NOT use emoji or markdown.\n\n"
        f"Return ONLY valid JSON:\n"
        f'{{"variants":['
        f'{{"style":"brief_diagnostic","label":"Brief Diagnostic","script":"..."}},'
        f'{{"style":"project_anchored","label":"Project-Anchored Direct","script":"..."}}'
        f']}}'
    )
    variants: list = []
    try:
        msg = _claude_create_with_retry(client,
            model="claude-haiku-4-5-20251001",
            max_tokens=1500,
            messages=[{"role": "user", "content": variant_prompt}])
        text = "".join(b.text for b in msg.content if hasattr(b, "text"))
        m = re.search(r'\{[\s\S]*\}', text)
        if m:
            parsed = json.loads(m.group(0))
            variants = parsed.get("variants") or []
    except Exception as ex:
        print(f"[CallBriefing] variants gen failed: {ex}", flush=True)
        variants = []

    # Populate result["variants"] and keep conversation_flow.opener in sync
    # with variant 1 for backwards compat with legacy UI code.
    if variants and isinstance(conversation_flow, dict) and conversation_flow:
        conversation_flow["opener"] = variants[0].get("script", conversation_flow.get("opener", ""))
    elif variants and not conversation_flow:
        # No conversation_flow generated (Step 2 failed) — synthesize minimal one.
        conversation_flow = {
            "opener": variants[0].get("script", ""),
        }

    # ── Step 4: Generate 2 voicemail variants in Leigh's pitch DNA ──
    # Same trial-options approach as the live-call openers: give the user
    # 2 styles so they can A/B which voice connects in their market.
    # Added 2026-05-12 per Leigh's feedback ("would be cool to do Live
    # Call AND Voicemail and have a few different versions").
    # Market-Insight dropped 2026-07-16 per user. Brief & Direct is FIRST
    # because the pill row defaults to index 0 — order selects the default.
    voicemail_variants: list = []
    vm_prompt = (
        f"You are writing 2 cold-call VOICEMAIL scripts for a recruiter "
        f"calling {company} about {sector or niche or 'their hiring needs'}. "
        f"These fire when no one picks up.\n\n"
        f"CONTEXT:\n{variant_context}\n"
        f"WRITE EXACTLY 2 VOICEMAILS, each in a distinct style:\n\n"
        f"VARIANT 1 — Brief & Direct\n"
        f"  Under 20 seconds. Direct: 'we run direct hire searches in "
        f"[sector], your hiring profile lines up — worth a 15-min call.' "
        f"Ends with the recruiter's phone number.\n\n"
        f"VARIANT 2 — Project-Anchored\n"
        f"  Reference a specific project / open role at the company so "
        f"the prospect knows the recruiter did real homework. Ends with "
        f"the recruiter's phone number. ~25 seconds spoken.\n\n"
        f"PHONE NUMBER — end with a short call-back line that uses the "
        f"placeholder {{phone}} once (e.g. 'Reach me at {{phone}}.'). "
        f"The UI substitutes the recruiter's actual number at display "
        f"time. Do NOT spell digits out, do NOT repeat the number, "
        f"do NOT add hyphens between every word.\n\n"
        f"STRICT RULES:\n"
        f"- Each variant under 70 words.\n"
        f"- Sound natural when spoken aloud. No corporate jargon.\n"
        f"- Do NOT lead with a market statistic. That style was removed.\n"
        f"- Use placeholders {{recruiter_name}} and {{firm_name}}; "
        f"address the prospect with {{first_name}}.\n"
        f"- Do NOT fabricate market stats. If no stat available, drop it.\n"
        f"- Do NOT use emoji, markdown, or numbered lists.\n\n"
        f"Return ONLY valid JSON:\n"
        f'{{"variants":['
        f'{{"style":"vm_brief_direct","label":"Brief & Direct","script":"..."}},'
        f'{{"style":"vm_project_anchored","label":"Project-Anchored","script":"..."}}'
        f']}}'
    )
    try:
        vm_msg = _claude_create_with_retry(client,
            model="claude-haiku-4-5-20251001",
            max_tokens=1200,
            messages=[{"role": "user", "content": vm_prompt}])
        vm_text = "".join(b.text for b in vm_msg.content if hasattr(b, "text"))
        vm_match = re.search(r'\{[\s\S]*\}', vm_text)
        if vm_match:
            vm_parsed = json.loads(vm_match.group(0))
            voicemail_variants = vm_parsed.get("variants") or []
    except Exception as ex:
        print(f"[CallBriefing] voicemail variants failed: {ex}", flush=True)
        voicemail_variants = []

    if not (open_jobs or news or candidates or talking_points or conversation_flow
            or company_overview or hq or offices):
        return None

    briefing = {
        "_schema_version": _CALL_BRIEFING_SCHEMA_VERSION,
        "company_name": company,
        "company_overview": company_overview,
        "hq": hq,
        "offices": offices,
        "open_jobs": open_jobs,
        "news": news,
        "candidates": candidates,
        "talking_points": talking_points,
        "conversation_flow": conversation_flow,
        "variants": variants,
        "voicemail_variants": voicemail_variants,
    }
    camp["call_briefing"] = briefing
    try:
        save_campaign(camp)
    except Exception as e:
        print(f"[CallBriefing] save_campaign failed: {e}", flush=True)
    return briefing


def _generate_li_message_for_campaign(camp: dict) -> str | None:
    """AI-generate a single LinkedIn connection-request message tailored
    to the campaign's audience. Returns the message string (under 300
    chars) or None on failure / missing API key.

    Cached on `camp["linkedin_message"]` and persisted via save_campaign().
    Safe to call from a background thread.
    """
    cached = camp.get("linkedin_message")
    if isinstance(cached, str) and cached.strip():
        return cached.strip()
    if not ANTHROPIC_API_KEY:
        return None
    try:
        from anthropic import Anthropic
        client = Anthropic(api_key=ANTHROPIC_API_KEY)
    except Exception as e:
        print(f"[LiMessage] Anthropic init failed: {e}", flush=True)
        return None

    sector = camp.get("market_sector", "") or ""
    niche = camp.get("market_niche", "") or ""
    region = camp.get("market_region", "") or ""

    _owner = camp.get("_owner_email") or _email_from_user_path(camp.get("_path", ""))
    if _owner:
        try:
            _CURRENT_USER_EMAIL.set(_owner)
            _switch_to_user_paths(_owner)
        except Exception:
            pass

    # Sender's firm name powers the brief intro line ("I'm with X, ...").
    sender_firm = ""
    try:
        sender_firm = _get_company_name() or ""
    except Exception:
        sender_firm = ""
    sender_firm = sender_firm.strip()

    # Topic for the email reference: prefer niche, fall back to sector,
    # fall back to a generic "your role".
    topic = (niche or sector or "your role").strip()

    prompt = (
        f"Write ONE LinkedIn connection-request message that follows up "
        f"on an email the recruiter ALREADY SENT.\n\n"
        f"CONTEXT:\n"
        f"- Sender works at: {sender_firm or 'a recruiting firm'}\n"
        f"- Recruiter focuses on: {topic} hires in {region or 'their market'}\n\n"
        f"STRUCTURE (3 short sentences, in this order):\n"
        f"1) Reference the email: 'Just sent you an email re: {topic}' "
        f"(or similar). Make clear they sent the email already.\n"
        f"2) Brief intro: who they are / what their firm does. "
        f"Mention {sender_firm or 'their firm'} by name if available.\n"
        f"3) Soft close: 'Open to a quick chat if useful' or similar.\n\n"
        f"STRICT RULES:\n"
        f"- Under 280 characters total (LinkedIn cap on connection notes).\n"
        f"- No greeting like 'Hi {{first_name}}' (LinkedIn shows the "
        f"name automatically).\n"
        f"- No 'Best,' or sign-off.\n"
        f"- Casual, peer-to-peer tone. Not salesy. No emoji.\n\n"
        f"Return ONLY the message text. No quotes, no explanation."
    )
    try:
        msg = _claude_create_with_retry(client,
            model="claude-haiku-4-5-20251001",
            max_tokens=300,
            messages=[{"role": "user", "content": prompt}])
        text = "".join(b.text for b in msg.content if hasattr(b, "text"))
    except Exception as e:
        print(f"[LiMessage] AI call failed: {e}", flush=True)
        return None

    out = (text or "").strip()
    # Strip surrounding quotes if Claude wrapped the message.
    if out and out[0] in ("\"", "'") and out[-1] in ("\"", "'"):
        out = out[1:-1].strip()
    if not out:
        return None
    if len(out) > 300:
        # Try truncating at the last sentence-ending period before 280.
        cut = out[:280]
        last_p = cut.rfind(".")
        if last_p >= 60:
            out = cut[: last_p + 1].strip()
        else:
            # Hard truncate.
            out = (out[:297]).rstrip() + "..."
    out = out.strip()
    if not out:
        return None

    camp["linkedin_message"] = out
    try:
        save_campaign(camp)
    except Exception as e:
        print(f"[LiMessage] save_campaign failed: {e}", flush=True)
    return out


def _gen_one_issue_for_campaign(camp_name: str, idx: int) -> bool:
    """Generate AI content for a single step of the named newsletter
    campaign. Returns True if content was successfully written (or was
    already present), False otherwise.

    Used by the post-create background thread to populate the first issue
    promptly (so the "Generating…" banner can flip to success after ~25s),
    and reused by `_gen_all_issues_for_campaign` for the remaining months.
    """
    fresh = next((c for c in load_campaigns() if c.get("name") == camp_name), None)
    if not fresh or not fresh.get("emails"):
        print(f"[NewsletterAutoOne] campaign not found: {camp_name}", flush=True)
        return False
    steps = fresh.get("emails", []) or []
    if idx < 0 or idx >= len(steps):
        return False
    st = steps[idx]
    if (st.get("body") or "").strip() and "[AI:" not in (st.get("body") or ""):
        return True  # already populated
    try:
        subj, body = _generate_newsletter_content_for_step(fresh, idx)
    except Exception as ex:
        print(f"[NewsletterAutoOne] step {idx} error for {camp_name}: {ex}",
              flush=True)
        return False
    if not subj or not body:
        print(f"[NewsletterAutoOne] step {idx} returned empty for {camp_name}",
              flush=True)
        return False
    steps[idx]["subject"] = subj
    steps[idx]["body"] = body
    _stashed = _pop_last_generated_corner(
        fresh.get("_owner_email", "")
        or _email_from_user_path(fresh.get("_path", "")) or "",
        camp_name, idx)
    if _stashed:
        steps[idx]["personal_corner_mode"] = _stashed.get("mode", "")
        steps[idx]["personal_corner_note"] = _stashed.get("note", "")
    save_campaign(fresh)
    print(f"[NewsletterAutoOne] step {idx} ready for {camp_name}", flush=True)
    return True


def _gen_all_issues_for_campaign(camp_name: str) -> None:
    """Generate AI content for every step of the named newsletter campaign.

    Used by the post-create background thread so users have a draft for
    every scheduled month immediately. Steps that already have non-empty
    bodies are skipped (idempotent — safe to re-run). Sleeps briefly
    between issues to keep the Anthropic rate limit happy.
    """
    import time as _time
    fresh = next((c for c in load_campaigns() if c.get("name") == camp_name), None)
    if not fresh or not fresh.get("emails"):
        print(f"[NewsletterAutoAll] campaign not found: {camp_name}", flush=True)
        return
    steps = fresh.get("emails", []) or []
    for idx in range(len(steps)):
        _gen_one_issue_for_campaign(camp_name, idx)
        _time.sleep(3)
    try:
        _cache_campaigns.invalidate()
    except Exception:
        pass


def _auto_refresh_newsletter_tick():
    """Scan every user's newsletter campaigns and refresh the next pending
    step whenever its send is within 5 days AND the step hasn't been
    auto-refreshed yet (or was refreshed more than 6 days ago).

    The refreshed content is written back to:
      - the campaign file (so the UI shows the new body/subject)
      - every pending queue item that maps to this step (so the scheduler
        sends the fresh version, not the stale cached one)

    Idempotent: a per-step `_auto_refreshed_at` timestamp prevents
    double-refreshing within the same window.
    """
    from datetime import timezone as _tz, timedelta as _td
    users_dir = _BASE_DATA_DIR / "users"
    if not users_dir.exists():
        return
    now_utc = datetime.now(_tz.utc)
    refresh_window = _td(days=3)
    cooldown = _td(days=6)
    refreshed_count = 0

    for user_dir in users_dir.iterdir():
        if not user_dir.is_dir():
            continue
        camp_dir = user_dir / "Campaigns"
        if not camp_dir.exists():
            continue
        queue_path = user_dir / "scheduled_queue.json"
        if not queue_path.exists():
            continue
        try:
            queue = json.loads(queue_path.read_text(encoding="utf-8"))
        except Exception:
            continue
        if not isinstance(queue, list):
            continue

        for camp_file in camp_dir.glob("*.json"):
            if camp_file.name == "responded.json":
                continue
            try:
                camp = json.loads(camp_file.read_text(encoding="utf-8"))
            except Exception:
                continue
            if not camp.get("market_analysis"):
                continue
            # Stamp _owner_email/_path so the content generator can rebind context
            camp["_path"] = str(camp_file)
            camp["_owner_email"] = camp.get("_owner_email") or _email_from_user_path(str(camp_file))

            camp_name = camp.get("name", "")
            steps = camp.get("emails", []) or []
            if not steps:
                continue

            # Find the next pending queue item for this campaign
            _next = None
            for q in queue:
                if q.get("campaign") != camp_name:
                    continue
                if q.get("status") != "pending":
                    continue
                _sdt = q.get("send_dt", "")
                if not _sdt:
                    continue
                try:
                    _naive = datetime.fromisoformat(_sdt)
                    _aware = _naive.replace(tzinfo=_tz.utc)
                except Exception:
                    continue
                if _next is None or _aware < _next[1]:
                    _next = (q, _aware)
            if not _next:
                continue
            q_item, send_aware = _next

            # Is the send within the 5-day window?
            if send_aware - now_utc > refresh_window:
                continue
            if send_aware <= now_utc:
                continue  # already due  -  leave it to the send scheduler

            # Map queue item → campaign step index (best-effort match on step_name or subject)
            step_idx = -1
            _qsname = (q_item.get("step_name") or "").strip()
            _qsubj = (q_item.get("subject") or "").strip()
            for i, st in enumerate(steps):
                if _qsname and (st.get("name") or "").strip() == _qsname:
                    step_idx = i; break
            if step_idx < 0:
                for i, st in enumerate(steps):
                    if _qsubj and (st.get("subject") or "").strip() == _qsubj:
                        step_idx = i; break
            if step_idx < 0:
                # Fall back to the first non-sent email step
                for i, st in enumerate(steps):
                    if st.get("step_type", "email_auto") in ("email_auto", "email", "email_manual", ""):
                        step_idx = i; break
            if step_idx < 0:
                continue

            step = steps[step_idx]
            # User-confirmed steps are owned by the user. Never overwrite.
            # `confirmed: true` is set when the user clicks Save in the Edit modal.
            if step.get("confirmed"):
                continue
            # Cooldown: skip if already refreshed recently
            _last = step.get("_auto_refreshed_at", "") or ""
            if _last:
                try:
                    _last_dt = datetime.fromisoformat(_last.replace("Z", "+00:00"))
                    if _last_dt.tzinfo is None:
                        _last_dt = _last_dt.replace(tzinfo=_tz.utc)
                    if now_utc - _last_dt < cooldown:
                        continue
                except Exception:
                    pass

            # Generate
            print(f"[NewsletterAutoRefresh] Refreshing {user_dir.name}/{camp_name} step {step_idx} "
                  f"(sends in {(send_aware - now_utc).total_seconds() / 3600:.1f}h)", flush=True)
            subj, body = _generate_newsletter_content_for_step(camp, step_idx)
            if not subj or not body:
                print(f"[NewsletterAutoRefresh] Generation failed for {camp_name}", flush=True)
                continue

            # Update the step on the campaign
            steps[step_idx]["subject"] = subj
            steps[step_idx]["body"] = body
            steps[step_idx]["_auto_refreshed_at"] = now_utc.isoformat()
            steps[step_idx]["auto_confirmed"] = True
            # Default the hero variant to a different photo per issue so
            # consecutive months don't look identical. User overrides win.
            if "_hero_variant" not in steps[step_idx]:
                steps[step_idx]["_hero_variant"] = step_idx % 3
            _stashed = _pop_last_generated_corner(
                camp.get("_owner_email", "")
                or _email_from_user_path(str(camp_file)) or "",
                camp_name, step_idx)
            if _stashed:
                steps[step_idx]["personal_corner_mode"] = _stashed.get("mode", "")
                steps[step_idx]["personal_corner_note"] = _stashed.get("note", "")
            camp["emails"] = steps

            # Persist campaign (drop helper-only keys before writing)
            _camp_to_save = dict(camp)
            try:
                tmp = camp_file.with_suffix(".tmp")
                tmp.write_text(json.dumps(_camp_to_save, indent=2, default=str), encoding="utf-8")
                tmp.replace(camp_file)
            except Exception as e:
                print(f"[NewsletterAutoRefresh] Campaign save failed: {e}", flush=True)
                continue

            # Update every pending queue item for this campaign+step with fresh content
            for q in queue:
                if q.get("campaign") != camp_name or q.get("status") != "pending":
                    continue
                _matches = False
                if _qsname and (q.get("step_name") or "").strip() == _qsname:
                    _matches = True
                elif _qsubj and (q.get("subject") or "").strip() == _qsubj:
                    _matches = True
                if _matches:
                    q["subject"] = subj
                    q["body"] = body
                    q["_auto_refreshed_at"] = now_utc.isoformat()

            # Persist queue
            try:
                tmp = queue_path.with_suffix(".tmp")
                tmp.write_text(json.dumps(queue, indent=2, default=str), encoding="utf-8")
                tmp.replace(queue_path)
            except Exception as e:
                print(f"[NewsletterAutoRefresh] Queue save failed: {e}", flush=True)
                continue

            # Fire a preview of the refreshed copy to the owner's inbox so
            # they get a heads-up before the actual send goes out in ≤5 days.
            _owner_email = (camp.get("_owner_email")
                            or _email_from_user_path(str(camp_file)))
            if _owner_email:
                try:
                    _user_cfg_path = user_dir / "dripdrop_config.json"
                    _ucfg = {}
                    if _user_cfg_path.exists():
                        try:
                            _ucfg = json.loads(_user_cfg_path.read_text(encoding="utf-8"))
                        except Exception:
                            _ucfg = {}
                    _inbox = (_ucfg.get("ms_email", "")
                              or (_ucfg.get("gmail_tokens", {}) or {}).get("email", "")
                              or _ucfg.get("sig_email", "")
                              or _ucfg.get("smtp_email", "")
                              or _owner_email)
                    _preview_subj = (f"Preview: {camp.get('newsletter_name') or camp_name}  -  "
                                     f"sends {send_aware.strftime('%b %d')}")
                    # Deep link back into DripDrop: clicking opens the
                    # Newsletters page with the Edit modal pre-opened on
                    # this campaign.
                    from urllib.parse import quote as _urlq
                    _edit_link = (
                        f"https://dripdripdrop.ai/?edit_newsletter="
                        f"{_urlq(camp_name)}"
                    )
                    _banner = (
                        f'<div style="background:#FFF8E1;border:1px solid #FFC107;'
                        f'border-radius:6px;padding:12px 16px;margin:0 0 16px;'
                        f'font-family:Arial,sans-serif;font-size:13px;color:#664400;">'
                        f'<strong>Preview only</strong> — this is what will go out '
                        f'on {send_aware.strftime("%b %d")}. '
                        f'<a href="{_edit_link}" style="color:#0066CC;font-weight:700;">'
                        f'Open in DripDrop to edit →</a>'
                        f'</div>'
                    )
                    ok, err = _send_email_universal(
                        to=_inbox,
                        subject=_preview_subj,
                        html_body=_banner + body,
                        is_preview=False,
                        _for_user_email=_owner_email,
                    )
                    if ok:
                        print(f"[NewsletterAutoRefresh] Preview sent to {_inbox}", flush=True)
                    else:
                        print(f"[NewsletterAutoRefresh] Preview send failed for "
                              f"{_owner_email}: {err}", flush=True)
                except Exception as e:
                    print(f"[NewsletterAutoRefresh] Preview dispatch error: {e}", flush=True)

            refreshed_count += 1

    if refreshed_count:
        print(f"[NewsletterAutoRefresh] Tick complete  -  {refreshed_count} newsletter(s) refreshed",
              flush=True)


NL_SAVE_DIR = USER_DIR / "Newsletters"

def _save_newsletter(data: dict) -> Path:
    _user_nl_dir().mkdir(parents=True, exist_ok=True)
    name = data.get("newsletter_name", "newsletter")
    slug = re.sub(r'[^\w\s-]', '', name).strip().replace(' ', '_')[:40]
    dt = date.today().strftime("%Y%m%d")
    p = _user_nl_dir() / f"{slug}_{dt}.json"
    p.write_text(json.dumps(data, indent=2, default=str), encoding="utf-8")
    return p

def _load_newsletters() -> list:
    if not _user_nl_dir().exists():
        return []
    result = []
    for p in sorted(_user_nl_dir().glob("*.json"), reverse=True):
        try:
            result.append(json.loads(p.read_text(encoding="utf-8")))
        except Exception:
            pass
    return result


_NL_NICHE_OPTIONS = [
    "General Construction", "Healthcare Construction", "Life Science / Cleanroom",
    "Data Centers", "Commercial TI", "Industrial / Warehouse", "Heavy Civil",
    "Manufacturing", "Skilled Trades", "Energy / Utilities", "Transportation / Logistics",
    "Food & Beverage Processing", "Aerospace & Defense", "Water / Wastewater",
]

def p_newsletter(s: AppState, rf):
    """Newsletter Builder  -  create branded HTML email newsletters."""
    # State
    if not hasattr(s, '_nl_data'):
        s._nl_data = {
            "company": _get_company_name(),
            "newsletter_name": "The Denver Dirt",
            "tagline": "Weekly Double D's",
            "website": "",
            "date": date.today().strftime("%B %Y"),
            "intro_text": "",
            "top_news": [],
            "article_title": "", "article_body": "",
            "spotlight_name": "", "spotlight_title": "", "spotlight_qa": [],
            "market_update": "",
            "open_roles": [],
            "cta_text": "", "cta_url": "",
            "custom_html": "",
            "contact_name": "", "contact_title": "", "contact_phone": "", "contact_email": "",
        }
    if not hasattr(s, '_nl_ai_generating'):
        s._nl_ai_generating = False
    if not hasattr(s, '_nl_setup_done'):
        s._nl_setup_done = False
    if not hasattr(s, '_nl_setup'):
        s._nl_setup = {
            "location": "",
            "niche": "",
            "target_roles": "",
            "spotlight_candidates": "",
            "wage_trends": True,
            "regulatory_updates": True,
            "new_projects": True,
            "labor_supply": True,
            "custom_topic": "",
            # Section visibility toggles
            "show_intro": True,
            "show_top_news": True,
            "show_article": True,
            "show_spotlight": True,
            "show_market_update": True,
            "show_open_roles": True,
            "show_cta": True,
        }

    d = s._nl_data
    setup = s._nl_setup

    # ════════════════════════════════════════════════════════════════════
    #  SETUP WIZARD  -  shown before the editor on first create
    # ════════════════════════════════════════════════════════════════════
    if not s._nl_setup_done:
        ui.label("Newsletter Builder").classes("fd-h1").style("margin-bottom:2px;")
        ui.label("Tell us about your market so we can generate a tailored newsletter.").classes("fd-sub")

        # Two-column wrapper  -  form left, recent newsletters right
        _nl_flex = ui.element("div").style("display:flex;gap:24px;align-items:flex-start;margin-top:16px;")
        with _nl_flex:
         with ui.element("div").style("flex:1;min-width:0;max-width:540px;"):
            _cs = (
                f"background:{C['card']};border:1px solid {C['border']};"
                f"border-radius:10px;padding:18px 20px;margin-bottom:12px;"
            )
            _sl = f"font-size:13px;font-weight:700;color:{C['text_l']};margin-bottom:8px;"

            # ── Newsletter Name ────────────────────────────────────────────
            with ui.element("div").style(_cs):
                ui.label("Newsletter Name").style(_sl)
                ui.label("Give your newsletter a name  -  this appears as the header in the email.").style(
                    f"font-size:11px;color:{C['muted']};margin-bottom:6px;")
                _nl_name = ui.input(
                    value=d.get("newsletter_name", ""),
                    placeholder="e.g. The Denver Construction Report, SoCal Talent Pulse"
                ).classes("fd-input").style("width:100%;")
                _nl_name.on("blur", lambda: d.update({"newsletter_name": _nl_name.value.strip()}))

            # ── Location ─────────────────────────────────────────────────
            with ui.element("div").style(_cs):
                # Sync setup → AppState
                if not (getattr(s, "_nl_location", "") or "").strip():
                    s._nl_location = (setup.get("location") or "").strip()
                _render_region_picker(
                    s, rf,
                    state_key="_nl_location",
                    multi=False,
                    container_style="margin-bottom:0;",
                    label="Market / Location",
                )
                # Write-back to setup so the rest of the newsletter pipeline
                # (which still reads setup["location"]) keeps working.
                setup["location"] = (getattr(s, "_nl_location", "") or "").strip()

            # ── Industry (Primary + Secondary) ───────────────────────────
            # Replaces the legacy single "niche" field. Mirrors the new
            # cross-app picker. Sync setup ↔ AppState attrs at render +
            # write-back. Backward-compat: setup["niche"] is updated on
            # every render with the joined Primary · Secondary string so
            # the rest of the newsletter pipeline keeps working unchanged.
            with ui.element("div").style(_cs):
                # Sync setup → AppState (read direction)
                if not (getattr(s, "_nl_primary_industry", "") or "").strip():
                    s._nl_primary_industry = (setup.get("primary_industry")
                                               or setup.get("niche") or "")
                if not hasattr(s, "_nl_secondary_industries"):
                    s._nl_secondary_industries = list(setup.get("secondary_industries", []) or [])

                _render_industry_picker(
                    s, rf,
                    primary_state_key="_nl_primary_industry",
                    secondary_state_key="_nl_secondary_industries",
                    container_style="margin-bottom:0;",
                    label_primary="Industry Niche",
                    label_secondary="Sub-niche(s)",
                )

                # Write-back: keep setup in sync with the picker on every
                # render (cheap; no async needed). Legacy "niche" key gets
                # the joined string for backward compat.
                _np = (getattr(s, "_nl_primary_industry", "") or "").strip()
                _ns = list(getattr(s, "_nl_secondary_industries", []) or [])
                setup["primary_industry"] = _np
                setup["secondary_industries"] = _ns
                setup["niche"] = _industry_to_vertical_string(_np, _ns) or _np

            # ── Target Roles ─────────────────────────────────────────────
            with ui.element("div").style(_cs):
                ui.label("Target Roles").style(_sl)
                ui.label("What positions do you fill? (comma-separated)").style(
                    f"font-size:11px;color:{C['muted']};margin-bottom:6px;")
                _roles = ui.input(
                    value=setup["target_roles"],
                    placeholder="e.g. Project Managers, Superintendents, Estimators, Safety Managers"
                ).classes("fd-input").style("width:100%;")
                _roles.on("blur", lambda: setup.update({"target_roles": _roles.value}))

            # ── Candidate Spotlights ─────────────────────────────────────
            with ui.element("div").style(_cs):
                ui.label("Candidates to Highlight").style(_sl)
                ui.label("Names, titles, and a quick note about each (optional  -  AI will build the spotlight section).").style(
                    f"font-size:11px;color:{C['muted']};margin-bottom:6px;")
                _cands = ui.textarea(
                    value=setup["spotlight_candidates"],
                    placeholder="e.g.\nJane Doe  -  Senior Project Manager, 12 yrs healthcare construction\nJohn Smith  -  Operations Director, 15 yrs industrial manufacturing"
                ).style(
                    f"width:100%;min-height:70px;background:{C['surface']};"
                    f"border:1px solid {C['border']};border-radius:6px;padding:8px;"
                    f"color:{C['text_l']};font-size:12px;font-family:inherit;resize:vertical;")
                _cands.on("blur", lambda: setup.update({"spotlight_candidates": _cands.value}))

            # ── Market Focus (single dropdown) ───────────────────────────
            with ui.element("div").style(_cs):
                ui.label("Market Focus").style(_sl)
                ui.label("What angle should the market content take?").style(
                    f"font-size:11px;color:{C['muted']};margin-bottom:6px;")
                _mf_options = {
                    "wages": "Wage & Compensation Trends",
                    "regulatory": "Regulatory & Compliance Updates",
                    "projects": "New Projects & Facility Openings",
                    "labor": "Labor Supply & Demand Shifts",
                }
                _mf_current = "wages"
                if setup.get("wage_trends") and not setup.get("regulatory_updates"): _mf_current = "wages"
                elif setup.get("regulatory_updates"): _mf_current = "regulatory"
                elif setup.get("new_projects"): _mf_current = "projects"
                elif setup.get("labor_supply"): _mf_current = "labor"
                _mf_sel = ui.select(options=_mf_options, value=_mf_current).style("width:100%;")
                def _on_mf_change():
                    v = _mf_sel.value
                    setup["wage_trends"] = v == "wages"
                    setup["regulatory_updates"] = v == "regulatory"
                    setup["new_projects"] = v == "projects"
                    setup["labor_supply"] = v == "labor"
                _mf_sel.on("update:model-value", lambda e: _on_mf_change())

            # ── Newsletter Sections (3 toggles) ──────────────────────────
            with ui.element("div").style(_cs):
                ui.label("Include in Newsletter").style(_sl)
                _cb_news = ui.checkbox("Industry Highlights", value=setup.get("show_top_news", True)).style(
                    f"font-size:12px;color:{C['text_l']};")
                _cb_news.on("update:model-value", lambda e: setup.update({"show_top_news": _cb_news.value}))
                _cb_spot = ui.checkbox("Candidate Spotlight", value=setup.get("show_spotlight", True)).style(
                    f"font-size:12px;color:{C['text_l']};")
                _cb_spot.on("update:model-value", lambda e: setup.update({"show_spotlight": _cb_spot.value}))
                _cb_cta = ui.checkbox("Call to Action Button", value=setup.get("show_cta", True)).style(
                    f"font-size:12px;color:{C['text_l']};")
                _cb_cta.on("update:model-value", lambda e: setup.update({"show_cta": _cb_cta.value}))
                # Always include intro + article + market update (core sections)
                setup["show_intro"] = True
                setup["show_article"] = True
                setup["show_market_update"] = True
                setup["show_open_roles"] = False

            # ── Custom Topic ─────────────────────────────────────────────
            with ui.element("div").style(_cs):
                ui.label("Additional Topic or Notes (optional)").style(_sl)
                _custom = ui.input(
                    value=setup["custom_topic"],
                    placeholder="e.g. Focus on data center construction boom in the Southwest"
                ).classes("fd-input").style("width:100%;")
                _custom.on("blur", lambda: setup.update({"custom_topic": _custom.value}))

            # ── Action Buttons ───────────────────────────────────────────
            with ui.element("div").style("display:flex;gap:10px;margin-top:16px;"):
                async def _generate_from_setup():
                    # Setup is already populated at render time by the
                    # picker write-back blocks above (location + niche).
                    # Just refresh the remaining text-input-backed fields
                    # from their widgets here.
                    setup["target_roles"] = _roles.value
                    setup["spotlight_candidates"] = _cands.value
                    setup["custom_topic"] = _custom.value

                    # Pre-populate open_roles from target_roles
                    if setup["target_roles"]:
                        d["open_roles"] = [
                            {"title": r.strip(), "location": setup["location"], "type": "Full-time"}
                            for r in setup["target_roles"].split(",") if r.strip()
                        ]

                    # Pre-populate spotlight from candidates
                    if setup["spotlight_candidates"]:
                        lines = [l.strip() for l in setup["spotlight_candidates"].strip().split("\n") if l.strip()]
                        if lines:
                            parts = lines[0].split(" - ", 1) if " - " in lines[0] else lines[0].split("-", 1)
                            d["spotlight_name"] = parts[0].strip()
                            d["spotlight_title"] = parts[1].strip() if len(parts) > 1 else ""

                    # Build AI prompt with setup context
                    if ANTHROPIC_API_KEY:
                        s._nl_ai_generating = True; rf()
                        try:
                            import anthropic as _anth
                            client = _anth.Anthropic(api_key=ANTHROPIC_API_KEY)
                            company = d.get("company", _get_company_name())

                            # Build market focus sections list
                            focus_sections = []
                            if setup["wage_trends"]: focus_sections.append("wage and compensation trends for the target roles")
                            if setup["regulatory_updates"]: focus_sections.append("regulatory and compliance changes (OSHA, licensing, labor laws)")
                            if setup["new_projects"]: focus_sections.append("new construction projects, facility openings, and expansion announcements")
                            if setup["labor_supply"]: focus_sections.append("labor supply and demand shifts, workforce availability, trade school pipeline")
                            focus_str = "\n".join(f"  - {f}" for f in focus_sections) if focus_sections else "  - general market conditions"

                            spotlight_ctx = ""
                            if setup["spotlight_candidates"]:
                                spotlight_ctx = (
                                    f"\n\nCANDIDATE SPOTLIGHT  -  The user provided this raw info:\n"
                                    f"{setup['spotlight_candidates']}\n\n"
                                    f"Turn this into a polished professional spotlight. Generate:\n"
                                    f"- spotlight_name: their full name\n"
                                    f"- spotlight_title: a compelling one-line title (role + key qualifier)\n"
                                    f"- spotlight_bullets: exactly 4 bullet points summarizing who they are. "
                                    f"Use the info provided but FILL IN THE GAPS  -  if the user was vague, "
                                    f"infer realistic details based on their role/industry/experience. "
                                    f"Bullets should cover: experience summary, key skills/certifications, "
                                    f"notable achievements, and what they're looking for next. Make them shine.\n"
                                    f"- spotlight_qa: exactly 2 Q&A pairs. Questions should be specific and "
                                    f"insightful (not 'tell us about yourself'). Answers should be confident, "
                                    f"detailed, and position the candidate as a top performer.\n"
                                )

                            prompt = (
                                f"You are a content strategist for {company}, a staffing and direct-hire "
                                f"recruitment firm. Generate a newsletter for {d.get('date', date.today().strftime('%B %Y'))}.\n\n"
                                f"MARKET CONTEXT:\n"
                                f"- Location/Region: {setup['location'] or 'Nationwide'}\n"
                                f"- Industry Niche: {setup['niche'] or 'Construction & Manufacturing'}\n"
                                f"- Target Roles: {setup['target_roles'] or 'Various skilled positions'}\n"
                                f"{'- Additional Focus: ' + setup['custom_topic'] + chr(10) if setup['custom_topic'] else ''}"
                                f"\nMARKET FOCUS:\n{focus_str}\n"
                                f"{spotlight_ctx}\n\n"
                                f"REQUIREMENTS:\n"
                                f"- Write for hiring managers in {setup['niche'] or 'construction/manufacturing'}\n"
                                f"- Be specific to {setup['location'] or 'national'} market\n"
                                f"- Actionable insights, no filler. Keep it concise.\n\n"
                            )
                            _spot_json = ""
                            if setup.get("show_spotlight") or setup.get("spotlight_candidates", "").strip():
                                _spot_json = (
                                    '"spotlight_name": "full name",'
                                    '"spotlight_title": "one-line title",'
                                    '"spotlight_bullets": ["bullet 1", "bullet 2", "bullet 3", "bullet 4"],'
                                    '"spotlight_qa": [{"q": "specific question", "a": "detailed answer"}, '
                                    '{"q": "specific question", "a": "detailed answer"}],'
                                )
                            prompt += (
                                f"Return ONLY valid JSON:\n"
                                f'{{"intro_text": "2-3 sentence intro",'
                                f'"top_news": ["4 bullet points"],'
                                f'"article_title": "headline",'
                                f'"article_body": "2 short paragraphs",'
                                f'"market_update": "1 paragraph snapshot",'
                                + _spot_json
                                + f'"cta_text": "3-5 word button text"}}'
                            )
                            msg = await asyncio.get_event_loop().run_in_executor(
                                None, lambda: _claude_create_with_retry(client,
                                    model="claude-haiku-4-5-20251001", max_tokens=2000,
                                    tools=[_safe_web_search_tool(max_uses=2)],
                                    messages=[{"role": "user", "content": prompt}]))
                            all_text = ""
                            for block in msg.content:
                                if hasattr(block, "text"):
                                    all_text += block.text
                            clean = all_text.replace("```json", "").replace("```", "").strip()
                            json_match = re.search(r'\{.*\}', clean, re.DOTALL)
                            if json_match:
                                ai = json.loads(json_match.group())
                                # Strip <cite> tags from web search results
                                for key in ("intro_text", "article_title", "article_body", "market_update", "cta_text"):
                                    if ai.get(key):
                                        d[key] = _strip_cite_tags(ai[key])
                                if ai.get("top_news"):
                                    d["top_news"] = [_strip_cite_tags(b) for b in ai["top_news"]]
                                # Spotlight: AI generates polished name/title + bullets
                                if ai.get("spotlight_name"):
                                    d["spotlight_name"] = _strip_cite_tags(ai["spotlight_name"])
                                if ai.get("spotlight_title"):
                                    d["spotlight_title"] = _strip_cite_tags(ai["spotlight_title"])
                                if ai.get("spotlight_bullets"):
                                    d["spotlight_bullets"] = [_strip_cite_tags(b) for b in ai["spotlight_bullets"][:4]]
                                if ai.get("spotlight_qa"):
                                    d["spotlight_qa"] = ai["spotlight_qa"][:2]
                                # Auto-save with setup data
                                d["_setup"] = dict(setup)
                                _save_newsletter(d)
                        except Exception as e:
                            print(f"[Newsletter] AI error: {e}")
                        finally:
                            s._nl_ai_generating = False

                    s._nl_setup_done = True; rf()

                def _skip_setup():
                    s._nl_setup_done = True; rf()

                if s._nl_ai_generating:
                    with ui.element("div").style("display:flex;align-items:center;gap:10px;"):
                        ui.spinner("dots", size="20px", color=C["teal"])
                        ui.label("Generating your newsletter...").style(f"font-size:13px;color:{C['warn']};")
                else:
                    if ANTHROPIC_API_KEY:
                        with ui.element("button").classes("fd-pb").style(
                                f"padding:12px 28px;font-size:14px;background:{C['teal']};").on("click", _generate_from_setup):
                            ui.label("✦ Generate Newsletter")
                    with ui.element("button").classes("fd-gb").style(
                            "padding:12px 28px;font-size:14px;").on("click", _skip_setup):
                        ui.label("Skip  -  Build Manually")

         # ── RIGHT: Recent Newsletters ─────────────────────────────────
         with ui.element("div").style(
                 "flex:1;min-width:280px;max-width:400px;position:sticky;top:16px;"):
            ui.label("Recent Newsletters").style(
                f"font-size:13px;font-weight:700;color:{C['text_l']};margin-bottom:10px;")
            saved_nls = _load_newsletters()
            if saved_nls:
                for ni, nl in enumerate(saved_nls[:10]):
                    nl_name = nl.get("newsletter_name", "Newsletter")
                    nl_date = nl.get("date", "")
                    nl_niche = nl.get("_setup", {}).get("niche", "") if isinstance(nl.get("_setup"), dict) else ""
                    nl_loc = nl.get("_setup", {}).get("location", "") if isinstance(nl.get("_setup"), dict) else ""
                    nl_has_setup = isinstance(nl.get("_setup"), dict) and nl.get("_setup")
                    meta_parts = [p for p in [nl_date, nl_niche, nl_loc] if p]
                    meta_str = " · ".join(meta_parts) if meta_parts else "No details"
                    with ui.element("div").style(
                            f"background:{C['card']};border:1px solid {C['border']};"
                            f"border-radius:8px;padding:10px 14px;margin-bottom:6px;"):
                        with ui.element("div").style("display:flex;align-items:center;justify-content:space-between;"):
                            with ui.element("div").style("min-width:0;flex:1;"):
                                ui.label(nl_name).style(
                                    f"font-size:12px;font-weight:600;color:{C['text_l']};"
                                    f"white-space:nowrap;overflow:hidden;text-overflow:ellipsis;")
                                ui.label(meta_str).style(
                                    f"font-size:10px;color:{C['muted']};margin-top:1px;")
                            with ui.element("div").style("display:flex;gap:4px;flex-shrink:0;margin-left:8px;"):
                                def _load_nl(data=nl):
                                    for k, v in data.items():
                                        if k != "_setup":
                                            d[k] = v
                                    if isinstance(data.get("_setup"), dict):
                                        for k, v in data["_setup"].items():
                                            setup[k] = v
                                    s._nl_setup_done = True; rf()
                                with ui.element("button").classes("fd-gb").style(
                                        "padding:3px 8px;font-size:10px;").on("click", _load_nl):
                                    ui.label("Open")
                                if nl_has_setup:
                                    def _reuse_nl(data=nl):
                                        if isinstance(data.get("_setup"), dict):
                                            for k, v in data["_setup"].items():
                                                setup[k] = v
                                        rf()
                                    with ui.element("button").classes("fd-gb").style(
                                            "padding:3px 8px;font-size:10px;").on("click", _reuse_nl):
                                        ui.label("Reuse")
            else:
                with ui.element("div").style(
                        f"background:{C['surface']};border:1px solid {C['border']};"
                        f"border-radius:8px;padding:20px;text-align:center;"):
                    ui.label("No saved newsletters yet.").style(
                        f"font-size:12px;color:{C['muted']};margin-bottom:4px;")
                    ui.label("Generate your first one and it will appear here.").style(
                        f"font-size:11px;color:{C['muted']};")
        return

    # ════════════════════════════════════════════════════════════════════
    #  EDITOR MODE (after setup)
    # ════════════════════════════════════════════════════════════════════

    # ── Title bar + action buttons ───────────────────────────────────────
    with ui.element("div").style("display:flex;align-items:center;justify-content:space-between;margin-bottom:16px;flex-wrap:wrap;gap:10px;"):
        with ui.element("div"):
            ui.label("Newsletter Builder").classes("fd-h1").style("margin-bottom:2px;")
            ui.label("Build and send a branded HTML newsletter  -  edits update the preview live.").classes("fd-sub")
        with ui.element("div").style("display:flex;gap:8px;align-items:center;"):
            # Back to setup
            def _back_to_setup():
                s._nl_setup_done = False; rf()
            with ui.element("button").classes("fd-gb").style(
                    "padding:8px 16px;font-size:12px;").on("click", _back_to_setup):
                ui.label("← Setup")

            # AI Regenerate button
            if ANTHROPIC_API_KEY:
                async def _ai_generate():
                    s._nl_ai_generating = True; rf()
                    try:
                        import anthropic as _anth
                        client = _anth.Anthropic(api_key=ANTHROPIC_API_KEY)
                        company = d.get("company", _get_company_name())
                        sig_name = ""
                        try:
                            if _user_sig_path().exists():
                                sig_lines = _user_sig_path().read_text(encoding="utf-8").strip().split("\n")
                                if sig_lines and sig_lines[0].strip().split(): sig_name = sig_lines[0].strip().split()[0]
                        except Exception: pass

                        # Use setup context if available
                        location = setup.get("location", "")
                        niche = setup.get("niche", "")
                        target_roles = setup.get("target_roles", "")

                        focus_sections = []
                        if setup.get("wage_trends"): focus_sections.append("wage and compensation trends")
                        if setup.get("regulatory_updates"): focus_sections.append("regulatory and compliance changes")
                        if setup.get("new_projects"): focus_sections.append("new projects and facility openings")
                        if setup.get("labor_supply"): focus_sections.append("labor supply and demand shifts")
                        focus_str = ", ".join(focus_sections) if focus_sections else "general market conditions"

                        prompt = (
                            f"You are a content strategist for {company}, a staffing and direct-hire "
                            f"recruitment firm. Generate engaging newsletter content for {d.get('date', date.today().strftime('%B %Y'))}.\n\n"
                            f"MARKET CONTEXT:\n"
                            f"- Location: {location or 'Nationwide'}\n"
                            f"- Niche: {niche or 'Construction & Manufacturing'}\n"
                            f"- Target Roles: {target_roles or 'Various'}\n"
                            f"- Focus Areas: {focus_str}\n"
                            f"{'- Additional: ' + setup.get('custom_topic', '') + chr(10) if setup.get('custom_topic') else ''}\n"
                            f"REQUIREMENTS:\n"
                            f"- Write for hiring managers in {niche or 'construction/manufacturing'}, {location or 'national market'}\n"
                            f"- Be specific with data points, trends, and actionable insights  -  avoid generic filler\n"
                            f"- Tone: authoritative but approachable, like a trusted advisor\n\n"
                            f"Return ONLY valid JSON with these fields:\n"
                            f'{{"intro_text": "2-3 sentence warm intro addressing the reader",'
                            f'"top_news": ["5 specific bullet points about the focus areas"],'
                            f'"article_title": "compelling headline for a feature article",'
                            f'"article_body": "3-4 paragraph feature article with specific insights and practical takeaways",'
                            f'"market_update": "2-3 paragraph market analysis",'
                            f'"cta_text": "short action-oriented button text (3-5 words)"}}'
                        )
                        msg = await asyncio.get_event_loop().run_in_executor(
                            None, lambda: _claude_create_with_retry(client,
                                model="claude-haiku-4-5-20251001", max_tokens=3000,
                                tools=[_safe_web_search_tool(max_uses=1)],
                                messages=[{"role": "user", "content": prompt}]))
                        all_text = ""
                        for block in msg.content:
                            if hasattr(block, "text"):
                                all_text += block.text
                        clean = all_text.replace("```json", "").replace("```", "").strip()
                        json_match = re.search(r'\{.*\}', clean, re.DOTALL)
                        if json_match:
                            ai = json.loads(json_match.group())
                            for key in ("intro_text", "article_title", "article_body", "market_update", "cta_text"):
                                if ai.get(key): d[key] = _strip_cite_tags(ai[key])
                            if ai.get("top_news"):
                                d["top_news"] = [_strip_cite_tags(b) for b in ai["top_news"]]
                            ui.notify("Newsletter content regenerated!", type="positive")
                        else:
                            ui.notify("Could not parse AI response", type="warning")
                    except Exception as e:
                        ui.notify(f"Error: {str(e)[:60]}", type="negative")
                    finally:
                        s._nl_ai_generating = False; rf()

                if s._nl_ai_generating:
                    with ui.element("div").style("display:flex;align-items:center;gap:8px;"):
                        ui.spinner("dots", size="16px", color=C["teal"])
                        ui.label("Generating...").style(f"font-size:12px;color:{C['warn']};")
                else:
                    with ui.element("button").classes("fd-pb").style(
                            "padding:8px 20px;font-size:12px;").on("click", _ai_generate):
                        ui.label("✦ AI Generate Content")

            def _save_nl():
                d["_setup"] = dict(setup)  # save setup config for reuse
                _save_newsletter(d)
                ui.notify("Newsletter saved!", type="positive")
            with ui.element("button").classes("fd-gb").style(
                    "padding:8px 16px;font-size:12px;").on("click", _save_nl):
                ui.label("Save Draft")

            # ── Change Hero Photo ──────────────────────────────────────
            _loc_raw_ui = _location_from_data(d)
            _loc_parts_ui = [p.strip() for p in _loc_raw_ui.split(",")] if _loc_raw_ui else []
            _city_ui = _loc_parts_ui[0] if _loc_parts_ui else ""
            _state_ui = (_loc_parts_ui[1][:2].upper() if len(_loc_parts_ui) > 1 else "")
            _slug_ui = re.sub(r'[^A-Za-z0-9]+', '_', f"{_city_ui}_{_state_ui}").strip('_').lower()

            def _handle_hero_upload(e):
                raw_bytes = e.content.read() if hasattr(e.content, 'read') else e.content
                if not raw_bytes:
                    ui.notify("Upload empty  -  try again.", type="warning")
                    return
                try:
                    from PIL import Image
                    from io import BytesIO
                    with Image.open(BytesIO(raw_bytes)) as im:
                        im = im.convert("RGB")
                        tw, th = 640, 180
                        sw, sh = im.size
                        scale = max(tw / sw, th / sh)
                        nw, nh = int(sw * scale), int(sh * scale)
                        im = im.resize((nw, nh), Image.LANCZOS)
                        left = (nw - tw) // 2
                        top = (nh - th) // 2
                        im = im.crop((left, top, left + tw, top + th))
                        buf = BytesIO()
                        im.save(buf, format="JPEG", quality=82, optimize=True)
                        cache_dir = _BASE_DATA_DIR / "city_images"
                        cache_dir.mkdir(parents=True, exist_ok=True)
                        (cache_dir / f"{_slug_ui}.hero.jpg").write_bytes(buf.getvalue())
                    ui.notify("Hero photo updated! Preview again to see it.", type="positive")
                    rf()
                except Exception as ex:
                    ui.notify(f"Image processing error: {str(ex)[:60]}", type="negative")

            _hero_upload = ui.upload(
                on_upload=_handle_hero_upload,
                auto_upload=True,
                max_files=1,
            ).props('accept="image/*"').style("display:none;")

            def _refetch_hero():
                # Wipes both the Unsplash meta (forcing a new 5-candidate
                # batch) and the Wikipedia cache so the very next preview
                # pulls fresh art from either source.
                cache_dir = _BASE_DATA_DIR / "city_images"
                _purged = 0
                for pat in (f"{_slug_ui}.hero.jpg", f"{_slug_ui}.img",
                            f"{_slug_ui}.unsplash.meta.json"):
                    fp = cache_dir / pat
                    if fp.exists(): fp.unlink(); _purged += 1
                # Also wipe any cached Unsplash variant crops
                for i in range(10):
                    fp = cache_dir / f"{_slug_ui}.unsplash.{i}.hero.jpg"
                    if fp.exists(): fp.unlink(); _purged += 1
                # Reset the variant cursor so the user starts from 0 again
                d["_hero_variant"] = 0
                ui.notify("Cleared. Preview again to fetch a fresh set of photos.", type="info")
                rf()

            def _cycle_hero():
                # Advance to the next Unsplash variant, wrapping around.
                # Only meaningful when _hero_total > 1 (i.e. Unsplash batch
                # succeeded). We read _hero_total from d where the renderer
                # stashed it on the previous pass.
                _total = int(d.get("_hero_total", 1) or 1)
                if _total <= 1:
                    ui.notify("Only one photo available — try 'Re-fetch' for a fresh set.",
                              type="info")
                    return
                _cur = int(d.get("_hero_variant", 0) or 0)
                d["_hero_variant"] = (_cur + 1) % _total
                ui.notify(f"Photo {d['_hero_variant'] + 1} of {_total}", type="info", timeout=1200)
                rf()

            # J's Way uses a fixed bundled banner (no per-issue hero photo), so
            # the whole hero-photo control cluster is hidden for J's Way issues.
            if _slug_ui and (d.get("newsletter_style") or "").strip() != "j_way":
                with ui.element("div").style("display:flex;align-items:center;gap:8px;margin-bottom:4px;flex-wrap:wrap;"):
                    with ui.element("button").classes("fd-gb").style(
                            "padding:6px 14px;font-size:11px;").on(
                            "click", lambda: _hero_upload.run_method("pickFiles")):
                        ui.label("🖼 Change Hero Photo")
                    # Only show "Try another photo" if Unsplash gave us more
                    # than one candidate on the last render. We default to
                    # showing it (enabled) — if the user clicks before any
                    # render has populated _hero_total, _cycle_hero() will
                    # gently notify "only one available".
                    with ui.element("button").classes("fd-gb").style(
                            "padding:6px 14px;font-size:11px;").on("click", _cycle_hero):
                        ui.label("↻ Try another photo")
                    with ui.element("button").classes("fd-gb").style(
                            "padding:6px 14px;font-size:11px;").on("click", _refetch_hero):
                        ui.label("↻ Fetch a fresh set")

            def _profile_ready_or_block() -> bool:
                """Block newsletter preview/send when the user's profile is
                missing the fields that would otherwise leak defaults or
                render an empty 'FROM' block."""
                _pc = _load_company_profile() or {}
                _cfg2 = load_config() or {}
                _missing = []
                if not (_cfg2.get("sig_name") or "").strip():
                    _missing.append("Signature Name (Profile \u2192 Signature)")
                if not (_pc.get("company_name") or "").strip():
                    _missing.append("Company Name (Profile \u2192 Company Info)")
                if not (_cfg2.get("newsletter_personal_note") or "").strip():
                    _missing.append("Newsletter Personal Note (Profile \u2192 Newsletter Signature)")
                if _missing:
                    with ui.dialog() as _gate_dlg, ui.card().style(
                            f"background:{C['card']};border:1px solid {C['warn']}80;"
                            f"min-width:460px;padding:22px 26px;border-radius:14px;"):
                        ui.label("\u26A0 Finish your profile first").style(
                            f"font-size:16px;font-weight:800;color:{C['warn']};"
                            f"font-family:'Nunito',sans-serif;margin-bottom:6px;")
                        ui.label("Newsletters pull from your profile. Before you "
                                 "send or preview, fill in:").style(
                            f"font-size:12px;color:{C['text']};margin-bottom:10px;line-height:1.5;")
                        for _m in _missing:
                            ui.label(f"\u2022 {_m}").style(
                                f"font-size:12px;color:{C['text_l']};"
                                f"margin-left:6px;line-height:1.6;")
                        with ui.element("div").style(
                                "display:flex;justify-content:flex-end;gap:8px;margin-top:16px;"):
                            with ui.element("button").classes("fd-gb").style(
                                    "padding:6px 14px;font-size:12px;").on(
                                    "click", _gate_dlg.close):
                                ui.label("Close")
                            def _go_profile():
                                _gate_dlg.close()
                                s.hub = "sales"; s.sp = "company_profile"
                                s._profile_edit_mode = True
                                rf()
                            with ui.element("button").classes("fd-pb").style(
                                    "padding:6px 16px;font-size:12px;").on(
                                    "click", _go_profile):
                                ui.label("Open Profile \u2192")
                    _gate_dlg.open()
                    return False
                return True

            def _preview_to_self():
                if not _profile_ready_or_block():
                    return
                # Render the newsletter HTML
                try:
                    html_body = _render_newsletter_html(d, setup)
                except Exception as ex:
                    print(f"[Newsletter] Render FAILED: {ex}")
                    _log_exception(ex, context="newsletter.render")
                    ui.notify(f"Preview render error: {str(ex)[:80]}", type="negative")
                    return

                # Determine which inbox to send the preview to  -  prefer the
                # logged-in user's email, then connected mailbox, then sig.
                _cfg = load_config()
                my_email = (
                    getattr(s, "_user_email", "")
                    or _cfg.get("ms_email", "")
                    or (_cfg.get("gmail_tokens", {}) or {}).get("email", "")
                    or _cfg.get("sig_email", "")
                    or _cfg.get("smtp_email", "")
                )
                if not my_email:
                    ui.notify(
                        "No inbox on file for previews. Connect Outlook/Gmail or set a signature email in Settings.",
                        type="warning", timeout=6000,
                    )
                    return

                subj = d.get("subject") or f"{d.get('newsletter_name', 'Newsletter')}  -  {d.get('date', '')}"
                _for_user = getattr(s, "_user_email", "") or ""

                def _do_send():
                    try:
                        ok, err = _send_email_universal(
                            to=my_email,
                            subject=subj,
                            html_body=html_body,
                            is_preview=True,
                            _for_user_email=_for_user,
                        )
                        if ok:
                            print(f"[Newsletter] Preview sent to {my_email}")
                        else:
                            print(f"[Newsletter] Preview send failed: {err}")
                    except Exception as ex:
                        print(f"[Newsletter] Preview send error: {ex}")
                        _log_exception(ex, context="newsletter.preview_send")

                threading.Thread(target=_do_send, daemon=True).start()
                ui.notify(f"Preview sent to {my_email}  -  check your inbox in a moment.",
                          type="positive", timeout=5000)

            with ui.element("button").classes("fd-pb").style(
                    "padding:8px 18px;font-size:12px;").on("click", _preview_to_self):
                ui.label("✉ Preview to My Inbox")

            def _send_newsletter():
                if not _profile_ready_or_block():
                    return
                contacts_path = d.get("_contacts_path", "")
                if not contacts_path:
                    ui.notify("Select a contact list first", type="warning")
                    return
                html_body = _render_newsletter_html(d, setup)
                rows, _ = safe_read_csv_rows(contacts_path)
                contacts = _normalize_rows(rows)
                sent = 0
                def _do_send():
                    nonlocal sent
                    import pythoncom, win32com.client.dynamic
                    try:
                        pythoncom.CoInitialize()
                        ol = win32com.client.dynamic.Dispatch("Outlook.Application")
                        for c in contacts:
                            em = c.get("Email", "").strip()
                            if not em:
                                continue
                            mail = ol.CreateItem(0)
                            mail.To = em
                            mail.Subject = d.get("subject", f"{d['newsletter_name']}  -  {d['date']}")
                            body = html_body.replace("{FirstName}", c.get("FirstName", ""))
                            mail.HTMLBody = body
                            mail.Send()
                            sent += 1
                            time.sleep(0.5)
                    except Exception as ex:
                        print(f"[Newsletter] Send error: {ex}")
                    finally:
                        pythoncom.CoUninitialize()
                threading.Thread(target=_do_send, daemon=True).start()
                ui.notify(f"Sending newsletter to {len(contacts)} contacts...", type="positive")

            with ui.element("button").classes("fd-pb").style(
                    f"padding:8px 20px;font-size:12px;background:{C['teal']};").on("click", _send_newsletter):
                ui.label("Send Newsletter")

    # ════════════════════════════════════════════════════════════════════
    #  SIDE-BY-SIDE: Editor (left) + Live Preview (right)
    # ════════════════════════════════════════════════════════════════════
    with ui.element("div").style("display:flex;gap:20px;align-items:flex-start;"):

        # ── LEFT: Editor Panel ──────────────────────────────────────────
        with ui.element("div").style("flex:1;min-width:0;max-width:520px;"):

            _card_style = (
                f"background:{C['card']};border:1px solid {C['border']};"
                f"border-radius:10px;padding:16px 18px;margin-bottom:10px;"
            )
            _section_label = f"font-size:13px;font-weight:700;color:{C['text_l']};margin-bottom:8px;"

            # ── Header Settings ──────────────────────────────────────────
            with ui.element("div").style(_card_style):
                ui.label("Header & Settings").style(_section_label)
                with ui.element("div").style("display:grid;grid-template-columns:1fr 1fr;gap:8px;"):
                    with ui.element("div"):
                        ui.label("Issue Date").classes("fd-fl")
                        _d_date = ui.input(value=d["date"]).classes("fd-input")
                        _d_date.on("blur", lambda: (d.update({"date": _d_date.value}), rf()))
                    with ui.element("div"):
                        ui.label("Email Subject").classes("fd-fl")
                        _d_subj = ui.input(value=d.get("subject", f"{d['newsletter_name']}  -  {d['date']}"),
                                           placeholder="Subject line").classes("fd-input")
                        _d_subj.on("blur", lambda: (d.update({"subject": _d_subj.value}), rf()))
                ui.label("Tagline").classes("fd-fl")
                _d_tag = ui.input(value=d.get("tagline", "")).classes("fd-input")
                _d_tag.on("blur", lambda: (d.update({"tagline": _d_tag.value}), rf()))
                # Region/location — drives the section labels ("Denver
                # Update", "Around Denver"). Editable here so typos at
                # creation time (e.g. "Demver") can be fixed without
                # rebuilding the newsletter (added 2026-05-12).
                ui.label("Market Region").classes("fd-fl")
                _d_loc = ui.input(value=d.get("location", ""),
                                  placeholder="e.g. Denver, CO").classes("fd-input")
                _d_loc.on("blur", lambda: (d.update({"location": _d_loc.value.strip()}), rf()))

            # ── Intro Text ───────────────────────────────────────────────
