MI_PATH = USER_DIR / "market_intel.json"

def _load_mi_watches() -> list:
    if _user_mi_path().exists():
        try:
            return json.loads(_user_mi_path().read_text(encoding="utf-8"))
        except Exception:
            pass
    return []

def _save_mi_watches(watches: list):
    _user_mi_path().parent.mkdir(parents=True, exist_ok=True)
    tmp = _user_mi_path().with_suffix(".tmp")
    tmp.write_text(json.dumps(watches, indent=2, default=str), encoding="utf-8")
    tmp.replace(_user_mi_path())

MI_RESULTS_PATH = USER_DIR / "market_intel_results.json"

def _load_mi_results() -> dict:
    if _user_mi_results_path().exists():
        try:
            return json.loads(_user_mi_results_path().read_text(encoding="utf-8"))
        except Exception:
            pass
    return {}

def _save_mi_results(results: dict):
    _user_mi_results_path().parent.mkdir(parents=True, exist_ok=True)
    tmp = _user_mi_results_path().with_suffix(".tmp")
    tmp.write_text(json.dumps(results, indent=2, default=str), encoding="utf-8")
    tmp.replace(_user_mi_results_path())


def _run_market_scan(watch: dict, scan_type: str, client) -> list:
    """Run a single scan. scan_type: scan1-scan5."""
    market = watch.get("market", "")
    roles = watch.get("roles", "")
    location = watch.get("location", "")
    company_size = watch.get("company_size", "medium")
    industry = watch.get("industry", "manufacturing")
    notes = watch.get("notes", "")
    context = f"MARKET: {market}\nROLES: {roles}\nLOCATION: {location}\nINDUSTRY: {industry}\nCOMPANY SIZE: {company_size}"
    if notes:
        context += f"\nADDITIONAL CONTEXT: {notes}"

    prompts = {
        "scan1": (
            f"You are a staffing industry market analyst. Find 15-20 NEW job postings "
            f"from DIRECT EMPLOYERS (not staffing agencies) in the last 7 days.\n\n"
            f"{context}\n\n"
            f"For EACH company/job, provide:\n"
            f"- Company name, job title, location, when posted\n"
            f"- Staffing Score (1-50): likelihood they'd use a staffing agency.\n"
            f"  40-50 = hot (urgent fill, no internal recruiting, growth mode)\n"
            f"  25-39 = warm (likely open to staffing, moderate urgency)\n"
            f"  1-24 = cold (large HR team, low urgency, unlikely to use staffing)\n"
            f"- Reason: why this score (be specific  -  mention employee count, multiple openings, etc.)\n"
            f"- Recommendation: 'go after' / 'monitor' / 'skip'\n"
            f"- Estimated company size\n\n"
            f"Return 15-20 results. Return ONLY valid JSON array:\n"
            f'[{{"company":"...","job_title":"...","location":"...","posted":"date or recency",'
            f'"staffing_score":35,"reason":"specific reason","company_size":"est. employees",'
            f'"recommendation":"go after / monitor / skip"}}]'
        ),
        "scan2": (
            f"You are a staffing industry competitive intelligence analyst.\n\n"
            f"Find 15-20 job postings by STAFFING/RECRUITING AGENCIES for:\n"
            f"{context}\n\n"
            f"For each posting, analyze the job description to reverse-engineer the end client:\n"
            f"- Which staffing company posted it\n"
            f"- Job title, location, salary/rate, schedule, posting date\n"
            f"- SUSPECTED END CLIENT: use clues from the posting (specific location/address, "
            f"equipment brands mentioned, project descriptions, industry specifics, company size hints, "
            f"benefits described) to deduce which actual company is hiring\n"
            f"- Confidence level: high/medium/low on your client guess\n\n"
            f"Return 15-20 results. Return ONLY valid JSON array:\n"
            f'[{{"staffing_company":"...","job_title":"...","location":"...","salary":"...",'
            f'"schedule":"...","posting_date":"...","suspected_client":"best guess",'
            f'"confidence":"high/medium/low","evidence":"clues that point to the client"}}]'
        ),
        "scan3": (
            f"You are a staffing market intelligence analyst. Build a COMPREHENSIVE market map:\n\n"
            f"{context}\n\n"
            f"Cross-reference everything to show:\n"
            f"1. Every company actively hiring for these roles in this market\n"
            f"2. Which staffing firms are already working each company\n"
            f"3. GAPS  -  companies hiring with NO staffing coverage (these are your golden opportunities)\n"
            f"4. Priority ranking based on opportunity size\n\n"
            f"Return 15-20 companies. Return ONLY valid JSON array:\n"
            f'[{{"company":"...","roles_hiring":["..."],"num_openings":"est. number",'
            f'"staffing_companies_working":["names or empty array if none"],'
            f'"gap":"yes/no","opportunity_notes":"why worth pursuing",'
            f'"priority":"high/medium/low","est_revenue":"if known"}}]'
        ),
        "scan4": (
            f"You are a B2B sales intelligence analyst for a staffing company.\n\n"
            f"For the top companies hiring in this market, identify the DECISION MAKERS "
            f"who would approve staffing agency partnerships:\n\n"
            f"{context}\n\n"
            f"For each company, find:\n"
            f"- Company name\n"
            f"- The most likely decision maker (VP Operations, Plant Manager, HR Director, etc.)\n"
            f"- Their likely title and department\n"
            f"- Why they're the right contact (controls headcount, manages production, etc.)\n"
            f"- Secondary contact (backup decision maker)\n"
            f"- Best approach angle (what pain point to lead with)\n\n"
            f"Return 10-15 companies with contacts. Return ONLY valid JSON array:\n"
            f'[{{"company":"...","primary_contact_title":"VP Operations",'
            f'"primary_department":"Operations","why_primary":"controls production headcount",'
            f'"secondary_contact_title":"HR Manager","approach_angle":"lead with candidate availability",'
            f'"talking_points":["point 1","point 2","point 3"]}}]'
        ),
        "scan5": (
            f"You are a company research analyst for a staffing recruiter.\n\n"
            f"Do a DEEP DIVE on the top 8-10 companies hiring in this market:\n\n"
            f"{context}\n\n"
            f"For each company, build a dossier:\n"
            f"- Company overview (what they do, size, reputation)\n"
            f"- Recent news or developments (expansion, contracts, layoffs, acquisitions)\n"
            f"- Work culture signals (Glassdoor/Indeed ratings, turnover indicators)\n"
            f"- Compensation data for the target roles if available\n"
            f"- Why they'd use staffing (pain points, growth signals)\n"
            f"- Recommended campaign angle  -  what should the first email say?\n\n"
            f"Return 8-10 companies. Return ONLY valid JSON array:\n"
            f'[{{"company":"...","overview":"2-3 sentences","employee_count":"est.",'
            f'"recent_news":"latest developments","culture_rating":"X/5 if available",'
            f'"comp_range":"salary range for target roles","pain_points":["..."],'
            f'"campaign_angle":"recommended first email approach",'
            f'"first_email_hook":"one-sentence opening line for a cold email"}}]'
        ),
    }

    prompt = prompts.get(scan_type, prompts["scan1"])
    # Retry with backoff for rate limits
    for attempt in range(3):
        try:
            msg = _claude_create_with_retry(client,
                model="claude-haiku-4-5-20251001",
                max_tokens=8000,
                tools=[_safe_web_search_tool(max_uses=3)],
                messages=[{"role": "user", "content": prompt}],
            )
            all_text = ""
            for block in msg.content:
                if hasattr(block, "text"):
                    all_text += block.text + "\n"
            clean = all_text.replace("```json", "").replace("```", "").strip()
            json_match = re.search(r'\[.*\]', clean, re.DOTALL)
            if json_match:
                try:
                    return json.loads(json_match.group())
                except json.JSONDecodeError:
                    print(f"[MarketIntel] {scan_type}: JSON parse error, trying smaller match")
                    # Try non-greedy match
                    json_match2 = re.search(r'\[[\s\S]*?\](?=\s*$|\s*[^,\[\{])', clean)
                    if json_match2:
                        return json.loads(json_match2.group())
            print(f"[MarketIntel] {scan_type}: no JSON in response ({len(all_text)} chars)")
            if all_text:
                print(f"[MarketIntel] Last 200 chars: {all_text[-200:]}")
            return []
        except Exception as e:
            err_str = str(e)
            if "rate_limit" in err_str.lower() or "429" in err_str:
                wait = 30 * (attempt + 1)
                print(f"[MarketIntel] Rate limited on {scan_type}, waiting {wait}s (attempt {attempt+1}/3)")
                time.sleep(wait)
                continue
            print(f"[MarketIntel] Scan {scan_type} error: {_friendly_ai_error(e)}")
            return []
    print(f"[MarketIntel] {scan_type}: gave up after 3 rate limit retries")
    return []


def p_market_intel(s: AppState, rf):
    """Market Intel  -  competitive intelligence scanner."""

    # Load watches on first render
    if not s.mi_watches:
        s.mi_watches = _load_mi_watches()
    if not s.mi_results:
        s.mi_results = _load_mi_results()

    ui.label("Market Intel").classes("fd-h1")
    ui.label("Scan your markets for new jobs, staffing activity, and opportunities.").classes("fd-sub")

    # ── Tabs: Watches | Results ──────────────────────────────────────────
    with ui.element("div").style(
            f"display:flex;gap:4px;background:{C['surface']};border-radius:10px;"
            f"padding:4px;margin-bottom:20px;max-width:300px;"):
        for key, label in [("watches", "My Watches"), ("results", "Scan Results")]:
            on = s.mi_tab == key
            def _switch(k=key):
                s.mi_tab = k; rf()
            with ui.element("button").classes("fd-hub" + (" on" if on else "")).style(
                    "border-radius:8px;padding:8px 20px;font-size:13px;").on("click", _switch):
                ui.label(label)

    # ════════════════════════════════════════════════════════════════════
    #  WATCHES TAB
    # ════════════════════════════════════════════════════════════════════
    if s.mi_tab == "watches":
        # Create new watch form
        with ui.element("div").style(
                f"background:{C['card']};border:1px solid {C['teal']}40;"
                f"border-radius:12px;padding:24px;margin-bottom:20px;max-width:700px;"):
            ui.label("Create a Market Watch").style(
                f"font-size:16px;font-weight:700;color:{C['teal']};"
                f"font-family:'Nunito',sans-serif;margin-bottom:4px;")
            ui.label("Define your target market and DripDrop will scan for opportunities.").style(
                f"font-size:12px;color:{C['muted']};margin-bottom:16px;")

            with ui.element("div").style("display:grid;grid-template-columns:1fr 1fr;gap:12px;"):
                with ui.element("div"):
                    ui.label("Market Name").classes("fd-fl")
                    _w_name = ui.input(placeholder="Market name").classes("fd-input")
                with ui.element("div"):
                    if not hasattr(s, "mi_w_location"):
                        s.mi_w_location = ""
                    _render_region_picker(
                        s, rf,
                        state_key="mi_w_location",
                        multi=False,
                        container_style="margin-bottom:0;",
                        label="Location",
                    )
                with ui.element("div"):
                    ui.label("Target Roles (comma-separated)").classes("fd-fl")
                    _w_roles = ui.input(placeholder="e.g. CNC Machinist, CNC Programmer, Machine Operator").classes("fd-input")
                with ui.element("div"):
                    # Industry picker — same Primary/Secondary scheme as
                    # the rest of the app. Default Primary stays empty until
                    # user picks one (no more hardcoded "Manufacturing").
                    if not hasattr(s, "mi_w_primary_industry"):
                        s.mi_w_primary_industry = ""
                    if not hasattr(s, "mi_w_secondary_industries"):
                        s.mi_w_secondary_industries = []
                    _render_industry_picker(
                        s, rf,
                        primary_state_key="mi_w_primary_industry",
                        secondary_state_key="mi_w_secondary_industries",
                        container_style="margin-bottom:0;",
                        label_primary="Industry",
                        label_secondary="Sub-niche(s)",
                    )
            with ui.element("div").style("display:grid;grid-template-columns:1fr 1fr;gap:12px;margin-top:12px;"):
                with ui.element("div"):
                    ui.label("Company Size Target").classes("fd-fl")
                    _w_size = ui.select(
                        options=["Small (1-50)", "Medium (50-500)", "Large (500+)", "Any"],
                        value="Medium (50-500)",
                    ).classes("fd-input").style("width:100%;")
                with ui.element("div"):
                    ui.label("Notes (optional)").classes("fd-fl")
                    _w_notes = ui.input(placeholder="e.g. Focus on defense contractors with clearances").classes("fd-input")

            def _add_watch():
                name = _w_name.value.strip()
                if not name:
                    ui.notify("Give your watch a name.", type="warning"); return
                _prim = (getattr(s, "mi_w_primary_industry", "") or "").strip() or "Manufacturing"
                _secs = list(getattr(s, "mi_w_secondary_industries", []) or [])
                _loc_val = (getattr(s, "mi_w_location", "") or "").strip()
                watch = {
                    "name": name,
                    "location": _loc_val,
                    "roles": _w_roles.value.strip(),
                    "industry": _prim,
                    "secondary_industries": _secs,
                    "company_size": _w_size.value or "Medium (50-500)",
                    "market": name,
                    "notes": _w_notes.value.strip(),
                    "created": date.today().isoformat(),
                    "last_scan": "",
                }
                s.mi_watches.append(watch)
                _save_mi_watches(s.mi_watches)
                ui.notify(f"Watch '{name}' created!", type="positive")
                _w_name.set_value(""); _w_roles.set_value("")
                _w_notes.set_value("")
                # Reset both pickers for the next watch
                s.mi_w_primary_industry = ""
                s.mi_w_secondary_industries = []
                s.mi_w_location = ""
                rf()
            with ui.element("div").style("margin-top:16px;"):
                with ui.element("button").classes("fd-pb").style(
                        "padding:10px 24px;font-size:13px;").on("click", _add_watch):
                    ui.label("+ Create Watch")

        # ── Existing watches ─────────────────────────────────────────────
        if s.mi_watches:
            ui.label("Your Watches").classes("fd-sec")
            for wi, w in enumerate(s.mi_watches):
                last_scan = w.get("last_scan", "")
                results_count = 0
                wr = s.mi_results.get(w["name"], {})
                for sk in ["scan1", "scan3"]:
                    results_count += len(wr.get(sk, []))

                with ui.element("div").style(
                        f"background:{C['card']};border:1px solid {C['border']};"
                        f"border-left:4px solid {C['teal']};border-radius:0 10px 10px 0;"
                        f"padding:14px 18px;margin-bottom:8px;"):
                    with ui.element("div").style(
                            "display:flex;align-items:center;justify-content:space-between;"):
                        with ui.element("div").style("flex:1;"):
                            with ui.element("div").style("display:flex;align-items:center;gap:10px;"):
                                ui.label(w["name"]).style(
                                    f"font-size:14px;font-weight:600;color:{C['text_l']};")
                                ui.label(w.get("industry", "")).style(
                                    f"font-size:10px;padding:2px 8px;border-radius:99px;"
                                    f"background:{C['teal_dim']};color:{C['teal']};")
                            with ui.element("div").style("display:flex;gap:12px;margin-top:4px;"):
                                ui.label(f"📍 {w.get('location','')}").style(
                                    f"font-size:11px;color:{C['muted']};")
                                ui.label(f"🔧 {w.get('roles','')}").style(
                                    f"font-size:11px;color:{C['muted']};")
                                if last_scan:
                                    ui.label(f"Last scan: {last_scan}").style(
                                        f"font-size:11px;color:{C['muted']};")
                                if results_count:
                                    ui.label(f"{results_count} results").style(
                                        f"font-size:11px;color:{C['teal']};font-weight:600;")

                        with ui.element("div").style("display:flex;flex-direction:column;gap:4px;flex-shrink:0;align-items:flex-end;"):
                            # Generic scan runner for one or more scan types
                            def _run_scans(idx, scan_keys):
                                """Run specific scans for a watch."""
                                w = s.mi_watches[idx]
                                s.mi_scanning = True
                                s.mi_sel_watch = idx
                                s.mi_scan_phase = "Starting..."
                                scan_labels = {
                                    "scan1": "Direct Jobs",
                                    "scan3": "Full Picture",
                                    "scan5": "Deep Dives",
                                }
                                def _run():
                                    import traceback
                                    try:
                                        import anthropic as _anth
                                        client = _anth.Anthropic(api_key=ANTHROPIC_API_KEY)
                                        # Load existing results to merge
                                        existing = s.mi_results.get(w["name"], {})
                                        if not isinstance(existing, dict):
                                            existing = {}
                                        for si, sk in enumerate(scan_keys):
                                            label = scan_labels.get(sk, sk)
                                            s.mi_scan_phase = f"{label}... ({si+1}/{len(scan_keys)})"
                                            print(f"[MarketIntel] {label} for {w['name']}")
                                            result = _run_market_scan(w, sk, client)
                                            existing[sk] = result
                                            print(f"[MarketIntel] {label}: {len(result)} results")
                                            if si < len(scan_keys) - 1:
                                                time.sleep(15)
                                        existing["timestamp"] = datetime.now().isoformat()
                                        s.mi_results[w["name"]] = existing
                                        _save_mi_results(s.mi_results)
                                        w["last_scan"] = date.today().isoformat()
                                        _save_mi_watches(s.mi_watches)
                                        print(f"[MarketIntel] Scans complete for {w['name']}")
                                    except Exception as e:
                                        print(f"[MarketIntel] THREAD ERROR: {e}")
                                        _log_exception(e, context="market_intel.thread")
                                        s._mi_error = str(e)[:100]
                                    finally:
                                        s.mi_scanning = False
                                        s.mi_scan_phase = ""
                                _run_as_user(getattr(s, "_user_email", "") or "", _run, name="market_intel_scan_worker")
                                rf()

                            if s.mi_scanning and s.mi_sel_watch == wi:
                                with ui.element("div").style(
                                        f"display:flex;align-items:center;gap:8px;padding-top:4px;"):
                                    ui.spinner("dots", size="16px", color=C["warn"])
                                    ui.label(s.mi_scan_phase or "Scanning...").style(
                                        f"font-size:11px;color:{C['warn']};font-weight:600;")
                                ui.timer(5.0, rf, once=True)
                            else:
                                # Individual scan buttons
                                with ui.element("div").style("display:flex;gap:4px;flex-wrap:wrap;justify-content:flex-end;"):
                                    for sk, sl, sc in [
                                        ("scan1", "Jobs", C["teal"]),
                                        ("scan3", "Full Map", C["indigo"]),
                                        ("scan5", "Deep Dive", "#F59E0B"),
                                    ]:
                                        def _one(idx=wi, k=sk):
                                            _run_scans(idx, [k])
                                        with ui.element("button").style(
                                                f"padding:3px 8px;font-size:9px;border-radius:4px;"
                                                f"cursor:pointer;font-family:inherit;"
                                                f"background:{sc}15;border:1px solid {sc}40;"
                                                f"color:{sc};font-weight:600;"
                                                ).on("click", _one):
                                            ui.label(sl)
                                # Run All button
                                def _all(idx=wi):
                                    _run_scans(idx, ["scan1", "scan3", "scan5"])
                                with ui.element("button").classes("fd-pb").style(
                                        "padding:5px 14px;font-size:10px;margin-top:2px;").on("click", _all):
                                    ui.label("🔍 Run All 5 Scans")

                            # View results
                            if results_count:
                                def _view(n=w["name"]):
                                    s.mi_tab = "results"; s.mi_sel_watch = next(
                                        (i for i, x in enumerate(s.mi_watches) if x["name"] == n), 0)
                                    rf()
                                with ui.element("button").classes("fd-gb").style(
                                        "padding:6px 16px;font-size:11px;").on("click", _view):
                                    ui.label("View Results")

                            # Delete
                            def _del(idx=wi):
                                name = s.mi_watches[idx]["name"]
                                s.mi_watches.pop(idx)
                                s.mi_results.pop(name, None)
                                _save_mi_watches(s.mi_watches)
                                _save_mi_results(s.mi_results)
                                rf()
                            with ui.element("span").style(
                                    f"color:{C['danger']};cursor:pointer;font-size:14px;padding:4px 8px;"
                                    ).on("click.stop", _del):
                                ui.label("✕")

        if not s.mi_watches:
            with ui.element("div").style(
                    f"text-align:center;padding:40px;color:{C['muted']};"):
                ui.label("No watches yet. Create one above to start scanning your markets.")

    # ════════════════════════════════════════════════════════════════════
    #  RESULTS TAB
    # ════════════════════════════════════════════════════════════════════
    elif s.mi_tab == "results":
        if not s.mi_watches:
            ui.label("Create a watch first.").style(f"color:{C['muted']};padding:20px;")
            return

        # Watch selector
        watch_names = [w["name"] for w in s.mi_watches]
        if s.mi_sel_watch < 0 or s.mi_sel_watch >= len(s.mi_watches):
            s.mi_sel_watch = 0
        sel_watch = s.mi_watches[s.mi_sel_watch]
        wr = s.mi_results.get(sel_watch["name"], {})

        with ui.element("div").style("display:flex;align-items:center;gap:12px;margin-bottom:16px;"):
            for i, wn in enumerate(watch_names):
                on = i == s.mi_sel_watch
                def _pick(idx=i):
                    s.mi_sel_watch = idx; rf()
                with ui.element("button").classes("fd-hub" + (" on" if on else "")).style(
                        "border-radius:8px;padding:7px 16px;font-size:12px;").on("click", _pick):
                    ui.label(wn)

        if not wr:
            with ui.element("div").style(
                    f"text-align:center;padding:40px;color:{C['muted']};"):
                ui.label(f"No scan results yet for '{sel_watch['name']}'. Go to Watches and run a scan.")
            return

        ts = wr.get("timestamp", "")
        if ts:
            try:
                dt_obj = datetime.fromisoformat(ts)
                ui.label(f"Last scanned: {dt_obj.strftime('%b %d, %Y at %I:%M %p')}").style(
                    f"font-size:12px;color:{C['muted']};margin-bottom:12px;")
            except Exception:
                pass

        # Scan tabs
        with ui.element("div").style(
                f"display:flex;gap:0;border-bottom:1px solid {C['border']};margin-bottom:16px;"):
            for tk, tl, tc in [
                ("scan1", f"Direct Jobs ({len(wr.get('scan1',[]))})", C["teal"]),
                ("scan3", f"Full Picture ({len(wr.get('scan3',[]))})", C["indigo"]),
                ("scan5", f"Deep Dives ({len(wr.get('scan5',[]))})", "#F59E0B"),
            ]:
                ton = s.mi_results_tab == tk
                def _st(k=tk):
                    s.mi_results_tab = k; rf()
                bb = f"border-bottom:2px solid {tc};" if ton else "border-bottom:2px solid transparent;"
                with ui.element("button").style(
                        f"padding:10px 20px;font-size:13px;font-weight:{'600' if ton else '400'};"
                        f"color:{tc if ton else C['muted']};background:transparent;border:none;"
                        f"cursor:pointer;font-family:inherit;{bb}").on("click", _st):
                    ui.label(tl)

        items = wr.get(s.mi_results_tab, [])
        if not items:
            ui.label("No results for this scan.").style(f"color:{C['muted']};padding:20px;")
        else:
            # ── SCAN 1: Direct Jobs ──────────────────────────────────
            if s.mi_results_tab == "scan1":
                # Sort by staffing score descending
                items_sorted = sorted(items, key=lambda x: x.get("staffing_score", 0), reverse=True)
                for item in items_sorted:
                    score = item.get("staffing_score", 0)
                    score_col = C["good"] if score >= 40 else (C["warn"] if score >= 25 else C["muted"])
                    rec = item.get("recommendation", "").lower()
                    rec_col = C["teal"] if "go" in rec else (C["warn"] if "monitor" in rec else C["muted"])
                    with ui.element("div").style(
                            f"background:{C['card']};border:1px solid {C['border']};"
                            f"border-left:4px solid {score_col};border-radius:0 10px 10px 0;"
                            f"padding:14px 18px;margin-bottom:8px;overflow:visible;"):
                        with ui.element("div").style(
                                "display:flex;align-items:center;gap:16px;"):
                            # Score badge (LEFT side, prominent)
                            with ui.element("div").style(
                                    f"text-align:center;flex-shrink:0;padding:10px 14px;"
                                    f"background:{score_col}15;border:1px solid {score_col}40;"
                                    f"border-radius:10px;min-width:64px;"):
                                ui.label(str(score)).style(
                                    f"font-size:24px;font-weight:700;color:{score_col};")
                                ui.label("/ 50").style(f"font-size:10px;color:{C['muted']};")
                            # Content
                            with ui.element("div").style("flex:1;min-width:0;"):
                                with ui.element("div").style("display:flex;align-items:center;gap:10px;flex-wrap:wrap;"):
                                    ui.label(item.get("company", "")).style(
                                        f"font-size:14px;font-weight:600;color:{C['text_l']};")
                                    ui.label(item.get("recommendation", "")).style(
                                        f"font-size:10px;padding:2px 8px;border-radius:99px;"
                                        f"background:{rec_col}20;color:{rec_col};font-weight:600;"
                                        f"text-transform:uppercase;")
                                ui.label(f"{item.get('job_title','')}  -  {item.get('location','')}").style(
                                    f"font-size:12px;color:{C['text']};margin-top:2px;")
                                ui.label(item.get("reason", "")).style(
                                    f"font-size:11px;color:{C['muted']};margin-top:4px;line-height:1.5;")
                                if item.get("company_size"):
                                    ui.label(f"Est. size: {item['company_size']}").style(
                                        f"font-size:10px;color:{C['muted']};margin-top:2px;")

                        # Action: start campaign
                        with ui.element("div").style("display:flex;gap:6px;margin-top:8px;margin-left:80px;"):
                            def _start_camp(co=item.get("company",""), role=item.get("job_title",""),
                                           loc=item.get("location","")):
                                s._nav_history.append(_nav_snapshot(s))
                                s.sp = "ai_campaign"; s.aicb_step = 1
                                s.aicb_company = co
                                s.aicb_sel_roles = [role] if role else []
                                s.aicb_sel_locations = [loc] if loc else []
                                rf()
                            with ui.element("button").classes("fd-pb").style(
                                    "padding:4px 12px;font-size:10px;").on("click", _start_camp):
                                ui.label("Start Campaign →")

            # ── SCAN 2: Staffing Activity ────────────────────────────
            elif s.mi_results_tab == "scan2":
                for item in items:
                    with ui.element("div").style(
                            f"background:{C['card']};border:1px solid {C['border']};"
                            f"border-left:4px solid {C['warn']};border-radius:0 10px 10px 0;"
                            f"padding:14px 18px;margin-bottom:8px;"):
                        with ui.element("div").style("display:flex;align-items:center;gap:10px;"):
                            ui.label(item.get("staffing_company", "")).style(
                                f"font-size:14px;font-weight:600;color:{C['warn']};")
                            ui.label(f"→ {item.get('suspected_client','Unknown client')}").style(
                                f"font-size:12px;color:{C['teal']};font-weight:500;")
                        ui.label(f"{item.get('job_title','')}  -  {item.get('location','')}").style(
                            f"font-size:12px;color:{C['text']};margin-top:4px;")
                        with ui.element("div").style("display:flex;gap:16px;margin-top:4px;"):
                            if item.get("salary"):
                                ui.label(f"💰 {item['salary']}").style(f"font-size:11px;color:{C['muted']};")
                            if item.get("schedule"):
                                ui.label(f"🕐 {item['schedule']}").style(f"font-size:11px;color:{C['muted']};")
                            if item.get("posting_date"):
                                ui.label(f"📅 {item['posting_date']}").style(f"font-size:11px;color:{C['muted']};")
                        if item.get("evidence"):
                            ui.label(f"Evidence: {item['evidence']}").style(
                                f"font-size:10px;color:{C['muted']};margin-top:4px;font-style:italic;")

            # ── SCAN 3: Full Picture ─────────────────────────────────
            elif s.mi_results_tab == "scan3":
                for item in items:
                    pri = item.get("priority", "").lower()
                    pri_col = C["teal"] if pri == "high" else (C["warn"] if pri == "medium" else C["muted"])
                    with ui.element("div").style(
                            f"background:{C['card']};border:1px solid {C['border']};"
                            f"border-left:4px solid {pri_col};border-radius:0 10px 10px 0;"
                            f"padding:14px 18px;margin-bottom:8px;"):
                        with ui.element("div").style("display:flex;align-items:center;gap:10px;"):
                            ui.label(item.get("company", "")).style(
                                f"font-size:14px;font-weight:600;color:{C['text_l']};")
                            ui.label(item.get("priority", "").upper()).style(
                                f"font-size:10px;padding:2px 8px;border-radius:99px;"
                                f"background:{pri_col}20;color:{pri_col};font-weight:700;")
                            gap = item.get("gap", "")
                            if gap.lower() == "yes":
                                ui.label("GAP  -  No staffing coverage").style(
                                    f"font-size:10px;padding:2px 8px;border-radius:99px;"
                                    f"background:{C['good']}20;color:{C['good']};font-weight:700;")
                        roles_hiring = item.get("roles_hiring", [])
                        if roles_hiring:
                            ui.label(f"Hiring: {', '.join(roles_hiring)}").style(
                                f"font-size:12px;color:{C['text']};margin-top:4px;")
                        staffing_cos = item.get("staffing_companies_working", [])
                        if staffing_cos and staffing_cos != ["none"]:
                            ui.label(f"Staffing already working: {', '.join(staffing_cos)}").style(
                                f"font-size:11px;color:{C['warn']};margin-top:2px;")
                        else:
                            ui.label("No staffing companies detected").style(
                                f"font-size:11px;color:{C['good']};margin-top:2px;")
                        if item.get("opportunity_notes"):
                            ui.label(item["opportunity_notes"]).style(
                                f"font-size:11px;color:{C['muted']};margin-top:4px;line-height:1.5;")

                        with ui.element("div").style("display:flex;gap:6px;margin-top:8px;"):
                            def _start_camp3(co=item.get("company",""),
                                            roles=item.get("roles_hiring",[])):
                                s._nav_history.append(_nav_snapshot(s))
                                s.sp = "ai_campaign"; s.aicb_step = 1
                                s.aicb_company = co
                                s.aicb_sel_roles = roles[:5] if roles else []
                                rf()
                            with ui.element("button").classes("fd-pb").style(
                                    "padding:4px 12px;font-size:10px;").on("click", _start_camp3):
                                ui.label("Start Campaign →")

            # ── SCAN 4: Decision Makers ──────────────────────────────
            elif s.mi_results_tab == "scan4":
                for item in items:
                    with ui.element("div").style(
                            f"background:{C['card']};border:1px solid {C['border']};"
                            f"border-left:4px solid {C['good']};border-radius:0 10px 10px 0;"
                            f"padding:14px 18px;margin-bottom:8px;"):
                        ui.label(item.get("company", "")).style(
                            f"font-size:14px;font-weight:600;color:{C['text_l']};margin-bottom:6px;")
                        with ui.element("div").style(
                                f"display:grid;grid-template-columns:1fr 1fr;gap:12px;"):
                            # Primary contact
                            with ui.element("div").style(
                                    f"background:{C['surface']};border:1px solid {C['border']};"
                                    f"border-radius:8px;padding:10px 14px;"):
                                ui.label("Primary Contact").style(
                                    f"font-size:10px;font-weight:700;color:{C['teal']};"
                                    f"text-transform:uppercase;letter-spacing:.06em;margin-bottom:4px;")
                                ui.label(item.get("primary_contact_title", "")).style(
                                    f"font-size:13px;font-weight:600;color:{C['text_l']};")
                                ui.label(item.get("primary_department", "")).style(
                                    f"font-size:11px;color:{C['muted']};")
                                ui.label(item.get("why_primary", "")).style(
                                    f"font-size:11px;color:{C['text']};margin-top:4px;")
                            # Secondary
                            with ui.element("div").style(
                                    f"background:{C['surface']};border:1px solid {C['border']};"
                                    f"border-radius:8px;padding:10px 14px;"):
                                ui.label("Secondary Contact").style(
                                    f"font-size:10px;font-weight:700;color:{C['muted']};"
                                    f"text-transform:uppercase;letter-spacing:.06em;margin-bottom:4px;")
                                ui.label(item.get("secondary_contact_title", "")).style(
                                    f"font-size:13px;font-weight:500;color:{C['text']};")
                        # Approach angle
                        if item.get("approach_angle"):
                            with ui.element("div").style(
                                    f"margin-top:8px;padding:8px 12px;background:{C['teal']}08;"
                                    f"border:1px solid {C['teal']}20;border-radius:6px;"):
                                ui.label("Approach Angle").style(
                                    f"font-size:10px;font-weight:700;color:{C['teal']};"
                                    f"text-transform:uppercase;letter-spacing:.06em;margin-bottom:2px;")
                                ui.label(item["approach_angle"]).style(
                                    f"font-size:12px;color:{C['text']};line-height:1.5;")
                        # Talking points
                        points = item.get("talking_points", [])
                        if points:
                            with ui.element("div").style("margin-top:6px;"):
                                for pt in points:
                                    ui.label(f"• {pt}").style(
                                        f"font-size:11px;color:{C['muted']};line-height:1.6;")
                        # Start campaign
                        with ui.element("div").style("margin-top:8px;"):
                            def _camp4(co=item.get("company","")):
                                s._nav_history.append(_nav_snapshot(s))
