#  PAGE: RECRUITING CAMPAIGN
# ═══════════════════════════════════════════════════════════════════════════

def _rc_research_company(s, rf):
    """Use AI to research the company and generate an anonymous pitch."""
    if not ANTHROPIC_API_KEY:
        s.rc_ai_pitch = ""
        s.rc_ai_generating = False
        s.rc_ai_error = "No API key configured. Go to Email & AI Setup to add your key."
        s.rc_step = 2
        rf()
        return

    import anthropic
    import threading

    def _run():
        import pythoncom
        pythoncom.CoInitialize()
        try:
            client = anthropic.Anthropic(api_key=ANTHROPIC_API_KEY)

            company = s.rc_company or ""
            job_title = s.rc_job_title or ""
            location = s.rc_location or ""
            job_url = s.rc_job_url or ""
            selling_points = s.rc_selling_points or ""
            salary = s.rc_salary_range or ""

            research_prompt = (
                f"You are a recruiting copywriter. Research a company and create "
                f"an ANONYMOUS pitch to entice candidates  -  WITHOUT revealing the company name.\n\n"
                f"COMPANY: {company}\n"
                f"JOB TITLE: {job_title}\n"
                f"LOCATION: {location}\n"
                f"{'JOB URL: ' + job_url if job_url else ''}\n"
                f"{'SALARY RANGE: ' + salary if salary else ''}\n"
                f"{'SELLING POINTS FROM USER: ' + selling_points if selling_points else ''}\n\n"
                f"INSTRUCTIONS:\n"
                f"1. Research this company  -  industry, size, reputation, culture, projects, awards, growth.\n"
                f"2. Return EXACTLY 4 bullet points in this HTML format (no other text):\n\n"
                f"<li>[Anonymous company description  -  e.g. 'A top-tier design-build contractor with $2B+ in annual revenue']</li>\n"
                f"<li>[Impressive project/growth detail  -  e.g. 'Ranked in ENR Top 50, with a $4B backlog across healthcare, data centers, and commercial']</li>\n"
                f"<li>[Culture/team detail  -  e.g. 'Known for a collaborative, people-first culture with industry-leading retention rates']</li>\n"
                f"<li>[Career opportunity detail  -  e.g. 'Actively expanding their leadership team with a clear path from PM to VP']</li>\n\n"
                f"RULES:\n"
                f"- NEVER mention the actual company name, motto, or tagline\n"
                f"- Use anonymous phrases: 'a leading firm', 'a top-tier company', 'an industry leader'\n"
                f"- Include specific impressive numbers (revenue, headcount, rankings) but anonymize the source\n"
                f"- Make each bullet punchy and compelling  -  one line each, no filler\n"
                f"- Return ONLY the 4 <li> lines, nothing else"
            )

            tools = []
            if job_url or company:
                tools = [{"type": "web_search_20250305", "name": "web_search", "max_uses": 3}]

            msg = _claude_create_with_retry(client,
                model="claude-haiku-4-5-20251001", max_tokens=1500,
                tools=tools if tools else None,
                messages=[{"role": "user", "content": research_prompt}])

            pitch = ""
            for block in msg.content:
                if hasattr(block, "text"):
                    pitch += block.text

            s.rc_ai_pitch = pitch.strip()
            s.rc_ai_generating = False
            s.rc_ai_error = ""
            s.rc_step = 2
        except Exception as e:
            s.rc_ai_pitch = ""
            s.rc_ai_generating = False
            s.rc_ai_error = str(e)[:200]
            s.rc_step = 2
        finally:
            pythoncom.CoUninitialize()
        rf()

    s.rc_ai_generating = True
    s.rc_ai_error = ""
    threading.Thread(target=_run, daemon=True).start()


def _rc_parse_pitch_bullets(pitch: str) -> list:
    """Parse AI pitch into clean bullet strings. Returns list of up to 4 strings."""
    import re
    bullets = []
    for m in re.finditer(r"<li>(.*?)</li>", pitch, re.DOTALL):
        txt = m.group(1).strip()
        if txt:
            bullets.append(txt)
    if not bullets:
        # Fallback: split on newlines if no <li> tags
        for line in pitch.split("\n"):
            line = line.strip().lstrip("•-*").strip()
            if line and len(line) > 10:
                bullets.append(line)
    return bullets[:4]


def _rc_build_aggressive(s):
    """Build 4-email aggressive campaign over 3 days  -  company kept anonymous."""
    jt = s.rc_job_title or "this role"
    loc = s.rc_location or ""
    sal = s.rc_salary_range or ""
    pitch = s.rc_ai_pitch or ""
    bullets = _rc_parse_pitch_bullets(pitch)

    loc_line = f" in {loc}" if loc else ""
    sal_line = f"<br><br><b>Compensation:</b> {sal}" if sal else ""

    # Build a clean bullet list for email 1
