def _rc_build_steady(s):
    """Build 3-email steady campaign over 4 days  -  company kept anonymous."""
    jt = s.rc_job_title or "this role"
    loc = s.rc_location or ""
    sal = s.rc_salary_range or ""
    pitch = s.rc_ai_pitch or ""
    bullets = _rc_parse_pitch_bullets(pitch)

    loc_line = f" in {loc}" if loc else ""
    sal_line = f"<br><br><b>Compensation:</b> {sal}" if sal else ""

    # Build bullet list for email 1
    if bullets:
        bullet_html = "<br>".join(f"&bull; {b}" for b in bullets[:2])
        pitch_section = f"<br><br><b>What I can share about this opportunity:</b><br>{bullet_html}"
    else:
        pitch_section = ""

    # Use remaining bullets for email 2
    extra_bullets = bullets[2:4] if len(bullets) > 2 else []
    if extra_bullets:
        extra_html = "<br>".join(f"&bull; {b}" for b in extra_bullets)
        extra_section = f"<br>&bull; {extra_bullets[0]}" if len(extra_bullets) == 1 else f"<br>{extra_html}"
