def p_recruiting_campaign(s: AppState, rf):
    """Recruiting Campaign page  -  enter job details, AI researches company, pick campaign type."""
    import copy as _copy_mod

    with ui.element("div").style("display:flex;align-items:center;gap:12px;margin-bottom:4px;"):
        ui.label("Recruiting Campaign").classes("fd-h1")

    # ═══ STEP 0: Free-flow brief input ═══════════════════════════════════════
    if s.rc_step == 0:
        ui.label("Tell AI about the role in your own words. That's it.").style(
            f"font-size:13px;color:{C['muted']};margin-bottom:16px;")

        with ui.element("div").style("width:100%;max-width:720px;"):
            ui.label("The brief").style(
                f"font-size:13px;font-weight:700;color:{C['text_l']};margin-bottom:-4px;"
                f"font-family:'Nunito',sans-serif;")
            ui.label(
                "Paste a job description, describe the role, or just tell AI what you need. "
                "Freeform - no required structure."
            ).style(f"font-size:11px;color:{C['muted']};margin-bottom:6px;")

            _brief_inp = ui.textarea(
                value=s.rc_brief,
                placeholder=(
                    "Paste the job description here, or describe the role in your own words.\n\n"
                    "Include whatever you have:\n"
                    "- Job title and location\n"
                    "- Comp range if known\n"
                    "- What makes this role worth leaving a current job for\n"
                    "- How many emails you want and over how many days\n"
                    "- Tone: casual, professional, urgent, etc.\n\n"
                    "The more detail you give, the better the emails will be."
                ),
            ).props("outlined autogrow input-class=min-h-[240px]").classes("w-full").style(
                f"font-size:13px;color:{C['text_l']};"
            )
            _brief_inp.bind_value(s, 'rc_brief')

            # Click-to-focus hint sitting just above the textarea.
            # Clicking it focuses the input so the user can start typing
            # without having to aim at the box itself. Nudge label styled
            # to look obviously interactive.
            with ui.element("div").style(
                    f"display:inline-flex;align-items:center;gap:6px;"
                    f"margin:-8px 0 6px;padding:5px 12px;"
                    f"background:{C['teal']}15;border:1px dashed {C['teal']}80;"
                    f"border-radius:99px;cursor:pointer;font-size:11px;"
                    f"font-weight:700;color:{C['teal']};font-family:inherit;"
                    f"transition:all .15s;width:fit-content;"
                    ).on("click", lambda: _brief_inp.run_method("focus")):
                ui.label("👆 Click here to start typing").style(
                    "pointer-events:none;")

        def _next():
            _b = (s.rc_brief or "").strip()
            if len(_b) < 20:
                ui.notify("Write a few lines about the role first.", type="warning")
                return
            if not ANTHROPIC_API_KEY:
                ui.notify("Set your API key in AI Settings first.", type="negative")
                return
            # Derive a campaign title from the brief
            _title = ""
            for _line in _b.split("\n"):
                _t = _line.strip()
                if not _t:
                    continue
                if _t.lower().startswith("role:"):
                    _title = _t.split(":", 1)[1].strip(); break
                if not _title and len(_t) < 80:
                    _title = _t
            s.rc_job_title = _title or "Recruiting Campaign"
            s.rc_selling_points = _b
            s.rc_step = 1  # Show generating spinner
            s.rc_ai_generating = True
            s.rc_ai_error = ""
            rf()

            def _run_ai():
                import anthropic
                try:
                    client = anthropic.Anthropic(api_key=ANTHROPIC_API_KEY)
                    campaign_prompt = (
                        f'You are writing a RECRUITING email campaign for a staffing recruiter.\n\n'
                        + _DRIPDROP_PLAYBOOK + '\n'
                        + _style_guide_prompt() + '\n'
                        f'RECRUITER BRIEF (this is exactly what the recruiter wrote  -  follow their instructions):\n'
                        f'{_b[:3000]}\n\n'
                        f'INSTRUCTIONS:\n'
                        f'- Read the brief carefully. The recruiter may specify how many emails, timing, tone, and strategy.\n'
                        f'- If they don\'t specify, default to 3 emails over 3-5 days.\n'
                        f'- Keep the client/company name CONFIDENTIAL in the emails unless the brief says otherwise.\n'
                        f'- Use "{{FirstName}}" as the only merge field.\n'
                        f'- Do NOT include any sign-off, closing, or sender name. No "Best,", no "Thanks,", no name. The signature is auto-appended.\n'
                        f'- Every email body MUST start with "Hi {{FirstName}}," on the first line.\n'
                        f'- These are candidate-facing recruiting emails, NOT business development.\n'
                        f'- Tone: conversational, direct, recruiter-to-candidate. Not corporate.\n\n'
                        f'Write a SHORT STRATEGY SYNOPSIS (2-3 sentences) about your outreach angle.\n\n'
                        f'Then write the email campaign based on the brief.\n\n'
                        f'CRITICAL: Each step MUST have a unique delay_days value. '
                        f'delay_days is RELATIVE  -  the number of days AFTER the previous step (NOT cumulative). '
                        f'Step 1 is always 0.\n\n'
                        f'STRICT RULES:\n'
                        f'- Include exactly one LinkedIn step at position 2 (delay_days:1, time:"10:00 AM"). '
                        f'Never place LinkedIn before email 1. Never include more than one LinkedIn step.\n\n'
                        f'Return ONLY valid JSON:\n'
                        f'{{"synopsis":"...","campaign_name":"Recruiting  -  {s.rc_job_title}",'
                        f'"emails":[{{"week":1,"name":"Step 1 - ...",'
                        f'"subject":"...","body":"Hi {{FirstName}},<br><br>...",'
                        f'"delay_days":0,"time":"9:00 AM","step_type":"email_auto"}},'
                        f'{{"week":1,"name":"Step 2 - LinkedIn touch",'
                        f'"subject":"","body":"Hi {{{{FirstName}}}}, I sent you an email about a {jt} opportunity I think you\'d find interesting. Would love to connect here too.",'
                        f'"delay_days":1,"time":"10:00 AM","step_type":"linkedin"}},'
                        f'{{"week":1,"name":"Step 3 - ...",'
                        f'"subject":"...","body":"Hi {{FirstName}},<br><br>...",'
                        f'"delay_days":1,"time":"9:00 AM","step_type":"email_auto"}},...]}}'
                    )
                    msg = _claude_create_with_retry(client,
                        model="claude-haiku-4-5-20251001",
                        max_tokens=8192,
                        messages=[{"role": "user", "content": campaign_prompt}],
                    )
                    text = msg.content[0].text
                    clean = text.replace("```json", "").replace("```", "").strip()
                    json_match = re.search(r'\{.*\}', clean, re.DOTALL)
                    if json_match:
                        campaign_data = json.loads(json_match.group())
                        # Post-process emails
                        for _em in campaign_data.get("emails", []):
                            _b2 = _em.get("body") or ""
                            _s2 = _em.get("subject") or ""
                            if "**" in _b2:
                                _b2 = re.sub(r'\*\*(.+?)\*\*', r'<b>\1</b>', _b2)
                            if "**" in _s2:
                                _s2 = re.sub(r'\*\*(.+?)\*\*', r'\1', _s2)
                            _b2 = _b2.replace("\n---\n", "\n<br>\n").replace("---", "")
                            _b2 = re.sub(r'(?m)^[\s]*\*\s+', '\u2022 ', _b2)
                            _b2 = re.sub(r'<br>\s*\*\s+', '<br>\u2022 ', _b2)
                            if not _b2.lstrip().startswith("Hi {FirstName}"):
                                _b2 = "Hi {FirstName},<br><br>" + _b2
                            _b2 = _strip_ai_signoff(_b2)
                            _s2 = _title_case_subject(_s2)
                            _b2 = _strip_dashes(_b2)
                            _s2 = _strip_dashes(_s2)
                            _em["body"] = _b2
                            _em["subject"] = _s2

                        steps = campaign_data.get("emails", [])
                        camp_name = campaign_data.get("campaign_name", f"Recruiting  -  {s.rc_job_title}")
                        camp = dict(
                            schema=2, name=camp_name,
                            template_key="__recruiting__", template_name="Recruiting Campaign",
                            start_date=date.today().isoformat(),
                            contacts=[], contact_count=0, contact_emails=[],
                            emails=steps, variables={}, status="draft",
                            responders=[], delays=[str(x.get("delay_days", 0)) for x in steps],
                            created_date=date.today().isoformat(),
                            recruiting_job=s.rc_job_title,
                        )
                        s._nav_history.append(_nav_snapshot(s))
                        s.loaded_camp = camp
                        s.loaded_view = "emails"
                        s.loaded_tab = 0
                        s._tab = "custom"
                        s.sp = "start_seq"
                    else:
                        s.rc_ai_error = "Could not parse AI response. Try again."
                        s.rc_step = 0
                except Exception as e:
                    s.rc_ai_error = _friendly_ai_error(e)
                    s.rc_step = 0
                finally:
                    s.rc_ai_generating = False
                rf()

            import threading
            threading.Thread(target=_run_ai, daemon=True).start()

        with ui.element("div").style("margin-top:14px;max-width:720px;"):
            with ui.element("button").classes("fd-pb").style(
                    "padding:10px 28px;font-size:14px;border-radius:8px;").on("click", _next):
                ui.label("Build Campaign →")

    # ═══ STEP 1: AI Generating ═══════════════════════════════════════════════
    elif s.rc_step == 1:
        if s.rc_ai_error:
            with ui.element("div").style(
                    f"text-align:center;padding:40px 20px;max-width:500px;margin:0 auto;"):
                ui.label("⚠").style("font-size:36px;margin-bottom:12px;")
                ui.label(s.rc_ai_error).style(
                    f"font-size:13px;color:{C['danger']};margin-bottom:16px;")
                def _retry():
                    s.rc_step = 0; s.rc_ai_error = ""; rf()
                with ui.element("button").classes("fd-pb").style(
                        "padding:8px 20px;font-size:13px;border-radius:8px;").on("click", _retry):
                    ui.label("← Edit Brief & Retry")
        else:
            with ui.element("div").style(
                    f"text-align:center;padding:60px 20px;max-width:500px;margin:0 auto;"):
                ui.label("✦").style("font-size:48px;margin-bottom:16px;")
                ui.label("Building Your Campaign...").style(
                    f"font-size:20px;font-weight:700;color:{C['text_l']};"
                    f"font-family:'Nunito',sans-serif;margin-bottom:8px;")
                ui.label(
                    "AI is reading your brief and writing the emails. This takes a few seconds."
                ).style(f"font-size:13px;color:{C['muted']};margin-bottom:24px;")
                ui.spinner("dots", size="lg", color="#8B5CF6")


