# Legal pages (/privacy, /terms) are registered at the top of the file
# near /download so they share the same routing path that's known to work.


@ui.page("/diagnostics")
def diagnostics_page():
    """Admin diagnostics: tail of errors.log + last error timestamp.
    Requires login. Intended for users to copy-paste into bug reports
    so we don't need SSH access to debug their issue."""
    # Auth gate: only logged-in users see the page; anonymous gets a
    # bare "log in first" prompt.
    try:
        email = (app.storage.user.get("email") or "").strip()
    except Exception:
        email = ""
    if not email or not _is_super_admin(email):
        # Non-admins see a generic 'not available' message rather than
        # 'log in first' — leaking the existence of an admin endpoint
        # is itself a small information disclosure.
        ui.label("Diagnostics not available.").style("padding:24px;")
        return

    log_file = _LOG_DIR / "errors.log"
    if not log_file.exists():
        ui.label("No errors logged yet.").style("padding:24px;")
        return

    try:
        # Read last 100 lines (cheap for an error log; rotates daily)
        lines = log_file.read_text(encoding="utf-8").splitlines()
        tail = lines[-100:]
        last_ts = ""
        for line in reversed(tail):
            # Each entry starts with a timestamp from the formatter
            # "%(asctime)s | …" — extract first " | " split's left side.
            if " | " in line:
                last_ts = line.split(" | ", 1)[0]
                break
    except Exception as ex:
        ui.label(f"Failed to read errors.log: {ex}").style("padding:24px;")
        return

    ui.label("DripDrop Diagnostics").style(
        "font-size:18px;font-weight:700;padding:16px 24px 4px;")
    ui.label(f"Last error: {last_ts or '(none in tail)'}").style(
        "padding:0 24px 12px;color:#666;font-size:12px;")
    ui.html(
        "<pre style='background:#f6f6f6;padding:16px 24px;font-size:11px;"
        "white-space:pre-wrap;word-break:break-all;'>"
        + "\n".join(tail).replace("<", "&lt;").replace(">", "&gt;")
        + "</pre>"
    )


# ── Main App (authenticated) ──────────────────────────────────────────────
@ui.page("/")
def index():
    # DIAGNOSTIC 2026-05-20: log every page-handler invocation so we can
    # correlate user-reported "refresh every 5 min" with actual handler
    # entries. If this fires periodically, the WebSocket is reconnecting
    # and NiceGUI is treating the reconnect as a brand-new client
    # (reconnect_timeout misconfigured / Cloudflare-induced). If it does
    # NOT fire periodically, the "refresh" is something else (a stray
    # rf() somewhere, or a JS-side reload).
    try:
        _client_email = (app.storage.user.get("email") or "anon")[:40]
    except Exception:
        _client_email = "?"
    print(f"[REFRESH-DBG] index() ENTER user={_client_email} "
          f"at={datetime.now().isoformat(timespec='seconds')}", flush=True)

    # Desktop mode: single user, no accounts, no auth wall. Auto-authenticate
    # as the local user so the cloud-mode landing page / login form never
    # appears. Cloud mode keeps the full auth flow.
    if not _SERVER_MODE:
        if not app.storage.user.get("authenticated"):
            app.storage.user["authenticated"] = True
            app.storage.user["email"] = "desktop@local"
            app.storage.user["name"] = os.environ.get("USERNAME") or os.environ.get("USER") or "Local User"
    else:
        if not app.storage.user.get("authenticated"):
            # Unauthenticated visitors see the public marketing landing page,
            # which has its own Sign In / Sign Up links.
            _render_landing_page()
            return

    inject_styles()
    _user_email = app.storage.user.get("email", "")
    # Switch to per-user data directories
    _switch_to_user_paths(_user_email)
    # Invalidate caches so user gets their own data
    _cache_campaigns.invalidate()
    _cache_responded.invalidate()
    _cache_queue.invalidate()

    s = AppState()
    s._user_email = _user_email
    s._user_name = app.storage.user.get("name", "")

    # Deep link from newsletter preview email: ?edit_newsletter=<name>
    # Route the user to the Newsletters page so the modal opens there.
    try:
        from nicegui import context as _ctx_for_qs
        _qs_initial = dict(_ctx_for_qs.client.request.query_params or {})
    except Exception:
        _qs_initial = {}
    if _qs_initial.get("edit_newsletter"):
        s.sp = "newsletters"
        s.hub = "sales"

    # Registry of QEditors that participate in the merge-field round-trip.
    # Populated by helper `_register_qeditor` below (stored on `s` so module-
    # level page functions can access it); consumed by the 'dd_qeditor_change'
    # event that ddInsert emits (C1 fix).
    _qeditor_registry = {}

    def _register_qeditor(editor, eid: str):
        """Tag a QEditor with a stable id so JS can target it after a
        merge-field insert, and Python can reflect HTML back into it."""
        _qeditor_registry[eid] = editor
        editor.props(f'data-dd-editor-id={eid}')
        return editor

    # Attach to s so module-level page functions can call s._register_qeditor()
    s._register_qeditor = _register_qeditor

    def _on_qeditor_change(e):
        eid = (getattr(e, 'args', None) or {}).get('editor_id') or ''
        html = (getattr(e, 'args', None) or {}).get('html') or ''
        ed = _qeditor_registry.get(eid)
        if ed is not None:
            ed.set_value(html)

    # NiceGUI 3.x: ui.on takes (type, handler) as positional args. Using it
    # as a decorator (@ui.on('name')) silently returns None and crashes the
    # page with "'NoneType' object is not callable" — root cause of the
    # 2026-04-26 signup outage.
    ui.on('dd_qeditor_change', _on_qeditor_change)

    # Honor a pending page hand-off (e.g. from /setup → Email & AI Setup).
    # This overrides the default landing page because it's an explicit
    # one-time intent from another flow.
    #
    # Otherwise: hitting the root URL ALWAYS lands the user on Dashboard
    # (the AppState default). User directive 2026-05-25: "When a user
    # opens the app it should go to their dashboard." The earlier
    # restore-last-page behavior conflated cold open with WS reconnect
    # and dropped users into list views (Active Sequences, Replies, etc.)
    # instead of the home page. AICB / Target-Candidate wizard state
    # still persists separately via _restore_aicb_state below for brief
    # WS reconnects.
    _pending = app.storage.user.pop("_pending_page", None)
    _ats_tc_contacts = None
    if _pending:
        s.hub = "sales"
        s.sp = _pending
        # ATS → "Start an MPC Campaign" hands off a candidate slate (1-3) via
        # storage. Hydrate the MPC builder so it opens ON those candidates
        # instead of the empty Top-Candidates picker.
        if _pending == "candidate_campaign":
            _mpc = app.storage.user.pop("_pending_mpc_candidates", None)
            if _mpc:
                s.cpc_candidates = list(_mpc)
                s.cpc_candidate = s.cpc_candidates[0]
                s.cpc_companies = []
                s.cpc_added_lists = []
                s.cpc_uploaded_contacts = []
                s.cpc_uploaded_sources = []
                s.cpc_step = 0
                s.cpc_campaign = None
                s._cpc_error = ""
                s.cpc_mode = app.storage.user.pop("_pending_mpc_mode", "mpc") or "mpc"
                # 4×4: aim at the anchor candidate's industry + location market.
                if s.cpc_mode == "4x4":
                    s.cpc_industry = (s.cpc_candidates[0].get("industry", "")
                                      or getattr(s, "aicb_industry", "") or "")
                    s.cpc_ad_location = s.cpc_candidates[0].get("location", "") or ""
                    s.cpc_ad_link = ""
        elif _pending == "target_candidate":
            # ATS "Send a Job Opening" — grab the pre-loaded recipients now; the
            # clean Step-1 reset is applied AFTER _restore_aicb_state below (it
            # would otherwise resurrect a stale tc_step and skip the JD step).
            _ats_tc_contacts = app.storage.user.pop("_pending_campaign_contacts", []) or []
    # Rehydrate the AICB ("Recruiting Campaign") wizard from session
    # storage so reconnects don't drop the user back to step 1 with
    # blank fields. Same root cause as _restore_page_if_recent — fresh
    # AppState on every websocket reconnect — but for in-wizard state.
    _restore_aicb_state(s)
    # ATS Find-Candidates handoff: force a clean Step 1 AFTER the restore, so a
    # stale persisted tc_step can't drop the user straight on Generate.
    if _pending == "target_candidate":
        s.tc_step = 0
        s.tc_jd_text = ""
        s.tc_jd_filename = ""
        s.tc_jd_parsed = {}
        s.tc_candidates = []
        s.tc_preset = ""
        s.tc_jd_mode = ""
        s.tc_contacts = _ats_tc_contacts or []
    refs = {}

    def rf():
        # Re-apply user paths on every render (multi-user safety)
        _switch_to_user_paths(s._user_email)
        _cache_campaigns.invalidate()
        _cache_responded.invalidate()
        _cache_queue.invalidate()
        # Snapshot wizard state + current page so a reconnect mid-flow
        # rebuilds the user where they were. _save_current_page used to
        # only fire from nav_go/nav_back, which missed direct s.sp =
        # "..." assignments (chooser cards, AICB step transitions, etc.)
        # — that gap caused user-reported "resets" mid-work on
        # 2026-05-11.
        _save_aicb_state(s)
        try:
            _save_current_page(s)
        except Exception:
            pass
        for k in ["tb", "sb", "ct"]:
            if k in refs:
                refs[k].clear()
        with refs["tb"]:
            topbar(s, rf)
        with refs["sb"]:
            sidebar(s, rf)
        with refs["ct"]:
            render_page(s, rf)

    with ui.element("div").classes("fd-shell"):
        with ui.element("div") as tb:
            refs["tb"] = tb; topbar(s, rf)
        with ui.element("div").classes("fd-row"):
            with ui.element("div") as sb:
                refs["sb"] = sb; sidebar(s, rf)
            with ui.element("div").style("flex:1;overflow-y:auto;width:100%;min-width:0;") as ct:
                refs["ct"] = ct; render_page(s, rf)

    # ── First-visit onboarding tour ──
    # Fires once per device (localStorage-gated). We inject the step config
    # and invoke ddMaybeStartTour() after the DOM settles. The JS itself
    # checks localStorage and no-ops on repeat visits.
    import json as _json
    _tour_steps = [
        {
            "selector": '[data-tour="avatar"]',
            "title": "Welcome to DripDrop!",
            "body": (
                "This is your profile menu. Click here anytime to edit your "
                "name, phone, or photo, connect your email, or sign out."
            ),
        },
        {
            "selector": '[data-tour="nav-ai_settings"]',
            "title": "Start here: connect your email",
            "body": (
                "Before you can send campaigns, DripDrop needs to connect to "
                "your email. You have three options: Microsoft, Gmail, or "
                "Twilio SendGrid. You'll also add a free AI key on this page."
            ),
            "warn": "⚠ Without this, you won't be able to send any campaigns.",
        },
        {
            "selector": '[data-tour="nav-start_seq"]',
            "title": "Build your first campaign",
            "body": (
                "This is where you create outreach sequences. Pick an AI "
                "Campaign Builder template, a Recruiting Campaign, or build "
                "a custom one from scratch  -  DripDrop will walk you through "
                "each step."
            ),
        },
        {
            "selector": '[data-tour="nav-contacts"]',
            "title": "Upload your contacts",
            "body": (
                "Upload a CSV of the people you want to reach. Each row should "
                "have at least a name and email. DripDrop will merge their "
                "details into every campaign email automatically."
            ),
        },
        {
            "selector": '[data-tour="nav-dashboard"]',
            "title": "Track everything from the Dashboard",
            "body": (
                "Your home base. Once campaigns are live, you'll see daily "
                "tasks, responses, active campaigns, and stats all on this "
                "page. You can always get back here with the Dashboard link."
            ),
        },
        {
            "selector": None,
            "title": "You're all set!",
            "body": (
                "Next up: connect your email in Email & AI Setup, then start "
                "your first campaign. Every page has a ⓘ help icon next to "
                "the title  -  click it anytime you're stuck."
            ),
        },
    ]
    _steps_json = _json.dumps(_tour_steps)
    ui.run_javascript(
        f"window._ddTourSteps = {_steps_json}; "
        f"if (window.ddMaybeStartTour) window.ddMaybeStartTour();"
    )

    async def _poll():
        # CRITICAL: only call rf() when there's actually new reply data
        # to surface. Earlier this called rf() unconditionally after every
        # 5-min sleep, which forced a full page rebuild every 300 seconds
        # — wiping unsaved input, closing modals, jumping scroll. Reported
        # 2026-05-19 as "the app keeps refreshing every 5 minutes."
        try:
            while True:
                await asyncio.sleep(REPLY_POLL_SEC)
                new = outlook_monitor.pop()
                # DIAGNOSTIC 2026-05-20: report on every 5-min tick so we
                # can correlate user-reported "refresh every 5 min" with
                # actual rf() calls. Remove this line once the report
                # is resolved.
                print(f"[REFRESH-DBG] index._poll tick "
                      f"user={getattr(s, '_user_email', '?')[:40]} "
                      f"new_count={len(new) if new else 0} "
                      f"will_rf={'YES' if new else 'no'}", flush=True)
                if not new:
                    continue
                for r in new:
                    ui.notify(f"{r['name']} replied - removed from all sequences",
                              type="positive", timeout=8000)
                rf()
        except Exception:
            pass  # client disconnected
    asyncio.ensure_future(_poll())

# ═══════════════════════════════════════════════════════════════════════════
#  SERVER-SIDE EMAIL SCHEDULER  -  Graph API + Gmail API
# ═══════════════════════════════════════════════════════════════════════════
# On the cloud server, emails are sent via Microsoft Graph API or Gmail API
# (both over HTTPS, port 443). This replaces funnelforge_core's scheduler
# which relies on Outlook COM (desktop-only) and SMTP (blocked by DO).
#
# Architecture:
#   - A background daemon thread wakes every 60 seconds
#   - Scans ALL per-user scheduled_queue.json files under data/users/
#   - For each due pending item: resolves the user's OAuth tokens, refreshes
#     if expired, and sends via the appropriate API
#   - Updates item status to "sent" or "failed" in the per-user queue file
#   - Rate-limits to 2 seconds between sends to avoid API throttling

_SERVER_SEND_INTERVAL = 30  # seconds between scheduler ticks

_SERVER_INTER_EMAIL_PAUSE = 2  # seconds between individual emails

# ── Deliverability pacing (PER-CAMPAIGN) ─────────────────────────────────
# Sending a whole batch of due emails at once (e.g. a step scheduled for 50
# contacts) bursts and gets accounts blocked. Instead, trickle. Pacing is
# PER CAMPAIGN: each campaign sends <=1 email per `send_gap_seconds`, but
# different campaigns may fire in the SAME tick (parallel across campaigns),
# so one large campaign can't starve the others (head-of-line blocking).
# Total throughput is still bounded per account by `daily_send_limit`.
# Tunable per user via config key "send_gap_seconds" (seconds; 0 disables).
_SERVER_MIN_SEND_GAP = 90      # default base seconds between a campaign's sends (jittered up to 2x)
_next_campaign_send_at = {}    # uname -> {campaign: epoch when next eligible} (in-memory)


def _select_due_per_campaign(due, now_epoch, gap, next_campaign_send_at,
                             remaining_budget, jitter=None):
    """Per-CAMPAIGN deliverability pacing (pure; unit-tested).

    From `due` (pending+due items in priority order) pick at most ONE item per
    campaign whose campaign is eligible (now_epoch >= its next-send time), up
    to `remaining_budget` items total. Different campaigns may be selected in
    the same call — they send in parallel — so one large campaign can't
    monopolize the throttle and starve the others.

    Side effect: for each campaign selected, sets its next eligible time in
    `next_campaign_send_at` (mutated in place) to now_epoch + gap + jitter(gap).
    Skipped campaigns are left untouched so they stay eligible on a later tick.

    gap <= 0 disables pacing: returns due[:remaining_budget] and does not touch
    the gate. `jitter` is a callable gap->float (defaults to
    random.uniform(0, gap)); injectable so tests are deterministic.
    """
    if remaining_budget <= 0:
        return []
    if gap <= 0:
        return list(due[:remaining_budget])
    if jitter is None:
        import random as _rng
        jitter = lambda g: _rng.uniform(0, g)
    selected = []
    picked = set()
    for item in due:
        if len(selected) >= remaining_budget:
            break
        camp = item.get("campaign", "")
        if camp in picked:
            continue  # already taking one from this campaign this tick
        if now_epoch < next_campaign_send_at.get(camp, 0):
            continue  # this campaign isn't eligible yet
        selected.append(item)
        picked.add(camp)
        next_campaign_send_at[camp] = now_epoch + gap + jitter(gap)
    return selected

_MAX_SEND_RETRIES = 3  # transient send failures retried this many times before giving up

# Substrings (lowercased) that mean the RECIPIENT address is bad and
# retrying won't help — these SHOULD opt-out the contact + cancel their
# campaign. Everything else is treated as transient (server/network/auth
# hiccup) and retried. See _classify_send_error.
_PERMANENT_SEND_MARKERS = (
    "errorinvalidrecipients",
    "invalidrecipients",
    "recipientnotfound",
    "recipient not found",
    "mailbox not found",
    "mailbox unavailable",
    "mailbox does not exist",
    "no such user",
    "address rejected",
    "550",
    "551",
    "553",
    "5.1.1",
)


def _classify_send_error(err: str) -> str:
    """Classify a send-failure string as 'permanent' or 'transient'.

    Permanent = the recipient address is bad and retrying won't help
    (invalid recipient, mailbox not found, SMTP 55x). Caller should
    opt-out the contact and cancel their campaign.

    Transient = a server / network / auth hiccup that says nothing
    about the recipient (HTTP 500/502/503/504, 429 throttling,
    timeouts, expired/revoked tokens, "No email provider configured").
    Caller should retry, never opt-out the contact.

    Unknown errors default to TRANSIENT — it's far safer to retry an
    email than to wrongly opt-out a valid contact.
    """
    e = (err or "").lower()
    for marker in _PERMANENT_SEND_MARKERS:
        if marker in e:
            return "permanent"
    return "transient"


def _body_is_html(body: str) -> bool:
    """Heuristic: does this body already contain HTML structure?

    Used so the sender NEVER HTML-escapes a real HTML payload that arrived
    with a missing/false is_html flag (legacy queue entry, auto-refresh
    re-queue, etc.). Escaping such a body ships "<!DOCTYPE html>…" to the
    recipient as visible raw markup."""
    if not body or "<" not in body:
        return False
    low = body.lower()
    return (
        "<!doctype" in low or "<html" in low or "<table" in low
        or "</div>" in low or "</td>" in low or "</p>" in low
        or "<br" in low or "</b>" in low
    )


def _resolve_body_from_campaign(item: dict, user_dir: Path) -> str:
    """Lazy lookup of the rendered email body from the campaign file.
    Used when queue items are written without an inlined body — currently
    for newsletter campaigns, where every recipient gets the same auto-
    generated issue HTML and inlining 380 KB per recipient was bloating
    scheduled_queue.json by hundreds of MB.

    Returns the step's `body` field, or empty string if the campaign
    file or step can't be found. Newsletter bodies have no per-contact
    placeholders, so no substitution is needed here.
    """
    camp_name = item.get("campaign", "") or ""
    step_idx = item.get("_step_idx")
    if not camp_name or step_idx is None:
        return ""
    # The filename slug MUST match save_campaign's: re.sub(r"[^\w\-]","_")
    # truncated to 60 chars. The previous re.sub(r"[^\w]+","_") collapsed
    # runs and dropped hyphens differently, so names with "&", multiple
    # spaces, or hyphens (e.g. "SoCal Schools & Staffing") resolved to the
    # WRONG filename → empty body → "Missing email body" → the newsletter
    # silently never sent.
    camp = None
    safe_name = re.sub(r"[^\w\-]", "_", camp_name)[:60]
    camp_path = user_dir / "Campaigns" / f"{safe_name}.json"
    if camp_path.exists():
        try:
            camp = json.loads(camp_path.read_text(encoding="utf-8"))
        except Exception:
            camp = None
    if camp is None:
        # Authoritative fallback: scan for a campaign whose stored `name`
        # matches exactly, so resolution survives any past/future slug
        # formula change.
        try:
            for _f in (user_dir / "Campaigns").glob("*.json"):
                try:
                    _c = json.loads(_f.read_text(encoding="utf-8"))
                except Exception:
                    continue
                if (_c.get("name") or "") == camp_name:
                    camp = _c
                    break
        except Exception:
            camp = None
    if camp is None:
        return ""
    steps = camp.get("emails", []) or []
    try:
        step = steps[int(step_idx)]
    except Exception:
        return ""
    return (step.get("body") or "").strip()


def _apply_merge_tokens(text: str, item: dict) -> str:
    """Replace {FirstName}/{LastName}/{Company}/{JobTitle} in `text` with the
    recipient's details from a queue item, at SEND time.

    Campaign bodies are substituted at queue time, so this is a no-op for them
    (fast-path: returns unchanged when there is no "{"). Newsletters defer their
    body, so this is where their auto "Hi {FirstName}," greeting and any tokens
    the user typed get personalized per recipient.

    First name comes from the explicit `first_name` field, else the first word
    of `contact_name`/`to_name`; it falls back to "there" so a greeting reads
    "Hi there," not "Hi ,". Other tokens fall back to empty string.
    """
    if not text or "{" not in text:
        return text or ""
    _name = (item.get("contact_name") or item.get("to_name") or "").strip()
    _parts = _name.split()
    first = (item.get("first_name") or (_parts[0] if _parts else "")).strip()
    last = (item.get("last_name")
            or (" ".join(_parts[1:]) if len(_parts) > 1 else "")).strip()
    for token, value in (
        ("{FirstName}", first or "there"),
        ("{LastName}", last),
        ("{Company}", (item.get("contact_company") or "").strip()),
        ("{JobTitle}", (item.get("contact_title") or "").strip()),
    ):
        text = text.replace(token, value)
    return text


def _server_send_one(item: dict, config_path: Path, user_dir: Path = None) -> tuple:
    """Send one queued email using the user's connected OAuth provider.
    Tries Microsoft Graph first, then Gmail. Returns (success, error).

    If the queue item has an empty body (newsletter campaigns now write
    items without inlining the body — see _resolve_body_from_campaign),
    the body is looked up from the campaign file at send time. Saves
    hundreds of MB on the queue file.
    """
    to = item.get("to", "")
    subject = item.get("subject", "")
    body = item.get("body", "") or ""
    is_html = item.get("is_html", False)
    attachments = item.get("attachments") or []

    # Lazy body lookup for newsletter (and any other) entries that were
    # queued without an inlined body. Falls back to empty string on lookup
    # failure → the empty-body guard below will refuse to send.
    if not body.strip() and user_dir is not None:
        body = _resolve_body_from_campaign(item, user_dir)
        # Newsletter HTML is pre-rendered; if we just loaded it, mark as html.
        if body and not is_html:
            is_html = True

    # Per-recipient merge tokens ({FirstName} etc.). No-op for campaign items
    # (already substituted at queue time); powers deferred newsletter bodies
    # and the auto "Hi {FirstName}," greeting.
    subject = _apply_merge_tokens(subject, item)
    body = _apply_merge_tokens(body, item)

    if not to or not subject:
        return False, "Missing recipient or subject"
    if not body.strip():
        return False, "Missing email body (campaign step body unavailable)"

    # Ensure body is HTML. Trust the flag, but ALSO sniff the body: a
    # mislabeled item (legacy queue entry, auto-refresh re-queue, etc.) can
    # carry real HTML with is_html missing/false. Escaping it would ship
    # "<!DOCTYPE html>…" to the recipient as visible raw markup (the
    # San Diego Scoop incident, 2026-06-04). Never escape real HTML.
    if not is_html and _body_is_html(body):
        is_html = True
    if not is_html:
        body = body.replace("&", "&amp;").replace("<", "&lt;").replace(">", "&gt;")
        body = body.replace("\n", "<br>")

    # Externalize any inline base64 images (e.g. logos baked into older issue
    # bodies) so Outlook renders them. No-op when there are none.
    body = _externalize_data_uri_images(body)

    # Build attachment list (only existing files, skip broken paths)
    valid_atts = [a for a in attachments if a and Path(a).is_file()]

    # Track whether the user HAS stored tokens (vs never connected) so we
    # can produce an accurate error message if every send path fails.
    ms_had_tokens = False
    gmail_had_tokens = False
    last_send_error = ""

    # ── Try Microsoft Graph API ──────────────────────────────────────────
    try:
        import ms_email
        if ms_email.is_configured():
            _ms_toks = ms_email.load_ms_tokens(config_path)
            ms_had_tokens = bool(_ms_toks.get("access_token") or _ms_toks.get("refresh_token"))
            token = ms_email.get_valid_token(config_path)
            if token:
                ok, err = ms_email.send_email(
                    access_token=token, to=to,
                    subject=subject, html_body=body,
                    attachments=valid_atts,
                )
                if ok:
                    return True, ""
                last_send_error = f"MS Graph send failed: {err}"
                print(f"[ServerSend] MS Graph failed for {to}: {err}", flush=True)
    except ImportError:
        pass
    except Exception as e:
        print(f"[ServerSend] MS Graph exception: {e}", flush=True)

    # ── Try Gmail API ────────────────────────────────────────────────────
    try:
        import gmail_oauth
        if gmail_oauth.is_configured():
            _g_toks = gmail_oauth.load_tokens(config_path)
            gmail_had_tokens = bool(_g_toks.get("access_token") or _g_toks.get("refresh_token"))
            token = gmail_oauth.get_valid_token(config_path)
            if token:
                from_email = _g_toks.get("email", "")
                from_name = _g_toks.get("name", "")
                ok, err = gmail_oauth.send_email(
                    access_token=token, to=to,
                    subject=subject, html_body=body,
                    from_email=from_email, from_name=from_name,
                    attachments=valid_atts,
                )
                if ok:
                    return True, ""
                last_send_error = f"Gmail send failed: {err}"
                print(f"[ServerSend] Gmail failed for {to}: {err}", flush=True)
    except ImportError:
        pass
    except Exception as e:
        print(f"[ServerSend] Gmail exception: {e}", flush=True)

    # Differentiate between "never connected" and "tokens expired/revoked"
    if last_send_error:
        return False, last_send_error
    if ms_had_tokens and gmail_had_tokens:
        return False, "Microsoft and Gmail connections both expired or revoked. Reconnect in Email & AI Setup."
    if ms_had_tokens:
        return False, "Microsoft connection expired or consent revoked. Reconnect Microsoft in Email & AI Setup."
    if gmail_had_tokens:
        return False, "Gmail connection expired or consent revoked. Reconnect Gmail in Email & AI Setup."
    return False, "No email provider configured  -  connect Microsoft or Gmail in Email & AI Setup."


def _server_scheduler_tick():
    """One tick: scan all per-user queues for due emails, send them.

    Timezone handling: queue items store send_dt as a naive ISO string
    in the user's local timezone (item["send_tz"], falling back to the
    user's current config, then to the default). We convert each to aware
    UTC for the "is this due?" comparison so the server OS timezone is
    irrelevant to when sends fire."""
    from zoneinfo import ZoneInfo, ZoneInfoNotFoundError
    users_dir = _BASE_DATA_DIR / "users"
    if not users_dir.exists():
        return

    # Always compare in UTC  -  robust against server clock changes.
    now_utc = datetime.now(ZoneInfo("UTC"))
    total_sent = 0
    total_failed = 0

    for user_dir in users_dir.iterdir():
        if not user_dir.is_dir():
            continue
        queue_path = user_dir / "scheduled_queue.json"
        if not queue_path.exists():
            continue
        config_path = user_dir / "dripdrop_config.json"

        # Load queue
        try:
            queue = json.loads(queue_path.read_text(encoding="utf-8"))
        except Exception:
            continue
        if not isinstance(queue, list):
            continue

        # Load the user's current tz as a fallback for items that predate
        # the per-item `send_tz` field.
        try:
            _user_cfg = json.loads(config_path.read_text(encoding="utf-8")) if config_path.exists() else {}
        except Exception:
            _user_cfg = {}
        _user_default_tz = (_user_cfg.get("user_timezone", "") or "").strip() or _DEFAULT_USER_TZ

        def _resolve_tz(name: str):
            try:
                return ZoneInfo(name)
            except ZoneInfoNotFoundError:
                return ZoneInfo(_DEFAULT_USER_TZ)

        # Find due items
        due = []
        for item in queue:
            if item.get("status") != "pending":
                continue
            send_dt = item.get("send_dt")
            if not send_dt:
                continue
            try:
                naive_local = datetime.fromisoformat(send_dt)
                _item_tz_name = item.get("send_tz") or _user_default_tz
                aware_local = naive_local.replace(tzinfo=_resolve_tz(_item_tz_name))
                if aware_local.astimezone(ZoneInfo("UTC")) <= now_utc:
                    due.append(item)
            except Exception:
                continue

        if not due:
            continue

        print(f"[ServerSend] {user_dir.name}: {len(due)} email(s) due", flush=True)

        # ── Daily send limit: respect per-user cap ────────────────────
        # Default raised 50 → 250 on 2026-05-20 per user direction.
        _daily_limit = _user_cfg.get("daily_send_limit", 250)
        # Count how many we already sent today (in user's timezone)
        _user_tz_obj = _resolve_tz(_user_default_tz)
        _user_today = datetime.now(ZoneInfo("UTC")).astimezone(_user_tz_obj).date().isoformat()
        _sent_today = sum(1 for q in queue
                         if q.get("status") == "sent"
                         and (q.get("sent_at") or "")[:10] == _user_today)
        _remaining_budget = max(0, _daily_limit - _sent_today)
        if _remaining_budget == 0:
            print(f"[ServerSend] {user_dir.name}: daily limit reached ({_daily_limit}/day, {_sent_today} sent today)  -  holding {len(due)} email(s)", flush=True)
            continue

        # ── Deliverability pacing: PER-CAMPAIGN, parallel across campaigns ──
        # Each campaign trickles <=1 email per `send_gap_seconds`; different
        # campaigns may fire in the same tick, so a big campaign can't starve
        # the others. Still bounded by the per-account daily budget above.
        _gap = _user_cfg.get("send_gap_seconds", _SERVER_MIN_SEND_GAP)
        try:
            _gap = int(_gap)
        except Exception:
            _gap = _SERVER_MIN_SEND_GAP
        _camp_gate = _next_campaign_send_at.setdefault(user_dir.name, {})
        _due_before = len(due)
        due = _select_due_per_campaign(
            due, time.time(), _gap, _camp_gate, _remaining_budget,
        )
        if not due:
            continue
        if len(due) < _due_before:
            _ncamps = len({i.get("campaign", "") for i in due})
            print(f"[ServerSend] {user_dir.name}: per-campaign pacing — sending "
                  f"{len(due)} from {_ncamps} campaign(s) of {_due_before} due "
                  f"(gap {_gap}s/campaign)", flush=True)

        # Send each due item
        changed = False
        for item in due:
            ok, err = _server_send_one(item, config_path, user_dir=user_dir)
            if ok:
                item["status"] = "sent"
                item["sent_at"] = datetime.now().isoformat()
                total_sent += 1
                print(f"[ServerSend] ✓ {item.get('to')}  -  {item.get('subject','')[:50]}", flush=True)
                # 4x4 -> J's Way: auto-enroll a non-responder who just finished
                # the final email of an Arena 4x4. Best-effort, never blocks.
                _maybe_handoff_4x4_graduate(item, user_dir)
            else:
                # Decide whether this failure means the address is bad
                # (permanent → opt-out + cancel) or just a server/network/
                # auth hiccup (transient → retry up to _MAX_SEND_RETRIES).
                # Real invalid-recipient bounces mostly arrive later as
                # NDRs, which the reply monitor handles separately.
                if _classify_send_error(err) == "transient":
                    _rc = int(item.get("retry_count", 0)) + 1
                    item["retry_count"] = _rc
                    item["last_transient_error"] = err[:200]
                    if _rc >= _MAX_SEND_RETRIES:
                        item["status"] = "failed"
                        item["failed_at"] = datetime.now().isoformat()
                        item["error"] = f"Gave up after {_rc} transient failures: {err[:160]}"
                        total_failed += 1
                        print(f"[ServerSend] ✗ {item.get('to')}: gave up after "
                              f"{_rc} transient attempts: {err}", flush=True)
                    else:
                        # Stay "pending" so this item is due again next tick
                        # (~60s). No campaign cancel, no DNC — the contact is
                        # not at fault.
                        print(f"[ServerSend] ↻ {item.get('to')}: transient fail "
                              f"(attempt {_rc}/{_MAX_SEND_RETRIES}), will retry: {err}",
                              flush=True)
                    changed = True
                    time.sleep(_SERVER_INTER_EMAIL_PAUSE)
                    continue

                # Permanent failure — the address is bad. Mark failed,
                # cancel the contact's remaining campaign emails, and
                # opt them out so we never hit the bad address again.
                item["status"] = "failed"
                item["failed_at"] = datetime.now().isoformat()
                item["error"] = err[:200]
                total_failed += 1
                print(f"[ServerSend] ✗ {item.get('to')}: {err}", flush=True)
                # ── Bounce protection: cancel all remaining pending emails
                # for this contact in this campaign. Sending to a known-bad
                # address again tanks sender reputation.
                _bounce_to = item.get("to", "").lower().strip()
                _bounce_camp = item.get("campaign", "")
                if _bounce_to and _bounce_camp:
                    _cancelled = 0
                    for other in queue:
                        if (other.get("status") == "pending"
                                and other.get("to", "").lower().strip() == _bounce_to
                                and other.get("campaign", "") == _bounce_camp
                                and other is not item):
                            other["status"] = "cancelled"
                            other["cancelled_at"] = datetime.now().isoformat()
                            other["cancel_reason"] = "bounce_protection"
                            _cancelled += 1
                    if _cancelled:
                        print(f"[ServerSend] Bounce protect: cancelled {_cancelled} pending email(s) for {_bounce_to} in '{_bounce_camp}'", flush=True)
                    # Add bounced address to user's DNC list
                    try:
                        _dnc_path = user_dir / "dnc_list.json"
                        _dnc = []
                        if _dnc_path.exists():
                            try: _dnc = json.loads(_dnc_path.read_text(encoding="utf-8"))
                            except Exception: _dnc = []
                        if not any(d.get("email", "").lower() == _bounce_to for d in _dnc):
                            _dnc.append({"email": _bounce_to, "added": datetime.now().isoformat(), "reason": f"Bounced: {err[:100]}"})
                            _dnc_path.write_text(json.dumps(_dnc, indent=2), encoding="utf-8")
                            print(f"[ServerSend] Added {_bounce_to} to DNC (bounce)", flush=True)
                    except Exception as dnc_err:
                        print(f"[ServerSend] DNC write error: {dnc_err}", flush=True)
            changed = True
            time.sleep(_SERVER_INTER_EMAIL_PAUSE)

        # Save updated queue
        if changed:
            try:
                tmp = queue_path.with_suffix(".tmp")
                tmp.write_text(json.dumps(queue, indent=2, default=str), encoding="utf-8")
                tmp.replace(queue_path)
            except Exception as e:
                print(f"[ServerSend] Queue save error for {user_dir.name}: {e}", flush=True)

    if total_sent or total_failed:
        print(f"[ServerSend] Tick complete  -  sent: {total_sent}, failed: {total_failed}", flush=True)


# ═══════════════════════════════════════════════════════════════════════════
#  LEADER ELECTION  -  for blue/green zero-downtime deploys
# ═══════════════════════════════════════════════════════════════════════════
# When we run two copies of DripDrop (blue on :8080, green on :8081) during
# a deploy, only ONE of them should run the email scheduler and reply
# monitor  -  otherwise we'd double-send every email. This picks a leader
# using a shared file-based heartbeat:
#
#   - Every 20 seconds each process writes {pid, port, hostname, timestamp}
#     to /opt/dripdrop/data/leader.json
#   - Before each scheduler tick, check the file:
#       - If I wrote it most recently (within 60s), I'm the leader → run
#       - If someone else wrote it and is still fresh (<60s old), I'm not
#         the leader → skip this tick silently
#       - If the file is stale (>60s), the current leader died → I take over
#
# This gives us automatic handoff during deploys with no coordination
# protocol  -  whichever process is healthier grabs the lease and keeps it.

_LEADER_FILE = _BASE_DATA_DIR / "leader.json"
_LEADER_HEARTBEAT_INTERVAL = 20  # seconds between my heartbeats
_LEADER_STALE_AFTER = 60  # seconds before I take over a silent leader
_MY_PORT = int(os.getenv("DRIPDROP_PORT", "8080"))
_MY_COLOR = os.getenv("DRIPDROP_COLOR", "blue")  # blue or green, for logs


def _read_leader() -> dict:
    """Read current leader record. Returns {} if missing/corrupt."""
    try:
        if _LEADER_FILE.exists():
            return json.loads(_LEADER_FILE.read_text(encoding="utf-8"))
    except Exception:
        pass
    return {}


def _write_leader_heartbeat():
    """Write my heartbeat to the leader file. Caller is responsible for
    only calling this when we ARE the leader."""
    try:
        _LEADER_FILE.parent.mkdir(parents=True, exist_ok=True)
        _LEADER_FILE.write_text(json.dumps({
            "pid": os.getpid(),
            "port": _MY_PORT,
            "color": _MY_COLOR,
            "ts": datetime.now().isoformat(),
        }, indent=2), encoding="utf-8")
    except Exception as e:
        print(f"[Leader] Heartbeat write failed: {e}", flush=True)


def _am_i_leader() -> bool:
    """Decide whether this process should run background workers this tick.
    If yes, also refreshes the heartbeat. Returns False if someone else
    has a fresh lease."""
    rec = _read_leader()
    now = datetime.now()

    # No current leader → I grab it
    if not rec or not rec.get("ts"):
        _write_leader_heartbeat()
        return True

    try:
        last_ts = datetime.fromisoformat(rec["ts"])
        age = (now - last_ts).total_seconds()
    except Exception:
        # Bad timestamp  -  treat as stale, I take over
        _write_leader_heartbeat()
        return True

    # Current leader is me → refresh my heartbeat
    if rec.get("pid") == os.getpid() and rec.get("port") == _MY_PORT:
        _write_leader_heartbeat()
        return True

    # Current leader is someone else and they're fresh → step aside
    if age < _LEADER_STALE_AFTER:
        return False

    # Current leader is stale → they probably died, I take over
    print(
        f"[Leader] Taking over stale lease (last={age:.0f}s ago, "
        f"was pid={rec.get('pid')} port={rec.get('port')})",
        flush=True,
    )
    _write_leader_heartbeat()
    return True


def _start_server_scheduler():
    """Start the server-only email scheduler as a background daemon thread.
    Wakes every _SERVER_SEND_INTERVAL seconds, scans per-user queues,
    sends due emails via Graph/Gmail API.

    Leader election: only the elected leader actually sends. The passive
    side wakes up just as often but exits early if someone else has the
    lease  -  so no double sends during blue/green handoff.

    The leader also runs the newsletter auto-refresh tick every 6 hours  - 
    piggybacks on this loop to avoid a second daemon thread."""
    # Track last newsletter refresh time at module scope so it persists
    # across ticks. Starts at epoch so the first leader tick kicks off a
    # refresh pass immediately (catches newsletters due within 5 days).
    _last_nl_refresh = [0.0]
    _NL_REFRESH_INTERVAL = 6 * 60 * 60  # 6 hours

    def _loop():
        print(f"[ServerSend] Server email scheduler started "
              f"(interval: {_SERVER_SEND_INTERVAL}s, color={_MY_COLOR}, "
              f"port={_MY_PORT}, pid={os.getpid()})", flush=True)
        # Stagger startup by port so blue and green don't race on first boot
        time.sleep(10 + (2 if _MY_COLOR == "green" else 0))
        while True:
            try:
                if _am_i_leader():
                    _server_scheduler_tick()
                    # Newsletter auto-refresh: every 6 hours, generate fresh
                    # content for any newsletter whose next send is ≤ 5 days
                    # away. Runs here (not in its own thread) so leadership
                    # handoff kills it cleanly on deploys.
                    _now_mono = time.monotonic()
                    if (_now_mono - _last_nl_refresh[0]) >= _NL_REFRESH_INTERVAL:
                        _last_nl_refresh[0] = _now_mono
                        try:
                            _auto_refresh_newsletter_tick()
                        except Exception as e:
                            print(f"[NewsletterAutoRefresh] Tick error: {e}", flush=True)
                # Passive side: silently skip. Heartbeat updates happen in
                # _am_i_leader(), which still runs so handoff works.
            except Exception as e:
                print(f"[ServerSend] Tick error: {e}", flush=True)
            time.sleep(_SERVER_SEND_INTERVAL)

    t = threading.Thread(target=_loop, daemon=True, name="ServerEmailScheduler")
    t.start()


# ═══════════════════════════════════════════════════════════════════════════
#  SERVER-SIDE REPLY MONITOR  -  Graph API + Gmail API inbox polling
# ═══════════════════════════════════════════════════════════════════════════
# Polls each user's inbox every 5 minutes for replies from campaign contacts.
# When a reply is detected:
#   1. Adds to responded.json (same as desktop OutlookMonitor)
#   2. Cancels pending emails for that contact in that campaign
#   3. Adds to campaign's responders list
#   4. Detects opt-out language and adds to DNC if found

_REPLY_POLL_INTERVAL = 300  # 5 minutes


def _is_ooo_text(subject: str, body: str) -> bool:
    """Check if a message looks like an out-of-office auto-reply."""
    s = (subject + " " + body).lower()
    ooo_signals = [
        "out of office", "out of the office", "automatic reply",
        "auto-reply", "autoreply", "away from", "on vacation",
        "on leave", "will return", "limited access to email",
        "currently out", "not in the office",
    ]
    return any(sig in s for sig in ooo_signals)


def _is_opt_out_text(subject: str, body: str) -> bool:
    """Check if a reply contains opt-out/unsubscribe language."""
    s = (subject + " " + body).lower()
    opt_out_signals = [
        "unsubscribe", "opt out", "opt-out", "remove me",
        "stop emailing", "stop contacting", "take me off",
        "do not contact", "don't contact", "not interested",
        "please remove", "no longer interested",
    ]
    return any(sig in s for sig in opt_out_signals)


def _one_user_reply_scan(user_email: str, force_full: bool = False) -> int:
    """Run the reply monitor against a single user (used by the 'Scan Now'
    button on the Responses page). Returns count of new replies detected.

    Internally just restricts the iterator in _server_reply_monitor_tick
    to one user by setting an env-style hint. We don't have a hint
    mechanism, so we replicate the minimal logic here.
    """
    if not user_email:
        return 0
    safe = user_email.lower().strip().replace("@", "_at_").replace(".", "_")
    user_dir = _BASE_DATA_DIR / "users" / safe
    if not user_dir.exists():
        return 0
    # Simplest implementation: temporarily restrict the iterdir() in the
    # main tick to this user by passing a hint global.
    global _REPLY_SCAN_ONLY_USER
    _REPLY_SCAN_ONLY_USER = safe
    try:
        return _server_reply_monitor_tick(force_full_scan=force_full) or 0
    finally:
        _REPLY_SCAN_ONLY_USER = None


_REPLY_SCAN_ONLY_USER = None  # set by _one_user_reply_scan to limit scope


def _server_reply_monitor_tick(force_full_scan: bool = False):
    """One tick: scan all users' inboxes for replies from campaign contacts.

    Uses a persistent per-user checkpoint (`last_reply_scan_at` in config)
    so we never miss replies during service restarts or deploy gaps.

    - First scan for a user OR force_full_scan=True: look back 24 hours.
    - Subsequent scans: look back to (last_scan - 5 min buffer), capped at 24h.
    - After scan: save new checkpoint = now.

    force_full_scan is used by the "Scan inbox now" button on the
    Responses page to force a full 24-hour re-scan on demand.
    """
    from datetime import timezone as _tz
    users_dir = _BASE_DATA_DIR / "users"
    if not users_dir.exists():
        return 0

    total_replies = 0
    users_scanned = 0

    # If _one_user_reply_scan() set a hint, only scan that user's directory.
    # Otherwise scan all users (normal background polling behavior).
    if _REPLY_SCAN_ONLY_USER:
        _target = users_dir / _REPLY_SCAN_ONLY_USER
        _iter = [_target] if _target.exists() and _target.is_dir() else []
    else:
        _iter = users_dir.iterdir()

    for user_dir in _iter:
        if not user_dir.is_dir():
            continue
        config_path = user_dir / "dripdrop_config.json"
        if not config_path.exists():
            continue

        # Temporarily switch paths to this user's directory
        campaigns_dir = user_dir / "Campaigns"
        responded_path = campaigns_dir / "responded.json"
        dnc_path = user_dir / "dnc_list.json"

        # Load this user's campaigns and build enrolled map
        try:
            all_camps = []
            if campaigns_dir.exists():
                for f in campaigns_dir.glob("*.json"):
                    if f.name == "responded.json":
                        continue
                    try:
                        all_camps.append(json.loads(f.read_text(encoding="utf-8")))
                    except Exception:
                        continue
        except Exception:
            continue

        if not all_camps:
            continue

        enrolled = {}
        for camp in all_camps:
            is_eg = camp.get("evergreen_only", False)
            for c in camp.get("contacts", []):
                em = (c.get("email", "") or c.get("Email", "")).lower().strip()
                if em:
                    enrolled.setdefault(em, []).append(dict(
                        name=f"{c.get('first_name', c.get('FirstName', ''))} {c.get('last_name', c.get('LastName', ''))}".strip(),
                        campaign=camp.get("name", ""),
                        is_evergreen=is_eg))

        if not enrolled:
            continue

        # Load already-responded set
        responded_set = set()
        try:
            if responded_path.exists():
                responded_set = {r.get("email", "").lower()
                                 for r in json.loads(responded_path.read_text(encoding="utf-8"))}
        except Exception:
            pass

        # Figure out how far back to scan for this user. Persistent
        # checkpoint in config ensures we never miss replies across
        # restarts/deploys/gaps. Buffer of 5 extra minutes gives the Graph
        # API room for any indexing lag on newly-arrived messages.
        try:
            _user_cfg = json.loads(config_path.read_text(encoding="utf-8"))
        except Exception:
            _user_cfg = {}
        _checkpoint_iso = _user_cfg.get("last_reply_scan_at", "")
        _now_utc = datetime.now(_tz.utc)
        if force_full_scan or not _checkpoint_iso:
            _since_minutes = 60 * 24 * 7  # 7 days (first scan / manual rescan)
        else:
            try:
                _ckpt = datetime.fromisoformat(_checkpoint_iso.replace("Z", "+00:00"))
                if _ckpt.tzinfo is None:
                    _ckpt = _ckpt.replace(tzinfo=_tz.utc)
                _delta = (_now_utc - _ckpt).total_seconds() / 60.0
                # Cap at 7 days (covers extended downtime / missed replies)
                _since_minutes = min(60 * 24 * 7, max(15, int(_delta) + 5))
            except Exception:
                _since_minutes = 60 * 24 * 7  # bad checkpoint → 7-day fallback

        # Try Microsoft Graph inbox
        inbox_messages = []
        try:
            import ms_email
            if ms_email.is_configured():
                token = ms_email.get_valid_token(config_path)
                if token:
                    inbox_messages = ms_email.get_recent_inbox(token, since_minutes=_since_minutes)
        except ImportError:
            pass
        except Exception as e:
            print(f"[ReplyMonitor] MS Graph error for {user_dir.name}: {e}", flush=True)

        # Try Gmail inbox if no MS messages
        if not inbox_messages:
            try:
                import gmail_oauth
                if gmail_oauth.is_configured():
                    token = gmail_oauth.get_valid_token(config_path)
                    if token:
                        inbox_messages = gmail_oauth.get_recent_inbox(token, since_minutes=_since_minutes)
            except ImportError:
                pass
            except Exception as e:
                print(f"[ReplyMonitor] Gmail error for {user_dir.name}: {e}", flush=True)

        users_scanned += 1

        # Save the new checkpoint regardless of whether we found replies
        # (empty inbox is still a successful scan).
        try:
            _user_cfg["last_reply_scan_at"] = _now_utc.isoformat()
            config_path.write_text(json.dumps(_user_cfg, indent=2, default=str), encoding="utf-8")
        except Exception as e:
            print(f"[ReplyMonitor] Checkpoint save error for {user_dir.name}: {e}", flush=True)

        # ── Audit log  -  append-only per-user record of every scan so we can
        # retroactively prove we saw a message, even if matching logic later
        # regresses. Rotates at 500 entries to stay bounded on disk.
        try:
            _matched_senders = [
                m.get("from_email", "").lower().strip() for m in inbox_messages
                if m.get("from_email", "").lower().strip() in enrolled
            ]
            _audit_entry = {
                "scanned_at": _now_utc.isoformat(),
                "lookback_minutes": _since_minutes,
                "inbox_count": len(inbox_messages),
                "enrolled_count": len(enrolled),
                "matched_senders": _matched_senders,
                "unmatched_senders": sorted({
                    m.get("from_email", "").lower().strip() for m in inbox_messages
                    if m.get("from_email", "").lower().strip()
                    and m.get("from_email", "").lower().strip() not in enrolled
                })[:20],
            }
            _audit_path = user_dir / "reply_scan_audit.json"
            _audit_log = []
            if _audit_path.exists():
                try: _audit_log = json.loads(_audit_path.read_text(encoding="utf-8"))
                except Exception: _audit_log = []
            _audit_log.append(_audit_entry)
            if len(_audit_log) > 500:
                _audit_log = _audit_log[-500:]
            _audit_path.write_text(json.dumps(_audit_log, indent=2, default=str), encoding="utf-8")
        except Exception as e:
            print(f"[ReplyMonitor] Audit log error for {user_dir.name}: {e}", flush=True)

        if not inbox_messages:
            continue

        # ── Bounce detection: catch NDRs and suppress dead addresses ─────
        # Rewritten 2026-07-17 after a deliverability incident. The old
        # check matched only "postmaster"/"mailer-daemon" senders AND
        # required the address to already be enrolled — it missed ~95% of
        # real bounces: 69% of NDRs come from Office 365's internal
        # generator (MicrosoftExchange<hex>@<domain>, display "Microsoft
        # Outlook"), and hard bounces should be suppressed whether or not
        # the address is still enrolled. See _is_ndr_message / the NDR
        # parser (near add_to_dnc).
        #
        # Only HARD bounces (recipient doesn't exist) are suppressed. Soft
        # ones — mailbox full, policy/reputation blocks (5.7.x), transient
        # 4.x.x — are left alone so a real prospect is never lost.
        _my_domain = ""
        for _k in ("ms_email", "gmail_email", "email"):
            _v = (_user_cfg.get(_k) or "").strip().lower()
            if "@" in _v:
                _my_domain = _v.split("@", 1)[1]
                break
        for msg in inbox_messages:
            _from = (msg.get("from_email") or "").lower().strip()
            _subj = msg.get("subject") or ""
            if not _is_ndr_message(_from, _subj):
                continue
            _body = msg.get("body_full") or msg.get("body_preview") or ""
            _bounced = _parse_ndr_recipient(_subj, _body, _my_domain)
            if not _bounced:
                continue
            _status = _parse_ndr_status(_body)
            if _classify_bounce(_status, _body) != "hard":
                continue  # soft/transient — do not suppress
            # Cancel this address's pending queue items (the send path does
            # not gate on DNC, so cancelling is what actually stops sends).
            queue_path = user_dir / "scheduled_queue.json"
            if queue_path.exists():
                try:
                    _q = json.loads(queue_path.read_text(encoding="utf-8"))
                    _cancelled = 0
                    for qi in _q:
                        if (qi.get("status") == "pending"
                                and (qi.get("to") or "").lower().strip() == _bounced):
                            qi["status"] = "cancelled"
                            qi["cancelled_at"] = datetime.now(_tz.utc).isoformat()
                            qi["cancel_reason"] = "bounce_ndr"
                            _cancelled += 1
                    if _cancelled:
                        _qtmp = queue_path.with_suffix(".json.tmp")
                        _qtmp.write_text(json.dumps(_q, indent=2, default=str), encoding="utf-8")
                        os.replace(_qtmp, queue_path)
                        print(f"[ReplyMonitor] Bounce NDR ({_status or 'no-code'}): "
                              f"cancelled {_cancelled} pending email(s) for {_bounced}", flush=True)
                except Exception as _qe:
                    print(f"[ReplyMonitor] Bounce queue cancel error: {_qe}", flush=True)
            # Add to DNC (prevents re-enrollment). Canonical-ish shape,
            # source tagged so these are distinguishable from opt-outs.
            try:
                _dnc = []
                if dnc_path.exists():
                    try: _dnc = json.loads(dnc_path.read_text(encoding="utf-8"))
                    except Exception: _dnc = []
                if not any((d.get("email") or "").lower().strip() == _bounced for d in _dnc):
                    _dnc.insert(0, {
                        "email": _bounced,
                        "name": "", "company": "",
                        "reason": f"Hard bounce (NDR {_status or 'no-code'})",
                        "source": "ndr-bounce",
                        "added_at": datetime.now(_tz.utc).isoformat(),
                    })
                    _dtmp = dnc_path.with_suffix(".json.tmp")
                    _dtmp.write_text(json.dumps(_dnc, indent=2), encoding="utf-8")
                    os.replace(_dtmp, dnc_path)
                    print(f"[ReplyMonitor] Added {_bounced} to DNC (hard bounce {_status or 'no-code'})", flush=True)
            except Exception:
                pass

        # Match inbox messages against enrolled contacts
        for msg in inbox_messages:
            sender = msg.get("from_email", "").lower().strip()
            if not sender or sender not in enrolled or sender in responded_set:
                continue

            # Skip out-of-office
            if _is_ooo_text(msg.get("subject", ""), msg.get("body_preview", "")):
                continue

            infos = enrolled[sender]
            first_info = infos[0]
            is_opt_out = _is_opt_out_text(msg.get("subject", ""), msg.get("body_preview", ""))

            # Handle opt-out
            if is_opt_out:
                try:
                    dnc_list = json.loads(dnc_path.read_text(encoding="utf-8")) if dnc_path.exists() else []
                    if not any(d.get("email", "").lower() == sender for d in dnc_list):
                        dnc_list.append({
                            "email": sender,
                            "name": first_info["name"],
                            "reason": "Auto-detected opt-out from reply",
                            "source": "auto-opt-out",
                            "date": date.today().isoformat(),
                        })
                        dnc_path.write_text(json.dumps(dnc_list, indent=2, default=str), encoding="utf-8")
                except Exception:
                    pass

            # Cancel pending emails and add to responders for non-evergreen campaigns
            for info in infos:
                camp_name = info["campaign"]
                if info["is_evergreen"]:
                    continue
                # Cancel pending queue items
                queue_path = user_dir / "scheduled_queue.json"
                try:
                    if queue_path.exists():
                        q = json.loads(queue_path.read_text(encoding="utf-8"))
                        changed = False
                        for item in q:
                            if (item.get("to", "").lower().strip() == sender
                                    and item.get("campaign") == camp_name
                                    and item.get("status") == "pending"):
                                item["status"] = "cancelled"
                                changed = True
                        if changed:
                            tmp = queue_path.with_suffix(".tmp")
                            tmp.write_text(json.dumps(q, indent=2, default=str), encoding="utf-8")
                            tmp.replace(queue_path)
                except Exception:
                    pass

                # Add to campaign's responders list
                try:
                    for f in campaigns_dir.glob("*.json"):
                        if f.name == "responded.json":
                            continue
                        try:
                            camp_data = json.loads(f.read_text(encoding="utf-8"))
                        except Exception:
                            continue
                        if camp_data.get("name") != camp_name:
                            continue
                        responders = camp_data.get("responders", [])
                        # Tolerate both string and dict entries — _add_responder_to_campaign
                        # used to write strings, OutlookMonitor writes dicts; older
                        # campaign files have a mix.
                        if not any(_responder_email(r) == sender for r in responders):
                            responders.append({
                                "email": sender,
                                "name": first_info["name"],
                                "date": date.today().isoformat(),
                            })
                            camp_data["responders"] = responders
                            f.write_text(json.dumps(camp_data, indent=2, default=str), encoding="utf-8")
                        break
                except Exception:
                    pass

            # Log the response
            try:
                responded = json.loads(responded_path.read_text(encoding="utf-8")) if responded_path.exists() else []
                responded.append({
                    "email": sender,
                    "name": first_info["name"],
                    "campaign": first_info["campaign"],
                    "touch": "",
                    "subject": msg.get("subject", ""),
                    "reply_body": msg.get("body_preview", "")[:2000],
                    "date": datetime.now().isoformat(),
                })
                responded_path.parent.mkdir(parents=True, exist_ok=True)
                responded_path.write_text(json.dumps(responded, indent=2, default=str), encoding="utf-8")
            except Exception:
                pass

            responded_set.add(sender)
            total_replies += 1
            print(f"[ReplyMonitor] Reply detected: {sender} → {first_info['campaign']} "
                  f"({'OPT-OUT' if is_opt_out else 'reply'})", flush=True)

    # Always log  -  makes it easy to verify the monitor is alive and see
    # which user directories got scanned.
    print(
        f"[ReplyMonitor] Tick complete  -  scanned {users_scanned} user(s), "
        f"{total_replies} new replies detected",
        flush=True,
    )
    return total_replies


def _start_server_reply_monitor():
    """Start the server-side reply monitor as a background daemon thread.
    Leader-gated  -  only the leader process actually scans inboxes.

    On startup, the leader runs one forced 7-day catch-up scan before
    entering the polling loop. This guarantees replies that arrived
    during downtime, deploys, or any time the checkpoint fell behind
    are still imported  -  we never silently lose a reply across restarts.
    """
    def _loop():
        print(f"[ReplyMonitor] Server reply monitor started "
              f"(interval: {_REPLY_POLL_INTERVAL}s, color={_MY_COLOR})",
              flush=True)
        time.sleep(30)  # Wait for app init
        # Startup catch-up: on the FIRST tick where this process holds the
        # leader lease, force a full 7-day rescan. Guarantees nothing is
        # lost across deploys/restarts even if a prior checkpoint was recent.
        _startup_catchup_done = False
        while True:
            try:
                if _am_i_leader():
                    if not _startup_catchup_done:
                        print("[ReplyMonitor] Startup catch-up: forcing 7-day rescan", flush=True)
                        _server_reply_monitor_tick(force_full_scan=True)
                        _startup_catchup_done = True
                    else:
                        _server_reply_monitor_tick()
            except Exception as e:
                print(f"[ReplyMonitor] Tick error: {e}", flush=True)
            time.sleep(_REPLY_POLL_INTERVAL)

    t = threading.Thread(target=_loop, daemon=True, name="ServerReplyMonitor")
    t.start()


# Entry point
# Register the gated Arena ATS page (/ats). Imported at module load so its
# @ui.page route registers before ui.run(). Guarded so an ats.py problem can
# never stop the main app from booting. ats.py reaches back into this module
# via sys.modules (never `import flowdrip_app`), so this is not circular.
try:
    import ats as _ats_module  # noqa: F401  (registers @ui.page("/ats"))
except Exception as _ats_imp_ex:
    print(f"[ATS] module import failed (ATS page disabled): {_ats_imp_ex}", flush=True)


if __name__ in {"__main__", "__mp_main__"}:
    # Silently archive queue entries older than 30 days before the UI starts.
    # This keeps the live queue file lean without any user action required.
    #
    # Server mode: archive_old_queue_entries() resolves to a per-user file
    # via _user_queue_path() — calling it here at module init (before any
    # user is bound) falls through LEAK_GUARD and would archive the SHARED
    # _BASE_DATA_DIR/scheduled_queue.json file (which may not even exist
    # in well-isolated installs). Per-user archiving in server mode is
    # better done lazily on first access or by the ServerEmailScheduler
    # iterating users. Skip the boot-time call until that's built.
    if not _SERVER_MODE:
        _archived = archive_old_queue_entries(days=30)
        if _archived:
            print(f"[DripDrop] Archived {_archived} old queue entries → scheduled_queue_archive.json")
    # One-shot tenant admin migration: promote the oldest user from each
    # email domain to tenant_admin if the domain has no admin yet. Fills
    # the gap for users (like Michael at arenastaffing.net) who signed up
    # before the is_tenant_admin field existed. Idempotent — re-running
    # does nothing if every domain already has an admin.
    try:
        _promoted = _bootstrap_tenant_admins()
        if _promoted:
            print(f"[DripDrop] Bootstrap promoted {_promoted} user(s) to tenant_admin")
    except Exception as _ex:
        print(f"[DripDrop] tenant admin bootstrap error: {_ex}")
    # Background services
    if _IS_WINDOWS:
        outlook_monitor.start()
        pool_scanner.start()  # Weekly auto-scan for new job postings
    else:
        print("[DripDrop] Server mode  -  Outlook monitor and pool scanner disabled")
    # Start the email scheduler
    if _SERVER_MODE:
        # Server: use the Graph/Gmail API scheduler (HTTPS, port 443)
        _start_server_scheduler()
        # Server: poll inboxes for replies from campaign contacts
        _start_server_reply_monitor()
    elif _FUNNELFORGE_OK and _ffc is not None:
        # Desktop: use funnelforge_core's Outlook COM scheduler.
        # C12: pass the per-user queue path explicitly; the scheduler
        # thread stores it and uses it on every tick.
        _ffc.start_scheduler(_user_queue_path())
    _port = int(os.getenv("DRIPDROP_PORT", "8080"))
    ui.run(
        title="DripDrop",
        port=_port,
        dark=True,
        reload=False,
        show=not _SERVER_MODE,
        host="0.0.0.0" if _SERVER_MODE else "127.0.0.1",
        favicon=str(_APP_DIR / "assets" / "dripdrop_icon.png"),
        storage_secret=_STORAGE_SECRET,
        # Short cache for NiceGUI's internal JS/CSS. Default is 1-year
        # immutable, which prevents browsers from ever re-fetching patched
        # component files (like our editor.js toolbar fix). 1-hour cache
        # balances performance with the ability to deploy patches.
        cache_control_directives="public, max-age=3600",
        # NiceGUI's default is 3 seconds — way too short. Cloudflare's
        # free-plan WS proxy drops idle sockets at ~100s and any normal
        # network blip is 5-30s, so the 3s default meant every reconnect
        # was treated as a NEW client: page handler re-ran, widgets
        # rebuilt, and anything the user had typed mid-sentence was wiped.
        # 600s holds the server-side client state for 10 minutes so a
        # reconnecting browser picks up exactly where it was. The JS
        # overlay at the top of this file still shows "Reconnecting…"
        # after 15s of failed reconnect — that UX is unchanged.
        reconnect_timeout=600.0,
    )

